    // Seat
    const seat = new THREE.Mesh(new THREE.BoxGeometry(1.4, 0.1, 1.4), mat);
    seat.position.y = 1;
    chair.add(seat);

    // Backrest
    const back = new THREE.Mesh(new THREE.BoxGeometry(1.4, 1.1, 0.08), mat);
    back.position.set(0, 1.6, -0.66);
