const pages = new THREE.Mesh(new THREE.BoxGeometry(w - 0.1, h - 0.1, d - 0.06), pageMat);
pages.castShadow = true;
book.add(pages);

// Spine
const spine = new THREE.Mesh(new THREE.BoxGeometry(0.05, h, d), spineMat);
spine.position.x = -w / 2;
spine.castShadow = true;
book.add(spine);

// Gold title band on cover
const band = new THREE.Mesh(new THREE.BoxGeometry(w * 0.6, 0.06, 0.052), goldMat);
band.position.set(0, 0.6, d / 2);
book.add(band);

const band2 = band.clone();
band2.position.y = -0.4;
book.add(band2);

// Page edge lines (decorative thin planes)
for (let i = 0; i < 8; i++) {
  const line = new THREE.Mesh(
    new THREE.BoxGeometry(w - 0.1, 0.008, d - 0.06),
    new THREE.MeshStandardMaterial({ color: 0xE8DDD0, roughness: 1 })
  );
  line.position.y = (i - 3.5) * (h - 0.1) / 8;
  book.add(line);
}

scene.add(book);

// ——— Ground plane (shadow catcher) ———
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(20, 20),
  new THREE.ShadowMaterial({ opacity: 0.3 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2;
ground.receiveShadow = true;
scene.add(ground);

// ——— Animate ———
function animate() {
  requestAnimationFrame(animate);
  book.rotation.y += 0.005;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// ——— Resize ———
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the file

| Piece | Purpose |
|---|---|
| **Covers** (front/back) | Dark red `BoxGeometry` slabs |
| **Pages** | Cream-colored block slightly inset from the covers |
| **Spine** | Darker red strip on the left edge |
| **Gold bands** | Thin metallic strips on the front cover for decoration |
| **Page-edge lines** | Thin horizontal planes simulating page separations |
| **OrbitControls** | Click-drag to rotate, scroll to zoom |
| **Auto-rotation** | The book slowly spins on its own (`book.rotation.y += 0.005`) |
| **Shadow ground** | A `ShadowMaterial` plane catches soft shadows |

