for (let i = 0; i < 5; i++) {
  const a = (i / 5) * Math.PI * 2;
  const sepal = createPetalMesh(0.2, 0.7, 0x2e8a2e, 8);
  sepal.position.set(0, 4.15, 0);
  sepal.rotation.y = a;
  sepal.rotation.x = -0.8;
  sepal.rotation.z = 0;
  flower.add(sepal);
}

/* ─── petals ─── */
const petalLayers = [
  { count: 8, w: 0.55, h: 1.35, color: 0xff4477, yOff: 4.35, xRot: -0.45, zTilt: 0.12 },
  { count: 8, w: 0.45, h: 1.10, color: 0xff6699, yOff: 4.42, xRot: -0.35, zTilt: 0.08, offset: Math.PI / 8 },
  { count: 6, w: 0.35, h: 0.85, color: 0xff88bb, yOff: 4.50, xRot: -0.25, zTilt: 0.05 },
  { count: 5, w: 0.25, h: 0.65, color: 0xffaaee, yOff: 4.58, xRot: -0.15, zTilt: 0.02 },
];

const allPetals = [];

petalLayers.forEach(layer => {
  for (let i = 0; i < layer.count; i++) {
    const angle = (i / layer.count) * Math.PI * 2 + (layer.offset || 0);
    const petal = createPetalMesh(layer.w, layer.h, layer.color);
    petal.position.set(0, layer.yOff, 0);
    petal.rotation.y = angle;
    petal.rotation.x = layer.xRot;
    petal.rotation.z = layer.zTilt * Math.cos(angle);
    petal.castShadow = true;
    petal.receiveShadow = true;
    flower.add(petal);
    allPetals.push(petal);
  }
});

/* ─── center (receptacle) ─── */
const centerGeo = new THREE.SphereGeometry(0.35, 24, 16);
const centerMat = new THREE.MeshStandardMaterial({
  color: 0xffcc00,
  roughness: 0.5,
  metalness: 0.1,
});
const center = new THREE.Mesh(centerGeo, centerMat);
center.position.y = 4.55;
center.scale.y = 0.6;
flower.add(center);

/* ─── stamen cluster ─── */
const stamenCount = 40;
for (let i = 0; i < stamenCount; i++) {
  const phi = Math.acos(1 - 2 * (i + 0.5) / stamenCount);
  const theta = Math.PI * (1 + Math.sqrt(5)) * i;
  const r = 0.18;

  const stemG = new THREE.CylinderGeometry(0.008, 0.008, 0.25, 4);
  const stemM = new THREE.MeshStandardMaterial({ color: 0xddaa00, roughness: 0.6 });
  const stamenStem = new THREE.Mesh(stemG, stemM);

  const tipG = new THREE.SphereGeometry(0.025, 6, 6);
  const tipM = new THREE.MeshStandardMaterial({
    color: 0xffee44,
    roughness: 0.3,
    metalness: 0.1,
    emissive: 0xffcc00,
    emissiveIntensity: 0.15,
  });
  const tip = new THREE.Mesh(tipG, tipM);
  tip.position.y = 0.13;
  stamenStem.add(tip);

  stamenStem.position.set(
    r * Math.sin(phi) * Math.cos(theta),
    4.55 + r * Math.cos(phi) * 0.4 + 0.05,
    r * Math.sin(phi) * Math.sin(theta)
  );
  stamenStem.lookAt(new THREE.Vector3(
    stamenStem.position.x * 2,
    stamenStem.position.y + 0.5,
    stamenStem.position.z * 2
  ));
  flower.add(stamenStem);
}

/* ─── pollen particles ─── */
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const pPositions = new Float32Array(particleCount * 3);
const pSizes = new Float32Array(particleCount);
for (let i = 0; i < particleCount; i++) {
  const angle = Math.random() * Math.PI * 2;
