<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene    = new THREE.Scene();
const camera   = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

camera.position.set(3, 2, 4);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;

// ── Lights ──
scene.add(new THREE.AmbientLight(0x404060, 0.5));
const dir = new THREE.DirectionalLight(0xffeedd, 2);
dir.position.set(5, 5, 5);
scene.add(dir);
const rim = new THREE.PointLight(0x4488ff, 1.5, 10);
rim.position.set(-3, 1, -2);
scene.add(rim);

// ── Material ──
const mat = new THREE.MeshStandardMaterial({
  color: 0xd4a843, metalness: 0.9, roughness: 0.25
});

// ── Key Group ──
const key = new THREE.Group();

// Bow (ring handle)
const bowGeo = new THREE.TorusGeometry(0.55, 0.12, 24, 48);
const bow = new THREE.Mesh(bowGeo, mat);
bow.position.set(-1.8, 0, 0);
key.add(bow);

// Bow center cap
const capGeo = new THREE.CylinderGeometry(0.15, 0.15, 0.08, 32);
const cap = new THREE.Mesh(capGeo, mat);
cap.rotation.z = Math.PI / 2;
cap.position.set(-1.8, 0, 0);
key.add(cap);

// Shaft
const shaftGeo = new THREE.CylinderGeometry(0.08, 0.08, 2.8, 16);
const shaft = new THREE.Mesh(shaftGeo, mat);
shaft.rotation.z = Math.PI / 2;
shaft.position.set(0.2, 0, 0);
key.add(shaft);

// Blade (flat bottom strip)
const bladeGeo = new THREE.BoxGeometry(1.2, 0.04, 0.3);
const blade = new THREE.Mesh(bladeGeo, mat);
blade.position.set(1.1, -0.1, 0);
key.add(blade);

// Teeth
const toothPositions = [
  { x: 1.35, h: 0.28 },
  { x: 1.60, h: 0.18 },
  { x: 1.85, h: 0.32 },
  { x: 2.10, h: 0.22 },
];
toothPositions.forEach(t => {
  const g = new THREE.BoxGeometry(0.12, t.h, 0.3);
  const m = new THREE.Mesh(g, mat);
  m.position.set(t.x, -0.12 - t.h / 2, 0);
  key.add(m);
});

// Tip
const tipGeo = new THREE.CylinderGeometry(0.08, 0.06, 0.2, 16);
const tip = new THREE.Mesh(tipGeo, mat);
tip.rotation.z = Math.PI / 2;
tip.position.set(1.9, 0, 0);
key.add(tip);

// Small decorative hole in bow
const holeGeo = new THREE.TorusGeometry(0.25, 0.03, 12, 32);
const hole = new THREE.Mesh(holeGeo, mat);
hole.position.set(-1.8, 0, 0);
key.add(hole);

// Slight tilt
key.rotation.x = 0.15;
key.rotation.z = 0.05;
scene.add(key);

// ── Ground plane (subtle reflection hint) ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(20, 20),
  new THREE.MeshStandardMaterial({ color: 0x1a1a2e, metalness: 0.3, roughness: 0.8 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.5;
scene.add(ground);

// ── Animate ──
function animate(t) {
  requestAnimationFrame(animate);
  key.rotation.y = Math.sin(t * 0.001) * 0.4;
  key.position.y = Math.sin(t * 0.0015) * 0.15;
  controls.update();
  renderer.render(scene, camera);
}
animate(0);

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **Golden metallic key** built from `TorusGeometry`, `CylinderGeometry`, and `BoxGeometry` primitives
- **Bow** — a ring handle with a center cap and decorative inner ring
- **Shaft & blade** — cylindrical shaft with a flat bottom strip
- **4 teeth** — varying heights to simulate real key bittings
- **Lighting** — warm directional + cool blue rim light for dramatic metallic reflections
- **Gentle animation** — the key slowly rocks and floats
- **Orbit controls** — drag to rotate, scroll to zoom

Just save as `index.html` and open in any modern browser.

