);
featherTube.castShadow = true;
hat.add(featherTube);

// Feather vane (flat ribbon-like shape)
const featherVaneShape = new THREE.Shape();
featherVaneShape.moveTo(0, 0);
featherVaneShape.bezierCurveTo(0.08, 0.15, 0.12, 0.4, 0.06, 0.6);
featherVaneShape.bezierCurveTo(0.02, 0.75, -0.02, 0.85, -0.05, 0.9);
featherVaneShape.bezierCurveTo(-0.08, 0.75, -0.06, 0.4, -0.04, 0.15);
featherVaneShape.lineTo(0, 0);

const featherVane = new THREE.Mesh(
  new THREE.ShapeGeometry(featherVaneShape, 32),
  new THREE.MeshStandardMaterial({
    color: 0xcc3333, roughness: 0.8, metalness: 0.05, side: THREE.DoubleSide
  })
);
featherVane.position.set(0.05, 0.3, -0.2);
featherVane.rotation.set(0.3, -0.5, 0.2);
featherVane.castShadow = true;
hat.add(featherVane);

/* ─── position hat ─── */
hat.position.y = 0.03;

/* ─── animation ─── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float
  hat.position.y = 0.03 + Math.sin(t * 0.8) * 0.08;
  hat.rotation.y = Math.sin(t * 0.3) * 0.15;

  // Feather sway
  featherTube.rotation.z = Math.sin(t * 1.5) * 0.06;
  featherVane.rotation.z = Math.sin(t * 1.5) * 0.08;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ─── resize ─── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

