<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 1000);
camera.position.set(0, 2, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 1, 0);

// --- Stars ---
const starsGeo = new THREE.BufferGeometry();
const starsPos = Array.from({ length: 2000 }, () => (Math.random() - 0.5) * 400);
starsGeo.setAttribute('position', new THREE.Float32BufferAttribute(starsPos, 3));
scene.add(new THREE.Points(starsGeo, new THREE.PointsMaterial({
  color: 0xffffff, size: 0.3, sizeAttenuation: true
})));

// --- Lighting ---
scene.add(new THREE.AmbientLight(0x334466, 0.8));
const sun = new THREE.DirectionalLight(0xffeedd, 3);
sun.position.set(5, 8, 5);
scene.add(sun);
const rim = new THREE.PointLight(0x4488ff, 2, 20);
rim.position.set(-3, 1, -3);
scene.add(rim);

// --- Rocket Group ---
const rocket = new THREE.Group();

// Body
rocket.add(Object.assign(
  new THREE.Mesh(new THREE.CylinderGeometry(0.4, 0.45, 3, 32),
    new THREE.MeshStandardMaterial({ color: 0xddeeff, metalness: 0.3, roughness: 0.4 })),
  { position: new THREE.Vector3(0, 1.5, 0) }
));

// Nose cone
rocket.add(Object.assign(
  new THREE.Mesh(new THREE.ConeGeometry(0.4, 1.2, 32),
    new THREE.MeshStandardMaterial({ color: 0xff4444, metalness: 0.2, roughness: 0.3 })),
  { position: new THREE.Vector3(0, 3.6, 0) }
));

// Window
rocket.add(Object.assign(
  new THREE.Mesh(new THREE.SphereGeometry(0.15, 16, 16),
    new THREE.MeshStandardMaterial({ color: 0x88ccff, metalness: 0.9, roughness: 0.1 })),
  { position: new THREE.Vector3(0, 2.4, 0.35) }
));

// Band stripe
rocket.add(Object.assign(
  new THREE.Mesh(new THREE.CylinderGeometry(0.46, 0.46, 0.15, 32),
    new THREE.MeshStandardMaterial({ color: 0xff4444, metalness: 0.2, roughness: 0.5 })),
  { position: new THREE.Vector3(0, 2.8, 0) }
));

// Fins
const finShape = new THREE.Shape();
finShape.moveTo(0, 0);
finShape.lineTo(0.7, -0.9);
finShape.lineTo(0.5, -1.0);
finShape.lineTo(0, -0.3);

const finGeo = new THREE.ExtrudeGeometry(finShape, { depth: 0.05, bevelEnabled: false });
const finMat = new THREE.MeshStandardMaterial({ color: 0xcc3333, metalness: 0.2, roughness: 0.5 });

for (let i = 0; i < 4; i++) {
  const fin = new THREE.Mesh(finGeo, finMat);
  fin.position.set(0, 0.1, 0);
  fin.rotation.y = (Math.PI / 2) * i;
  fin.translateZ(0.42);
  rocket.add(fin);
}

// Nozzle
rocket.add(Object.assign(
  new THREE.Mesh(new THREE.CylinderGeometry(0.2, 0.3, 0.3, 16),
    new THREE.MeshStandardMaterial({ color: 0x444444, metalness: 0.8, roughness: 0.3 })),
  { position: new THREE.Vector3(0, -0.05, 0) }
));

scene.add(rocket);

// --- Flame Particles ---
const FLAME_COUNT = 200;
const flameGeo = new THREE.BufferGeometry();
const flamePositions = new Float32Array(FLAME_COUNT * 3);
const flameSizes = new Float32Array(FLAME_COUNT);
const flameData = []; // store velocity, life, maxLife

for (let i = 0; i < FLAME_COUNT; i++) {
  flamePositions[i * 3] = (Math.random() - 0.5) * 0.15;
  flamePositions[i * 3 + 1] = -0.3;
  flamePositions[i * 3 + 2] = (Math.random() - 0.5) * 0.15;
  flameSizes[i] = Math.random() * 6 + 2;
  flameData.push({
    vy: -(Math.random() * 0.08 + 0.04),
    life: Math.random(),
    spread: Math.random() * 0.005
  });
}

flameGeo.setAttribute('position', new THREE.Float32BufferAttribute(flamePositions, 3));
flameGeo.setAttribute('size', new THREE.Float32BufferAttribute(flameSizes, 1));

const flameMat = new THREE.ShaderMaterial({
  uniforms: { uTime: { value: 0 } },
  vertexShader: `
    attribute float size;
    varying float vAlpha;
    void main() {
      vAlpha = 1.0 - smoothstep(0.0, 1.0, position.y / -3.0);
      vec4 mv = modelViewMatrix * vec4(position, 1.0);
      gl_PointSize = size * (200.0 / -mv.z);
      gl_Position = projectionMatrix * mv;
    }
  `,
  fragmentShader: `
    varying float vAlpha;
    void main() {
      float d = length(gl_PointCoord - 0.5) * 2.0;
      float alpha = smoothstep(1.0, 0.0, d) * vAlpha;
      vec3 color = mix(vec3(1.0, 0.9, 0.3), vec3(1.0, 0.3, 0.05), 1.0 - vAlpha);
      gl_FragColor = vec4(color, alpha * 0.8);
    }
  `,
  transparent: true,
  depthWrite: false,
  blending: THREE.AdditiveBlending
});

const flameParticles = new THREE.Points(flameGeo, flameMat);
rocket.add(flameParticles);

// --- Smoke Particles ---
const SMOKE_COUNT = 80;
const smokeGeo = new THREE.BufferGeometry();
const smokePositions = new Float32Array(SMOKE_COUNT * 3);
const smokeSizes = new Float32Array(SMOKE_COUNT);
const smokeData = [];

for (let i = 0; i < SMOKE_COUNT; i++) {
  smokePositions[i * 3] = (Math.random() - 0.5) * 0.5;
  smokePositions[i * 3 + 1] = -0.5 - Math.random() * 3;
  smokePositions[i * 3 + 2] = (Math.random() - 0.5) * 0.5;
  smokeSizes[i] = Math.random() * 10 + 5;
  smokeData.push({
    vy: -(Math.random() * 0.02 + 0.01),
    life: Math.random(),
    spread: Math.random() * 0.01 + 0.005
  });
}

smokeGeo.setAttribute('position', new THREE.Float32BufferAttribute(smokePositions, 3));
smokeGeo.setAttribute('size', new THREE.Float32BufferAttribute(smokeSizes, 1));

const smokeMat = new THREE.ShaderMaterial({
  vertexShader: `
    attribute float size;
    varying float vAlpha;
    void main() {
      vAlpha = 1.0 - smoothstep(-0.5, -3.5, position.y);
      vec4 mv = modelViewMatrix * vec4(position, 1.0);
      gl_PointSize = size * (200.0 / -mv.z);
      gl_Position = projectionMatrix * mv;
    }
  `,
  fragmentShader: `
    varying float vAlpha;
    void main() {
      float d = length(gl_PointCoord - 0.5) * 2.0;
      float alpha = smoothstep(1.0, 0.2, d) * vAlpha * 0.25;
      gl_FragColor = vec4(0.6, 0.6, 0.65, alpha);
    }
  `,
  transparent: true,
  depthWrite: false
});

const smokeParticles = new THREE.Points(smokeGeo, smokeMat);
rocket.add(smokeParticles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Idle hover
  rocket.position.y = Math.sin(t * 1.2) * 0.15;
  rocket.rotation.z = Math.sin(t * 0.7) * 0.02;

  // Update flame particles
  const fp = flameGeo.attributes.position.array;
  for (let i = 0; i < FLAME_COUNT; i++) {
    const d = flameData[i];
    fp[i * 3 + 1] += d.vy;
    fp[i * 3] += (Math.random() - 0.5) * d.spread;
    fp[i * 3 + 2] += (Math.random() - 0.5) * d.spread;
    if (fp[i * 3 + 1] < -3) {
      fp[i * 3] = (Math.random() - 0.5) * 0.15;
      fp[i * 3 + 1] = -0.3;
      fp[i * 3 + 2] = (Math.random() - 0.5) * 0.15;
