}
scene.add(createTrack());

// --- Wheels ---
function createWheelPair(z) {
  const group = new THREE.Group();
  const wheelGeo = new THREE.CylinderGeometry(0.45, 0.45, 0.15, 16);

  const w1 = new THREE.Mesh(wheelGeo, mat.wheel);
  w1.rotation.x = Math.PI / 2;
  w1.position.set(0, 0.45, z - 0.1);
  w1.castShadow = true;
  group.add(w1);

  const w2 = new THREE.Mesh(wheelGeo, mat.wheel);
  w2.rotation.x = Math.PI / 2;
  w2.position.set(0, 0.45, z + 0.1);
  w2.castShadow = true;
  group.add(w2);

  // Axle
  const axle = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.08, 0.4, 8), mat.darkMetal);
  axle.rotation.x = Math.PI / 2;
  axle.position.set(0, 0.45, z);
  group.add(axle);

  return group;
}

// --- Smokestack ---
function createSmokestack() {
  const group = new THREE.Group();
  const stack = new THREE.Mesh(new THREE.CylinderGeometry(0.2, 0.3, 1.2, 12), mat.darkMetal);
  stack.position.y = 2.6;
  stack.castShadow = true;
  group.add(stack);

  const cap = new THREE.Mesh(new THREE.CylinderGeometry(0.35, 0.2, 0.2, 12), mat.gold);
  cap.position.y = 3.2;
  group.add(cap);

  const dome = new THREE.Mesh(new THREE.SphereGeometry(0.35, 12, 8, 0, Math.PI * 2, 0, Math.PI / 2), mat.darkMetal);
  dome.position.y = 2.6;
  group.add(dome);

  return group;
}

// --- Locomotive ---
function createLocomotive() {
  const loco = new THREE.Group();

  // Boiler
  const boiler = new THREE.Mesh(new THREE.CylinderGeometry(0.9, 0.9, 3.5, 16), mat.body);
  boiler.rotation.x = Math.PI / 2;
  boiler.position.set(-1.5, 1.3, 0);
  boiler.castShadow = true;
  loco.add(boiler);

  // Boiler bands
  for (let i = 0; i < 3; i++) {
    const band = new THREE.Mesh(new THREE.TorusGeometry(0.92, 0.04, 8, 16), mat.gold);
    band.rotation.y = Math.PI / 2;
    band.position.set(-2.5 + i * 1.2, 1.3, 0);
    loco.add(band);
  }

  // Cabin
  const cabin = new THREE.Mesh(new THREE.BoxGeometry(1.5, 1.8, 2.2), mat.bodyDark);
  cabin.position.set(2, 2.2, 0);
  cabin.castShadow = true;
  loco.add(cabin);

  // Cabin roof
  const roof = new THREE.Mesh(new THREE.BoxGeometry(1.7, 0.1, 2.4), mat.darkMetal);
  roof.position.set(2, 3.15, 0);
  roof.castShadow = true;
  loco.add(roof);

  // Cabin windows
  const winGeo = new THREE.PlaneGeometry(0.6, 0.7);
  for (let side of [-1, 1]) {
    const win = new THREE.Mesh(winGeo, mat.glass);
    win.position.set(2, 2.3, side * 1.11);
    win.rotation.y = side * Math.PI / 2;
    loco.add(win);
  }
  // Front cabin window
  const fWin = new THREE.Mesh(new THREE.PlaneGeometry(0.8, 0.7), mat.glass);
  fWin.position.set(2.76, 2.3, 0);
  loco.add(fWin);

  // Smokestack
  loco.add(createSmokestack());

  // Cowcatcher
  const cow = new THREE.Mesh(new THREE.BoxGeometry(0.8, 0.3, 1.6), mat.darkMetal);
  cow.position.set(-3.4, 0.55, 0);
  cow.rotation.z = 0.15;
  cow.castShadow = true;
  loco.add(cow);

  // Chimney front
  const frontPlate = new THREE.Mesh(new THREE.BoxGeometry(0.1, 1.6, 1.8), mat.darkMetal);
  frontPlate.position.set(-3.2, 1.2, 0);
  loco.add(frontPlate);

  // Headlight
  const light = new THREE.Mesh(new THREE.SphereGeometry(0.15, 8, 8), mat.gold);
  light.position.set(-3.25, 2.0, 0);
  loco.add(light);

  // Wheels: 3 driving wheels + 1 smaller front
  const wheelGroups = [];
  const positions = [
    { x: -2.8, z: 0, r: 0.35 },
    { x: -1.5, z: 0, r: 0.55 },
    { x: 0, z: 0, r: 0.55 },
    { x: 1.5, z: 0, r: 0.55 },
    { x: 2.8, z: 0, r: 0.4 },
  ];

  positions.forEach(p => {
    const wp = createWheelPair(p.z);
    wp.children.forEach(c => {
      if (c.geometry?.type === 'CylinderGeometry' && c.geometry.parameters.radiusTop === (p.r || 0.45)) {
        c.scale.set(p.r / 0.45, 1, 1);
        c.position.y = (p.r || 0.45);
      }
    });
    // Rebuild with correct radius
    wp.clear();
    const wGeo = new THREE.CylinderGeometry(p.r, p.r, 0.15, 16);
    const w1 = new THREE.Mesh(wGeo, mat.wheel);
    w1.rotation.x = Math.PI / 2;
    w1.position.set(0, p.r, -0.1);
    w1.castShadow = true;
    wp.add(w1);
    const w2 = new THREE.Mesh(wGeo, mat.wheel);
    w2.rotation.x = Math.PI / 2;
    w2.position.set(0, p.r, 0.1);
    w2.castShadow = true;
    wp.add(w2);
    const axle = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.06, 0.4, 8), mat.darkMetal);
    axle.rotation.x = Math.PI / 2;
    axle.position.set(0, p.r, 0);
    wp.add(axle);

    wp.position.set(p.x, 0, 0);
    loco.add(wp);
    wheelGroups.push(wp);
  });

  loco.position.set(0, 0, 0);
  loco.userData.wheels = wheelGroups;
  return loco;
}

// --- Passenger Carriage ---
function createCarriage(color) {
  const car = new THREE.Group();
  const bodyMat = new THREE.MeshStandardMaterial({ color, roughness: 0.3 });

  // Main body
  const body = new THREE.Mesh(new THREE.BoxGeometry(4, 2, 2), bodyMat);
  body.position.set(0, 1.8, 0);
  body.castShadow = true;
  car.add(body);

  // Cream stripe
  const stripe = new THREE.Mesh(new THREE.BoxGeometry(4.02, 0.3, 2.02), mat.carriageCream);
  stripe.position.set(0, 2.2, 0);
  car.add(stripe);

  // Roof
  const roof = new THREE.Mesh(new THREE.BoxGeometry(4.1, 0.1, 2.2), mat.darkMetal);
  roof.position.set(0, 2.9, 0);
  roof.castShadow = true;
  car.add(roof);

  // Windows
  const winGeo = new THREE.PlaneGeometry(0.5, 0.6);
  for (let side of [-1, 1]) {
    for (let i = -1; i <= 1; i++) {
      const win = new THREE.Mesh(winGeo, mat.glass);
      win.position.set(i * 1.2, 1.9, side * 1.01);
      win.rotation.y = side * Math.PI / 2;
      car.add(win);
    }
  }

  // Wheels
  const wheelGroups = [];
  for (let x of [-1.3, 1.3]) {
    const wp = createWheelPair(0);
    wp.position.set(x, 0, 0);
    car.add(wp);
    wheelGroups.push(wp);
  }

  // Coupler
  const coupler = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.06, 0.5, 8), mat.darkMetal);
  coupler.rotation.z = Math.PI / 2;
  coupler.position.set(2.1, 0.7, 0);
  car.add(coupler);
  const coupler2 = coupler.clone();
  coupler2.position.set(-2.1, 0.7, 0);
  car.add(coupler2);

  car.userData.wheels = wheelGroups;
  return car;
}

