// --- Shaft ---
const shaftGeo = new THREE.CylinderGeometry(0.05, 0.05, 4.5, 8);
const shaftMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.3, metalness: 0.5 });
const shaft = new THREE.Mesh(shaftGeo, shaftMat);
shaft.position.y = -1.5;
shaft.castShadow = true;
umbrella.add(shaft);

// --- Curved handle (J-shape via Torus segment) ---
const handleCurve = new THREE.Curve();
const handlePath = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, -3.75, 0),
  new THREE.Vector3(0.15, -3.9, 0),
  new THREE.Vector3(0.4, -3.85, 0),
  new THREE.Vector3(0.55, -3.7, 0),
  new THREE.Vector3(0.5, -3.5, 0),
  new THREE.Vector3(0.3, -3.4, 0),
]);
const handleGeo = new THREE.TubeGeometry(handlePath, 20, 0.055, 8, false);
const handleMat = new THREE.MeshStandardMaterial({ color: 0x5C3317, roughness: 0.6, metalness: 0.1 });
const handle = new THREE.Mesh(handleGeo, handleMat);
handle.castShadow = true;
umbrella.add(handle);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(20, 32);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x4A7C59, roughness: 0.9 });
