<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Three.js Wheel</title>
<style>body { margin: 0; overflow: hidden; background: #111; }</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x111111);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);

// Lights
scene.add(new THREE.AmbientLight(0x404050, 2));
const dirLight = new THREE.DirectionalLight(0xffffff, 3);
dirLight.position.set(5, 5, 5);
dirLight.castShadow = true;
scene.add(dirLight);

// Materials
const tireMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.9 });
const rimMat  = new THREE.MeshStandardMaterial({ color: 0xcccccc, metalness: 0.8, roughness: 0.2 });
const hubMat  = new THREE.MeshStandardMaterial({ color: 0x888888, metalness: 0.6, roughness: 0.3 });

// Wheel group
const wheel = new THREE.Group();

// Tire (torus)
const tire = new THREE.Mesh(
  new THREE.TorusGeometry(1.2, 0.35, 24, 48),
  tireMat
);
tire.castShadow = true;
wheel.add(tire);

// Rim disc (flat cylinder)
const rim = new THREE.Mesh(
  new THREE.CylinderGeometry(1.0, 1.0, 0.08, 48),
  rimMat
);
rim.rotation.x = Math.PI / 2;
rim.castShadow = true;
wheel.add(rim);

// Rim barrel (inner cylinder)
const barrel = new THREE.Mesh(
  new THREE.CylinderGeometry(0.95, 0.95, 0.5, 48),
  rimMat
);
barrel.rotation.x = Math.PI / 2;
wheel.add(barrel);

// Hub
const hub = new THREE.Mesh(
  new THREE.CylinderGeometry(0.2, 0.2, 0.55, 16),
  hubMat
);
hub.rotation.x = Math.PI / 2;
hub.castShadow = true;
wheel.add(hub);

// Spokes
const spokeCount = 5;
const spokeLen = 0.85;
const spokeW = 0.06;
const spokeD = 0.12;
for (let i = 0; i < spokeCount; i++) {
  const angle = (i / spokeCount) * Math.PI * 2;
  const spoke = new THREE.Mesh(
    new THREE.BoxGeometry(spokeLen, spokeD, spokeW),
    rimMat
  );
  spoke.position.set(0, Math.cos(angle) * spokeLen / 2, Math.sin(angle) * spokeLen / 2);
  spoke.rotation.x = angle;
  spoke.castShadow = true;
  wheel.add(spoke);
}

// Hub cap
const cap = new THREE.Mesh(
  new THREE.CylinderGeometry(0.22, 0.22, 0.02, 16),
  rimMat
);
cap.rotation.x = Math.PI / 2;
cap.position.z = 0.28;
wheel.add(cap);

scene.add(wheel);

// Ground plane (for shadow)
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(20, 20),
  new THREE.MeshStandardMaterial({ color: 0x222222 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2;
ground.receiveShadow = true;
scene.add(ground);

// Animate
function animate() {
  requestAnimationFrame(animate);
  wheel.rotation.x += 0.02;
  renderer.render(scene, camera);
}
animate();

// Resize
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **Tire** — a black torus forming the outer rubber ring
- **Rim** — a metallic cylinder disc + barrel
- **5 Spokes** — thin rectangular bars radiating from the hub at equal angles
- **Hub & cap** — small central cylinder with a decorative cap
- **Spinning animation** — the wheel continuously rotates around its X-axis
- **Orbit controls** — click and drag to rotate the view, scroll to zoom
- **Shadows** — directional light casts shadows onto a ground plane

Just save it as `index.html` and open in any modern browser.

