// ── Tail Flukes ───────────────────────────────────────────
function createFluke(side) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.5, 1.8, 0.3, 3.0);
  shape.quadraticCurveTo(0.1, 3.3, -0.1, 3.1);
  shape.quadraticCurveTo(-0.4, 2.5, -0.5, 1.0);
  shape.quadraticCurveTo(-0.4, 0.3, 0, 0);

  const extrudeSettings = { depth: 0.08, bevelEnabled: true, bevelThickness: 0.04, bevelSize: 0.04, bevelSegments: 4 };
  const geo = new THREE.ExtrudeGeometry(shape, extrudeSettings);
  const mesh = new THREE.Mesh(geo, darkMat);
  mesh.rotation.x = -Math.PI / 2;
  mesh.position.set(-4.5, 0.3, side * 0.6);
  mesh.rotation.z = side * 0.3;
  return mesh;
}

whale.add(createFluke(1));
whale.add(createFluke(-1));

// ── Dorsal Fin ────────────────────────────────────────────
const dorsalShape = new THREE.Shape();
dorsalShape.moveTo(0, 0);
dorsalShape.quadraticCurveTo(0.1, 0.8, -0.1, 1.4);
dorsalShape.quadraticCurveTo(-0.3, 1.5, -0.5, 1.3);
dorsalShape.quadraticCurveTo(-0.4, 0.6, -0.3, 0);
dorsalShape.closePath();

const dorsalGeo = new THREE.ExtrudeGeometry(dorsalShape, {
  depth: 0.06, bevelEnabled: true, bevelThickness: 0.03, bevelSize: 0.03, bevelSegments: 3
});
