    depth: 0.06, bevelEnabled: true, bevelThickness: 0.03, bevelSize: 0.03, bevelSegments: 3
  });
  const mesh = new THREE.Mesh(geo, darkMat);
  mesh.rotation.x = -Math.PI / 2;
  mesh.position.set(1.5, -0.5, side * 1.35);
  mesh.rotation.y = side * 0.6;
  mesh.rotation.z = side * -0.3;
