    dir.position.set(3, 5, 4);
    scene.add(dir);
    const rim = new THREE.DirectionalLight(0xff6666, 0.6);
    rim.position.set(-3, 2, -2);
    scene.add(rim);

    // ── Apple group ──
    const apple = new THREE.Group();

    // Body — slightly flattened sphere
    const bodyGeo = new THREE.SphereGeometry(1, 64, 64);
    // Dimple top and bottom to look more apple-like
    const pos = bodyGeo.attributes.position;
    for (let i = 0; i < pos.count; i++) {
      const y = pos.getY(i);
      const topDimple = Math.max(0, (y - 0.55) * 3);
      const bottomDimple = Math.max(0, (-y - 0.55) * 3);
      const scale = 1 - topDimple * 0.18 - bottomDimple * 0.12;
      pos.setX(i, pos.getX(i) * scale);
      pos.setZ(i, pos.getZ(i) * scale);
    }
    bodyGeo.computeVertexNormals();

    const bodyMat = new THREE.MeshStandardMaterial({
      color: 0xcc2233,
      roughness: 0.35,
      metalness: 0.05,
    });
    apple.add(new THREE.Mesh(bodyGeo, bodyMat));

