{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.Fog(0x87CEEB, 15, 30);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2, 0);
controls.enableDamping = true;
controls.maxPolarAngle = Math.PI / 2 + 0.1;

// ── Lighting ──
const ambient = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
sun.position.set(5, 10, 5);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 25;
sun.shadow.camera.left = -6;
sun.shadow.camera.right = 6;
sun.shadow.camera.top = 6;
sun.shadow.camera.bottom = -6;
scene.add(sun);

const fill = new THREE.DirectionalLight(0xc0d8ff, 0.4);
fill.position.set(-4, 4, -3);
scene.add(fill);

const rim = new THREE.PointLight(0xffe0a0, 0.6, 15);
rim.position.set(-3, 5, -4);
scene.add(rim);

// ── Materials ──
const fur = new THREE.MeshStandardMaterial({ color: 0x8B6914, roughness: 0.85, metalness: 0.0 });
const darkFur = new THREE.MeshStandardMaterial({ color: 0x5C4410, roughness: 0.85, metalness: 0.0 });
const snoutMat = new THREE.MeshStandardMaterial({ color: 0xD4A76A, roughness: 0.7 });
const noseMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.3, metalness: 0.1 });
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.2, metalness: 0.3 });
const eyeWhite = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 });
const pinkMat = new THREE.MeshStandardMaterial({ color: 0xE8A0A0, roughness: 0.6 });
const pawMat = new THREE.MeshStandardMaterial({ color: 0x5C4410, roughness: 0.9 });

// ── Bear Group ──
const bear = new THREE.Group();

// Body
const body = new THREE.Mesh(new THREE.SphereGeometry(1.2, 32, 32), fur);
body.scale.set(1, 1.15, 0.9);
body.position.set(0, 2.0, 0);
body.castShadow = true;
bear.add(body);

// Belly
const belly = new THREE.Mesh(new THREE.SphereGeometry(0.85, 32, 32), snoutMat);
belly.scale.set(1, 1.1, 0.6);
belly.position.set(0, 1.85, 0.55);
bear.add(belly);

// ── Head ──
const head = new THREE.Group();
head.position.set(0, 3.55, 0.7);

const headMesh = new THREE.Mesh(new THREE.SphereGeometry(0.85, 32, 32), fur);
headMesh.scale.set(1.05, 1, 0.95);
headMesh.castShadow = true;
head.add(headMesh);

// Snout
const snout = new THREE.Mesh(new THREE.SphereGeometry(0.35, 24, 24), snoutMat);
snout.scale.set(1.1, 0.8, 1);
snout.position.set(0, -0.15, 0.65);
head.add(snout);

// Nose
const nose = new THREE.Mesh(new THREE.SphereGeometry(0.13, 16, 16), noseMat);
nose.scale.set(1.3, 0.9, 1);
nose.position.set(0, 0.02, 0.92);
head.add(nose);

// Mouth line (small torus)
const mouthGeo = new THREE.TorusGeometry(0.12, 0.02, 8, 16, Math.PI);
const mouth = new THREE.Mesh(mouthGeo, noseMat);
mouth.rotation.z = Math.PI;
mouth.position.set(0, -0.12, 0.88);
head.add(mouth);

// Eyes
const eyePositions = [[-0.32, 0.22, 0.62], [0.32, 0.22, 0.62]];
eyePositions.forEach(([x, y, z]) => {
  const white = new THREE.Mesh(new THREE.SphereGeometry(0.13, 16, 16), eyeWhite);
  white.position.set(x, y, z);
  head.add(white);
  const pupil = new THREE.Mesh(new THREE.SphereGeometry(0.08, 16, 16), eyeMat);
  pupil.position.set(x, y, z + 0.08);
  head.add(pupil);
  // Eye shine
  const shine = new THREE.Mesh(new THREE.SphereGeometry(0.025, 8, 8), new THREE.MeshBasicMaterial({ color: 0xffffff }));
  shine.position.set(x + 0.03, y + 0.03, z + 0.13);
  head.add(shine);
});

// Eyebrows
[-1, 1].forEach(s => {
  const brow = new THREE.Mesh(new THREE.SphereGeometry(0.06, 8, 8), darkFur);
  brow.scale.set(2.2, 0.5, 1);
  brow.position.set(s * 0.32, 0.42, 0.58);
  head.add(brow);
});

// Ears
const earPositions = [[-0.6, 0.65, 0.05], [0.6, 0.65, 0.05]];
earPositions.forEach(([x, y, z]) => {
  const ear = new THREE.Mesh(new THREE.SphereGeometry(0.28, 24, 24), fur);
  ear.position.set(x, y, z);
  ear.castShadow = true;
  head.add(ear);
  const innerEar = new THREE.Mesh(new THREE.SphereGeometry(0.16, 16, 16), pinkMat);
  innerEar.position.set(x, y, z + 0.08);
  head.add(innerEar);
});

bear.add(head);

// ── Legs ──
const legPositions = [
  [-0.55, 0.5, 0.5], [0.55, 0.5, 0.5],
  [-0.55, 0.5, -0.5], [0.55, 0.5, -0.5]
];
const legs = [];
legPositions.forEach(([x, y, z]) => {
  const leg = new THREE.Group();
  const thigh = new THREE.Mesh(new THREE.SphereGeometry(0.35, 24, 24), fur);
  thigh.scale.set(1, 1.3, 1);
  thigh.position.y = 0.35;
  thigh.castShadow = true;
  leg.add(thigh);

  const foot = new THREE.Mesh(new THREE.SphereGeometry(0.3, 24, 24), pawMat);
  foot.scale.set(1.1, 0.6, 1.4);
  foot.position.set(0, 0.02, 0.15);
  foot.castShadow = true;
  leg.add(foot);

  // Toe lines
  for (let i = -1; i <= 1; i++) {
    const toe = new THREE.Mesh(new THREE.SphereGeometry(0.04, 8, 8), noseMat);
    toe.position.set(i * 0.12, 0.02, 0.38);
    leg.add(toe);
  }

  leg.position.set(x, y, z);
  legs.push(leg);
  bear.add(leg);
});

// ── Arms ──
const armPositions = [[-1.05, 2.3, 0.3], [1.05, 2.3, 0.3]];
const arms = [];
armPositions.forEach(([x, y, z], i) => {
  const arm = new THREE.Group();
  const upperArm = new THREE.Mesh(new THREE.SphereGeometry(0.28, 24, 24), fur);
  upperArm.scale.set(1, 1.4, 1);
  upperArm.position.set(x > 0 ? 0.15 : -0.15, -0.3, 0);
  upperArm.castShadow = true;
  arm.add(upperArm);

  const paw = new THREE.Mesh(new THREE.SphereGeometry(0.22, 24, 24), pawMat);
  paw.scale.set(1.1, 1, 1.2);
  paw.position.set(x > 0 ? 0.2 : -0.2, -0.75, 0.1);
  paw.castShadow = true;
  arm.add(paw);

  arm.position.set(x, y, z);
  arm.rotation.z = (x > 0 ? -1 : 1) * 0.3;
  arm.rotation.x = -0.2;
  arms.push(arm);
  bear.add(arm);
});

// ── Tail ──
const tail = new THREE.Mesh(new THREE.SphereGeometry(0.18, 16, 16), fur);
tail.position.set(0, 1.9, -1.0);
tail.castShadow = true;
bear.add(tail);

scene.add(bear);

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(12, 64),
  new THREE.MeshStandardMaterial({ color: 0x4a8c3f, roughness: 0.95 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Grass tufts
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 1.5 + Math.random() * 8;
  const tuft = new THREE.Mesh(
    new THREE.ConeGeometry(0.05 + Math.random() * 0.05, 0.15 + Math.random() * 0.2, 6),
    new THREE.MeshStandardMaterial({ color: new THREE.Color().setHSL(0.28 + Math.random() * 0.06, 0.6, 0.3 + Math.random() * 0.15) })
  );
  tuft.position.set(Math.cos(angle) * radius, 0.05, Math.sin(angle) * radius);
  tuft.rotation.z = (Math.random() - 0.5) * 0.3;
  scene.add(tuft);
}

// Small flowers
for (let i = 0; i < 12; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 2 + Math.random() * 6;
  const flowerGroup = new THREE.Group();
  const stem = new THREE.Mesh(
    new THREE.CylinderGeometry(0.015, 0.015, 0.3, 6),
    new THREE.MeshStandardMaterial({ color: 0x2d6b1e })
  );
  stem.position.y = 0.15;
  flowerGroup.add(stem);
  const petalColor = [0xff6b8a, 0xffd166, 0xff85a1, 0xa8e6cf, 0xdcedc1][Math.floor(Math.random() * 5)];
  const petals = new THREE.Mesh(
    new THREE.SphereGeometry(0.08, 8, 8),
    new THREE.MeshStandardMaterial({ color: petalColor })
  );
  petals.position.y = 0.32;
  petals.scale.y = 0.5;
  flowerGroup.add(petals);
  const center = new THREE.Mesh(
    new THREE.SphereGeometry(0.035, 8, 8),
    new THREE.MeshStandardMaterial({ color: 0xffd700 })
  );
  center.position.y = 0.33;
  flowerGroup.add(center);
  flowerGroup.position.set(Math.cos(angle) * radius, 0, Math.sin(angle) * radius);
  scene.add(flowerGroup);
}

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle body bob
  bear.position.y = Math.sin(t * 1.5) * 0.08;

  // Head tilt
  head.rotation.z = Math.sin(t * 0.8) * 0.06;
  head.rotation.y = Math.sin(t * 0.5) * 0.08;

  // Arm swing
  arms[0].rotation.x = -0.2 + Math.sin(t * 1.5) * 0.08;
  arms[1].rotation.x = -0.2 - Math.sin(t * 1.5) * 0.08;

  // Leg subtle shift
  legs[0].rotation.x = Math.sin(t * 1.5) * 0.04;
  legs[2].rotation.x = -Math.sin(t * 1.5) * 0.04;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
