controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0.6, 0);

// ── Bell profile (revolved around Y axis) ──
const bellProfile = [
  new THREE.Vector2(0.75, 0.0),
  new THREE.Vector2(0.82, 0.02),
  new THREE.Vector2(0.84, 0.06),
