const clapperMat = new THREE.MeshStandardMaterial({
  color: 0xb8860b,
  metalness: 0.9,
  roughness: 0.2,
});
const clapper = new THREE.Mesh(clapperGeo, clapperMat);
clapper.position.set(0, 0.25, 0);
clapper.castShadow = true;
scene.add(clapper);

// clapper rod
const rodGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.55, 12);
const rod = new THREE.Mesh(rodGeo, clapperMat);
rod.position.set(0, 0.55, 0);
