for (const side of [-1, 1]) {
  const curve = new THREE.CubicBezierCurve3(
    new THREE.Vector3(side * 0.2, 0.35, 2.0),
    new THREE.Vector3(side * 0.5, 0.7, 2.2),
    new THREE.Vector3(side * 0.7, 0.9, 1.9),
    new THREE.Vector3(side * 0.6, 1.1, 1.6)
  );
  const tubeGeo = new THREE.TubeGeometry(curve, 12, 0.035, 8, false);
  const antenna = new THREE.Mesh(tubeGeo, blackMat);
  bee.add(antenna);

  // Antenna tip
  const tipGeo = new THREE.SphereGeometry(0.06, 8, 8);
  const tip = new THREE.Mesh(tipGeo, blackMat);
  const end = curve.getPoint(1);
  tip.position.copy(end);
  bee.add(tip);
}

// ── Wings ──
const wingGroup = new THREE.Group();
const wingShape = new THREE.Shape();
wingShape.moveTo(0, 0);
wingShape.bezierCurveTo(0.3, 0.6, 1.0, 1.0, 0.6, 1.6);
wingShape.bezierCurveTo(0.3, 1.8, -0.2, 1.4, -0.3, 0.8);
wingShape.bezierCurveTo(-0.4, 0.4, -0.2, 0.1, 0, 0);

const wingExtrudeSettings = { depth: 0.01, bevelEnabled: false };
const wingGeo = new THREE.ExtrudeGeometry(wingShape, wingExtrudeSettings);

for (const side of [-1, 1]) {
  const wing = new THREE.Mesh(wingGeo, wingMat);
  wing.position.set(side * 0.1, 0.5, 0.5);
  wing.rotation.set(-0.3, side * 0.1, side * 1.2);
  wing.scale.set(side, 1, 1);
  wingGroup.add(wing);

  // Second (smaller) wing behind
  const wing2 = new THREE.Mesh(wingGeo, wingMat);
  wing2.position.set(side * 0.15, 0.3, 0.3);
  wing2.rotation.set(-0.2, side * 0.15, side * 1.3);
  wing2.scale.set(side * 0.7, 0.7, 0.7);
  wingGroup.add(wing2);
}
bee.add(wingGroup);

// ── Legs ──
for (const side of [-1, 1]) {
  for (let i = 0; i < 3; i++) {
    const legGroup = new THREE.Group();
    const zPos = 0.3 + i * 0.35;

    // Upper leg
    const upperGeo = new THREE.CylinderGeometry(0.03, 0.03, 0.5, 8);
    const upper = new THREE.Mesh(upperGeo, blackMat);
    upper.position.y = -0.25;
    legGroup.add(upper);

    // Lower leg
    const lowerGeo = new THREE.CylinderGeometry(0.025, 0.02, 0.4, 8);
    const lower = new THREE.Mesh(lowerGeo, blackMat);
    lower.position.set(0, -0.45, 0.15);
    lower.rotation.x = 0.4;
    legGroup.add(lower);

    legGroup.position.set(side * 0.75, -0.3, zPos);
    legGroup.rotation.z = side * 0.6;
    bee.add(legGroup);
  }
}

// ── Stinger ──
const stingerGeo = new THREE.ConeGeometry(0.08, 0.35, 8);
const stinger = new THREE.Mesh(stingerGeo, stingerMat);
stinger.position.set(0, 0, -2.0);
stinger.rotation.x = Math.PI / 2;
bee.add(stinger);

scene.add(bee);

/* ───────── Flowers ───────── */
function makeFlower(x, z, color, scale = 1) {
  const group = new THREE.Group();
  const stemGeo = new THREE.CylinderGeometry(0.04, 0.05, 1.5 * scale, 6);
  const stemMat = new THREE.MeshStandardMaterial({ color: 0x2d6b1e });
  const stem = new THREE.Mesh(stemGeo, stemMat);
  stem.position.y = 0.75 * scale;
  group.add(stem);

  const petalCount = 5 + Math.floor(Math.random() * 3);
  for (let i = 0; i < petalCount; i++) {
    const petalGeo = new THREE.SphereGeometry(0.2 * scale, 8, 8);
    const petalMat = new THREE.MeshStandardMaterial({ color, roughness: 0.6 });
    const petal = new THREE.Mesh(petalGeo, petalMat);
    const angle = (i / petalCount) * Math.PI * 2;
    petal.position.set(Math.cos(angle) * 0.25 * scale, 1.55 * scale, Math.sin(angle) * 0.25 * scale);
    petal.scale.set(1, 0.5, 1);
    group.add(petal);
  }

  // Center
  const centerGeo = new THREE.SphereGeometry(0.15 * scale, 8, 8);
  const centerMat = new THREE.MeshStandardMaterial({ color: 0xffd700, roughness: 0.4 });
  const center = new THREE.Mesh(centerGeo, centerMat);
  center.position.y = 1.55 * scale;
  group.add(center);

  group.position.set(x, -4, z);
  return group;
}

const flowerColors = [0xff6b8a, 0xff9e3d, 0xe040fb, 0xff5252, 0xba68c8, 0xffab40, 0xffffff];
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 2 + Math.random() * 35;
  const x = Math.cos(angle) * radius;
  const z = Math.sin(angle) * radius;
  scene.add(makeFlower(x, z, flowerColors[Math.floor(Math.random() * flowerColors.length)], 0.6 + Math.random() * 0.8));
}

/* ───────── Animation ───────── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Hover bob
  bee.position.y = Math.sin(t * 1.5) * 0.4;
  bee.position.x = Math.sin(t * 0.7) * 0.3;
  bee.rotation.z = Math.sin(t * 1.2) * 0.08;
  bee.rotation.x = Math.sin(t * 0.9) * 0.05;

  // Gentle yaw
  bee.rotation.y = Math.sin(t * 0.4) * 0.3;

  // Wing flap
  wingGroup.rotation.z = Math.sin(t * 25) * 0.35;
  wingGroup.rotation.x = Math.sin(t * 20) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}

animate();

/* ───────── Resize ───────── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's included

| Feature | Details |
|---|---|
| **Bee body** | Yellow abdomen with 3 black stripe rings, yellow thorax with black band, black head |
| **Wings** | Two pairs of translucent, curved wings using `ExtrudeGeometry` + `MeshPhysicalMaterial` with transmission |
| **Details** | Compound eyes, curved antennae with tips, 6 legs (upper + lower segments), stinger |
| **Animation** | Hover bobbing, gentle yaw/roll, rapid wing flapping (~25 Hz) |
| **Environment** | Blue sky with fog, green ground plane, 60 procedural flowers in various colors |
| **Lighting** | Ambient + hemisphere + directional sun with soft shadow maps |
| **Controls** | `OrbitControls` — drag to rotate, scroll to zoom |

Just save as `index.html` and open in any modern browser — no build step needed.

