controls.maxDistance = 60;
controls.update();

/* ─── Sky Dome ─── */
const skyGeo = new THREE.SphereGeometry(200, 32, 32);
const skyMat = new THREE.ShaderMaterial({
  side: THREE.BackSide,
  uniforms: {
    topColor:    { value: new THREE.Color(0x3a7bd5) },
    bottomColor: { value: new THREE.Color(0xd4f0ff) },
    offset:      { value: 20 },
    exponent:    { value: 0.4 }
  },
  vertexShader: `
    varying vec3 vWorldPos;
    void main() {
      vec4 wp = modelMatrix * vec4(position, 1.0);
      vWorldPos = wp.xyz;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    uniform vec3 topColor;
    uniform vec3 bottomColor;
    uniform float offset;
    uniform float exponent;
    varying vec3 vWorldPos;
    void main() {
      float h = normalize(vWorldPos + offset).y;
      gl_FragColor = vec4(mix(bottomColor, topColor, max(pow(max(h, 0.0), exponent), 0.0)), 1.0);
    }
  `
});
scene.add(new THREE.Mesh(skyGeo, skyMat));

/* ─── Sun ─── */
const sunLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
sunLight.position.set(30, 40, 20);
sunLight.castShadow = true;
sunLight.shadow.mapSize.set(2048, 2048);
sunLight.shadow.camera.left = -30;
sunLight.shadow.camera.right = 30;
sunLight.shadow.camera.top = 30;
sunLight.shadow.camera.bottom = -30;
sunLight.shadow.camera.near = 1;
sunLight.shadow.camera.far = 100;
sunLight.shadow.bias = -0.001;
scene.add(sunLight);

const ambientLight = new THREE.AmbientLight(0x6688aa, 0.8);
scene.add(ambientLight);

const hemiLight = new THREE.HemisphereLight(0x87ceeb, 0x362907, 0.6);
scene.add(hemiLight);

/* ─── Water ─── */
const waterSize = 200;
const waterSeg = 128;
const waterGeo = new THREE.PlaneGeometry(waterSize, waterSize, waterSeg, waterSeg);
waterGeo.rotateX(-Math.PI / 2);

const waterMat = new THREE.ShaderMaterial({
  uniforms: {
    uTime:       { value: 0 },
    uDeepColor:  { value: new THREE.Color(0x0a3d6b) },
    uShallowColor:{ value: new THREE.Color(0x2e8bc0) },
    uFresnelColor:{ value: new THREE.Color(0xffffff) },
    uSunDir:     { value: new THREE.Vector3(30, 40, 20).normalize() }
  },
  vertexShader: `
    uniform float uTime;
    varying vec3 vWorldPos;
    varying vec3 vNormal;
    varying float vFoam;

    // Simplex-ish noise
    vec3 mod289(vec3 x){ return x - floor(x*(1.0/289.0))*289.0; }
    vec4 mod289(vec4 x){ return x - floor(x*(1.0/289.0))*289.0; }
    vec4 perm(vec4 x){ return mod289(((x*34.0)+1.0)*x); }
    float noise(vec3 p){
      vec3 a = floor(p); vec3 d = p - a;
      d = d*d*(3.0-2.0*d);
      vec4 b = a.xxyy + vec4(0,1,0,1);
      vec4 k1 = perm(b.xyxy);
      vec4 k2 = perm(k1.xyxy + b.zzww);
      vec4 c = k2 + a.zzzz;
      vec4 k3 = perm(c); vec4 k4 = perm(c+1.0);
      vec4 o1 = fract(k3*(1.0/41.0));
      vec4 o2 = fract(k4*(1.0/41.0));
      vec4 o3 = o2*d.z + o1*(1.0-d.z);
      vec2 o4 = o3.yw*d.x + o3.xz*(1.0-d.x);
      return o4.y*d.y + o4.x*(1.0-d.y);
    }

    void main() {
      vec3 pos = position;
      float wave1 = sin(pos.x * 0.15 + uTime * 0.8) * 0.6;
      float wave2 = sin(pos.z * 0.12 + uTime * 0.6) * 0.5;
      float wave3 = sin((pos.x + pos.z) * 0.08 + uTime * 1.0) * 0.4;
      float wave4 = sin(pos.x * 0.3 + pos.z * 0.25 + uTime * 1.3) * 0.15;
      float n = noise(vec3(pos.xz * 0.05, uTime * 0.15)) * 0.8;
      pos.y += wave1 + wave2 + wave3 + wave4 + n;
      vFoam = smoothstep(0.6, 1.0, n + wave4 * 2.0);

      // Approximate normal via neighbors
      float eps = 0.5;
      float hL = sin((pos.x-eps)*0.15+uTime*0.8)*0.6 + sin(pos.z*0.12+uTime*0.6)*0.5
                + sin((pos.x-eps+pos.z)*0.08+uTime)*0.4;
      float hR = sin((pos.x+eps)*0.15+uTime*0.8)*0.6 + sin(pos.z*0.12+uTime*0.6)*0.5
                + sin((pos.x+eps+pos.z)*0.08+uTime)*0.4;
      float hD = sin(pos.x*0.15+uTime*0.8)*0.6 + sin((pos.z-eps)*0.12+uTime*0.6)*0.5
                + sin((pos.x+pos.z-eps)*0.08+uTime)*0.4;
      float hU = sin(pos.x*0.15+uTime*0.8)*0.6 + sin((pos.z+eps)*0.12+uTime*0.6)*0.5
                + sin((pos.x+pos.z+eps)*0.08+uTime)*0.4;
      vec3 norm = normalize(vec3(hL-hR, 2.0*eps, hD-hU));
      vNormal = normalize(normalMatrix * norm);
      vWorldPos = (modelMatrix * vec4(pos, 1.0)).xyz;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
    }
  `,
  fragmentShader: `
    uniform vec3 uDeepColor;
    uniform vec3 uShallowColor;
    uniform vec3 uFresnelColor;
    uniform vec3 uSunDir;
    uniform float uTime;
    varying vec3 vWorldPos;
    varying vec3 vNormal;
    varying float vFoam;

    void main() {
      vec3 viewDir = normalize(cameraPosition - vWorldPos);
      float fresnel = pow(1.0 - max(dot(viewDir, vNormal), 0.0), 3.0);
      vec3 color = mix(uShallowColor, uDeepColor, 0.4 + 0.3 * fresnel);
      color = mix(color, uFresnelColor, fresnel * 0.5);

      // Specular sun glint
      vec3 halfDir = normalize(uSunDir + viewDir);
      float spec = pow(max(dot(vNormal, halfDir), 0.0), 128.0);
      color += vec3(1.0, 0.95, 0.8) * spec * 1.5;

      // Foam on wave crests
      color = mix(color, vec3(0.85, 0.92, 0.95), vFoam * 0.35);

      gl_FragColor = vec4(color, 0.92);
    }
  `,
  transparent: true,
  side: THREE.DoubleSide
});

const water = new THREE.Mesh(waterGeo, waterMat);
water.receiveShadow = true;
scene.add(water);

/* ─── Boat Group ─── */
