// ── Wing Shape Function ──
function wingVertexColor(u, v) {
  const r = Math.sin(u * 6.28 * 1.5 + v * 3) * 0.5 + 0.5;
  const g = Math.sin(u * 6.28 * 1.5 + v * 3 + 2.094) * 0.5 + 0.5;
  const b = Math.sin(u * 6.28 * 1.5 + v * 3 + 4.189) * 0.5 + 0.5;
  // Darker veins
  const vein = Math.exp(-Math.pow((Math.sin(u * 12.56) * 0.5 + 0.5) * 4, 2));
  const spot = Math.exp(-Math.pow(u - 0.5, 2) * 30 - Math.pow(v - 0.4, 2) * 30) * 0.8;
  return new THREE.Color(
    r * 0.6 + spot * 0.3,
    g * 0.4 + vein * 0.1,
    b * 0.8 + spot * 0.5
  );
}

function createWingGeometry(side) {
  const segs = 80;
  const positions = [], normals = [], colors = [], indices = [];

  for (let i = 0; i <= segs; i++) {
    const u = i / segs;
    for (let j = 0; j <= segs; j++) {
      const v = j / segs;

      // Butterfly wing parametric shape
      const angle = u * Math.PI * 2;
      const r = 1.8 * Math.exp(Math.cos(angle)) - 2 * Math.cos(4 * angle)
        + Math.pow(Math.sin(angle / 12), 5);
      const spread = 0.3 + v * 0.7;

      const x = side * r * Math.sin(angle) * spread * 1.2;
      const z = r * Math.cos(angle) * spread * 0.8 - 0.5;
      const y = Math.sin(u * Math.PI) * 0.3 * (1 - v) + v * 0.15;

      positions.push(x, y, z);

      const col = wingVertexColor(u, v);
      colors.push(col.r, col.g, col.b);
    }
  }

  // Compute normals from position
  for (let i = 0; i < positions.length; i += 3) {
    const i9 = i / 3;
    const ii = Math.floor(i9 / (segs + 1));
    const jj = i9 % (segs + 1);
    const u = ii / segs, v = jj / segs;
    const n = new THREE.Vector3(
      -side * Math.sin(u * Math.PI * 2) * 0.5,
      0.7 + Math.cos(u * Math.PI) * 0.3,
      -Math.cos(u * Math.PI * 2) * 0.3
    ).normalize();
    normals.push(n.x, n.y, n.z);
  }

  for (let i = 0; i < segs; i++) {
    for (let j = 0; j < segs; j++) {
      const a = i * (segs + 1) + j;
      const b = a + 1;
      const c = (i + 1) * (segs + 1) + j;
      const d = c + 1;
      indices.push(a, b, c, b, d, c);
    }
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geo.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
  geo.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  geo.setIndex(indices);
  return geo;
}

