  <script type="module">
    import * as THREE from 'three';

    // 1. Scene Setup
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a1a);
    scene.fog = new THREE.Fog(0x1a1a1a, 5, 15);

    // 2. Camera Setup
    const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 100);
    camera.position.set(0, 0, 6);

    // 3. Renderer Setup
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    document.body.appendChild(renderer.domElement);

    // 4. Build a Simple Camera Model
    const camGroup = new THREE.Group();

    // Body
    const bodyGeo = new THREE.BoxGeometry(2.2, 1.4, 1.2);
    const bodyMat = new THREE.MeshStandardMaterial({ color: 0x2a2a2a, roughness: 0.6, metalness: 0.3 });
    camGroup.add(new THREE.Mesh(bodyGeo, bodyMat));

    // Lens Housing
    const housingGeo = new THREE.CylinderGeometry(0.5, 0.5, 0.6, 32);
    const housingMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.4 });
    const housing = new THREE.Mesh(housingGeo, housingMat);
    housing.rotation.x = Math.PI / 2;
    housing.position.z = 0.8;
    camGroup.add(housing);

    // Lens Glass
    const lensGeo = new THREE.CircleGeometry(0.42, 32);
    const lensMat = new THREE.MeshStandardMaterial({ color: 0x00bfff, metalness: 0.9, roughness: 0.1 });
    const lens = new THREE.Mesh(lensGeo, lensMat);
    lens.position.z = 1.12;
    camGroup.add(lens);

    // Top Bump (Viewfinder/Flash)
    const bumpGeo = new THREE.BoxGeometry(0.8, 0.3, 0.4);
    const bumpMat = new THREE.MeshStandardMaterial({ color: 0x333333 });
    const bump = new THREE.Mesh(bumpGeo, bumpMat);
    bump.position.set(0, 0.85, -0.2);
    camGroup.add(bump);

    scene.add(camGroup);

    // 5. Lighting
    const ambient = new THREE.AmbientLight(0xffffff, 0.4);
    scene.add(ambient);

    const keyLight = new THREE.DirectionalLight(0xffffff, 1.2);
    keyLight.position.set(4, 5, 4);
    scene.add(keyLight);

    const rimLight = new THREE.DirectionalLight(0x4488ff, 0.5);
    rimLight.position.set(-3, 2, -3);
    scene.add(rimLight);

    // 6. Animation Loop
    function animate(time) {
      requestAnimationFrame(animate);

      // Gentle idle rotation
      camGroup.rotation.y = Math.sin(time * 0.001) * 0.3;
      camGroup.rotation.z = Math.sin(time * 0.0008) * 0.05;

      renderer.render(scene, camera);
    }

    // 7. Handle Window Resize
    window.addEventListener('resize', () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    });

    animate(0);
  </script>
