    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0xc4d4ff, 0.5);
    fillLight.position.set(-3, 3, -2);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xff9944, 0.6, 10);
    rimLight.position.set(-2, 4, -3);
    scene.add(rimLight);

    // ── Materials ────────────────────────────────────────────
    const cupMat = new THREE.MeshStandardMaterial({
      color: 0xf5f0eb,
      roughness: 0.25,
      metalness: 0.02,
    });

    const coffeeMat = new THREE.MeshStandardMaterial({
      color: 0x3c1a0e,
      roughness: 0.15,
      metalness: 0.05,
    });

    const saucerMat = new THREE.MeshStandardMaterial({
      color: 0xf0ebe5,
      roughness: 0.3,
      metalness: 0.02,
    });

    // ── Cup Body ─────────────────────────────────────────────
    const cupGroup = new THREE.Group();

    const cupBody = new THREE.Mesh(
      new THREE.CylinderGeometry(0.7, 0.55, 1.6, 48, 1, true),
      cupMat
    );
    cupBody.position.y = 0.8;
    cupBody.castShadow = true;
    cupBody.receiveShadow = true;
    cupGroup.add(cupBody);

    // Cup bottom (thin disc)
