<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene, Camera, Renderer ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a1a);
scene.fog = new THREE.FogExp2(0x0a0a1a, 0.035);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 1.2, 0);
controls.maxPolarAngle = Math.PI * 0.85;
controls.minDistance = 4;
controls.maxDistance = 16;

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0x334466, 0.5);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
keyLight.position.set(5, 8, 5);
keyLight.castShadow = true;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 1);
fillLight.position.set(-5, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffaa44, 2);
rimLight.position.set(0, 2, -6);
scene.add(rimLight);

const pointLight1 = new THREE.PointLight(0xff4444, 3, 15);
pointLight1.position.set(3, 4, 2);
scene.add(pointLight1);

const pointLight2 = new THREE.PointLight(0x4444ff, 3, 15);
pointLight2.position.set(-3, 4, 2);
scene.add(pointLight2);

// ── Materials ──
const goldMaterial = new THREE.MeshStandardMaterial({
  color: 0xffd700,
  metalness: 0.95,
  roughness: 0.15,
});

const darkGoldMaterial = new THREE.MeshStandardMaterial({
  color: 0xb8860b,
  metalness: 0.9,
  roughness: 0.25,
});

const rubyMaterial = new THREE.MeshStandardMaterial({
  color: 0xcc0022,
  metalness: 0.1,
  roughness: 0.05,
  emissive: 0x330000,
  emissiveIntensity: 0.3,
});

const sapphireMaterial = new THREE.MeshStandardMaterial({
  color: 0x1144cc,
  metalness: 0.1,
  roughness: 0.05,
  emissive: 0x000033,
  emissiveIntensity: 0.3,
});

const diamondMaterial = new THREE.MeshStandardMaterial({
  color: 0xffffff,
  metalness: 0.0,
  roughness: 0.0,
  emissive: 0x444466,
  emissiveIntensity: 0.15,
  transparent: true,
  opacity: 0.9,
});

const emeraldMaterial = new THREE.MeshStandardMaterial({
  color: 0x00aa44,
  metalness: 0.1,
  roughness: 0.05,
  emissive: 0x002200,
  emissiveIntensity: 0.3,
});

// ── Crown Group ──
const crown = new THREE.Group();

// ── Base Band ──
const bandRadius = 2;
const bandTube = 0.18;
const bandHeight = 0.6;

// Main band (torus, lying on its side)
const bandGeo = new THREE.TorusGeometry(bandRadius, bandTube, 24, 64);
const band = new THREE.Mesh(bandGeo, goldMaterial);
band.rotation.x = Math.PI / 2;
band.position.y = 0.6;
crown.add(band);

// Inner band (slightly smaller, for thickness illusion)
const innerBandGeo = new THREE.TorusGeometry(bandRadius, bandTube * 0.6, 16, 64);
const innerBand = new THREE.Mesh(innerBandGeo, darkGoldMaterial);
innerBand.rotation.x = Math.PI / 2;
innerBand.position.y = 0.6;
crown.add(innerBand);

// ── Prongs / Peaks ──
const peakCount = 5;
const peakHeights = [2.2, 1.5, 1.8, 1.5, 2.2];
const peakWidths =  [0.22, 0.18, 0.20, 0.18, 0.22];

for (let i = 0; i < peakCount; i++) {
  const angle = (i / peakCount) * Math.PI * 2;
  const x = Math.cos(angle) * bandRadius;
  const z = Math.sin(angle) * bandRadius;
  const h = peakHeights[i];
  const w = peakWidths[i];

  // Create a tapered prong using a custom shape extruded or a cone
  const prongGeo = new THREE.CylinderGeometry(w * 0.3, w, h, 8, 1, false);
  const prong = new THREE.Mesh(prongGeo, goldMaterial);
  prong.position.set(x, 0.6 + bandTube + h / 2 - 0.05, z);
  crown.add(prong);

  // Decorative ridge along prong
  const ridgeGeo = new THREE.CylinderGeometry(w * 0.08, w * 0.15, h * 0.85, 6);
  const ridge = new THREE.Mesh(ridgeGeo, darkGoldMaterial);
  ridge.position.copy(prong.position);
  ridge.position.y += 0.05;
  crown.add(ridge);

  // Jewel on top
  const jewelGeo = new THREE.SphereGeometry(w * 0.55, 16, 16);
  const jewelMat = i === 2 ? rubyMaterial : (i % 2 === 0 ? sapphireMaterial : diamondMaterial);
  const jewel = new THREE.Mesh(jewelGeo, jewelMat);
  jewel.position.set(x, 0.6 + bandTube + h + w * 0.2, z);
  crown.add(jewel);
}

// ── Side Jewels (on the band) ──
const sideJewelCount = 10;
for (let i = 0; i < sideJewelCount; i++) {
  const angle = (i / sideJewelCount) * Math.PI * 2 + Math.PI / sideJewelCount;
  const x = Math.cos(angle) * (bandRadius + bandTube * 0.5);
  const z = Math.sin(angle) * (bandRadius + bandTube * 0.5);

  const sjGeo = new THREE.SphereGeometry(0.12, 12, 12);
  const sjMat = i % 3 === 0 ? rubyMaterial : (i % 3 === 1 ? sapphireMaterial : emeraldMaterial);
  const sj = new THREE.Mesh(sjGeo, sjMat);
  sj.position.set(x, 0.6, z);
  crown.add(sj);
}

// ── Front Central Jewel (large ruby) ──
const frontJewelGeo = new THREE.SphereGeometry(0.35, 24, 24);
const frontJewel = new THREE.Mesh(frontJewelGeo, rubyMaterial);
frontJewel.position.set(0, 0.6, bandRadius + bandTube * 0.3);
crown.add(frontJewel);

// Front jewel setting
const settingGeo = new THREE.TorusGeometry(0.3, 0.05, 8, 24);
const setting = new THREE.Mesh(settingGeo, goldMaterial);
setting.position.copy(frontJewel.position);
crown.add(setting);

// ── Back Central Jewel ──
const backJewelGeo = new THREE.SphereGeometry(0.3, 24, 24);
const backJewel = new THREE.Mesh(backJewelGeo, sapphireMaterial);
backJewel.position.set(0, 0.6, -(bandRadius + bandTube * 0.3));
crown.add(backJewel);

// ── Decorative Arcs between peaks ──
for (let i = 0; i < peakCount; i++) {
  const angle1 = (i / peakCount) * Math.PI * 2;
  const angle2 = ((i + 1) / peakCount) * Math.PI * 2;
  const midAngle = (angle1 + angle2) / 2;

  const x1 = Math.cos(angle1) * bandRadius;
  const z1 = Math.sin(angle1) * bandRadius;
  const x2 = Math.cos(angle2) * bandRadius;
  const z2 = Math.sin(angle2) * bandRadius;

  // Small arc using a tube
  const curve = new THREE.QuadraticBezierCurve3(
    new THREE.Vector3(x1, 0.6 + bandTube + 0.5, z1),
    new THREE.Vector3(Math.cos(midAngle) * (bandRadius + 0.3), 0.6 + bandTube + 0.9, Math.sin(midAngle) * (bandRadius + 0.3)),
    new THREE.Vector3(x2, 0.6 + bandTube + 0.5, z2)
  );

  const tubeGeo = new THREE.TubeGeometry(curve, 16, 0.04, 8, false);
  const arc = new THREE.Mesh(tubeGeo, goldMaterial);
  crown.add(arc);

  // Small jewel at arc peak
  const arcJewelGeo = new THREE.SphereGeometry(0.08, 8, 8);
  const arcJewel = new THREE.Mesh(arcJewelGeo, diamondMaterial);
  arcJewel.position.copy(curve.getPoint(0.5));
  crown.add(arcJewel);
}

// ── Inner rim detail ──
const innerRimGeo = new THREE.TorusGeometry(bandRadius - 0.05, 0.04, 8, 64);
const innerRim = new THREE.Mesh(innerRimGeo, darkGoldMaterial);
innerRim.rotation.x = Math.PI / 2;
innerRim.position.y = 0.6;
crown.add(innerRim);

// ── Position and add crown ──
crown.position.y = -0.5;
scene.add(crown);

// ── Pedestal ──
const pedestalGeo = new THREE.CylinderGeometry(1.8, 2.2, 0.4, 32);
const pedestalMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e,
  metalness: 0.3,
  roughness: 0.6,
});
const pedestal = new THREE.Mesh(pedestalGeo, pedestalMat);
pedestal.position.y = -0.9;
scene.add(pedestal);

const pedestalTopGeo = new THREE.CylinderGeometry(1.6, 1.8, 0.15, 32);
const pedestalTop = new THREE.Mesh(pedestalTopGeo, darkGoldMaterial);
pedestalTop.position.y = -0.65;
scene.add(pedestalTop);

// ── Particle Stars ──
const starCount = 300;
const starGeo = new THREE.BufferGeometry();
const starPositions = new Float32Array(starCount * 3);
const starSizes = new Float32Array(starCount);

for (let i = 0; i < starCount; i++) {
  starPositions[i * 3] = (Math.random() - 0.5) * 40;
  starPositions[i * 3 + 1] = Math.random() * 20 + 2;
  starPositions[i * 3 + 2] = (Math.random() - 0.5) * 40;
  starSizes[i] = Math.random() * 2 + 0.5;
}

starGeo.setAttribute('position', new THREE.BufferAttribute(starPositions, 3));
starGeo.setAttribute('size', new THREE.BufferAttribute(starSizes, 1));

const starMat = new THREE.PointsMaterial({
  color: 0xffffff,
  size: 0.08,
  transparent: true,
  opacity: 0.6,
  sizeAttenuation: true,
});

const stars = new THREE.Points(starGeo, starMat);
scene.add(stars);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Slow crown rotation
  crown.rotation.y = t * 0.3;

  // Gentle floating
  crown.position.y = -0.5 + Math.sin(t * 0.8) * 0.15;

  // Animate point lights
  pointLight1.position.x = Math.sin(t * 0.5) * 4;
  pointLight1.position.z = Math.cos(t * 0.5) * 4;
  pointLight2.position.x = Math.cos(t * 0.7) * 4;
  pointLight2.position.z = Math.sin(t * 0.7) * 4;

  // Twinkle stars
  stars.rotation.y = t * 0.02;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

