## What's in the scene

| Feature | Detail |
|---|---|
| **Diamond shape** | `LatheGeometry` with a 6-point profile matching a real brilliant-cut cross-section (table → crown → girdle → pavilion → culet) |
| **Material** | `MeshPhysicalMaterial` with **IOR 2.42** (real diamond), 97% transmission, clearcoat, and blue-ish attenuation color for that classic diamond tint |
| **Environment map** | Procedural shader with bright spots baked into a `PMREMGenerator` so the transparent material has something to refract/reflect |
| **Lighting** | Key, fill, rim, and bottom lights for sparkle and depth |
| **Animation** | Slow Y-axis rotation + gentle floating + orbiting sparkle particles |
| **Controls** | `OrbitControls` — drag to rotate, scroll to zoom |

Open the file in any modern browser and you'll see a floating, rotating diamond with glass-like refraction and subtle sparkle particles orbiting around it.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Three.js Door Demo</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
    #info {
      position: absolute; top: 16px; width: 100%; text-align: center;
      color: #ccc; font-family: system-ui, sans-serif; font-size: 14px;
      pointer-events: none; text-shadow: 0 1px 3px rgba(0,0,0,.8);
    }
  </style>
</head>
<body>
  <div id="info">Click &amp; drag to orbit · Scroll to zoom · Press <b>Space</b> to toggle door</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene, Camera, Renderer ──────────────────────────────
    const scene    = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.Fog(0x1a1a2e, 12, 25);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 2.2, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ─────────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 1.8, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.minDistance = 3;
    controls.maxDistance = 14;
    controls.maxPolarAngle = Math.PI * 0.85;
    controls.update();

    // ── Lights ───────────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0x404060, 0.6));

    const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
    keyLight.position.set(4, 6, 4);
    keyLight.castShadow = true;
    keyLight.shadow.mapSize.set(1024, 1024);
    keyLight.shadow.camera.near = 1;
    keyLight.shadow.camera.far = 20;
    keyLight.shadow.camera.left = -5;
    keyLight.shadow.camera.right = 5;
    keyLight.shadow.camera.top = 5;
    keyLight.shadow.camera.bottom = -1;
    keyLight.shadow.bias = -0.002;
    scene.add(keyLight);

    const fillLight = new THREE.PointLight(0x4488ff, 1.5, 12);
    fillLight.position.set(-3, 3, 2);
    scene.add(fillLight);

    // ── Materials ────────────────────────────────────────────
    const wallMat   = new THREE.MeshStandardMaterial({ color: 0x8a8a8a, roughness: 0.9 });
    const floorMat  = new THREE.MeshStandardMaterial({ color: 0x3a3a3a, roughness: 0.7 });
    const frameMat  = new THREE.MeshStandardMaterial({ color: 0x2c2c2c, roughness: 0.4, metalness: 0.3 });
    const doorMat   = new THREE.MeshStandardMaterial({ color: 0x6b3a2a, roughness: 0.65, metalness: 0.05 });
    const handleMat = new THREE.MeshStandardMaterial({ color: 0xd4d4d4, roughness: 0.15, metalness: 0.9 });
    const panelMat  = new THREE.MeshStandardMaterial({ color: 0x5a2e1f, roughness: 0.7 });
    const trimMat   = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.5 });

    // ── Wall ─────────────────────────────────────────────────
    const wallGeo = new THREE.BoxGeometry(10, 5, 0.3);
    const wall = new THREE.Mesh(wallGeo, wallMat);
    wall.position.set(0, 2.5, -0.3);
    wall.receiveShadow = true;
    scene.add(wall);

    // ── Floor ────────────────────────────────────────────────
    const floorGeo = new THREE.BoxGeometry(10, 0.15, 8);
    const floor = new THREE.Mesh(floorGeo, floorMat);
    floor.position.set(0, -0.075, 2.5);
    floor.receiveShadow = true;
    scene.add(floor);

    // ── Door Frame (Architrave) ──────────────────────────────
    const frameW = 0.12, frameD = 0.35;
    const doorW = 1.4, doorH = 3.0;

    // Side jambs
    [-1, 1].forEach(side => {
      const jamb = new THREE.Mesh(new THREE.BoxGeometry(frameW, doorH + 0.2, frameD), frameMat);
      jamb.position.set(side * (doorW / 2 + frameW / 2), doorH / 2, 0.02);
      jamb.castShadow = jamb.receiveShadow = true;
      scene.add(jamb);
    });

    // Top header
    const header = new THREE.Mesh(new THREE.BoxGeometry(doorW + frameW * 2, frameW, frameD), frameMat);
    header.position.set(0, doorH + frameW / 2, 0.02);
    header.castShadow = header.receiveShadow = true;
    scene.add(header);

    // Bottom sill
    const sill = new THREE.Mesh(new THREE.BoxGeometry(doorW + frameW * 2, 0.08, frameD + 0.1), trimMat);
    sill.position.set(0, 0.04, 0.05);
    sill.receiveShadow = true;
    scene.add(sill);

    // ── Door Pivot Group ─────────────────────────────────────
    const doorPivot = new THREE.Group();
    doorPivot.position.set(-doorW / 2 - 0.01, 0, 0);
    scene.add(doorPivot);

    // Door leaf
    const doorGeo = new THREE.BoxGeometry(doorW, doorH, 0.08);
    const door = new THREE.Mesh(doorGeo, doorMat);
    door.position.set(doorW / 2, doorH / 2, 0);
    door.castShadow = door.receiveShadow = true;
    doorPivot.add(door);

    // Raised panels on door (front and back)
    const pw = doorW - 0.3, ph = doorH - 0.5;
    const panelY = doorH / 2;
    [-1, 1].forEach(side => {
      const pg = new THREE.BoxGeometry(pw, ph, 0.025);
      const panel = new THREE.Mesh(pg, panelMat);
      panel.position.set(doorW / 2, panelY, side * 0.055);
      panel.castShadow = true;
      doorPivot.add(panel);
    });

    // Stiles and rails (thin strips creating the panel frame look)
    const stripThick = 0.06;
    [0.25, doorH - 0.25].forEach(y => {
      const rail = new THREE.Mesh(
        new THREE.BoxGeometry(doorW, stripThick, 0.095), doorMat
      );
      rail.position.set(doorW / 2, y, 0);
      rail.castShadow = true;
      doorPivot.add(rail);
    });

    // ── Handle ───────────────────────────────────────────────
    const handleGroup = new THREE.Group();
    handleGroup.position.set(doorW - 0.15, 1.1, 0);
    doorPivot.add(handleGroup);

    // Plate
    const plate = new THREE.Mesh(new THREE.BoxGeometry(0.04, 0.25, 0.06), handleMat);
    plate.castShadow = true;
    handleGroup.add(plate);

    // Knob
    const knob = new THREE.Mesh(new THREE.SphereGeometry(0.055, 16, 16), handleMat);
    knob.position.set(0, -0.1, 0.04);
    knob.castShadow = true;
    handleGroup.add(knob);

    // ── Hinges ───────────────────────────────────────────────
    [0.6, 2.3].forEach(y => {
      const hinge = new THREE.Mesh(new THREE.BoxGeometry(0.04, 0.15, 0.1), handleMat);
      hinge.position.set(0.02, y, 0);
      hinge.castShadow = true;
      doorPivot.add(hinge);
    });

    // ── Door Opening / Closing ───────────────────────────────
    let doorOpen = false;
    let targetRot = 0;

    window.addEventListener('keydown', e => {
      if (e.code === 'Space') {
        e.preventDefault();
        doorOpen = !doorOpen;
        targetRot = doorOpen ? -Math.PI * 0.55 : 0;
      }
    });

    // ── Resize ───────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });

    // ── Animate ──────────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const dt = clock.getDelta();

      // Smooth door rotation
      doorPivot.rotation.y += (targetRot - doorPivot.rotation.y) * Math.min(dt * 3.5, 1);

      controls.update();
      renderer.render(scene, camera);
    }

    animate();
  </script>
</body>
</html>
