const panGeo = new THREE.BoxGeometry(2.5, 0.4, 3.7);
const pan = mesh(panGeo, matBlock, [0, -0.2, 0]);
engine.add(pan);

/* ── animation ── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  const crankAngle = t * 4; // rotation speed

  // rotate flywheel & timing gear
  flywheel.rotation.z = crankAngle;
  timingGear.rotation.z = crankAngle * 2; // 2:1 ratio

  // pistons & rods
  const crankRadius = 0.35;
  const rodLength = 1.1;

  pistons.forEach((p, i) => {
    const angle = crankAngle + p.phase;
    // piston Y position using slider-crank approximation
    const sinA = Math.sin(angle);
    const cosA = Math.cos(angle);
    const pistonY = 0.35 + crankRadius * cosA + Math.sqrt(rodLength * rodLength - (crankRadius * sinA) ** 2);

    p.mesh.position.y = pistonY;

    // rod midpoint between crank pin and piston
    const pinX = crankRadius * sinA;
    const pinY = 0.35 + crankRadius * cosA;
    rods[i].position.set(pinX / 2, (pinY + pistonY) / 2, p.z);

    // rod tilt
    const dx = pinX;
    const dy = pistonY - pinY;
    rods[i].rotation.z = Math.atan2(dx, dy);

    // crank pin position
    crankPins[i].mesh.position.set(pinX, pinY, p.z);
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

/* ── resize ── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What's in the demo

| Component | Geometry | Notes |
|---|---|---|
| **Engine block** | `BoxGeometry` | Main body with detail strips |
| **Cylinder head + valve cover** | `Box` + `Cylinder` | Sits atop the block |
| **4 pistons** | `CylinderGeometry` | Animated with slider-crank kinematics |
| **Connecting rods** | `CylinderGeometry` | Tilts realistically as crank rotates |
| **Crankshaft** | `CylinderGeometry` | Central rotating shaft |
| **Flywheel** | `CylinderGeometry` | Rotates at crank speed (back) |
| **Timing gear** | `CylinderGeometry` | 2:1 ratio (front) |
| **Exhaust manifold & pipe** | `Box` + `Cylinder` + `Torus` | Bent pipe on the left side |
| **Intake manifold + runners** | `Box` + `Cylinder`s | Blue-colored, right side |
| **Spark plugs** | `CylinderGeometry` | Glowing orange on top |
| **Oil pan** | `BoxGeometry` | Bottom of the block |

**Animations:** Pistons reciprocate using real slider-crank math (`Y = r·cosθ + √(L² − r²sin²θ)`), rods tilt to follow, and the flywheel/timing gear spin continuously. Drag to orbit and scroll to zoom.

