const centerX = 256, centerY = 256;
const imageData = ctx.createImageData(512, 512);
const data = imageData.data;

for (let y = 0; y < 512; y++) {
  for (let x = 0; x < 512; x++) {
    const dx = x - centerX;
    const dy = y - centerY;
    const dist = Math.sqrt(dx * dx + dy * dy);
    const angle = Math.atan2(dy, dx);

    if (dist > 256) {
      const idx = (y * 512 + x) * 4;
      data[idx] = 0; data[idx + 1] = 0; data[idx + 2] = 0; data[idx + 3] = 0;
      continue;
    }

    // Complex iris pattern
    const normalizedDist = dist / 256;
    const ring1 = Math.sin(dist * 0.15 + angle * 8) * 0.5 + 0.5;
    const ring2 = Math.sin(dist * 0.08 - angle * 12) * 0.5 + 0.5;
    const ring3 = Math.sin(dist * 0.25 + angle * 5) * 0.5 + 0.5;
    const radialFibers = Math.sin(angle * 30 + dist * 0.05) * 0.5 + 0.5;
    const noise = Math.sin(x * 0.1 + y * 0.13) * Math.sin(x * 0.07 - y * 0.11) * 0.5 + 0.5;

    // Color mixing - green-blue iris
    const r = Math.floor(30 + ring1 * 40 + radialFibers * 20 + noise * 15);
    const g = Math.floor(80 + ring2 * 60 + radialFibers * 30 + noise * 20);
    const b = Math.floor(60 + ring3 * 50 + radialFibers * 25 + noise * 15);

    // Darker near pupil, lighter near edge
    const edgeFade = normalizedDist > 0.8 ? 1.0 - (normalizedDist - 0.8) * 3 : 1.0;
    const pupilDark = normalizedDist < 0.35 ? normalizedDist / 0.35 : 1.0;

    const idx = (y * 512 + x) * 4;
    data[idx]     = Math.min(255, r * edgeFade * pupilDark);
    data[idx + 1] = Math.min(255, g * edgeFade * pupilDark);
    data[idx + 2] = Math.min(255, b * edgeFade * pupilDark);
    data[idx + 3] = 255;
  }
}
