    heartShape.bezierCurveTo(x + 1.15, y + 0.3, x + 1.15, y + 1.0, x + 0.5, y + 1.0);
    heartShape.bezierCurveTo(x, y + 1.0,   x, y + 0.5,   x, y + 0.5);

    // ── Extrude Settings ─────────────────────────────────────
    const extrudeSettings = {
      depth: 0.6,
      bevelEnabled: true,
      bevelSegments: 12,
      bevelSize: 0.18,
      bevelThickness: 0.15,
      curveSegments: 24,
    };

    const heartGeo = new THREE.ExtrudeGeometry(heartShape, extrudeSettings);
    heartGeo.center();

    // ── Material ─────────────────────────────────────────────
    const heartMat = new THREE.MeshStandardMaterial({
      color: 0xe03050,
      metalness: 0.1,
      roughness: 0.35,
      emissive: 0x3a0010,
      emissiveIntensity: 0.4,
    });

    const heart = new THREE.Mesh(heartGeo, heartMat);
    scene.add(heart);

    // ── Lights ───────────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0x404060, 1.5));

    const keyLight = new THREE.DirectionalLight(0xffeedd, 3);
    keyLight.position.set(3, 4, 5);
    scene.add(keyLight);

    const fillLight = new THREE.DirectionalLight(0x8888ff, 1);
    fillLight.position.set(-4, -2, 3);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xff6688, 2, 15);
    rimLight.position.set(0, 2, -4);
    scene.add(rimLight);

    // ── Particles (floating sparkles) ────────────────────────
    const count = 300;
    const positions = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 12;
      positions[i * 3 + 1] = (Math.random() - 0.5) * 12;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 12;
    }
    const particleGeo = new THREE.BufferGeometry();
    particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

    const particleMat = new THREE.PointsMaterial({
      color: 0xff8899,
      size: 0.03,
      transparent: true,
      opacity: 0.6,
      sizeAttenuation: true,
    });
    const particles = new THREE.Points(particleGeo, particleMat);
    scene.add(particles);

    // ── Animation Loop ───────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle rotation
      heart.rotation.y = Math.sin(t * 0.5) * 0.4;

      // Heartbeat pulse
      const beat = Math.pow(Math.sin(t * 3.5) * 0.5 + 0.5, 3);
      const scale = 1 + beat * 0.08;
      heart.scale.setScalar(scale);

      // Subtle emissive pulse
      heartMat.emissiveIntensity = 0.3 + beat * 0.5;

      // Slow particle drift
      particles.rotation.y = t * 0.05;
      particles.rotation.x = Math.sin(t * 0.03) * 0.1;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
