const camera = new THREE.PerspectiveCamera(50, innerWidth/innerHeight, 0.1, 200);
camera.position.set(8, 5, 10);
camera.lookAt(0, 2, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

/* ── Lights ── */
scene.add(new THREE.AmbientLight(0x4466aa, 0.4));
const moon = new THREE.DirectionalLight(0xaaccff, 0.8);
moon.position.set(5, 15, 8);
moon.castShadow = true;
moon.shadow.mapSize.set(1024, 1024);
scene.add(moon);
const warm = new THREE.PointLight(0xffaa44, 0.6, 12);
warm.position.set(0, 1.5, 0);
scene.add(warm);

/* ── Snow ground ── */
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(60, 64),
  new THREE.MeshStandardMaterial({ color: 0xddeeff, roughness: 0.9, metalness: 0 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

/* ── Igloo dome from ice blocks ── */
const iceMat = new THREE.MeshStandardMaterial({
  color: 0xc8ddf0, roughness: 0.35, metalness: 0.05,
  transparent: true, opacity: 0.88
});

const igloo = new THREE.Group();
const R = 3.5;              // base radius
const rows = 7;
const blockH = 0.35;

for (let r = 0; r < rows; r++) {
  const t = r / (rows - 1);            // 0 → 1
  const ringR = R * Math.cos(t * Math.PI / 2);
  const y = R * Math.sin(t * Math.PI / 2);
  const count = Math.max(3, Math.round(18 * (1 - t * 0.55)));

  for (let i = 0; i < count; i++) {
    const a = (i / count) * Math.PI * 2;
    const w = (Math.PI * 2 * ringR) / count * 0.92;
    const geo = new THREE.BoxGeometry(w, blockH, 0.65);
    const block = new THREE.Mesh(geo, iceMat);
    block.position.set(
      ringR * Math.cos(a),
      y + blockH / 2,
      ringR * Math.sin(a)
    );
    block.rotation.y = -a;
    block.castShadow = true;
    block.receiveShadow = true;
    igloo.add(block);
  }
}
scene.add(igloo);

/* ── Entrance tunnel ── */
const tunnelGeo = new THREE.CylinderGeometry(0.55, 0.65, 2.2, 12, 1, true, 0, Math.PI);
const tunnelMat = new THREE.MeshStandardMaterial({
  color: 0xb0cce0, roughness: 0.4, side: THREE.DoubleSide,
  transparent: true, opacity: 0.85
});
const tunnel = new THREE.Mesh(tunnelGeo, tunnelMat);
tunnel.rotation.x = Math.PI / 2;
tunnel.position.set(0, 0.45, R + 0.5);
tunnel.castShadow = true;
scene.add(tunnel);

/* ── Tunnel roof (half-tube) ── */
const roofGeo = new THREE.CylinderGeometry(0.6, 0.7, 2.2, 12, 1, false, 0, Math.PI);
const roof = new THREE.Mesh(roofGeo, tunnelMat);
roof.rotation.x = Math.PI / 2;
roof.position.set(0, 1.1, R + 0.5);
roof.castShadow = true;
scene.add(roof);

/* ── Snow particles ── */
const snowCount = 600;
const snowGeo = new THREE.BufferGeometry();
const snowPos = new Float32Array(snowCount * 3);
for (let i = 0; i < snowCount; i++) {
  snowPos[i * 3]     = (Math.random() - 0.5) * 50;
  snowPos[i * 3 + 1] = Math.random() * 25;
  snowPos[i * 3 + 2] = (Math.random() - 0.5) * 50;
}
snowGeo.setAttribute('position', new THREE.BufferAttribute(snowPos, 3));
const snowMat = new THREE.PointsMaterial({
  color: 0xffffff, size: 0.12, transparent: true, opacity: 0.7
});
const snow = new THREE.Points(snowGeo, snowMat);
scene.add(snow);

/* ── Stars ── */
const starCount = 400;
const starGeo = new THREE.BufferGeometry();
const starPos = new Float32Array(starCount * 3);
for (let i = 0; i < starCount; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.random() * Math.PI * 0.45;
  const s = 80 + Math.random() * 40;
  starPos[i * 3]     = s * Math.sin(phi) * Math.cos(theta);
  starPos[i * 3 + 1] = s * Math.cos(phi);
  starPos[i * 3 + 2] = s * Math.sin(phi) * Math.sin(theta);
}
starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
scene.add(new THREE.Points(starGeo, new THREE.PointsMaterial({
  color: 0xffffff, size: 0.15, transparent: true, opacity: 0.8
})));

/* ── Animation ── */
const clock = new THREE.Clock();
(function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  snow.rotation.y = t * 0.02;
  const pos = snow.geometry.attributes.position.array;
  for (let i = 0; i < snowCount; i++) {
    pos[i * 3 + 1] -= 0.015;
    if (pos[i * 3 + 1] < 0) pos[i * 3 + 1] = 25;
  }
  snow.geometry.attributes.position.needsUpdate = true;

  warm.intensity = 0.5 + Math.sin(t * 2) * 0.15;

  renderer.render(scene, camera);
})();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's in it:**

| Feature | Detail |
|---|---|
| **Dome** | 7 concentric rows of `BoxGeometry` blocks, radius shrinking toward the top to form a hemispherical igloo shape |
| **Entrance tunnel** | Half-cylinder opening at the base with a matching roof piece |
| **Ice material** | Translucent, slightly bluish `MeshStandardMaterial` with soft roughness |
| **Warm interior glow** | A flickering `PointLight` inside the dome |
| **Snowfall** | 600 animated particles drifting downward |
| **Night sky** | 400 stars scattered across a dark hemisphere + exponential fog |
| **Lighting** | Moonlight (`DirectionalLight`) with soft shadows + ambient fill |
| **Responsive** | Handles window resize |

