dome.position.set(0, 3.9, -0.2);
helicopter.add(dome);

// ── Main Rotor ──
const mainRotorGroup = new THREE.Group();
mainRotorGroup.position.set(0, 4.2, -0.2);

const hubGeo = new THREE.CylinderGeometry(0.18, 0.18, 0.15, 12);
const hub = new THREE.Mesh(hubGeo, darkMat);
mainRotorGroup.add(hub);

for (let i = 0; i < 4; i++) {
  const bladeGeo = new THREE.BoxGeometry(0.12, 0.06, 5.5);
