// H on pad
const hShape = new THREE.Shape();
hShape.moveTo(-0.8, -1); hShape.lineTo(-0.8, 1);
hShape.lineTo(-0.4, 1); hShape.lineTo(-0.4, -1);
hShape.moveTo(0.8, -1); hShape.lineTo(0.8, 1);
hShape.lineTo(0.4, 1); hShape.lineTo(0.4, -1);
hShape.moveTo(-0.4, 0); hShape.lineTo(0.4, 0);
hShape.lineTo(0.4, -0.3); hShape.lineTo(-0.4, -0.3);
hShape.closePath();
const hGeo = new THREE.ExtrudeGeometry(hShape, { depth: 0.06, bevelEnabled: false });
const hMesh = new THREE.Mesh(hGeo, new THREE.MeshStandardMaterial({ color: 0xffffff }));
hMesh.rotation.x = -Math.PI / 2;
hMesh.position.y = 0.055;
scene.add(hMesh);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Rotor speeds
  mainRotorGroup.rotation.y = t * 12;
  tailRotorGroup.rotation.y = t * 25;

  // Gentle hover
  helicopter.position.y = Math.sin(t * 1.5) * 0.2 + 0.5;
  helicopter.rotation.z = Math.sin(t * 0.7) * 0.015;
  helicopter.rotation.x = Math.sin(t * 0.5) * 0.01;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
