// ── Island Terrain ─────────────────────────────────────────────
const islandRadius = 14;
const islandGeo = new THREE.CircleGeometry(islandRadius, 128, 64);
islandGeo.rotateX(-Math.PI / 2);

const posAttr = islandGeo.attributes.position;
const colors = new Float32Array(posAttr.count * 3);
const sandColor = new THREE.Color(0xe8d5a3);
const grassColor = new THREE.Color(0x4a8c3f);
const darkGrass = new THREE.Color(0x357a2a);
const rockColor = new THREE.Color(0x6b6b5e);

for (let i = 0; i < posAttr.count; i++) {
  const x = posAttr.getX(i);
  const z = posAttr.getZ(i);
  const dist = Math.sqrt(x * x + z * z);
  const normDist = dist / islandRadius;

  // Height: peaked in center, sloping to edges
  let height = (1 - normDist * normDist) * 6;
  height += fbm(x * 0.15 + 10, z * 0.15 + 10, 5) * 2.5;
  height -= normDist * 1.5; // extra slope at edges

  // Shoreline smoothing
  if (normDist > 0.8) {
    height *= Math.max(0, 1 - (normDist - 0.8) / 0.2);
  }

  posAttr.setY(i, Math.max(height, -0.1));

  // Vertex colors
  const c = new THREE.Color();
  if (height < 0.3) {
    c.copy(sandColor);
  } else if (height < 3.5) {
    const t = (height - 0.3) / 3.2;
    c.copy(grassColor).lerp(darkGrass, t);
  } else {
    c.copy(darkGrass).lerp(rockColor, Math.min(1, (height - 3.5) / 3));
  }
  colors[i * 3] = c.r;
  colors[i * 3 + 1] = c.g;
  colors[i * 3 + 2] = c.b;
}

islandGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
islandGeo.computeVertexNormals();

const islandMat = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.85,
  metalness: 0.05,
  flatShading: false,
});
