// ── Palm Tree Generator ────────────────────────────────────────
function createPalmTree(height = 5 + Math.random() * 3) {
  const group = new THREE.Group();

  // Trunk (slightly curved)
  const trunkCurve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(0, 0, 0),
    new THREE.Vector3(0.3, height * 0.3, 0),
    new THREE.Vector3(0.5, height * 0.6, 0.1),
    new THREE.Vector3(0.2, height, 0),
  ]);
  const trunkGeo = new THREE.TubeGeometry(trunkCurve, 12, 0.25, 8, false);
  const trunkMat = new THREE.MeshStandardMaterial({ color: 0x8B6914, roughness: 0.9 });
  const trunk = new THREE.Mesh(trunkGeo, trunkMat);
  trunk.castShadow = true;
  group.add(trunk);

  // Leaves
  const leafMat = new THREE.MeshStandardMaterial({
    color: 0x2d8a2d,
    roughness: 0.7,
    side: THREE.DoubleSide,
  });
  const leafPositions = [
    { angle: 0, tilt: -0.6 },
    { angle: Math.PI * 0.4, tilt: -0.4 },
    { angle: Math.PI * 0.8, tilt: -0.7 },
    { angle: Math.PI * 1.2, tilt: -0.5 },
    { angle: Math.PI * 1.6, tilt: -0.6 },
    { angle: Math.PI * 2.0, tilt: -0.45 },
  ];

  for (const lp of leafPositions) {
    const leafShape = new THREE.Shape();
    leafShape.moveTo(0, 0);
    leafShape.quadraticCurveTo(1.5, 1.2, 3.5, 0);
    leafShape.quadraticCurveTo(1.5, -0.5, 0, 0);

    const leafGeo = new THREE.ShapeGeometry(leafShape, 8);
    const leaf = new THREE.Mesh(leafGeo, leafMat);
    leaf.position.set(0, height, 0);
    leaf.rotation.y = lp.angle;
    leaf.rotation.x = lp.tilt;
    leaf.castShadow = true;
    group.add(leaf);
  }

  return group;
}

// ── Scatter Trees & Rocks ──────────────────────────────────────
function getTerrainHeight(x, z) {
  const dist = Math.sqrt(x * x + z * z);
  const normDist = dist / islandRadius;
  if (normDist > 1) return -1;
  let h = (1 - normDist * normDist) * 6;
  h += fbm(x * 0.15 + 10, z * 0.15 + 10, 5) * 2.5;
  h -= normDist * 1.5;
  if (normDist > 0.8) h *= Math.max(0, 1 - (normDist - 0.8) / 0.2);
  return Math.max(h, -0.1);
}

