  depthWrite: false,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ─── Light rays (subtle volumetric feel) ───
const rayGeo = new THREE.PlaneGeometry(0.3, 40);
const rayMat = new THREE.MeshBasicMaterial({
