  ray.rotation.z = (Math.random() - 0.5) * 0.3;
  ray.rotation.y = Math.random() * Math.PI;
  scene.add(ray);
}

// ─── Animation ───
const clock = new THREE.Clock();

function animateTentacle(tentacle, time, pulsePhase) {
  const { basePoints, angle, radius, phase, numSegments, mesh } = tentacle;
  const positions = [];

  for (let j = 0; j <= numSegments; j++) {
    const t = j / numSegments;
    const bp = basePoints[j];

    // Wavy motion
    const wave1 = Math.sin(t * 4 + time * 1.5 + phase) * 0.4 * t;
    const wave2 = Math.cos(t * 3 + time * 1.2 + phase * 1.3) * 0.3 * t;
    const wave3 = Math.sin(t * 6 + time * 0.8 + phase * 0.7) * 0.15 * t;

    // Pulse response - tentacles droop when bell contracts
    const pulseEffect = (1 - Math.sin(pulsePhase)) * 0.3 * t;

    const px = bp.x + Math.cos(angle) * wave1 + Math.sin(angle) * wave3;
    const py = bp.y - pulseEffect;
    const pz = bp.z + Math.sin(angle) * wave1 + Math.cos(angle) * wave2;

    positions.push(new THREE.Vector3(px, py, pz));
  }

  const curve = new THREE.CatmullRomCurve3(positions);
  mesh.geometry.dispose();
  mesh.geometry = new THREE.TubeGeometry(curve, 40, 0.03, 5, false);
}

function animateOralArm(arm, time, pulsePhase) {
  const { basePoints, angle, radius, phase, mesh } = arm;
  const positions = [];

  for (let j = 0; j <= basePoints.length - 1; j++) {
    const t = j / (basePoints.length - 1);
    const bp = basePoints[j];

    const wave1 = Math.sin(t * 3 + time * 1.0 + phase) * 0.3 * t;
    const wave2 = Math.cos(t * 2.5 + time * 0.8 + phase) * 0.2 * t;
    const pulseEffect = (1 - Math.sin(pulsePhase)) * 0.2 * t;

    const px = bp.x + Math.cos(angle + phase) * wave1;
    const py = bp.y - pulseEffect;
    const pz = bp.z + Math.sin(angle + phase) * wave2;

    positions.push(new THREE.Vector3(px, py, pz));
  }

  const curve = new THREE.CatmullRomCurve3(positions);
  mesh.geometry.dispose();
  mesh.geometry = new THREE.TubeGeometry(curve, 30, 0.12, 8, false);
}

