    for (let i = 0; i < 120; i++) {
      const g = new THREE.Mesh(new THREE.ConeGeometry(0.08, 0.3 + Math.random() * 0.2, 4), grassMat);
      g.position.set((Math.random() - 0.5) * 20, 0.12, (Math.random() - 0.5) * 20);
      g.rotation.y = Math.random() * Math.PI;
      g.castShadow = true;
      scene.add(g);
    }

    /* ── Kangaroo Materials ── */
    const bodyMat   = new THREE.MeshStandardMaterial({ color: 0xA0722A, roughness: 0.85 });
    const darkMat   = new THREE.MeshStandardMaterial({ color: 0x7A5420, roughness: 0.85 });
    const lightMat  = new THREE.MeshStandardMaterial({ color: 0xC89B5B, roughness: 0.8 });
    const noseMat   = new THREE.MeshStandardMaterial({ color: 0x3A2010, roughness: 0.6 });
    const eyeMat    = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.3 });
    const eyeWhite  = new THREE.MeshStandardMaterial({ color: 0xEEEEEE, roughness: 0.3 });
    const innerEar  = new THREE.MeshStandardMaterial({ color: 0xD4956A, roughness: 0.7 });
    const footMat   = new THREE.MeshStandardMaterial({ color: 0x5C3A1E, roughness: 0.9 });

    /* ── Kangaroo Group ── */
    const kangaroo = new THREE.Group();
    scene.add(kangaroo);

    // Helper
    function addMesh(geo, mat, parent, pos, rot, scl, castShadow = true) {
      const m = new THREE.Mesh(geo, mat);
      if (pos) m.position.set(...pos);
      if (rot) m.rotation.set(...rot);
      if (scl) m.scale.set(...scl);
      if (castShadow) { m.castShadow = true; m.receiveShadow = true; }
      (parent || kangaroo).add(m);
      return m;
    }

    /* ── Body ── */
    const bodyGroup = new THREE.Group();
    bodyGroup.position.set(0, 2.0, 0);
    kangaroo.add(bodyGroup);

    // Torso
    addMesh(new THREE.SphereGeometry(1, 24, 18), bodyMat, bodyGroup, [0, 0, 0], null, [1, 1.15, 0.85]);
    // Chest (lighter)
