    addMesh(new THREE.SphereGeometry(0.08, 8, 6), eyeMat, headGroup, [-0.32, 0.12, 0.5]);
    addMesh(new THREE.SphereGeometry(0.12, 10, 8), eyeWhite, headGroup, [0.32, 0.12, 0.42]);
