renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
document.body.appendChild(renderer.domElement);

// Lighting
const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambientLight);

const sunLight = new THREE.DirectionalLight(0xfff4e0, 1.2);
sunLight.position.set(10, 20, 10);
sunLight.castShadow = true;
scene.add(sunLight);

const backLight = new THREE.DirectionalLight(0x8ec8f0, 0.4);
backLight.position.set(-5, 5, -10);
scene.add(backLight);

// ── Kite Group ──
const kite = new THREE.Group();
scene.add(kite);

// Diamond kite body (thin extruded diamond)
const kiteShape = new THREE.Shape();
kiteShape.moveTo(0, 3.5);
kiteShape.lineTo(2.2, 0);
kiteShape.lineTo(0, -4.5);
kiteShape.lineTo(-2.2, 0);
kiteShape.closePath();

const extrudeSettings = { depth: 0.25, bevelEnabled: true, bevelThickness: 0.15, bevelSize: 0.15, bevelSegments: 3 };
const kiteGeom = new THREE.ExtrudeGeometry(kiteShape, extrudeSettings);
kiteGeom.center();

const kiteMat = new THREE.MeshStandardMaterial({
  color: 0xff4466,
  roughness: 0.4,
  metalness: 0.1,
  side: THREE.DoubleSide,
  transparent: true,
  opacity: 0.92
});
const kiteMesh = new THREE.Mesh(kiteGeom, kiteMat);
kiteMesh.castShadow = true;
kite.add(kiteMesh);

// Back face (slightly different shade)
const backMat = new THREE.MeshStandardMaterial({
  color: 0xee2244,
  roughness: 0.5,
  side: THREE.BackSide,
  transparent: true,
  opacity: 0.85
});

// Cross sticks
const stickMat = new THREE.MeshStandardMaterial({ color: 0xc8a050, roughness: 0.7 });

const vStick = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.04, 8, 8), stickMat);
vStick.position.z = 0.1;
kite.add(vStick);

const hStick = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.04, 4.4, 8), stickMat);
hStick.rotation.z = Math.PI / 2;
hStick.position.set(0, 0.2, 0.1);
kite.add(hStick);

// String attachment point (small ring)
const ringGeom = new THREE.TorusGeometry(0.12, 0.025, 8, 16);
const ringMat = new THREE.MeshStandardMaterial({ color: 0x888888, metalness: 0.8, roughness: 0.2 });
const ring = new THREE.Mesh(ringGeom, ringMat);
ring.position.set(0, 3.5, 0.1);
kite.add(ring);

// ── Tail ──
const tailSegments = 24;
const tailPoints = [];
const tailGroup = new THREE.Group();
kite.add(tailGroup);

for (let i = 0; i < tailSegments; i++) {
  const t = i / tailSegments;
  const size = 0.35 * (1 - t * 0.7);
  const colors = [0xff6633, 0xffcc00, 0x33cc33, 0x3399ff, 0xcc33ff];
  const color = colors[i % colors.length];

  const seg = new THREE.Mesh(
    new THREE.SphereGeometry(size, 8, 6),
    new THREE.MeshStandardMaterial({ color, roughness: 0.5 })
  );
  seg.position.y = -4.5 - i * 0.55;
  seg.castShadow = true;
  tailGroup.add(seg);
  tailPoints.push(seg);
}

// Connecting tail string
const tailCurve = new THREE.CatmullRomCurve3(tailPoints.map(p => p.position));
const tailLineGeom = new THREE.TubeGeometry(tailCurve, 48, 0.02, 6, false);
const tailLine = new THREE.Mesh(tailLineGeom, new THREE.MeshStandardMaterial({ color: 0x555555 }));
kite.add(tailLine);

// ── Main String ──
const stringCurve = new THREE.QuadraticBezierCurve3(
  new THREE.Vector3(0, 3.5, 0),
  new THREE.Vector3(0.5, 8, 0),
  new THREE.Vector3(0, 18, 0)
);
const stringGeom = new THREE.TubeGeometry(stringCurve, 32, 0.015, 6, false);
const stringMesh = new THREE.Mesh(stringGeom, new THREE.MeshStandardMaterial({ color: 0xdddddd }));
kite.add(stringMesh);

// ── Clouds ──
function makeCloud(x, y, z, scale) {
  const cloud = new THREE.Group();
  const mat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 1, flatShading: true });
  const blobs = [
    { r: 1.5, p: [0, 0, 0] },
    { r: 1.2, p: [1.5, 0.2, 0.3] },
    { r: 1.0, p: [-1.3, -0.1, -0.2] },
    { r: 0.9, p: [0.8, 0.6, -0.1] },
    { r: 1.1, p: [-0.6, 0.4, 0.2] },
  ];
  blobs.forEach(b => {
    const m = new THREE.Mesh(new THREE.SphereGeometry(b.r, 8, 6), mat);
    m.position.set(...b.p);
    cloud.add(m);
  });
  cloud.position.set(x, y, z);
  cloud.scale.setScalar(scale);
  return cloud;
}

const clouds = [];
[
  [15, 12, -20, 2], [-18, 16, -15, 1.5], [10, 8, -30, 1.8],
  [-12, 20, -25, 2.2], [25, 14, -18, 1.3]
].forEach(c => {
  const cl = makeCloud(...c);
  scene.add(cl);
  clouds.push(cl);
});

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(200, 200),
  new THREE.MeshStandardMaterial({ color: 0x4a8c3f, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -12;
ground.receiveShadow = true;
scene.add(ground);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle kite swaying
  kite.rotation.z = Math.sin(t * 0.7) * 0.08;
  kite.rotation.x = Math.sin(t * 0.5) * 0.04;
  kite.position.y = Math.sin(t * 0.9) * 0.3;
  kite.position.x = Math.sin(t * 0.3) * 0.2;

  // Tail wave
  tailPoints.forEach((seg, i) => {
    const phase = i * 0.4;
    seg.position.x = Math.sin(t * 1.5 + phase) * 0.6;
    seg.position.z = Math.cos(t * 1.2 + phase) * 0.3;
  });

  // Update tail curve
  tailLine.geometry.dispose();
  const updatedCurve = new THREE.CatmullRomCurve3(tailPoints.map(p => p.position));
  tailLine.geometry = new THREE.TubeGeometry(updatedCurve, 48, 0.02, 6, false);

  // Drift clouds
  clouds.forEach((cl, i) => {
    cl.position.x += 0.008 + i * 0.002;
    if (cl.position.x > 40) cl.position.x = -40;
  });

  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's included:**

- **Diamond kite body** — an extruded 2D diamond shape with bevel, semi-transparent red material
- **Cross sticks** — vertical and horizontal wooden-colored cylinders
- **Attachment ring** — small metallic torus at the top
- **Flowing tail** — 24 colorful sphere segments connected by a dynamically updated tube string
- **Main string** — quadratic Bézier curve extending upward
- **Clouds** — clustered sphere puffs that drift across the sky
- **Ground plane** — green surface below
- **Animation** — gentle swaying/rocking of the kite, sinusoidal tail wave, drifting clouds
- **Lighting** — ambient + directional sun + back fill light with fog

