    // ── Scene, Camera, Renderer ──────────────────────────────
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0a0a14);
    scene.fog = new THREE.FogExp2(0x0a0a14, 0.08);

    const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 2, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 1.5, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    // ── Ground ───────────────────────────────────────────────
    const ground = new THREE.Mesh(
      new THREE.CircleGeometry(8, 64),
      new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 0.9 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Lantern Group ────────────────────────────────────────
    const lantern = new THREE.Group();
    lantern.position.y = 0.01;

    const metalMat  = new THREE.MeshStandardMaterial({ color: 0x2a1a0a, metalness: 0.8, roughness: 0.3 });
    const brassMat  = new THREE.MeshStandardMaterial({ color: 0xb8860b, metalness: 0.9, roughness: 0.2 });
    const glassMat  = new THREE.MeshPhysicalMaterial({
      color: 0xffeedd, transparent: true, opacity: 0.15,
      roughness: 0.05, metalness: 0, transmission: 0.9, thickness: 0.3,
      ior: 1.5, side: THREE.DoubleSide
    });

    // Base
    const base = new THREE.Mesh(new THREE.CylinderGeometry(0.5, 0.6, 0.2, 32), metalMat);
    base.position.y = 0.1;
    base.castShadow = true;
    lantern.add(base);

    // Glass body
    const glass = new THREE.Mesh(new THREE.CylinderGeometry(0.4, 0.45, 1.4, 32, 1, true), glassMat);
    glass.position.y = 0.9;
    lantern.add(glass);

    // Glass panels (vertical lines)
    for (let i = 0; i < 8; i++) {
      const angle = (i / 8) * Math.PI * 2;
      const panel = new THREE.Mesh(
        new THREE.BoxGeometry(0.015, 1.4, 0.015),
        brassMat
      );
      panel.position.set(
        Math.cos(angle) * 0.42,
        0.9,
        Math.sin(angle) * 0.42
      );
      panel.rotation.y = -angle;
      lantern.add(panel);
    }

    // Middle ring
    const midRing = new THREE.Mesh(new THREE.TorusGeometry(0.4, 0.025, 8, 32), brassMat);
    midRing.position.y = 0.9;
    midRing.rotation.x = Math.PI / 2;
    lantern.add(midRing);

    // Top cap (cone)
    const cap = new THREE.Mesh(new THREE.ConeGeometry(0.45, 0.35, 32, 1, true), brassMat);
    cap.position.y = 1.775;
    cap.castShadow = true;
    lantern.add(cap);

    // Cap rim
    const capRim = new THREE.Mesh(new THREE.TorusGeometry(0.4, 0.02, 8, 32), brassMat);
    capRim.position.y = 1.6;
    capRim.rotation.x = Math.PI / 2;
    lantern.add(capRim);

    // Handle (torus arc)
    const handleCurve = new THREE.CatmullRomCurve3([
      new THREE.Vector3(0, 2.1, 0),
      new THREE.Vector3(0, 2.6, 0),
      new THREE.Vector3(0, 2.8, 0),
      new THREE.Vector3(0, 2.6, 0.5),
    ]);
    // Simpler: half-torus handle
    const handleGeo = new THREE.TorusGeometry(0.35, 0.025, 8, 32, Math.PI);
    const handle = new THREE.Mesh(handleGeo, brassMat);
    handle.position.y = 2.1;
    handle.rotation.z = Math.PI;
    lantern.add(handle);

    // Handle attachment points
    [-1, 1].forEach(side => {
      const dot = new THREE.Mesh(new THREE.SphereGeometry(0.035, 8, 8), brassMat);
      dot.position.set(0, 1.78, side * 0.35);
      lantern.add(dot);
    });

    // ── Inner Flame ──────────────────────────────────────────
    const flameLight = new THREE.PointLight(0xff9933, 15, 12, 2);
    flameLight.position.set(0, 0.9, 0);
    flameLight.castShadow = true;
    flameLight.shadow.mapSize.set(512, 512);
    lantern.add(flameLight);

    const flameGeo = new THREE.SphereGeometry(0.12, 16, 16);
    const flameMat = new THREE.MeshBasicMaterial({ color: 0xffaa44 });
    const flame = new THREE.Mesh(flameGeo, flameMat);
    flame.position.y = 0.9;
    lantern.add(flame);

    // Inner glow sphere
    const glowGeo = new THREE.SphereGeometry(0.3, 16, 16);
    const glowMat = new THREE.MeshBasicMaterial({
      color: 0xff8822, transparent: true, opacity: 0.08
    });
    const glow = new THREE.Mesh(glowGeo, glowMat);
    glow.position.y = 0.9;
    lantern.add(glow);

    scene.add(lantern);

    // ── Ambient ──────────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0x1a1a3a, 0.5));

    // ── Floating Particles ───────────────────────────────────
    const particleCount = 60;
    const particlesGeo = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    const velocities = [];
    for (let i = 0; i < particleCount; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 6;
      positions[i * 3 + 1] = Math.random() * 4;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 6;
      velocities.push({ y: 0.002 + Math.random() * 0.005, x: (Math.random() - 0.5) * 0.002 });
    }
    particlesGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    const particlesMat = new THREE.PointsMaterial({
      color: 0xffaa55, size: 0.03, transparent: true, opacity: 0.6,
      blending: THREE.AdditiveBlending, depthWrite: false
    });
    const particles = new THREE.Points(particlesGeo, particlesMat);
    scene.add(particles);

    // ── Animation ────────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Flicker
      const flicker = 0.85 + Math.sin(t * 12) * 0.08 + Math.sin(t * 23) * 0.05 + Math.sin(t * 7) * 0.04;
      flameLight.intensity = 15 * flicker;
      flame.scale.setScalar(0.8 + flicker * 0.25);
      glow.scale.setScalar(0.9 + flicker * 0.2);

      // Gentle sway
      lantern.rotation.z = Math.sin(t * 0.8) * 0.03;
      lantern.rotation.x = Math.sin(t * 0.6) * 0.015;

      // Particles
      const pos = particles.geometry.attributes.position.array;
      for (let i = 0; i < particleCount; i++) {
        pos[i * 3]     += velocities[i].x + Math.sin(t + i) * 0.0005;
        pos[i * 3 + 1] += velocities[i].y;
        if (pos[i * 3 + 1] > 5) {
          pos[i * 3 + 1] = 0;
          pos[i * 3]     = (Math.random() - 0.5) * 6;
          pos[i * 3 + 2] = (Math.random() - 0.5) * 6;
        }
      }
      particles.geometry.attributes.position.needsUpdate = true;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
