// ── Helpers ──────────────────────────────────────────────────
function makeLimb(radiusTop, radiusBot, length, segments = 4) {
  return new THREE.Mesh(
    new THREE.CylinderGeometry(radiusTop, radiusBot, length, segments),
    shellMat
  );
}

function mergeGeometries(geometries, matrices) {
  const merged = new THREE.BufferGeometry();
  const positions = [];
  const normals = [];
  const uvs = [];
  const indices = [];
  let indexOffset = 0;

  for (let i = 0; i < geometries.length; i++) {
    const geo = geometries[i].toNonIndexed();
    const pos = geo.attributes.position.array;
    const nor = geo.attributes.normal ? geo.attributes.normal.array : new Float32Array(pos.length);
    const uv = geo.attributes.uv ? geo.attributes.uv.array : new Float32Array(pos.length / 3 * 2);

    for (let j = 0; j < pos.length; j += 3) {
      const v = new THREE.Vector3(pos[j], pos[j+1], pos[j+2]);
      const n = new THREE.Vector3(nor[j], nor[j+1], nor[j+2]);
      if (matrices[i]) {
        v.applyMatrix4(matrices[i]);
        const normMat = matrices[i].clone().invert().transpose();
        n.applyMatrix4(normMat).normalize();
      }
      positions.push(v.x, v.y, v.z);
      normals.push(n.x, n.y, n.z);
    }
    for (let j = 0; j < uv.length; j++) uvs.push(uv[j]);
    const count = pos.length / 3;
    for (let j = 0; j < count; j++) indices.push(indexOffset + j);
    indexOffset += count;
  }

  merged.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  merged.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
  merged.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  merged.setIndex(indices);
  merged.computeVertexNormals();
  return merged;
}

// ── Lobster Group ────────────────────────────────────────────
const lobster = new THREE.Group();

// ── Head / Carapace ──────────────────────────────────────────
const headGroup = new THREE.Group();

// Main carapace body
