  const stalkGeo = new THREE.CylinderGeometry(0.06, 0.08, 0.7, 8);
  const stalk = new THREE.Mesh(stalkGeo, shellMat);
  stalk.castShadow = true;
  eyeGroup.add(stalk);

  // Bulb
  const bulbGeo = new THREE.SphereGeometry(0.15, 12, 8);
  const bulb = new THREE.Mesh(bulbGeo, eyeMat);
  bulb.position.y = 0.4;
  bulb.castShadow = true;
  eyeGroup.add(bulb);

  // Pupil highlight
