  const pupilMat = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.1, metalness: 0.5 });
  const pupil = new THREE.Mesh(pupilGeo, pupilMat);
  pupil.position.set(x > 0 ? 0.06 : -0.06, 0.45, -0.08);
