  eyeGroup.rotation.z = x > 0 ? 0.3 : -0.3;
  eyeGroup.rotation.x = -0.3;
  return eyeGroup;
}

headGroup.add(makeEye(-0.55));
headGroup.add(makeEye(0.55));

// ── Antennae ─────────────────────────────────────────────────
function makeAntenna(side, length, thickness) {
  const points = [];
  const segments = 20;
  for (let i = 0; i <= segments; i++) {
    const t = i / segments;
    const x = side * (0.3 + t * 0.8 + Math.sin(t * 3) * 0.15);
    const y = 0.6 + t * length;
    const z = -0.6 - t * length * 0.7 + Math.sin(t * 2.5) * 0.3;
    points.push(new THREE.Vector3(x, y, z));
  }
  const curve = new THREE.CatmullRomCurve3(points);
  const tubeGeo = new THREE.TubeGeometry(curve, 32, thickness, 6, false);
  const tube = new THREE.Mesh(tubeGeo, shellMat);
  tube.castShadow = true;
  return tube;
}

headGroup.add(makeAntenna(-1, 2.5, 0.035));
headGroup.add(makeAntenna(1, 2.5, 0.035));

// Shorter antennules
