lobster.add(headGroup);

// ── Abdomen / Tail Segments ──────────────────────────────────
const tailGroup = new THREE.Group();

const segmentData = [
  { radius: 0.55, length: 0.7, z: 1.55 },
  { radius: 0.52, length: 0.65, z: 2.25 },
