  const upper = new THREE.Mesh(upperGeo, i % 2 === 0 ? shellMat : shellLightMat);
  upper.rotation.x = Math.PI / 2;
  upper.scale.set(1, seg.length / (seg.radius * 2), 1);
  upper.position.z = seg.z;
  upper.castShadow = true;
  tailGroup.add(upper);

  // Lower belly
  const lowerGeo = new THREE.SphereGeometry(seg.radius * 0.92, 16, 8, 0, Math.PI * 2, Math.PI * 0.5, Math.PI * 0.4);
  const lower = new THREE.Mesh(lowerGeo, undersideMat);
  lower.rotation.x = -Math.PI / 2;
  lower.scale.set(1, seg.length / (seg.radius * 2), 1);
  lower.position.z = seg.z;
  tailGroup.add(lower);

  // Segment groove
  if (i < segmentData.length - 1) {
    const grooveGeo = new THREE.TorusGeometry(seg.radius * 0.95, 0.03, 8, 20);
