<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x111111);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 6);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 1.5, 0);

// --- Vase profile (x = radius, y = height) ---
const points = [
  new THREE.Vector2(0.0, 0.0),
  new THREE.Vector2(0.5, 0.0),
  new THREE.Vector2(0.7, 0.1),
  new THREE.Vector2(0.9, 0.4),
  new THREE.Vector2(1.0, 0.8),
  new THREE.Vector2(1.0, 1.2),
  new THREE.Vector2(0.9, 1.6),
  new THREE.Vector2(0.6, 2.0),
  new THREE.Vector2(0.4, 2.3),
  new THREE.Vector2(0.35,2.5),
  new THREE.Vector2(0.45,2.6),
  new THREE.Vector2(0.5, 2.7),
  new THREE.Vector2(0.4, 2.7),
  new THREE.Vector2(0.0, 2.7),
];

const geometry = new THREE.LatheGeometry(points, 64);
geometry.computeVertexNormals();

const material = new THREE.MeshStandardMaterial({
  color: 0xcc6644,
  roughness: 0.35,
  metalness: 0.1,
});

const vase = new THREE.Mesh(geometry, material);
scene.add(vase);

// --- Lights ---
scene.add(new THREE.AmbientLight(0xffffff, 0.4));

const dir = new THREE.DirectionalLight(0xffffff, 1.5);
dir.position.set(3, 5, 4);
scene.add(dir);

const rim = new THREE.PointLight(0xffaa66, 0.8, 8);
rim.position.set(-2, 3, 1);
scene.add(rim);

// --- Animate ---
function loop() {
  requestAnimationFrame(loop);
  vase.rotation.y += 0.005;
  controls.update();
  renderer.render(scene, camera);
}
loop();

// --- Resize ---
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
