const handleGeo = new THREE.CylinderGeometry(0.06, 0.075, 3.2, 12);
const handle = new THREE.Mesh(handleGeo, woodMaterial);
handle.position.y = 1.4;
handle.castShadow = true;
axe.add(handle);

// Handle top cap (pommel area)
const handleCapGeo = new THREE.SphereGeometry(0.075, 12, 8, 0, Math.PI * 2, 0, Math.PI / 2);
const handleCap = new THREE.Mesh(handleCapGeo, woodMaterial);
handleCap.position.y = 3.0;
handleCap.rotation.x = Math.PI;
axe.add(handleCap);

// Handle bottom - slight taper
const handleBottomGeo = new THREE.SphereGeometry(0.075, 12, 8, 0, Math.PI * 2, 0, Math.PI / 2);
const handleBottom = new THREE.Mesh(handleBottomGeo, woodMaterial);
handleBottom.position.y = -0.2;
axe.add(handleBottom);

// ── Axe Head Group ──
const headGroup = new THREE.Group();
headGroup.position.y = 2.4;

// Main head body (the block the handle passes through)
const headBodyGeo = new THREE.BoxGeometry(0.9, 0.5, 0.45);
const headBody = new THREE.Mesh(headBodyGeo, steelMaterial);
headBody.castShadow = true;
headGroup.add(headBody);

// Eye hole (dark cylinder inside the head)
const eyeGeo = new THREE.CylinderGeometry(0.085, 0.085, 0.55, 12);
const eyeMat = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 1, metalness: 0 });
const eye = new THREE.Mesh(eyeGeo, eyeMat);
eye.rotation.x = Math.PI / 2;
headGroup.add(eye);

// ── Blade (right side) ──
const bladeShape = new THREE.Shape();
bladeShape.moveTo(0, 0);
bladeShape.lineTo(0.55, 0.05);
bladeShape.lineTo(0.75, -0.05);
bladeShape.lineTo(0.85, -0.18);
bladeShape.lineTo(0.82, -0.28);
bladeShape.lineTo(0.70, -0.35);
bladeShape.lineTo(0.50, -0.38);
bladeShape.lineTo(0.25, -0.35);
bladeShape.lineTo(0, -0.28);
bladeShape.closePath();

const bladeExtrudeSettings = { depth: 0.12, bevelEnabled: true, bevelThickness: 0.015, bevelSize: 0.015, bevelSegments: 3 };
