// ── Procedural Bump Map ──
function createBumpMap(width, height, scale, intensity) {
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#808080';
  ctx.fillRect(0, 0, width, height);

  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const idx = (y * width + x) * 4;
      let nx = x / width * scale;
      let ny = y / height * scale;
      let value = 0;

      // Multi-octave noise
      value += Math.sin(nx * 3.7 + ny * 2.3) * Math.cos(ny * 4.1 + nx * 1.7) * 0.5;
      value += Math.sin(nx * 7.3 + ny * 5.9) * Math.cos(ny * 8.7 + nx * 3.1) * 0.25;
      value += Math.sin(nx * 13.7 + ny * 11.3) * Math.cos(ny * 17.1 + nx * 13.7) * 0.125;
      value += Math.sin(nx * 23.3 + ny * 19.7) * Math.cos(ny * 29.3 + nx * 23.1) * 0.0625;

      // Add some "bump" clusters like avocado skin dimples
      const dx = x / width - 0.5;
      const dy = y / height - 0.5;
      const dist = Math.sqrt(dx * dx + dy * dy);
      value += Math.sin(dist * 30) * Math.exp(-dist * 3) * 0.3;

      value = (value + 1) * 0.5; // normalize to 0-1
      const val = Math.floor(value * 255 * intensity + (1 - intensity) * 128);
      data[idx] = data[idx + 1] = data[idx + 2] = Math.max(0, Math.min(255, val));
    }
  }

  ctx.putImageData(imageData, 0, 0);

  const texture = new THREE.CanvasTexture(canvas);
  texture.wrapS = THREE.RepeatWrapping;
  texture.wrapT = THREE.RepeatWrapping;
  return texture;
}

function createNormalMap(width, height, scale) {
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');

  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  const getNoise = (x, y) => {
    let nx = x / width * scale;
    let ny = y / height * scale;
    let v = 0;
    v += Math.sin(nx * 3.7 + ny * 2.3) * Math.cos(ny * 4.1 + nx * 1.7) * 0.5;
    v += Math.sin(nx * 7.3 + ny * 5.9) * Math.cos(ny * 8.7 + nx * 3.1) * 0.25;
    v += Math.sin(nx * 13.7 + ny * 11.3) * Math.cos(ny * 17.1 + nx * 13.7) * 0.125;
    return v;
  };

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const idx = (y * width + x) * 4;
      const eps = 1.0;
      const hL = getNoise(x - eps, y);
      const hR = getNoise(x + eps, y);
      const hU = getNoise(x, y - eps);
      const hD = getNoise(x, y + eps);

      const nx = (hL - hR) * 2.0;
      const ny = (hU - hD) * 2.0;

      data[idx]     = Math.floor(Math.max(0, Math.min(255, nx * 127.5 + 128)));
      data[idx + 1] = Math.floor(Math.max(0, Math.min(255, ny * 127.5 + 128)));
      data[idx + 2] = 255;
      data[idx + 3] = 255;
    }
  }

  ctx.putImageData(imageData, 0, 0);
  const texture = new THREE.CanvasTexture(canvas);
  texture.wrapS = THREE.RepeatWrapping;
  texture.wrapT = THREE.RepeatWrapping;
  return texture;
}

