// Profile points for the outer skin (cross-section from center line outward)
function createAvocadoProfile(skinOffset) {
  const points = [];
  const steps = 60;

  for (let i = 0; i <= steps; i++) {
    const t = i / steps;
    const angle = t * Math.PI; // 0 to PI

    // Avocado shape: wider in the middle-bottom, tapered at top and bottom
    let radius;
    if (t < 0.05) {
      // Stem end - small taper
      radius = Math.sin(angle) * 0.85 * (t / 0.05) * 0.15;
    } else if (t < 0.15) {
      // Top section - narrow
      const lt = (t - 0.05) / 0.1;
      radius = 0.15 + lt * (0.85 - 0.15);
    } else if (t < 0.5) {
      // Upper body - expanding to widest
      const lt = (t - 0.15) / 0.35;
      radius = 0.85 + lt * 0.15;
    } else if (t < 0.85) {
      // Lower body - tapering
      const lt = (t - 0.5) / 0.35;
      radius = 1.0 - lt * 0.55;
    } else {
      // Bottom tip - narrow
      const lt = (t - 0.85) / 0.15;
      radius = 0.45 * (1 - lt);
    }

    // Slight asymmetry for organic feel
    radius *= (1 + Math.sin(t * Math.PI * 2) * 0.03);

    // Height: stretched along Y
    const y = Math.cos(angle) * 1.4;

    radius += skinOffset;
    points.push(new THREE.Vector2(Math.max(0.001, radius), y));
  }

  return points;
}

