<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Balloon</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js"
  }
}
</script>
<script type="module">
import * as THREE from 'three';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.015);

// ── Camera ─────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);
camera.lookAt(0, 0, 0);

// ── Renderer ───────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Lights ─────────────────────────────────────────────
scene.add(new THREE.AmbientLight(0xffffff, 0.6));
const sun = new THREE.DirectionalLight(0xffffff, 2.5);
sun.position.set(5, 10, 7);
scene.add(sun);
const fill = new THREE.DirectionalLight(0x8888ff, 0.4);
fill.position.set(-5, 0, -3);
scene.add(fill);

// ── Balloon Body (custom lathe profile) ────────────────
const profile = [];
const steps = 30;
for (let i = 0; i <= steps; i++) {
  const t = i / steps;
  const angle = t * Math.PI;
  // Shape: wide balloon that tapers at top and bottom
  let r = Math.sin(angle) * Math.sin(angle) * 1.6;
  // Slight elongation
  const y = (t - 0.5) * 2.8;
  profile.push(new THREE.Vector2(r, y));
}

const balloonGeo = new THREE.LatheGeometry(profile, 48);
const balloonMat = new THREE.MeshPhysicalMaterial({
  color: 0xe63946,
  roughness: 0.15,
  metalness: 0.0,
  clearcoat: 0.8,
  clearcoatRoughness: 0.1,
  reflectivity: 0.6,
  sheen: 0.3,
  sheenColor: 0xff6b6b,
  side: THREE.DoubleSide,
});
const balloon = new THREE.Mesh(balloonGeo, balloonMat);
scene.add(balloon);

// ── Knot ───────────────────────────────────────────────
const knotGeo = new THREE.SphereGeometry(0.12, 16, 16);
const knotMat = new THREE.MeshStandardMaterial({ color: 0xcc2233, roughness: 0.4 });
const knot = new THREE.Mesh(knotGeo, knotMat);
knot.position.y = -1.45;
scene.add(knot);

// ── Neck (short taper) ─────────────────────────────────
const neckGeo = new THREE.CylinderGeometry(0.08, 0.15, 0.3, 16);
const neck = new THREE.Mesh(neckGeo, balloonMat);
neck.position.y = -1.35;
scene.add(neck);

// ── String ─────────────────────────────────────────────
const stringPoints = [];
for (let i = 0; i <= 20; i++) {
  const t = i / 20;
  const x = Math.sin(t * Math.PI * 1.5) * 0.15;
  const z = Math.cos(t * Math.PI * 1.2) * 0.08;
  stringPoints.push(new THREE.Vector3(x, -1.5 - t * 2.5, z));
}
const stringCurve = new THREE.CatmullRomCurve3(stringPoints);
const stringGeo = new THREE.TubeGeometry(stringCurve, 32, 0.008, 8, false);
const stringMat = new THREE.MeshStandardMaterial({ color: 0x555555, roughness: 0.8 });
const string = new THREE.Mesh(stringGeo, stringMat);
scene.add(string);

// ── Highlight / shine patch ────────────────────────────
const shineGeo = new THREE.SphereGeometry(0.35, 32, 16, 0, Math.PI * 0.6, 0, Math.PI * 0.5);
const shineMat = new THREE.MeshBasicMaterial({
  color: 0xffffff,
  transparent: true,
  opacity: 0.25,
  side: THREE.DoubleSide,
});
const shine = new THREE.Mesh(shineGeo, shineMat);
shine.position.set(-0.5, 0.5, 1.15);
shine.rotation.z = 0.3;
balloon.add(shine);

// ── Animation ──────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float
  balloon.position.y = Math.sin(t * 0.8) * 0.2;
  knot.position.y = -1.45 + Math.sin(t * 0.8) * 0.2;
  neck.position.y = -1.35 + Math.sin(t * 0.8) * 0.2;
  string.position.y = Math.sin(t * 0.8) * 0.2;

  // Slight sway
  balloon.rotation.z = Math.sin(t * 0.5) * 0.04;
  knot.rotation.z = balloon.rotation.z;
  neck.rotation.z = balloon.rotation.z;
  string.rotation.z = balloon.rotation.z;

  // String sway
  for (let i = 0; i <= 20; i++) {
    const t2 = i / 20;
    const x = Math.sin(t2 * Math.PI * 1.5 + t * 1.2) * (0.15 + t2 * 0.15);
    const z = Math.cos(t2 * Math.PI * 1.2 + t * 0.8) * (0.08 + t2 * 0.1);
    stringPoints[i].set(x, -1.5 - t2 * 2.5 + Math.sin(t * 0.8) * 0.2, z);
  }
  stringCurve.points = stringPoints;
  string.geometry.dispose();
  string.geometry = new THREE.TubeGeometry(stringCurve, 32, 0.008, 8, false);

  renderer.render(scene, camera);
}

animate();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What this gives you:**

- **Balloon body** — a `LatheGeometry` revolved from a custom profile curve, giving a realistic rounded balloon shape that tapers at the top and bottom
- **Material** — `MeshPhysicalMaterial` with clearcoat and sheen for that glossy, slightly translucent balloon look
- **Knot & neck** — a small sphere knot and tapered cylinder where the string attaches
- **String** — a `TubeGeometry` along a CatmullRom curve that dynamically sways
- **Shine patch** — a semi-transparent white sphere baked onto the balloon for a specular highlight
- **Animation** — gentle floating bob + sway, with the string rippling independently
- **Lighting** — ambient + directional sun + blue fill light, with ACES filmic tone mapping
- **Responsive** — handles window resize automatically

