    // ── Lighting ──
    const ambientLight = new THREE.AmbientLight(0x8899bb, 0.6);
    scene.add(ambientLight);

    const hemiLight = new THREE.HemisphereLight(0xddeeff, 0x556633, 0.5);
    scene.add(hemiLight);

    const sunLight = new THREE.DirectionalLight(0xfff4e0, 1.8);
    sunLight.position.set(15, 25, 10);
    sunLight.castShadow = true;
    sunLight.shadow.mapSize.set(2048, 2048);
    sunLight.shadow.camera.left = -20;
    sunLight.shadow.camera.right = 20;
    sunLight.shadow.camera.top = 20;
    sunLight.shadow.camera.bottom = -20;
    sunLight.shadow.camera.near = 1;
    sunLight.shadow.camera.far = 60;
    sunLight.shadow.bias = -0.001;
    scene.add(sunLight);

    const fillLight = new THREE.DirectionalLight(0x88aacc, 0.4);
    fillLight.position.set(-10, 10, -5);
    scene.add(fillLight);

    // ── Materials ──
    const wallMat = new THREE.MeshStandardMaterial({ color: 0xe8ddd0, roughness: 0.85, metalness: 0.05 });
    const floorMat = new THREE.MeshStandardMaterial({ color: 0xc4a882, roughness: 0.7, metalness: 0.05 });
    const railingMat = new THREE.MeshStandardMaterial({ color: 0x3a3a3a, roughness: 0.3, metalness: 0.8 });
    const doorMat = new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 0.7, metalness: 0.1 });
    const groundMat = new THREE.MeshStandardMaterial({ color: 0x4a7c3f, roughness: 0.95, metalness: 0.0 });
    const roofMat = new THREE.MeshStandardMaterial({ color: 0xb85c38, roughness: 0.8, metalness: 0.05 });
    const windowMat = new THREE.MeshStandardMaterial({ color: 0x88bbdd, roughness: 0.1, metalness: 0.3, transparent: true, opacity: 0.45 });
    const potMat = new THREE.MeshStandardMaterial({ color: 0xc4704f, roughness: 0.85, metalness: 0.05 });
    const plantMat = new THREE.MeshStandardMaterial({ color: 0x2d6b1e, roughness: 0.8, metalness: 0.0 });
    const stairMat = new THREE.MeshStandardMaterial({ color: 0xb0a090, roughness: 0.75, metalness: 0.05 });

    // ── Helper functions ──
    function box(w, h, d, mat, x, y, z, ry = 0) {
      const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), mat);
      m.position.set(x, y, z);
      m.rotation.y = ry;
      m.castShadow = true;
      m.receiveShadow = true;
      scene.add(m);
      return m;
    }

    function cyl(rt, rb, h, seg, mat, x, y, z) {
      const m = new THREE.Mesh(new THREE.CylinderGeometry(rt, rb, h, seg), mat);
      m.position.set(x, y, z);
      m.castShadow = true;
      m.receiveShadow = true;
      scene.add(m);
      return m;
    }

    // ── Ground ──
    const ground = new THREE.Mesh(new THREE.PlaneGeometry(200, 200), groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.05;
    ground.receiveShadow = true;
    scene.add(ground);

    // Gravel / pathway
    const path = new THREE.Mesh(new THREE.PlaneGeometry(4, 30), new THREE.MeshStandardMaterial({ color: 0x9e9080, roughness: 0.95 }));
    path.rotation.x = -Math.PI / 2;
    path.position.set(0, 0.01, 18);
    path.receiveShadow = true;
    scene.add(path);

    // ── Building Wall ──
    // Main wall behind balcony
    box(16, 12, 1, wallMat, 0, 6, -5);

