    // Balcony underside / soffit
    box(14, 0.2, 4, wallMat, 0, 4.8, 0);

    // ── Railing System ──
    const railHeight = 1.3;
    const balconyEdge = 1.8;
    const balSpacing = 0.6;
    const balRadius = 0.04;

    // Front railing (along the open side)
    const frontZ = balconyEdge;
    const railY = 5.15 + railHeight;
    const bottomRailY = 5.15 + 0.1;

    // Top rail - front
    box(14, 0.08, 0.08, railingMat, 0, railY, frontZ);
    // Bottom rail - front
    box(14, 0.06, 0.06, railingMat, 0, bottomRailY, frontZ);

    // Front balusters
    for (let i = -6.5; i <= 6.5; i += balSpacing) {
      cyl(balRadius, balRadius, railHeight, 8, railingMat, i, 5.15 + railHeight / 2, frontZ);
    }

    // Side railings (left and right)
    [-7, 7].forEach(x => {
      // Top rail
      box(0.08, 0.08, 3.8, railingMat, x, railY, 1.8);
      // Bottom rail
      box(0.06, 0.06, 3.8, railingMat, x, bottomRailY, 1.8);
      // Side balusters
      for (let j = 0.3; j <= 3.3; j += balSpacing) {
        cyl(balRadius, balRadius, railHeight, 8, railingMat, x, 5.15 + railHeight / 2, j);
      }
    });

    // Decorative top cap on front rail
    box(14.2, 0.12, 0.14, new THREE.MeshStandardMaterial({ color: 0x4a4a4a, roughness: 0.25, metalness: 0.85 }), 0, railY + 0.06, frontZ);

    // ── Stairs going down ──
    const stairW = 3;
    const stairD = 0.8;
    const stairH = 0.25;
    const stairCount = 10;
    for (let i = 0; i < stairCount; i++) {
      box(stairW, stairH, stairD, stairMat, 0, 5 - i * stairH, 2.2 + i * stairD / 2);
    }

    // Stair stringers (angled supports)
    [-stairW / 2 - 0.15, stairW / 2 + 0.15].forEach(x => {
      const angle = Math.atan2(5, stairCount * stairD / 2);
      const len = Math.sqrt(5 * 5 + (stairCount * stairD / 2) ** 2);
      const stringer = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.12, len), stairMat);
      stringer.position.set(x, 2.5, 2.2 + stairCount * stairD / 4);
      stringer.rotation.x = -angle;
      stringer.castShadow = true;
      scene.add(stringer);
    });

    // ── Planters / Pots ──
    function addPlanter(x, z) {
      // Pot
      const pot = new THREE.Mesh(new THREE.CylinderGeometry(0.3, 0.22, 0.5, 12), potMat);
      pot.position.set(x, 5.4, z);
      pot.castShadow = true;
      scene.add(pot);

      // Soil
      const soil = new THREE.Mesh(new THREE.CylinderGeometry(0.28, 0.28, 0.05, 12),
        new THREE.MeshStandardMaterial({ color: 0x3d2b1f }));
      soil.position.set(x, 5.65, z);
      scene.add(soil);

      // Plant (cluster of spheres)
      const plantGroup = new THREE.Group();
      const positions = [
        [0, 0.55, 0, 0.25],
        [0.12, 0.45, 0.05, 0.18],
        [-0.1, 0.5, -0.08, 0.2],
        [0.05, 0.6, -0.1, 0.15],
