<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

// --- Camera ---
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 2, 6);

// --- Renderer ---
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// --- Controls ---
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0.5, 0);

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0xffeedd, 0.6);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffffff, 2.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0xffaa44, 1.0);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0xffdd88, 1.5, 15);
pointLight.position.set(0, 3, 2);
scene.add(pointLight);

// --- Banana Geometry ---
function createBananaShape() {
  const curve = new THREE.CatmullRomCurve3([
    new THREE.Vector3(-1.6, 0.0, 0.0),
    new THREE.Vector3(-1.2, 0.35, 0.0),
    new THREE.Vector3(-0.5, 0.75, 0.0),
    new THREE.Vector3(0.3, 0.95, 0.0),
    new THREE.Vector3(1.0, 0.85, 0.0),
    new THREE.Vector3(1.5, 0.55, 0.0),
    new THREE.Vector3(1.75, 0.2, 0.0),
  ]);

  const tubeSegments = 128;
  const radialSegments = 16;

  // Custom flattened cross-section shape
  const shape = new THREE.Shape();
  const w = 0.22, h = 0.30;
  shape.moveTo(0, h);
  shape.bezierCurveTo(w * 1.2, h * 0.8, w * 1.2, -h * 0.8, 0, -h);
  shape.bezierCurveTo(-w * 1.2, -h * 0.8, -w * 1.2, h * 0.8, 0, h);

  const extrudeSettings = {
    steps: tubeSegments,
    extrudePath: curve,
    bevelEnabled: false,
  };

  // Use a TubeGeometry with a custom radius profile
  const points = curve.getPoints(tubeSegments);
  const geometry = new THREE.TubeGeometry(curve, tubeSegments, 0.25, radialSegments, false);

  // Modify vertices for banana shape
  const pos = geometry.attributes.position;
  const uv = geometry.attributes.uv;
  const colors = new Float32Array(pos.count * 3);

  for (let i = 0; i < pos.count; i++) {
    const u = uv.getX(i); // 0..1 along the curve
    const v = uv.getY(i); // 0..1 around the cross-section

    // Taper at both ends
    const taper = Math.sin(u * Math.PI);
    const taper2 = Math.pow(taper, 0.6);

    // Flatten the cross-section slightly
    const angle = v * Math.PI * 2;
    let x = pos.getX(i);
    let y = pos.getY(i);
    let z = pos.getZ(i);

    // Get the normal direction in local cross-section
    const localY = Math.cos(angle);
    const localZ = Math.sin(angle);

    // Flatten: squash in one direction
    const flatten = 0.75;
    const radius = 0.25 * taper2;

    // Rebuild position relative to curve point
    const curvePoint = curve.getPoint(u);
    const tangent = curve.getTangent(u);

    // Simple flattening: scale Y more than Z
    pos.setY(i, curvePoint.y + localY * radius * 1.15);
    pos.setZ(i, curvePoint.z + localZ * radius * 0.7);
    pos.setX(i, curvePoint.x);

    // Add subtle ridges
    const ridge = Math.sin(angle * 3) * 0.015 * taper;
    pos.setY(i, pos.getY(i) + localY * ridge);
    pos.setZ(i, pos.getZ(i) + localZ * ridge);

    // Color: yellow body, green tips, brown spots
    const tipFactor = Math.pow(1 - taper, 3);
    const green = new THREE.Color(0.25, 0.6, 0.1);
    const yellow = new THREE.Color(1.0, 0.85, 0.15);
    const darkYellow = new THREE.Color(0.85, 0.7, 0.05);
    const brown = new THREE.Color(0.4, 0.25, 0.1);

    let color;
    if (u < 0.08 || u > 0.92) {
      color = green.clone().lerp(yellow, 1 - tipFactor * 2);
    } else {
      color = yellow.clone().lerp(darkYellow, Math.abs(localY) * 0.3);
    }

    // Add some brown spots
    const spotNoise = Math.sin(u * 47.0) * Math.cos(v * 31.0 + u * 13.0);
    if (spotNoise > 0.82 && u > 0.1 && u < 0.9) {
      color.lerp(brown, (spotNoise - 0.82) * 5);
    }

    // Darken the stem area
    if (u < 0.05) {
      color.lerp(new THREE.Color(0.15, 0.3, 0.08), 1 - u * 20);
    }

    colors[i * 3] = color.r;
    colors[i * 3 + 1] = color.g;
    colors[i * 3 + 2] = color.b;
  }

  geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));
  geometry.computeVertexNormals();
  return geometry;
}

// --- Banana Mesh ---
const bananaGeometry = createBananaShape();
const bananaMaterial = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.45,
  metalness: 0.05,
  side: THREE.DoubleSide,
});

const banana = new THREE.Mesh(bananaGeometry, bananaMaterial);
banana.castShadow = true;
banana.receiveShadow = true;
banana.rotation.z = 0.15;
scene.add(banana);

// --- Stem ---
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(-1.6, 0.0, 0.0),
  new THREE.Vector3(-1.75, -0.05, 0.0),
  new THREE.Vector3(-1.95, -0.12, 0.0),
  new THREE.Vector3(-2.1, -0.15, 0.02),
]);
const stemGeo = new THREE.TubeGeometry(stemCurve, 20, 0.04, 8, false);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x3a6b18,
  roughness: 0.7,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
stem.rotation.z = 0.15;
scene.add(stem);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x16213e,
  roughness: 0.9,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.2;
ground.receiveShadow = true;
scene.add(ground);

// --- Floating particles ---
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  particlePositions[i * 3] = (Math.random() - 0.5) * 12;
  particlePositions[i * 3 + 1] = Math.random() * 6 - 1;
  particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 12;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xffdd88,
  size: 0.04,
  transparent: true,
  opacity: 0.5,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  banana.rotation.y = Math.sin(t * 0.5) * 0.3;
  banana.position.y = Math.sin(t * 0.8) * 0.1;
  stem.rotation.y = banana.rotation.y;
  stem.position.y = banana.position.y;

  // Particles drift
  particles.rotation.y = t * 0.05;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single HTML file creates a procedurally generated banana with Three.js featuring:

- **Curved tube geometry** shaped along a CatmullRom spline to mimic the banana's crescent form
- **Tapered ends** that narrow at both tips
- **Flattened cross-section** (not a perfect cylinder) for realism
- **Vertex colors** — yellow body, green tips, brown spots, and a dark stem
- **Subtle ridges** along the surface
- **A separate green stem** piece
- **Three-point lighting** (ambient, directional, rim) with soft shadows
- **Gentle floating animation** — the banana slowly bobs and rotates
- **Floating golden particles** in the background for atmosphere
- **OrbitControls** — drag to rotate, scroll to zoom
- **Responsive** to window resizing

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bamboo Grove</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.163.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.015);

const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 200);
camera.position.set(8, 6, 12);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 4, 0);
controls.enableDamping = true;
controls.maxPolarAngle = Math.PI / 2.05;
controls.update();

// --- Lighting ---
const ambient = new THREE.AmbientLight(0x406040, 0.8);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 2.5);
sun.position.set(10, 20, 8);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 50;
sun.shadow.camera.left = -15;
sun.shadow.camera.right = 15;
sun.shadow.camera.top = 15;
sun.shadow.camera.bottom = -5;
sun.shadow.bias = -0.001;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8090ff, 0.4);
fill.position.set(-8, 5, -5);
scene.add(fill);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(60, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x3a7d44,
  roughness: 0.95,
  metalness: 0.0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt path
const dirtGeo = new THREE.PlaneGeometry(4, 30, 1, 1);
const dirtMat = new THREE.MeshStandardMaterial({ color: 0x6b5a3e, roughness: 1.0 });
const dirt = new THREE.Mesh(dirtGeo, dirtMat);
dirt.rotation.x = -Math.PI / 2;
dirt.position.y = 0.005;
dirt.receiveShadow = true;
scene.add(dirt);

// --- Bamboo Builder ---
function createBambooStalk(height, baseX, baseZ, lean) {
  const group = new THREE.Group();
  const segments = Math.floor(height / 1.8);
  const segHeight = 1.5;
  const nodeRadius = 0.22;
  const stalkRadius = 0.18;
  let y = 0;

  const greenMat = new THREE.MeshStandardMaterial({
    color: 0x4a8c3f,
    roughness: 0.5,
    metalness: 0.1,
  });
  const nodeMat = new THREE.MeshStandardMaterial({
    color: 0x3a7030,
    roughness: 0.4,
    metalness: 0.15,
  });

  for (let i = 0; i < segments; i++) {
    const t = i / segments;
    const r = stalkRadius * (1 - t * 0.3);

    // Segment
    const segGeo = new THREE.CylinderGeometry(r, r, segHeight, 12);
    const seg = new THREE.Mesh(segGeo, greenMat.clone());
    seg.position.y = y + segHeight / 2;
    seg.castShadow = true;
    seg.receiveShadow = true;
    // Slight color variation
    const hue = 0.28 + Math.random() * 0.06;
    seg.material.color.setHSL(hue, 0.5 + Math.random() * 0.2, 0.35 + Math.random() * 0.1);
    group.add(seg);

    // Node ring
    if (i > 0) {
      const nodeGeo = new THREE.TorusGeometry(r + 0.04, 0.04, 8, 16);
      const node = new THREE.Mesh(nodeGeo, nodeMat);
      node.position.y = y;
      node.rotation.x = Math.PI / 2;
      node.castShadow = true;
      group.add(node);
    }

    y += segHeight;

    // Leaves at some nodes
    if (i > 0 && Math.random() > 0.25) {
      const leafCount = 2 + Math.floor(Math.random() * 3);
      for (let l = 0; l < leafCount; l++) {
        const leaf = createLeaf();
        leaf.position.y = y;
        const angle = (l / leafCount) * Math.PI * 2 + Math.random() * 0.5;
        leaf.rotation.y = angle;
        leaf.rotation.z = (Math.random() - 0.5) * 0.8 - 0.3;
        leaf.rotation.x = (Math.random() - 0.5) * 0.6;
        leaf.castShadow = true;
        group.add(leaf);
      }
    }
  }

  // Top leaves
  for (let l = 0; l < 5; l++) {
    const leaf = createLeaf();
    leaf.position.y = y;
    leaf.rotation.y = (l / 5) * Math.PI * 2;
    leaf.rotation.z = -0.5 - Math.random() * 0.8;
    leaf.rotation.x = (Math.random() - 0.5) * 0.5;
    leaf.scale.setScalar(0.7 + Math.random() * 0.5);
    leaf.castShadow = true;
    group.add(leaf);
  }

  group.position.set(baseX, 0, baseZ);
  group.rotation.z = lean;
  return group;
}

function createLeaf() {
  const shape = new THREE.Shape();
  const len = 1.2 + Math.random() * 0.8;
  const wid = 0.12 + Math.random() * 0.06;
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(wid, len * 0.4, 0, len);
  shape.quadraticCurveTo(-wid, len * 0.4, 0, 0);

  const geo = new THREE.ShapeGeometry(shape, 4);
  const mat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.28 + Math.random() * 0.08, 0.6, 0.35 + Math.random() * 0.15),
    side: THREE.DoubleSide,
    roughness: 0.7,
    metalness: 0.0,
  });
  return new THREE.Mesh(geo, mat);
}

// --- Create Grove ---
const stalks = [];
const bambooData = [
  { h: 14, x: 0, z: 0, lean: -0.02 },
  { h: 11, x: -2.5, z: 1.5, lean: 0.04 },
  { h: 13, x: 2.8, z: -1, lean: -0.03 },
  { h: 9, x: -4, z: -2, lean: 0.05 },
  { h: 12, x: 4.5, z: 2, lean: -0.04 },
  { h: 10, x: 1.5, z: 3.5, lean: 0.03 },
  { h: 8, x: -1, z: -4, lean: -0.02 },
  { h: 15, x: -5.5, z: 0.5, lean: 0.01 },
  { h: 11, x: 6, z: -2.5, lean: -0.03 },
  { h: 10, x: -3, z: 4, lean: 0.04 },
  { h: 13, x: 3, z: -4, lean: -0.02 },
  { h: 9, x: -6, z: -3, lean: 0.03 },
];

bambooData.forEach(d => {
  const stalk = createBambooStalk(d.h, d.x, d.z, d.lean);
  scene.add(stalk);
  stalks.push(stalk);
});

// --- Small grass tufts ---
for (let i = 0; i < 200; i++) {
  const angle = Math.random() * Math.PI * 2;
  const dist = 2 + Math.random() * 20;
  const x = Math.cos(angle) * dist;
  const z = Math.sin(angle) * dist;

  const bladeGeo = new THREE.PlaneGeometry(0.06, 0.3 + Math.random() * 0.4);
  const bladeMat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.25 + Math.random() * 0.1, 0.5, 0.3 + Math.random() * 0.15),
    side: THREE.DoubleSide,
    roughness: 0.9,
  });
  const blade = new THREE.Mesh(bladeGeo, bladeMat);
  blade.position.set(x, 0.15, z);
  blade.rotation.y = Math.random() * Math.PI;
  blade.rotation.z = (Math.random() - 0.5) * 0.4;
  scene.add(blade);
}

// --- Falling leaves particles ---
const leafCount = 30;
const leafParticles = [];
for (let i = 0; i < leafCount; i++) {
  const geo = new THREE.PlaneGeometry(0.15, 0.06);
  const mat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.28, 0.5, 0.35),
    side: THREE.DoubleSide,
    transparent: true,
    opacity: 0.8,
  });
  const leaf = new THREE.Mesh(geo, mat);
  resetLeaf(leaf, true);
  scene.add(leaf);
  leafParticles.push(leaf);
}

function resetLeaf(leaf, init = false) {
  leaf.position.set(
    (Math.random() - 0.5) * 20,
    init ? Math.random() * 15 : 10 + Math.random() * 8,
    (Math.random() - 0.5) * 20
  );
  leaf.userData.speed = 0.3 + Math.random() * 0.5;
  leaf.userData.wobble = Math.random() * Math.PI * 2;
  leaf.userData.wobbleSpeed = 1 + Math.random() * 2;
  leaf.userData.rotSpeed = (Math.random() - 0.5) * 3;
}

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Sway bamboo
  stalks.forEach((stalk, i) => {
    const phase = i * 0.7;
    stalk.rotation.z = stalk.userData.lean + Math.sin(t * 0.8 + phase) * 0.015;
    stalk.rotation.x = Math.sin(t * 0.6 + phase + 1) * 0.01;
  });

  // Animate falling leaves
  leafParticles.forEach(leaf => {
    leaf.position.y -= leaf.userData.speed * 0.016;
    leaf.userData.wobble += leaf.userData.wobbleSpeed * 0.016;
    leaf.position.x += Math.sin(leaf.userData.wobble) * 0.005;
    leaf.rotation.z += leaf.userData.rotSpeed * 0.016;
    leaf.rotation.y += leaf.userData.rotSpeed * 0.5 * 0.016;

    if (leaf.position.y < 0) {
      resetLeaf(leaf);
    }
  });

  controls.update();
  renderer.render(scene, camera);
}

// Store lean for animation
stalks.forEach((s, i) => {
  s.userData.lean = bambooData[i].lean;
});

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
