This creates a **serene bamboo grove** scene with:

- **12 bamboo stalks** of varying heights, each built from green cylindrical segments with torus node rings
- **Dozens of curved leaves** sprouting from nodes and the top of each stalk
- **Gentle swaying animation** — each stalk sways with a slightly different phase
- **Falling leaf particles** that drift and wobble down through the air
- **A dirt path** through the grove and **200 grass tufts** scattered on the ground
- **Cinematic lighting** — warm sun with soft shadows, cool blue fill light, and ambient green
- **Fog** for atmospheric depth
- **OrbitControls** — drag to rotate, scroll to zoom
- **ACES filmic tone mapping** for a rich, natural look

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Bandage Demo</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
#info {
  position: absolute; top: 16px; left: 50%; transform: translateX(-50%);
  color: #ccc; font-family: system-ui, sans-serif; font-size: 14px;
  background: rgba(0,0,0,.45); padding: 8px 18px; border-radius: 20px;
  pointer-events: none;
}
</style>
</head>
<body>
<div id="info">🩹 Drag to orbit &nbsp;·&nbsp; Scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.163.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { RoundedBoxGeometry } from 'three/addons/geometries/RoundedBoxGeometry.js';

/* ── renderer ── */
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

/* ── scene & camera ── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.06);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 6);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;

/* ── lighting ── */
scene.add(new THREE.AmbientLight(0xffffff, 0.6));

const key = new THREE.DirectionalLight(0xfff4e6, 2.5);
key.position.set(4, 6, 4);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
key.shadow.camera.near = 1; key.shadow.camera.far = 20;
key.shadow.camera.left = -4; key.shadow.camera.right = 4;
key.shadow.camera.top = 4; key.shadow.camera.bottom = -4;
key.shadow.bias = -0.002;
scene.add(key);

const fill = new THREE.DirectionalLight(0xc8d8ff, 0.8);
fill.position.set(-3, 2, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xff9966, 1.2, 12);
rim.position.set(-2, 1, -3);
scene.add(rim);

/* ── helpers: canvas textures ── */
function makeFabricTexture() {
  const c = document.createElement('canvas');
  c.width = c.height = 256;
  const ctx = c.getContext('2d');
  ctx.fillStyle = '#e8c89e';
  ctx.fillRect(0, 0, 256, 256);
  // woven crosshatch
  ctx.strokeStyle = 'rgba(180,140,100,0.25)';
  ctx.lineWidth = 1;
  for (let i = 0; i < 256; i += 6) {
    ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, 256); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(256, i); ctx.stroke();
  }
  // subtle noise
  for (let n = 0; n < 6000; n++) {
    const x = Math.random() * 256, y = Math.random() * 256;
    const a = Math.random() * 0.06;
    ctx.fillStyle = `rgba(0,0,0,${a})`;
    ctx.fillRect(x, y, 1, 1);
  }
  const tex = new THREE.CanvasTexture(c);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  tex.repeat.set(3, 1);
  return tex;
}

function makePadTexture() {
  const c = document.createElement('canvas');
  c.width = c.height = 128;
  const ctx = c.getContext('2d');
  ctx.fillStyle = '#f5f0eb';
  ctx.fillRect(0, 0, 128, 128);
  // soft dot pattern
  for (let i = 0; i < 4000; i++) {
    const x = Math.random() * 128, y = Math.random() * 128;
    ctx.fillStyle = `rgba(200,190,180,${Math.random() * 0.12})`;
    ctx.fillRect(x, y, 1, 1);
  }
  const tex = new THREE.CanvasTexture(c);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  tex.repeat.set(2, 2);
  return tex;
}

const fabricTex = makeFabricTexture();
const padTex = makePadTexture();

/* ── bandage group ── */
const bandage = new THREE.Group();

// Wrapped fabric tube
const fabricGeo = new THREE.CylinderGeometry(0.55, 0.55, 3.6, 32, 1, true);
const fabricMat = new THREE.MeshStandardMaterial({
  map: fabricTex,
  color: 0xe0c4a0,
  roughness: 0.85,
  metalness: 0.0,
  side: THREE.DoubleSide,
});
const fabricMesh = new THREE.Mesh(fabricGeo, fabricMat);
fabricMesh.rotation.z = Math.PI / 2;
fabricMesh.castShadow = true;
fabricMesh.receiveShadow = true;
bandage.add(fabricMesh);

// End caps for fabric (closed circles)
const capGeo = new THREE.CircleGeometry(0.55, 32);
const capMat = fabricMat.clone();
capMat.side = THREE.FrontSide;

const capL = new THREE.Mesh(capGeo, capMat);
capL.rotation.y = -Math.PI / 2;
capL.position.x = -1.8;
bandage.add(capL);

const capR = new THREE.Mesh(capGeo, capMat);
capR.rotation.y = Math.PI / 2;
capR.position.x = 1.8;
bandage.add(capR);

// Central pad – raised rounded box
const padGeo = new RoundedBoxGeometry(1.5, 1.1, 0.22, 5, 0.06);
const padMat = new THREE.MeshStandardMaterial({
  map: padTex,
  color: 0xfaf6f2,
  roughness: 0.9,
  metalness: 0.0,
});
const padMesh = new THREE.Mesh(padGeo, padMat);
padMesh.position.set(0, 0.55, 0);
padMesh.castShadow = true;
padMesh.receiveShadow = true;
bandage.add(padMesh);

// Pad top – slightly domed hemisphere
const domeGeo = new THREE.SphereGeometry(0.58, 32, 16, 0, Math.PI * 2, 0, Math.PI * 0.35);
const domeMesh = new THREE.Mesh(domeGeo, padMat.clone());
domeMesh.position.set(0, 0.62, 0);
domeMesh.scale.set(1.3, 0.4, 1);
domeMesh.castShadow = true;
bandage.add(domeMesh);

// Small adhesive tabs (flaps) at each end
const tabShape = new THREE.Shape();
tabShape.moveTo(0, 0);
tabShape.lineTo(0.5, 0);
tabShape.quadraticCurveTo(0.55, 0, 0.55, 0.05);
tabShape.lineTo(0.55, 0.55);
tabShape.quadraticCurveTo(0.55, 0.6, 0.5, 0.6);
tabShape.lineTo(0, 0.6);
tabShape.closePath();

const tabGeo = new THREE.ExtrudeGeometry(tabShape, { depth: 0.02, bevelEnabled: true, bevelThickness: 0.01, bevelSize: 0.01, bevelSegments: 2 });
const tabMat = new THREE.MeshStandardMaterial({ color: 0xdab88a, roughness: 0.8 });

const tabL = new THREE.Mesh(tabGeo, tabMat);
tabL.position.set(-1.82, -0.3, -0.32);
tabL.rotation.y = Math.PI / 2;
bandage.add(tabL);

const tabR = new THREE.Mesh(tabGeo.clone(), tabMat.clone());
tabR.position.set(1.27, -0.3, -0.32);
tabR.rotation.y = -Math.PI / 2;
bandage.add(tabR);

// Slight curl on the ends for realism
bandage.rotation.x = 0.15;
scene.add(bandage);

/* ── ground plane ── */
const groundGeo = new THREE.PlaneGeometry(20, 20);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.2;
ground.receiveShadow = true;
scene.add(ground);

/* ── animation ── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float + rotate
  bandage.position.y = Math.sin(t * 0.8) * 0.15;
  bandage.rotation.y = t * 0.3;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── resize ── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
