);
moonGlow.position.copy(moon.position);
scene.add(moonGlow);

// ─── Stars ───
const starCount = 2000;
const starGeo = new THREE.BufferGeometry();
const starPos = new Float32Array(starCount * 3);
const starSizes = new Float32Array(starCount);
for (let i = 0; i < starCount; i++) {
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.acos(2 * Math.random() - 1);
  const r = 100 + Math.random() * 150;
  starPos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
  starPos[i * 3 + 1] = Math.abs(r * Math.sin(phi) * Math.sin(theta)) + 10;
  starPos[i * 3 + 2] = r * Math.cos(phi);
  starSizes[i] = 0.3 + Math.random() * 1.2;
}
starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
starGeo.setAttribute('size', new THREE.BufferAttribute(starSizes, 1));
const starMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.5, sizeAttenuation: true });
scene.add(new THREE.Points(starGeo, starMat));

// ─── Cave / Ground ───
const groundGeo = new THREE.PlaneGeometry(200, 200, 80, 80);
const posAttr = groundGeo.attributes.position;
for (let i = 0; i < posAttr.count; i++) {
  const x = posAttr.getX(i), y = posAttr.getY(i);
  posAttr.setZ(i, (Math.sin(x * 0.3) * Math.cos(y * 0.2) * 1.5 +
    Math.sin(x * 0.1 + y * 0.15) * 2 + Math.random() * 0.3));
}
groundGeo.computeVertexNormals();
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2a, roughness: 0.95, metalness: 0.05
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -4;
ground.receiveShadow = true;
scene.add(ground);

// Rock formations
function createRock(x, z, scale) {
  const geo = new THREE.DodecahedronGeometry(scale, 1);
  const a = geo.attributes.position;
  for (let i = 0; i < a.count; i++) {
    a.setX(i, a.getX(i) + (Math.random() - 0.5) * scale * 0.4);
    a.setY(i, a.getY(i) * (0.4 + Math.random() * 0.6) + (Math.random() - 0.5) * scale * 0.3);
    a.setZ(i, a.getZ(i) + (Math.random() - 0.5) * scale * 0.4);
  }
  geo.computeVertexNormals();
  const mat = new THREE.MeshStandardMaterial({
    color: new THREE.Color(0.08 + Math.random() * 0.06, 0.08 + Math.random() * 0.04, 0.12 + Math.random() * 0.06),
    roughness: 0.95, flatShading: true
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(x, scale * 0.3 - 4, z);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  scene.add(mesh);
}
for (let i = 0; i < 30; i++) {
  const angle = Math.random() * Math.PI * 2;
  const dist = 8 + Math.random() * 50;
  createRock(Math.cos(angle) * dist, Math.sin(angle) * dist, 1 + Math.random() * 3);
}

