// ─── Wing Geometry Builder ───
function createWingGeometry(side) {
  // Bat wing: membrane between body and elongated fingers
  const segments = 12; // span (body to tip)
  const ribs = 7;      // chord (fingers)

  const positions = [];
  const normals = [];
  const uvs = [];
  const indices = [];

  // Finger lengths (simulating the 5 elongated bat fingers)
  const fingerLengths = [0.0, 0.55, 0.75, 0.85, 0.82, 0.65, 0.35];

  for (let i = 0; i <= segments; i++) {
    const t = i / segments; // 0 at body, 1 at tip
    for (let j = 0; j <= ribs; j++) {
      const s = j / ribs; // 0 at body edge, 1 at finger edge

      const baseX = side * t * 3.5;
      const fingerLen = fingerLengths[j];
      const baseZ = s * fingerLen * 2.5;

      // Wing membrane curve
      const y = Math.sin(t * Math.PI) * 0.15 * (1 - s * 0.3);
      const z = baseZ - t * 0.3;

      positions.push(baseX, y, z);
      uvs.push(s, t);
    }
  }

  // Indices
  for (let i = 0; i < segments; i++) {
    for (let j = 0; j < ribs; j++) {
      const a = i * (ribs + 1) + j;
      const b = a + 1;
      const c = (i + 1) * (ribs + 1) + j;
      const d = c + 1;
      indices.push(a, b, c);
      indices.push(b, d, c);
    }
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geo.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
  geo.setIndex(indices);
  geo.computeVertexNormals();

