    const posTerminal = new THREE.Mesh(posTerminalGeo, terminalMaterial);
    posTerminal.position.y = 2.6;
    posTerminal.castShadow = true;
    battery.add(posTerminal);

    // Positive terminal top cap (flat disc)
    const posCapGeo = new THREE.CylinderGeometry(0.28, 0.28, 0.04, 32);
    const posCap = new THREE.Mesh(posCapGeo, terminalMaterial);
    posCap.position.y = 2.71;
    posCap.castShadow = true;
    battery.add(posCap);

    // Negative terminal (flat bottom with slight rim)
    const negRimGeo = new THREE.CylinderGeometry(0.62, 0.62, 0.04, 64);
    const negRim = new THREE.Mesh(negRimGeo, negativeTerminalMaterial);
    negRim.position.y = 0.02;
    negRim.castShadow = true;
    battery.add(negRim);

