    const negIndent = new THREE.Mesh(negIndentGeo, bodyMaterial);
    negIndent.position.y = 0.015;
    battery.add(negIndent);

    // Label band (mid-body)
    const labelGeo = new THREE.CylinderGeometry(0.605, 0.605, 0.9, 64, 1, true);
    const label = new THREE.Mesh(labelGeo, labelMaterial);
    label.position.y = 1.2;
    battery.add(label);

    // "+" symbol ring (small torus on the positive side)
    const plusRingGeo = new THREE.TorusGeometry(0.45, 0.02, 8, 32, Math.PI);
    const plusRingMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5, metalness: 0.3 });
    const plusRing = new THREE.Mesh(plusRingGeo, plusRingMat);
    plusRing.position.set(0, 2.15, 0.6);
    plusRing.rotation.y = Math.PI / 2;
    battery.add(plusRing);

    // Tilt battery slightly for a dynamic look
    battery.rotation.z = Math.PI / 2;
    battery.rotation.x = -Math.PI / 12;
    battery.position.y = 0.04;

    scene.add(battery);

    // ── Floating Particles ───────────────────────────────────
    const particleCount = 60;
    const particleGeo = new THREE.BufferGeometry();
    const positions = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 12;
      positions[i * 3 + 1] = Math.random() * 6;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 12;
    }
    particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    const particleMat = new THREE.PointsMaterial({
      color: 0x6688cc,
      size: 0.04,
      transparent: true,
      opacity: 0.6
    });
    const particles = new THREE.Points(particleGeo, particleMat);
    scene.add(particles);

    // ── Animation ────────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle battery hover
      battery.position.y = 0.04 + Math.sin(t * 0.8) * 0.08;

      // Particle drift
      const pos = particles.geometry.attributes.position.array;
      for (let i = 0; i < particleCount; i++) {
        pos[i * 3 + 1] += 0.003;
        if (pos[i * 3 + 1] > 6) pos[i * 3 + 1] = 0;
      }
      particles.geometry.attributes.position.needsUpdate = true;
      particles.rotation.y = t * 0.02;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ───────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
