</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x020208);
scene.fog = new THREE.FogExp2(0x020208, 0.012);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(8, 6, 12);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 4, 0);
controls.maxPolarAngle = Math.PI / 2 + 0.1;

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(80, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x111118, roughness: 0.9, metalness: 0.1
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Beacon Pole ──
const poleGroup = new THREE.Group();
scene.add(poleGroup);

// Main shaft
const shaftGeo = new THREE.CylinderGeometry(0.08, 0.12, 8, 8);
const shaftMat = new THREE.MeshStandardMaterial({
  color: 0x333340, roughness: 0.4, metalness: 0.8
});
const shaft = new THREE.Mesh(shaftGeo, shaftMat);
shaft.position.y = 4;
poleGroup.add(shaft);

// Base ring
const baseGeo = new THREE.TorusGeometry(0.5, 0.06, 8, 24);
const baseMat = new THREE.MeshStandardMaterial({
  color: 0x444455, roughness: 0.3, metalness: 0.9
});
const base = new THREE.Mesh(baseGeo, baseMat);
base.rotation.x = Math.PI / 2;
base.position.y = 0.06;
poleGroup.add(base);

// Mid ring
const midGeo = new THREE.TorusGeometry(0.25, 0.04, 8, 24);
const mid = new THREE.Mesh(midGeo, baseMat);
mid.rotation.x = Math.PI / 2;
mid.position.y = 3;
poleGroup.add(mid);

// Top housing
const housingGeo = new THREE.CylinderGeometry(0.15, 0.12, 0.4, 8);
const housing = new THREE.Mesh(housingGeo, baseMat);
housing.position.y = 8.1;
poleGroup.add(housing);

// Dome
const domeGeo = new THREE.SphereGeometry(0.18, 16, 8, 0, Math.PI * 2, 0, Math.PI / 2);
const dome = new THREE.Mesh(domeGeo, baseMat);
dome.position.y = 8.3;
poleGroup.add(dome);

// ── Glowing Core ──
const coreGeo = new THREE.SphereGeometry(0.12, 16, 16);
const coreMat = new THREE.MeshBasicMaterial({ color: 0xff8833 });
const core = new THREE.Mesh(coreGeo, coreMat);
core.position.y = 8.3;
poleGroup.add(core);

// Glow sprite
const canvas = document.createElement('canvas');
canvas.width = canvas.height = 128;
const ctx = canvas.getContext('2d');
const gradient = ctx.createRadialGradient(64, 64, 0, 64, 64, 64);
gradient.addColorStop(0, 'rgba(255, 170, 60, 1)');
gradient.addColorStop(0.2, 'rgba(255, 120, 30, 0.6)');
gradient.addColorStop(0.5, 'rgba(255, 80, 10, 0.15)');
gradient.addColorStop(1, 'rgba(255, 50, 0, 0)');
ctx.fillStyle = gradient;
ctx.fillRect(0, 0, 128, 128);

const glowTexture = new THREE.CanvasTexture(canvas);
const glowMat = new THREE.SpriteMaterial({
  map: glowTexture, transparent: true, blending: THREE.AdditiveBlending
});
const glowSprite = new THREE.Sprite(glowMat);
glowSprite.position.y = 8.3;
glowSprite.scale.set(2.5, 2.5, 1);
poleGroup.add(glowSprite);

// ── Light Beam (volumetric cone) ──
const beamGeo = new THREE.ConeGeometry(0.6, 6, 32, 1, true);
const beamMat = new THREE.MeshBasicMaterial({
  color: 0xff9944,
  transparent: true,
  opacity: 0.06,
  side: THREE.DoubleSide,
  blending: THREE.AdditiveBlending,
  depthWrite: false
});
const beam = new THREE.Mesh(beamGeo, beamMat);
beam.position.y = 11.3;
poleGroup.add(beam);

// Inner beam
const beamInnerGeo = new THREE.ConeGeometry(0.25, 6, 32, 1, true);
const beamInnerMat = new THREE.MeshBasicMaterial({
  color: 0xffcc77,
  transparent: true,
  opacity: 0.1,
  side: THREE.DoubleSide,
  blending: THREE.AdditiveBlending,
  depthWrite: false
});
const beamInner = new THREE.Mesh(beamInnerGeo, beamInnerMat);
beamInner.position.y = 11.3;
poleGroup.add(beamInner);

// ── Point Light ──
const beaconLight = new THREE.PointLight(0xff8833, 8, 30, 1.5);
beaconLight.position.y = 8.3;
beaconLight.castShadow = false;
poleGroup.add(beaconLight);

// Subtle hemisphere light for ambient
const hemiLight = new THREE.HemisphereLight(0x111133, 0x000000, 0.3);
scene.add(hemiLight);

// ── Particles ──
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const velocities = new Float32Array(particleCount * 3);
const lifetimes = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  resetParticle(i);
}

function resetParticle(i) {
  const angle = Math.random() * Math.PI * 2;
  const radius = Math.random() * 0.5;
  positions[i * 3]     = Math.cos(angle) * radius;
  positions[i * 3 + 1] = 8 + Math.random() * 4;
  positions[i * 3 + 2] = Math.sin(angle) * radius;
  velocities[i * 3]     = (Math.random() - 0.5) * 0.02;
  velocities[i * 3 + 1] = 0.01 + Math.random() * 0.03;
  velocities[i * 3 + 2] = (Math.random() - 0.5) * 0.02;
  lifetimes[i] = Math.random();
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));

const particleCanvas = document.createElement('canvas');
particleCanvas.width = particleCanvas.height = 32;
const pctx = particleCanvas.getContext('2d');
const pg = pctx.createRadialGradient(16, 16, 0, 16, 16, 16);
pg.addColorStop(0, 'rgba(255, 200, 100, 1)');
pg.addColorStop(0.4, 'rgba(255, 140, 40, 0.4)');
pg.addColorStop(1, 'rgba(255, 80, 0, 0)');
pctx.fillStyle = pg;
pctx.fillRect(0, 0, 32, 32);

const particleMat = new THREE.PointsMaterial({
  map: new THREE.CanvasTexture(particleCanvas),
  size: 0.3,
  transparent: true,
  blending: THREE.AdditiveBlending,
  depthWrite: false,
  sizeAttenuation: true
});

const particles = new THREE.Points(particleGeo, particleMat);
poleGroup.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  const pulse = 0.5 + 0.5 * Math.sin(t * 2.5);

  // Core glow
  const s = 1 + pulse * 0.4;
  core.scale.setScalar(s);
  glowSprite.scale.setScalar(2.5 + pulse * 0.8);

  // Light intensity
  beaconLight.intensity = 5 + pulse * 6;

  // Beam opacity
  beam.material.opacity = 0.04 + pulse * 0.04;
  beamInner.material.opacity = 0.06 + pulse * 0.08;

  // Particles
  const pos = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    pos[i * 3]     += velocities[i * 3];
    pos[i * 3 + 1] += velocities[i * 3 + 1];
    pos[i * 3 + 2] += velocities[i * 3 + 2];
    lifetimes[i] += 0.005;

    if (lifetimes[i] > 1 || pos[i * 3 + 1] > 14) {
      resetParticle(i);
    }
  }
  particles.geometry.attributes.position.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What this renders:**

- **Pole structure** — metallic shaft with decorative rings and a dome housing
- **Pulsing core** — an orange emissive sphere that breathes in intensity
- **Additive glow sprite** — soft radial gradient halo around the core
- **Volumetric light beam** — two layered transparent cones shooting upward with additive blending
- **Point light** — casts warm orange light that pulses across the ground
- **Rising particles** — 200 ember-like particles drift upward from the beacon
- **Fog + dark environment** — exponential fog fades distant geometry to black
- **Orbit controls** — drag to rotate, scroll to zoom, auto-damped

Just save it as `index.html` and open in any modern browser.

