controls.dampingFactor = 0.06;

// ── Sky Dome ──
const skyGeo = new THREE.SphereGeometry(200, 32, 32);
const skyMat = new THREE.ShaderMaterial({
  side: THREE.BackSide,
  uniforms: {
    topColor:    { value: new THREE.Color(0x1a6fc4) },
    midColor:    { value: new THREE.Color(0x87CEEB) },
    bottomColor: { value: new THREE.Color(0xffe4b5) },
    sunDir:      { value: new THREE.Vector3(0.4, 0.3, 0.5).normalize() },
    sunColor:    { value: new THREE.Color(0xffffee) }
  },
  vertexShader: `
    varying vec3 vWorldPos;
    void main(){
      vWorldPos = (modelMatrix * vec4(position,1.0)).xyz;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
    }
  `,
  fragmentShader: `
    uniform vec3 topColor, midColor, bottomColor, sunDir, sunColor;
    varying vec3 vWorldPos;
    void main(){
      vec3 dir = normalize(vWorldPos);
      float h = dir.y;
      vec3 sky;
      if(h > 0.0){
        sky = mix(midColor, topColor, pow(h, 0.5));
      } else {
        sky = mix(midColor, bottomColor, pow(-h, 0.6));
      }
      float sunDot = max(dot(dir, sunDir), 0.0);
      sky += sunColor * pow(sunDot, 256.0) * 2.0;
      sky += sunColor * pow(sunDot, 16.0) * 0.3;
      sky += vec3(1.0,0.9,0.7) * pow(sunDot, 4.0) * 0.15;
      gl_FragColor = vec4(sky, 1.0);
    }
  `
});
scene.add(new THREE.Mesh(skyGeo, skyMat));

// ── Lighting ──
const sunDir = new THREE.Vector3(0.4, 0.35, 0.5).normalize();
