// ── Wet Sand (shoreline) ──
const wetSandGeo = new THREE.PlaneGeometry(200, 12, 64, 8);
const wetSandMat = new THREE.MeshStandardMaterial({
  color: 0xb8956a,
  roughness: 0.3,
  metalness: 0.1,
});
