wetSand.rotation.x = -Math.PI / 2;
wetSand.position.set(0, -0.15, -6);
wetSand.receiveShadow = true;
scene.add(wetSand);

// ── Ocean ──
const oceanGeo = new THREE.PlaneGeometry(300, 200, 256, 192);
const oceanMat = new THREE.ShaderMaterial({
  uniforms: {
    uTime:       { value: 0 },
    uDeepColor:  { value: new THREE.Color(0x015c7a) },
    uShallowColor:{ value: new THREE.Color(0x3ab5d4) },
    uFoamColor:  { value: new THREE.Color(0xe8f8ff) },
    uSunDir:     { value: sunDir.clone() },
    uCamPos:     { value: camera.position }
  },
  vertexShader: `
    uniform float uTime;
    varying vec3 vWorldPos;
    varying vec3 vNormal;
    varying float vFoam;

    // Simplex-ish noise
    vec3 mod289(vec3 x){ return x - floor(x*(1.0/289.0))*289.0; }
    vec2 mod289(vec2 x){ return x - floor(x*(1.0/289.0))*289.0; }
    vec3 permute(vec3 x){ return mod289(((x*34.0)+1.0)*x); }
    float snoise(vec2 v){
      const vec4 C = vec4(0.211324865405187, 0.366025403784439,
                         -0.577350269189626, 0.024390243902439);
      vec2 i  = floor(v + dot(v, C.yy));
      vec2 x0 = v - i + dot(i, C.xx);
      vec2 i1 = (x0.x > x0.y) ? vec2(1.0,0.0) : vec2(0.0,1.0);
      vec4 x12 = x0.xyxy + C.xxzz;
      x12.xy -= i1;
      i = mod289(i);
      vec3 p = permute(permute(i.y + vec3(0.0, i1.y, 1.0)) + i.x + vec3(0.0, i1.x, 1.0));
      vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
      m = m*m; m = m*m;
      vec3 x = 2.0*fract(p*C.www) - 1.0;
      vec3 h = abs(x) - 0.5;
      vec3 ox = floor(x + 0.5);
      vec3 a0 = x - ox;
      m *= 1.79284291400159 - 0.85373472095314*(a0*a0 + h*h);
      vec3 g;
      g.x = a0.x*x0.x + h.x*x0.y;
      g.yz = a0.yz*x12.xz + h.yz*x12.yw;
      return 130.0*dot(m, g);
    }

    void main(){
      vec3 pos = position;
      float t = uTime;

      // Multiple wave layers
      float wave1 = snoise(vec2(pos.x*0.02 + t*0.3, pos.y*0.015)) * 1.2;
      float wave2 = snoise(vec2(pos.x*0.04 - t*0.2, pos.y*0.035 + t*0.1)) * 0.5;
      float wave3 = snoise(vec2(pos.x*0.08 + t*0.5, pos.y*0.06)) * 0.2;
      float wave4 = snoise(vec2(pos.x*0.15 - t*0.7, pos.y*0.12 + t*0.3)) * 0.08;

      pos.z = wave1 + wave2 + wave3 + wave4;

      // Foam near shore (pos.y ≈ -100 is far ocean, pos.y ≈ 0 is shore)
      float shoreFactor = smoothstep(-15.0, 5.0, pos.y);
      float waveHeight = abs(wave1 + wave2);
      vFoam = shoreFactor * smoothstep(0.8, 2.0, waveHeight) * 0.7;

      // Compute normal via neighbors
      float eps = 0.5;
      float dx = snoise(vec2((pos.x+eps)*0.02+t*0.3, pos.y*0.015))*1.2
               + snoise(vec2((pos.x+eps)*0.04-t*0.2, pos.y*0.035+t*0.1))*0.5
               + snoise(vec2((pos.x+eps)*0.08+t*0.5, pos.y*0.06))*0.2;
      float dy = snoise(vec2(pos.x*0.02+t*0.3, (pos.y+eps)*0.015))*1.2
               + snoise(vec2(pos.x*0.04-t*0.2, (pos.y+eps)*0.035+t*0.1))*0.5
               + snoise(vec2(pos.x*0.08+t*0.5, (pos.y+eps)*0.06))*0.2;
      vNormal = normalize(vec3(-(dx-pos.z)/eps, -(dy-pos.z)/eps, 1.0));

      vWorldPos = (modelMatrix * vec4(pos, 1.0)).xyz;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
    }
  `,
  fragmentShader: `
    uniform vec3 uDeepColor, uShallowColor, uFoamColor, uSunDir, uCamPos;
    uniform float uTime;
    varying vec3 vWorldPos, vNormal;
    varying float vFoam;

    void main(){
      vec3 N = normalize(vNormal);
      vec3 V = normalize(uCamPos - vWorldPos);
      vec3 L = normalize(uSunDir);

      // Depth-based color
      float depth = smoothstep(-60.0, 5.0, vWorldPos.y);
      vec3 waterColor = mix(uDeepColor, uShallowColor, depth * 0.6);

      // Fresnel
      float fresnel = pow(1.0 - max(dot(N, V), 0.0), 3.0);
      vec3 skyReflect = mix(vec3(0.5, 0.7, 0.9), vec3(1.0, 0.95, 0.8), pow(max(dot(V, L), 0.0), 4.0));
      waterColor = mix(waterColor, skyReflect, fresnel * 0.6);

      // Diffuse
      float diff = max(dot(N, L), 0.0) * 0.3;
      waterColor += diff * vec3(0.2, 0.4, 0.4);

      // Specular
      vec3 H = normalize(L + V);
      float spec = pow(max(dot(N, H), 0.0), 128.0);
      waterColor += vec3(1.0, 0.95, 0.8) * spec * 1.5;

      // Foam
      waterColor = mix(waterColor, uFoamColor, vFoam * 0.6);

      // Subsurface-ish glow
      float sss = pow(max(dot(V, -L + N * 0.6), 0.0), 4.0) * 0.15;
      waterColor += vec3(0.1, 0.5, 0.4) * sss;

      gl_FragColor = vec4(waterColor, 0.92);
    }
  `,
  transparent: true,

