<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>A Bean</title>
  <style>
    * { margin: 0; padding: 0; }
    body { overflow: hidden; background: #1a1a2e; }
    canvas { display: block; }
  </style>
</head>
<body>
  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>
  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x1a1a2e);
    scene.fog = new THREE.FogExp2(0x1a1a2e, 0.08);

    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(0, 1, 5);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(devicePixelRatio);
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    // --- Build the bean geometry ---
    const geo = new THREE.SphereGeometry(1, 128, 128);
    const pos = geo.attributes.position;

    for (let i = 0; i < pos.count; i++) {
      let x = pos.getX(i);
      let y = pos.getY(i);
      let z = pos.getZ(i);

      // Elongate along X
      x *= 1.8;

      // Flatten slightly
      z *= 0.65;

      // Create the bean indentation on the "inner" side (positive X, near Z=0)
      const innerFactor = Math.exp(-((x - 0.3) ** 2 + z ** 2) / 0.6);
      z -= innerFactor * 0.55 * Math.max(0, z > 0 ? 1 : 0.3);

      // Taper the ends
      const taper = Math.exp(-(x * 0.5) ** 2);
      y *= taper;
      z *= taper;

      // Gentle curve along the length
      y += Math.sin(x * 1.2) * 0.08;

      // Small bumps for organic feel
      const bump = Math.sin(x * 12 + y * 8) * 0.015 + Math.cos(z * 10 + y * 6) * 0.01;
      x += bump;
      y += bump * 0.5;
      z += bump;

      pos.setXYZ(i, x, y, z);
    }

    geo.computeVertexNormals();

    const mat = new THREE.MeshStandardMaterial({
      color: 0x4a7c3f,
      roughness: 0.55,
      metalness: 0.05,
    });

    const bean = new THREE.Mesh(geo, mat);
    bean.rotation.z = Math.PI * 0.15;
    scene.add(bean);

    // --- Lighting ---
    const ambient = new THREE.AmbientLight(0x8899aa, 0.6);
    scene.add(ambient);

    const key = new THREE.DirectionalLight(0xffeedd, 2.5);
    key.position.set(4, 6, 4);
    scene.add(key);

    const fill = new THREE.DirectionalLight(0x8899cc, 0.8);
    fill.position.set(-4, 2, -2);
    scene.add(fill);

    const rim = new THREE.DirectionalLight(0xffccaa, 1.0);
    rim.position.set(0, -3, -5);
    scene.add(rim);

    // --- Subtle ground reflection ---
    const groundGeo = new THREE.CircleGeometry(4, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x1a1a2e,
      roughness: 0.9,
      metalness: 0.1,
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -2;
    scene.add(ground);

    // --- Animate ---
    function animate(t) {
      requestAnimationFrame(animate);
      bean.rotation.y = Math.sin(t * 0.0005) * 0.3;
      bean.position.y = Math.sin(t * 0.001) * 0.15;
      controls.update();
      renderer.render(scene, camera);
    }
    animate(0);

    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

**What's happening:**

- **Bean shape** — A high-resolution sphere is sculpted via vertex displacement: elongated along one axis, flattened, given a characteristic kidney-bean indentation on one side, tapered at both ends, and sprinkled with tiny organic bumps.
- **Material** — A green `MeshStandardMaterial` with moderate roughness for a matte, natural look.
- **Lighting** — Three-point setup (key, fill, rim) plus ambient for soft, cinematic shading.
- **Animation** — The bean gently bobs up/down and sways side-to-side.
- **OrbitControls** — Click and drag to rotate around, scroll to zoom.

