<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.018);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(6, 5, 8);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.2, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 3;
controls.maxDistance = 20;
controls.update();

// ── Lighting ──
const ambient = new THREE.AmbientLight(0x404060, 0.6);
scene.add(ambient);

const keyLight = new THREE.DirectionalLight(0xffeedd, 2.5);
keyLight.position.set(5, 8, 4);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(2048, 2048);
keyLight.shadow.camera.near = 0.5;
keyLight.shadow.camera.far = 25;
keyLight.shadow.camera.left = -8;
keyLight.shadow.camera.right = 8;
keyLight.shadow.camera.top = 8;
keyLight.shadow.camera.bottom = -8;
keyLight.shadow.bias = -0.0005;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.4);
fillLight.position.set(-4, 4, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff9966, 1.5, 15);
rimLight.position.set(-3, 3, -4);
scene.add(rimLight);

// ── Materials ──
const mat = {
  wood:      new THREE.MeshStandardMaterial({ color: 0x5c3a1e, roughness: 0.7, metalness: 0.05 }),
  woodLight: new THREE.MeshStandardMaterial({ color: 0x8b6914, roughness: 0.6, metalness: 0.05 }),
  mattress:  new THREE.MeshStandardMaterial({ color: 0xf5f0e8, roughness: 0.9, metalness: 0 }),
  pillow:    new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.95, metalness: 0 }),
  blanket:   new THREE.MeshStandardMaterial({ color: 0x3b5998, roughness: 0.85, metalness: 0 }),
  sheet:     new THREE.MeshStandardMaterial({ color: 0xe8e0d4, roughness: 0.9, metalness: 0 }),
  floor:     new THREE.MeshStandardMaterial({ color: 0x2a2a3e, roughness: 0.85, metalness: 0.1 }),
};

// ── Helpers ──
function box(w, h, d, material, x, y, z, ry = 0) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), material);
  m.position.set(x, y, z);
  m.rotation.y = ry;
  m.castShadow = true;
  m.receiveShadow = true;
  return m;
}

const bed = new THREE.Group();

// ── Floor / Rug ──
scene.add(box(20, 0.05, 20, mat.floor, 0, -0.025, 0));
scene.add(box(5, 0.01, 4, new THREE.MeshStandardMaterial({ color: 0x3a2a1a, roughness: 0.95 }), 0, 0.005, 0));

// ── Bed Frame Base ──
const frameW = 2.2, frameD = 3.6, frameH = 0.15;
bed.add(box(frameW, frameH, frameD, mat.wood, 0, 0.45, 0));

// ── Side Rails ──
const railH = 0.25, railT = 0.08;
bed.add(box(railT, railH, frameD - 0.1, mat.wood, -frameW / 2 + railT / 2, 0.55, 0));
bed.add(box(railT, railH, frameD - 0.1, mat.wood,  frameW / 2 - railT / 2, 0.55, 0));

// ── Headboard ──
const hbW = frameW + 0.1, hbH = 1.4, hbD = 0.1;
bed.add(box(hbW, hbH, hbD, mat.woodLight, 0, 0.45 + hbH / 2, -frameD / 2 + hbD / 2));
// Headboard panels
bed.add(box(hbW - 0.2, hbH - 0.3, 0.02, mat.wood, 0, 0.45 + hbH / 2, -frameD / 2 + hbD / 2 + 0.04));

// ── Footboard ──
const fbH = 0.6;
bed.add(box(frameW, fbH, 0.08, mat.woodLight, 0, 0.45 + fbH / 2, frameD / 2 - 0.04));

// ── Legs ──
const legR = 0.06, legH = 0.4;
const legPositions = [
  [-frameW / 2 + 0.15, legH / 2, -frameD / 2 + 0.15],
  [ frameW / 2 - 0.15, legH / 2, -frameD / 2 + 0.15],
  [-frameW / 2 + 0.15, legH / 2,  frameD / 2 - 0.15],
  [ frameW / 2 - 0.15, legH / 2,  frameD / 2 - 0.15],
];
legPositions.forEach(([x, y, z]) => {
  const leg = new THREE.Mesh(new THREE.CylinderGeometry(legR, legR * 1.1, legH, 12), mat.wood);
  leg.position.set(x, y, z);
  leg.castShadow = true;
  bed.add(leg);
});

// ── Mattress ──
const mattW = frameW - 0.2, mattD = frameD - 0.3, mattH = 0.25;
bed.add(box(mattW, mattH, mattD, mat.mattress, 0, 0.45 + frameH + mattH / 2, 0));

// ── Sheet (thin layer on mattress) ──
bed.add(box(mattW - 0.05, 0.02, mattD - 0.05, mat.sheet, 0, 0.45 + frameH + mattH + 0.01, 0));

// ── Blanket / Comforter ──
const blW = mattW - 0.1, blD = mattD * 0.55, blH = 0.08;
bed.add(box(blW, blH, blD, mat.blanket, 0, 0.45 + frameH + mattH + 0.04, mattD / 2 - blD / 2 + 0.3));

// Blanket fold at foot
bed.add(box(blW - 0.05, 0.04, 0.15, mat.blanket, 0, 0.45 + frameH + mattH + 0.03, mattD / 2 - 0.1));

// ── Pillows ──
const pW = 0.65, pH = 0.12, pD = 0.4;
const pillowGeo = new THREE.BoxGeometry(pW, pH, pD, 4, 2, 4);
// Round pillow edges slightly
const pos = pillowGeo.attributes.position;
for (let i = 0; i < pos.count; i++) {
  let x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);
  const r = 0.08;
  x = Math.sign(x) * Math.max(Math.abs(x) - r * 0.3, 0) + Math.sign(x) * r * 0.3 * Math.min(Math.abs(x) / (pW / 2), 1);
  y = Math.sign(y) * Math.max(Math.abs(y) - r * 0.5, 0) + Math.sign(y) * r * 0.5 * Math.min(Math.abs(y) / (pH / 2), 1);
  pos.setXYZ(i, x, y, z);
}
pillowGeo.computeVertexNormals();

const p1 = new THREE.Mesh(pillowGeo, mat.pillow);
p1.position.set(-0.45, 0.45 + frameH + mattH + 0.07, -mattD / 2 + pD / 2 + 0.15);
p1.castShadow = true;
bed.add(p1);

const p2 = new THREE.Mesh(pillowGeo, mat.pillow);
p2.position.set(0.45, 0.45 + frameH + mattH + 0.07, -mattD / 2 + pD / 2 + 0.15);
p2.castShadow = true;
bed.add(p2);

// ── Small side table ──
const table = new THREE.Group();
table.add(box(0.5, 0.04, 0.5, mat.woodLight, 0, 0.5, 0));
table.add(box(0.04, 0.5, 0.04, mat.woodLight, -0.2, 0.25, -0.2));
table.add(box(0.04, 0.5, 0.04, mat.woodLight,  0.2, 0.25, -0.2));
table.add(box(0.04, 0.5, 0.04, mat.woodLight, -0.2, 0.25,  0.2));
table.add(box(0.04, 0.5, 0.04, mat.woodLight,  0.2, 0.25,  0.2));
table.position.set(frameW / 2 + 0.6, 0, -frameD / 2 + 0.5);
table.children.forEach(c => { c.castShadow = true; c.receiveShadow = true; });
scene.add(table);

// ── Lamp on table ──
const lamp = new THREE.Group();
lamp.add(new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.15, 0.04, 16), mat.wood));
lamp.add(new THREE.Mesh(new THREE.CylinderGeometry(0.015, 0.015, 0.4, 8), mat.woodLight));
const shade = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.18, 0.2, 16, 1, true),
  new THREE.MeshStandardMaterial({ color: 0xfff5e0, roughness: 0.9, side: THREE.DoubleSide }));
shade.position.y = 0.3;
lamp.add(shade);
lamp.position.set(frameW / 2 + 0.6, 0.52, -frameD / 2 + 0.5);
lamp.children.forEach(c => c.castShadow = true);
scene.add(lamp);

const lampLight = new THREE.PointLight(0xffddaa, 1.2, 6);
lampLight.position.set(frameW / 2 + 0.6, 0.9, -frameD / 2 + 0.5);
lampLight.castShadow = true;
scene.add(lampLight);

// ── Assemble ──
scene.add(bed);

// ── Animate ──
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  // Subtle lamp flicker
  lampLight.intensity = 1.2 + Math.sin(t * 2) * 0.05 + Math.sin(t * 3.7) * 0.03;
  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
