</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87ceeb);
scene.fog = new THREE.FogExp2(0x87ceeb, 0.012);

// ── Camera ──
const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(5, 3, 8);

// ── Renderer ──
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0, 0);

// ── Lights ──
const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambientLight);

const sunLight = new THREE.DirectionalLight(0xfff4e0, 2.5);
sunLight.position.set(10, 15, 10);
sunLight.castShadow = true;
sunLight.shadow.mapSize.set(2048, 2048);
sunLight.shadow.camera.near = 0.5;
sunLight.shadow.camera.far = 50;
sunLight.shadow.camera.left = -10;
sunLight.shadow.camera.right = 10;
sunLight.shadow.camera.top = 10;
sunLight.shadow.camera.bottom = -10;
scene.add(sunLight);

const fillLight = new THREE.DirectionalLight(0xc0d8ff, 0.8);
fillLight.position.set(-8, 5, -5);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffe0a0, 1.5, 30);
rimLight.position.set(-3, 4, -6);
scene.add(rimLight);

// ── Materials ──
const yellowMat = new THREE.MeshStandardMaterial({
  color: 0xffd700, roughness: 0.45, metalness: 0.05
});
const blackMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1a, roughness: 0.5, metalness: 0.1
});
const wingMat = new THREE.MeshPhysicalMaterial({
  color: 0xffffff, transparent: true, opacity: 0.25,
  roughness: 0.05, metalness: 0.0, transmission: 0.8,
  thickness: 0.1, ior: 1.3, side: THREE.DoubleSide
});
const wingVeinMat = new THREE.MeshStandardMaterial({
  color: 0xcccccc, transparent: true, opacity: 0.3,
  roughness: 0.3, side: THREE.DoubleSide
});
const eyeMat = new THREE.MeshStandardMaterial({
  color: 0x111111, roughness: 0.2, metalness: 0.3
});
const eyeShineMat = new THREE.MeshStandardMaterial({
  color: 0xffffff, roughness: 0.1, emissive: 0xffffff, emissiveIntensity: 0.3
});
const stingerMat = new THREE.MeshStandardMaterial({
  color: 0x222222, roughness: 0.3, metalness: 0.4
});
const legMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1a, roughness: 0.6
});

// ── Bee Group ──
const bee = new THREE.Group();
scene.add(bee);

// ── Abdomen (main striped body) ──
const abdomenGroup = new THREE.Group();
bee.add(abdomenGroup);

// Create abdomen with stripes using a scaled sphere + torus rings
const abdomenGeo = new THREE.SphereGeometry(1, 32, 32);
const abdomen = new THREE.Mesh(abdomenGeo, yellowMat);
abdomen.scale.set(0.85, 0.85, 1.6);
abdomen.position.set(0, 0, -1.2);
abdomen.castShadow = true;
abdomenGroup.add(abdomen);

// Black stripes on abdomen
const stripePositions = [-0.5, 0.0, 0.5, 1.0];
const stripeWidths = [0.12, 0.12, 0.12, 0.12];
stripePositions.forEach((zOff, i) => {
  const stripeGeo = new THREE.TorusGeometry(0.74, stripeWidths[i], 16, 48);
  const stripe = new THREE.Mesh(stripeGeo, blackMat);
  stripe.position.set(0, 0, -1.2 + zOff * 0.9);
  stripe.rotation.x = Math.PI / 2;
  stripe.castShadow = true;
  abdomenGroup.add(stripe);
});

// ── Thorax ──
const thoraxGeo = new THREE.SphereGeometry(1, 32, 32);
const thorax = new THREE.Mesh(thoraxGeo, blackMat);
thorax.scale.set(0.9, 0.85, 0.65);
thorax.position.set(0, 0, 0.6);
thorax.castShadow = true;
bee.add(thorax);

// Fuzzy texture on thorax - small bumps
for (let i = 0; i < 60; i++) {
  const bumpGeo = new THREE.SphereGeometry(0.04, 6, 6);
  const bump = new THREE.Mesh(bumpGeo, yellowMat);
  const theta = Math.random() * Math.PI * 2;
  const phi = Math.random() * Math.PI;
  const r = 0.78;
  bump.position.set(
    r * Math.sin(phi) * Math.cos(theta) * 0.9,
    r * Math.sin(phi) * Math.sin(theta) * 0.85,
    0.6 + r * Math.cos(phi) * 0.65
  );
  bee.add(bump);
}

// ── Head ──
const headGroup = new THREE.Group();
bee.add(headGroup);

const headGeo = new THREE.SphereGeometry(0.65, 32, 32);
const head = new THREE.Mesh(headGeo, blackMat);
head.position.set(0, 0, 1.5);
head.castShadow = true;
headGroup.add(head);

// Eyes (large compound eyes on sides)
const eyeGeo = new THREE.SphereGeometry(0.3, 24, 24);
const leftEye = new THREE.Mesh(eyeGeo, eyeMat);
leftEye.position.set(-0.55, 0.2, 1.7);
leftEye.scale.set(1, 1.1, 0.8);
headGroup.add(leftEye);

const rightEye = new THREE.Mesh(eyeGeo, eyeMat);
rightEye.position.set(0.55, 0.2, 1.7);
rightEye.scale.set(1, 1.1, 0.8);
headGroup.add(rightEye);

// Eye shine
const eyeShineGeo = new THREE.SphereGeometry(0.08, 8, 8);
const leftShine = new THREE.Mesh(eyeShineGeo, eyeShineMat);
leftShine.position.set(-0.65, 0.3, 1.9);
headGroup.add(leftShine);

const rightShine = new THREE.Mesh(eyeShineGeo, eyeShineMat);
rightShine.position.set(0.65, 0.3, 1.9);
headGroup.add(rightShine);

// ── Antennae ──
function createAntenna(side) {
  const antennaGroup = new THREE.Group();
  const segments = 6;
  const start = new THREE.Vector3(side * 0.2, 0.4, 1.85);

  let prevPoint = start.clone();
  for (let i = 0; i < segments; i++) {
    const t = i / segments;
    const end = new THREE.Vector3(
      side * (0.6 + t * 1.2),
      0.8 + t * 1.0,
      1.6 - t * 0.3
    );
    const dir = end.clone().sub(prevPoint);
    const len = dir.length();

    const segGeo = new THREE.CylinderGeometry(0.018 - t * 0.008, 0.022 - t * 0.008, len, 6);
    const seg = new THREE.Mesh(segGeo, blackMat);
    seg.position.copy(prevPoint.clone().add(end).multiplyScalar(0.5));
    seg.lookAt(end);
    seg.rotateX(Math.PI / 2);
    antennaGroup.add(seg);

    prevPoint = end.clone();
  }

  // Antenna tip
  const tipGeo = new THREE.SphereGeometry(0.035, 8, 8);
  const tip = new THREE.Mesh(tipGeo, blackMat);
  tip.position.copy(prevPoint);
  antennaGroup.add(tip);

  return antennaGroup;
}

bee.add(createAntenna(-1));
bee.add(createAntenna(1));

// ── Legs ──
function createLeg(side, zPos, bendAmount) {
  const legGroup = new THREE.Group();
  const startX = side * 0.75;
  const startY = -0.3;

  // Upper leg
  const upperGeo = new THREE.CylinderGeometry(0.035, 0.03, 0.6, 8);
  const upper = new THREE.Mesh(upperGeo, legMat);
  upper.position.set(startX, startY - 0.3, zPos);
  upper.rotation.z = side * 0.5;
  upper.castShadow = true;
  legGroup.add(upper);

  // Lower leg
  const lowerGeo = new THREE.CylinderGeometry(0.03, 0.025, 0.5, 8);
  const lower = new THREE.Mesh(lowerGeo, legMat);
  lower.position.set(startX + side * 0.25, startY - 0.7, zPos);
  lower.rotation.z = side * 0.3;
  lower.castShadow = true;
  legGroup.add(lower);

  // Foot
  const footGeo = new THREE.SphereGeometry(0.04, 8, 8);
  const foot = new THREE.Mesh(footGeo, legMat);
  foot.position.set(startX + side * 0.4, startY - 0.95, zPos);
  legGroup.add(foot);

  // Yellow stripe on leg
  const stripeGeo = new THREE.TorusGeometry(0.036, 0.01, 8, 12);
  const legStripe = new THREE.Mesh(stripeGeo, yellowMat);
  legStripe.position.set(startX, startY - 0.5, zPos);
  legStripe.rotation.x = Math.PI / 2;
  legStripe.rotation.y = side * 0.5;
  legGroup.add(legStripe);

  return legGroup;
}

// Three pairs of legs
const legZPositions = [0.2, 0.5, 0.8];
legZPositions.forEach(z => {
  bee.add(createLeg(-1, z, 0));
  bee.add(createLeg(1, z, 0));
});

// ── Wings ──
function createWing(side, yOffset, scale) {
  const wingGroup = new THREE.Group();

  // Main wing membrane
  const wingShape = new THREE.Shape();
  wingShape.moveTo(0, 0);
  wingShape.bezierCurveTo(0.3, 0.8, 1.5, 1.2, 2.2, 0.5);
  wingShape.bezierCurveTo(2.5, 0.1, 2.0, -0.3, 1.2, -0.2);
  wingShape.bezierCurveTo(0.5, -0.1, 0.2, 0, 0, 0);

  const wingGeo = new THREE.ShapeGeometry(wingShape, 24);
  const wing = new THREE.Mesh(wingGeo, wingMat);
  wing.scale.setScalar(scale);
  wingGroup.add(wing);

  // Wing veins
  const veinPaths = [
    [[0, 0], [0.5, 0.5], [1.2, 0.7], [1.8, 0.4]],
    [[0.3, 0.2], [0.8, 0.6], [1.5, 0.6]],
    [[0.2, -0.05], [0.7, 0.1], [1.3, 0.1]],
    [[0.6, 0.4], [1.0, 0.7], [1.6, 0.5]],
  ];

  veinPaths.forEach(path => {
    const points = path.map(p => new THREE.Vector3(p[0] * scale, p[1] * scale, 0.005));
    const curve = new THREE.CatmullRomCurve3(points);
    const tubeGeo = new THREE.TubeGeometry(curve, 12, 0.008 * scale, 4, false);
    const tube = new THREE.Mesh(tubeGeo, wingVeinMat);
    wingGroup.add(tube);
  });

  wingGroup.position.set(side * 0.5, yOffset, 0.3);
  wingGroup.rotation.z = side * 0.15;
  wingGroup.rotation.x = -0.1;

  return wingGroup;
}

const upperLeftWing = createWing(-1, 0.5, 1.0);
const upperRightWing = createWing(1, 0.5, 1.0);
const lowerLeftWing = createWing(-1, 0.15, 0.75);
const lowerRightWing = createWing(1, 0.15, 0.75);

bee.add(upperLeftWing, upperRightWing, lowerLeftWing, lowerRightWing);

// ── Stinger ──
const stingerGeo = new THREE.ConeGeometry(0.06, 0.3, 8);
const stinger = new THREE.Mesh(stingerGeo, stingerMat);
stinger.position.set(0, 0, -2.6);
stinger.rotation.x = Math.PI / 2;
bee.add(stinger);

