    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 1.2, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.update();

    // ── Lighting ───────────────────────────────────────────
    const ambient = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambient);

    const dir = new THREE.DirectionalLight(0xffeedd, 2.5);
    dir.position.set(5, 8, 4);
    dir.castShadow = true;
    dir.shadow.mapSize.set(1024, 1024);
    dir.shadow.camera.near = 1;
    dir.shadow.camera.far = 20;
    dir.shadow.camera.left = -5;
    dir.shadow.camera.right = 5;
    dir.shadow.camera.top = 5;
    dir.shadow.camera.bottom = -5;
    scene.add(dir);

    const rim = new THREE.PointLight(0x4488ff, 1.5, 12);
    rim.position.set(-3, 2, -2);
    scene.add(rim);

    const warm = new THREE.PointLight(0xffaa44, 1.0, 10);
    warm.position.set(3, 0.5, 2);
    scene.add(warm);

    // ── Bell Profile (for LatheGeometry) ───────────────────
    // Each point is [radius, height]. We trace the right-half cross-section.
    const points = [
      // Bottom rim — outer edge
      new THREE.Vector2(0.02, 0.00),
      new THREE.Vector2(0.12, 0.00),
      new THREE.Vector2(0.28, 0.01),
      new THREE.Vector2(0.42, 0.03),
      // Flared rim — outer curve
      new THREE.Vector2(0.52, 0.06),
      new THREE.Vector2(0.58, 0.10),
      new THREE.Vector2(0.60, 0.14),
      // Rim thickness — step inward
      new THREE.Vector2(0.56, 0.18),
      new THREE.Vector2(0.52, 0.20),
      // Lower body — sweeping inward
      new THREE.Vector2(0.48, 0.28),
      new THREE.Vector2(0.44, 0.38),
      new THREE.Vector2(0.40, 0.50),
      new THREE.Vector2(0.37, 0.62),
      new THREE.Vector2(0.35, 0.74),
      // Waist — narrowest point
      new THREE.Vector2(0.34, 0.82),
      new THREE.Vector2(0.35, 0.90),
      // Upper body — slight flare
      new THREE.Vector2(0.37, 0.98),
      new THREE.Vector2(0.40, 1.05),
      new THREE.Vector2(0.42, 1.10),
      // Shoulders — curve to dome
      new THREE.Vector2(0.43, 1.14),
      new THREE.Vector2(0.41, 1.18),
      new THREE.Vector2(0.37, 1.22),
      new THREE.Vector2(0.31, 1.26),
      new THREE.Vector2(0.24, 1.29),
      new THREE.Vector2(0.16, 1.31),
      // Dome top
      new THREE.Vector2(0.08, 1.32),
      new THREE.Vector2(0.02, 1.31),
      new THREE.Vector2(0.00, 1.30),
    ];

    const bellGeo = new THREE.LatheGeometry(points, 64);
    bellGeo.computeVertexNormals();

    const bellMat = new THREE.MeshStandardMaterial({
      color: 0xd4a843,
      metalness: 0.85,
      roughness: 0.22,
    });

    const bell = new THREE.Mesh(bellGeo, bellMat);
    bell.castShadow = true;
    bell.receiveShadow = true;
    scene.add(bell);

    // ── Handle / Loop on top ───────────────────────────────
    const handleCurve = new THREE.CatmullRomCurve3([
      new THREE.Vector3(0, 1.30, 0),
      new THREE.Vector3(0, 1.45, 0),
      new THREE.Vector3(0.10, 1.55, 0),
      new THREE.Vector3(0.12, 1.65, 0),
      new THREE.Vector3(0.00, 1.70, 0),
      new THREE.Vector3(-0.12, 1.65, 0),
      new THREE.Vector3(-0.10, 1.55, 0),
      new THREE.Vector3(0, 1.45, 0),
      new THREE.Vector3(0, 1.30, 0),
    ]);

    const handleGeo = new THREE.TubeGeometry(handleCurve, 48, 0.025, 12, false);
    const handle = new THREE.Mesh(handleGeo, bellMat);
    handle.castShadow = true;
    scene.add(handle);

    // ── Clapper (internal rod + ball) ──────────────────────
    const clapperRodGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.5, 12);
    const clapperMat = new THREE.MeshStandardMaterial({
      color: 0xb8862d, metalness: 0.8, roughness: 0.3
    });
    const clapperRod = new THREE.Mesh(clapperRodGeo, clapperMat);
    clapperRod.position.set(0, 0.45, 0);
    scene.add(clapperRod);

    const clapperBallGeo = new THREE.SphereGeometry(0.07, 24, 24);
    const clapperBall = new THREE.Mesh(clapperBallGeo, clapperMat);
    clapperBall.position.set(0, 0.18, 0);
    clapperBall.castShadow = true;
    scene.add(clapperBall);

    // ── Ground Plane ───────────────────────────────────────
    const groundGeo = new THREE.CircleGeometry(6, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x2a2a3e, metalness: 0.1, roughness: 0.8
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Subtle pedestal ring ───────────────────────────────
    const ringGeo = new THREE.TorusGeometry(0.65, 0.03, 16, 64);
    const ringMat = new THREE.MeshStandardMaterial({
      color: 0x888899, metalness: 0.6, roughness: 0.3
    });
    const ring = new THREE.Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = 0.005;
    ring.receiveShadow = true;
    scene.add(ring);

    // ── Animation ──────────────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle sway
      bell.rotation.z = Math.sin(t * 0.8) * 0.04;
      handle.rotation.z = Math.sin(t * 0.8) * 0.04;
      clapperRod.rotation.z = Math.sin(t * 0.8) * 0.04;

      // Clapper swings opposite
      clapperBall.rotation.x = Math.sin(t * 1.2) * 0.3;
      clapperBall.position.z = Math.sin(t * 1.2) * 0.06;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ─────────────────────────────────────────────
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
</html>
```

