// --- Leather Texture (Procedural) ---
function createLeatherTexture() {
    const canvas = document.createElement('canvas');
    canvas.width = 512;
    canvas.height = 512;
    const ctx = canvas.getContext('2d');

    // Base color
    ctx.fillStyle = '#3d2b1f';
    ctx.fillRect(0, 0, 512, 512);

    // Grain noise
    for (let i = 0; i < 15000; i++) {
        const x = Math.random() * 512;
        const y = Math.random() * 512;
        const size = Math.random() * 3 + 0.5;
        const brightness = Math.random() * 30 - 15;
        const r = 61 + brightness;
        const g = 43 + brightness;
        const b = 31 + brightness;
        ctx.fillStyle = `rgb(${r},${g},${b})`;
        ctx.beginPath();
        ctx.ellipse(x, y, size, size * 0.6, Math.random() * Math.PI, 0, Math.PI * 2);
        ctx.fill();
    }

    // Wrinkles
    for (let i = 0; i < 60; i++) {
        ctx.strokeStyle = `rgba(20,12,6,${Math.random() * 0.3 + 0.1})`;
        ctx.lineWidth = Math.random() * 2 + 0.5;
        ctx.beginPath();
        const sx = Math.random() * 512;
        const sy = Math.random() * 512;
        ctx.moveTo(sx, sy);
        ctx.bezierCurveTo(
            sx + (Math.random() - 0.5) * 80, sy + (Math.random() - 0.5) * 40,
            sx + (Math.random() - 0.5) * 100, sy + (Math.random() - 0.5) * 60,
            sx + (Math.random() - 0.5) * 120, sy + (Math.random() * 60)
        );
        ctx.stroke();
    }

    const texture = new THREE.CanvasTexture(canvas);
    texture.wrapS = THREE.RepeatWrapping;
    texture.wrapT = THREE.RepeatWrapping;
    texture.repeat.set(3, 1);
    return texture;
}

function createLeatherNormalMap() {
