    roughness: 0.7,
    metalness: 0.05,
    side: THREE.DoubleSide
});

const darkLeatherMaterial = new THREE.MeshStandardMaterial({
    map: leatherTexture,
    bumpMap: leatherBump,
    bumpScale: 0.02,
