  new THREE.Vector3(0.1, 1.4, 0)
);
const stemGeo = new THREE.TubeGeometry(stemCurve, 8, 0.03, 6, false);
const stemMat = new THREE.MeshStandardMaterial({ color: 0x3a7a3a, roughness: 0.7 });
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
berryGroup.add(stem);

// --- Ground plane ---
const groundGeo = new THREE.CircleGeometry(4, 48);
