fillLight.position.set(-5, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6644, 1.5, 20);
rimLight.position.set(-2, 3, 5);
scene.add(rimLight);

// ── Materials ────────────────────────────────────────────────
const frameMat = new THREE.MeshStandardMaterial({
  color: 0xcc2222, metalness: 0.7, roughness: 0.25
});
const darkMat = new THREE.MeshStandardMaterial({
  color: 0x222222, metalness: 0.5, roughness: 0.4
});
const chromeMat = new THREE.MeshStandardMaterial({
  color: 0xcccccc, metalness: 0.95, roughness: 0.08
});
const tireMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1a, metalness: 0.0, roughness: 0.9
});
const seatMat = new THREE.MeshStandardMaterial({
  color: 0x111111, metalness: 0.1, roughness: 0.8
});
const accentMat = new THREE.MeshStandardMaterial({
  color: 0xffaa00, metalness: 0.6, roughness: 0.3
});

// ── Helper Functions ─────────────────────────────────────────
function makeTire(radius = 0.9, tubeRadius = 0.12, segments = 48) {
  const g = new THREE.TorusGeometry(radius, tubeRadius, 16, segments);
  const m = new THREE.Mesh(g, tireMat);
  m.castShadow = true;
  return m;
}

function makeRim(radius = 0.82, spokes = 12) {
  const group = new THREE.Group();
  const rimG = new THREE.TorusGeometry(radius, 0.025, 8, 48);
  const rim = new THREE.Mesh(rimG, chromeMat);
  group.add(rim);
  const hubG = new THREE.CylinderGeometry(0.06, 0.06, 0.15, 12);
  hubG.rotateZ(Math.PI / 2);
  const hub = new THREE.Mesh(hubG, chromeMat);
  group.add(hub);
  for (let i = 0; i < spokes; i++) {
    const angle = (i / spokes) * Math.PI * 2;
    const spokeG = new THREE.CylinderGeometry(0.006, 0.006, radius * 1.8, 4);
    const spoke = new THREE.Mesh(spokeG, chromeMat);
    spoke.position.set(0, Math.cos(angle) * radius * 0.5, Math.sin(angle) * radius * 0.5);
    spoke.rotation.x = angle;
    group.add(spoke);
  }
  return group;
}

function makeTube(start, end, radius = 0.035) {
  const dir = new THREE.Vector3().subVectors(end, start);
  const length = dir.length();
  const g = new THREE.CylinderGeometry(radius, radius, length, 12);
  g.translate(0, length / 2, 0);
  const m = new THREE.Mesh(g, frameMat);
  m.position.copy(start);
  m.quaternion.setFromUnitVectors(new THREE.Vector3(0, 1, 0), dir.normalize());
  m.castShadow = true;
  return m;
}

function makeTubeAt(start, end, radius, mat) {
  const dir = new THREE.Vector3().subVectors(end, start);
  const length = dir.length();
  const g = new THREE.CylinderGeometry(radius, radius, length, 12);
  g.translate(0, length / 2, 0);
  const m = new THREE.Mesh(g, mat);
  m.position.copy(start);
  m.quaternion.setFromUnitVectors(new THREE.Vector3(0, 1, 0), dir.normalize());
  m.castShadow = true;
  return m;
}

// ── Build Bicycle ────────────────────────────────────────────
const bike = new THREE.Group();

// Frame connection points (y = up)
const rearAxle   = new THREE.Vector3(0, 0, 0);
const bottomBracket = new THREE.Vector3(2.4, -0.1, 0);
const seatCluster = new THREE.Vector3(1.6, 1.4, 0);
const headTubeBottom = new THREE.Vector3(4.2, 0.3, 0);
const headTubeTop    = new THREE.Vector3(4.4, 1.1, 0);
const frontAxle    = new THREE.Vector3(5.0, 0, 0);

// ── Rear Wheel ───────────────────────────────────────────────
const rearWheel = new THREE.Group();
rearWheel.add(makeTire());
rearWheel.add(makeRim());
rearWheel.position.copy(rearAxle);
bike.add(rearWheel);

// ── Front Wheel ──────────────────────────────────────────────
const frontWheel = new THREE.Group();
frontWheel.add(makeTire());
frontWheel.add(makeRim());
frontWheel.position.copy(frontAxle);
bike.add(frontWheel);

// ── Frame Tubes ──────────────────────────────────────────────
bike.add(makeTube(rearAxle, bottomBracket, 0.04));       // seat stay lower
bike.add(makeTube(rearAxle, seatCluster, 0.035));         // seat stay upper
bike.add(makeTube(bottomBracket, seatCluster, 0.045));    // seat tube
bike.add(makeTube(bottomBracket, headTubeBottom, 0.04));  // down tube lower
bike.add(makeTube(seatCluster, headTubeTop, 0.035));      // top tube
bike.add(makeTube(headTubeBottom, headTubeTop, 0.04));    // head tube
bike.add(makeTube(headTubeBottom, frontAxle, 0.035));     // fork lower
bike.add(makeTube(headTubeTop, new THREE.Vector3(4.6, -0.05, 0), 0.03)); // fork blade

// Fork dropout
const forkBlade = new THREE.Vector3(4.6, -0.05, 0);
bike.add(makeTube(forkBlade, frontAxle, 0.025));

// ── Seat ─────────────────────────────────────────────────────
const seatPost = makeTubeAt(seatCluster, new THREE.Vector3(1.55, 1.65, 0), 0.02, chromeMat);
bike.add(seatPost);

const seatRail = makeTubeAt(
  new THREE.Vector3(1.1, 1.65, 0),
  new THREE.Vector3(1.9, 1.65, 0),
  0.015, chromeMat
);
bike.add(seatRail);

const saddleG = new THREE.BoxGeometry(0.7, 0.06, 0.28);
saddleG.translate(0, 0, 0);
const saddle = new THREE.Mesh(saddleG, seatMat);
saddle.position.set(1.5, 1.72, 0);
saddle.castShadow = true;
bike.add(saddle);

// ── Handlebars ───────────────────────────────────────────────
const stem = makeTubeAt(
  headTubeTop,
  new THREE.Vector3(4.35, 1.35, 0),
  0.025, chromeMat
);
bike.add(stem);

const handlebarG = new THREE.TorusGeometry(0.25, 0.018, 8, 16, Math.PI);
const handlebar = new THREE.Mesh(handlebarG, darkMat);
handlebar.position.set(4.35, 1.45, 0);
handlebar.rotation.y = Math.PI / 2;
handlebar.rotation.z = 0.2;
handlebar.castShadow = true;
bike.add(handlebar);

// Grip ends
[-1, 1].forEach(side => {
  const gripG = new THREE.CylinderGeometry(0.022, 0.022, 0.12, 8);
  const grip = new THREE.Mesh(gripG, darkMat);
  grip.position.set(4.35 + side * 0.22, 1.52, side * 0.08);
  grip.rotation.z = side * 1.2;
  bike.add(grip);
});

// ── Crank / Pedals ───────────────────────────────────────────
const crankGroup = new THREE.Group();
crankGroup.position.copy(bottomBracket);

const chainringG = new THREE.TorusGeometry(0.22, 0.02, 8, 24);
const chainring = new THREE.Mesh(chainringG, darkMat);
chainring.rotation.y = Math.PI / 2;
crankGroup.add(chainring);

// Chainring teeth accent
const ringG = new THREE.TorusGeometry(0.22, 0.008, 6, 32);
const ring = new THREE.Mesh(ringG, accentMat);
ring.rotation.y = Math.PI / 2;
crankGroup.add(ring);

// Crank arms
[-1, 1].forEach(side => {
  const armG = new THREE.CylinderGeometry(0.018, 0.018, 0.3, 8);
  armG.rotateZ(Math.PI / 2);
  const arm = new THREE.Mesh(armG, darkMat);
  arm.position.set(0, side * 0.15, 0);
  crankGroup.add(arm);

  // Pedal
  const pedalG = new THREE.BoxGeometry(0.12, 0.03, 0.06);
  const pedal = new THREE.Mesh(pedalG, darkMat);
  pedal.position.set(0, side * 0.3, 0);
  pedal.castShadow = true;
  crankGroup.add(pedal);

  // Pedal pins
  const pinG = new THREE.CylinderGeometry(0.005, 0.005, 0.08, 4);
  const pin = new THREE.Mesh(pinG, chromeMat);
  pin.position.set(0, side * 0.3, 0);
  crankGroup.add(pin);
});

bike.add(crankGroup);

// ── Chain ────────────────────────────────────────────────────
const chainG = new THREE.TorusGeometry(0.22, 0.005, 4, 32);
const chain = new THREE.Mesh(chainG, darkMat);
chain.rotation.y = Math.PI / 2;
chain.position.copy(bottomBracket);
bike.add(chain);

// Rear cassette
const cassetteG = new THREE.CylinderGeometry(0.1, 0.1, 0.04, 16);
cassetteG.rotateZ(Math.PI / 2);
const cassette = new THREE.Mesh(cassetteG, darkMat);
cassette.position.copy(rearAxle);
bike.add(cassette);

// ── Headlight ────────────────────────────────────────────────
const lightG = new THREE.SphereGeometry(0.06, 12, 8);
const lightMat = new THREE.MeshStandardMaterial({
  color: 0xffffaa, emissive: 0xffff44, emissiveIntensity: 0.8
});
const headlight = new THREE.Mesh(lightG, lightMat);
headlight.position.set(4.55, 0.15, 0);
bike.add(headlight);

// ── Ground / Shadow Catcher ──────────────────────────────────
const groundG = new THREE.CircleGeometry(20, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e, roughness: 1, metalness: 0
});
const ground = new THREE.Mesh(groundG, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.92;
ground.receiveShadow = true;
scene.add(ground);

// Grid
const grid = new THREE.GridHelper(30, 30, 0x2a2a4e, 0x222244);
grid.position.y = -0.91;
scene.add(grid);

// ── Position Bike ────────────────────────────────────────────
bike.position.y = 0

