<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Billboard Scene</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
#info {
  position: absolute; top: 16px; left: 50%; transform: translateX(-50%);
  color: #fff; font-family: 'Segoe UI', sans-serif; font-size: 14px;
  background: rgba(0,0,0,0.5); padding: 8px 18px; border-radius: 20px;
  pointer-events: none; letter-spacing: 0.5px;
}
</style>
</head>
<body>
<div id="info">Click &amp; drag to orbit · Scroll to zoom</div>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.008);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 500);
camera.position.set(12, 8, 20);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 4, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 8;
controls.maxDistance = 60;

// ── Lighting ─────────────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0x8899BB, 0.6);
scene.add(ambientLight);

const hemiLight = new THREE.HemisphereLight(0x87CEEB, 0x556B2F, 0.4);
scene.add(hemiLight);

const sunLight = new THREE.DirectionalLight(0xFFF4E0, 1.8);
sunLight.position.set(15, 25, 10);
sunLight.castShadow = true;
sunLight.shadow.mapSize.set(2048, 2048);
sunLight.shadow.camera.left = -20;
sunLight.shadow.camera.right = 20;
sunLight.shadow.camera.top = 20;
sunLight.shadow.camera.bottom = -20;
sunLight.shadow.camera.near = 1;
sunLight.shadow.camera.far = 60;
sunLight.shadow.bias = -0.001;
scene.add(sunLight);

// ── Ground ───────────────────────────────────────────────
const groundGeo = new THREE.PlaneGeometry(200, 200);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x4A7C3F, roughness: 0.95, metalness: 0.0
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Dirt road
const roadGeo = new THREE.PlaneGeometry(6, 200);
const roadMat = new THREE.MeshStandardMaterial({ color: 0x8B7D6B, roughness: 1 });
const road = new THREE.Mesh(roadGeo, roadMat);
road.rotation.x = -Math.PI / 2;
road.position.set(0, 0.01, 0);
road.receiveShadow = true;
scene.add(road);

// Road lines
const lineGeo = new THREE.PlaneGeometry(0.15, 200);
const lineMat = new THREE.MeshStandardMaterial({ color: 0xDDDD44, roughness: 0.8 });
const line = new THREE.Mesh(lineGeo, lineMat);
line.rotation.x = -Math.PI / 2;
line.position.set(0, 0.02, 0);
scene.add(line);

// ── Billboard Texture (Canvas) ──────────────────────────
function createBillboardTexture() {
  const canvas = document.createElement('canvas');
  canvas.width = 1024;
  canvas.height = 512;
  const ctx = canvas.getContext('2d');

  // Background gradient
  const grad = ctx.createLinearGradient(0, 0, 1024, 512);
  grad.addColorStop(0, '#1a1a2e');
  grad.addColorStop(0.5, '#16213e');
  grad.addColorStop(1, '#0f3460');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, 1024, 512);

  // Subtle pattern
  ctx.strokeStyle = 'rgba(255,255,255,0.03)';
  ctx.lineWidth = 1;
  for (let i = 0; i < 1024; i += 20) {
    ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, 512); ctx.stroke();
  }

  // Border
  ctx.strokeStyle = '#e94560';
  ctx.lineWidth = 6;
  ctx.strokeRect(12, 12, 1000, 488);
  ctx.strokeStyle = 'rgba(233,69,96,0.3)';
  ctx.lineWidth = 2;
  ctx.strokeRect(24, 24, 976, 464);

  // Main text
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';

  ctx.font = 'bold 110px "Segoe UI", Arial, sans-serif';
  ctx.fillStyle = '#e94560';
  ctx.shadowColor = 'rgba(233,69,96,0.5)';
  ctx.shadowBlur = 20;
  ctx.fillText('BILLBOARD', 512, 200);

  ctx.shadowBlur = 0;
  ctx.font = '36px "Segoe UI", Arial, sans-serif';
  ctx.fillStyle = '#a8d8ea';
  ctx.fillText('Three.js Scene', 512, 290);

  // Decorative line
  ctx.strokeStyle = '#e94560';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(312, 320);
  ctx.lineTo(712, 320);
  ctx.stroke();

  ctx.font = '28px "Segoe UI", Arial, sans-serif';
  ctx.fillStyle = '#7f8fa6';
  ctx.fillText('Click & drag to explore', 512, 370);

  // Small accent dots
  ctx.fillStyle = '#e94560';
  for (const x of [380, 400, 420, 512, 604, 624, 644]) {
    ctx.beginPath();
    ctx.arc(x, 410, 3, 0, Math.PI * 2);
    ctx.fill();
  }

  const tex = new THREE.CanvasTexture(canvas);
  tex.colorSpace = THREE.SRGBColorSpace;
  return tex;
}

// ── Billboard Structure ──────────────────────────────────
const billboardGroup = new THREE.Group();
scene.add(billboardGroup);

// Sign panel
const signWidth = 10, signHeight = 5;
const signGeo = new THREE.BoxGeometry(signWidth, signHeight, 0.15);
const signMat = new THREE.MeshStandardMaterial({
  map: createBillboardTexture(),
  roughness: 0.3,
  metalness: 0.1,
  emissive: 0x111122,
  emissiveMap: createBillboardTexture(),
  emissiveIntensity: 0.15
});
const sign = new THREE.Mesh(signGeo, signMat);
sign.position.y = signHeight / 2 + 5;
sign.castShadow = true;
sign.receiveShadow = true;
billboardGroup.add(sign);

// Sign frame
const frameMat = new THREE.MeshStandardMaterial({ color: 0x333344, roughness: 0.4, metalness: 0.8 });
function makeFramePiece(w, h, d, x, y) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), frameMat);
  m.position.set(x, y, 0);
  m.castShadow = true;
  return m;
}
billboardGroup.add(makeFramePiece(signWidth + 0.3, 0.15, 0.2, 0, 5.0));
billboardGroup.add(makeFramePiece(signWidth + 0.3, 0.15, 0.2, 0, 10.05));
billboardGroup.add(makeFramePiece(0.15, signHeight + 0.3, 0.2, -signWidth / 2 - 0.075, 7.5));
billboardGroup.add(makeFramePiece(0.15, signHeight + 0.3, 0.2, signWidth / 2 + 0.075, 7.5));

// Poles
const poleMat = new THREE.MeshStandardMaterial({ color: 0x555566, roughness: 0.5, metalness: 0.7 });
const poleGeo = new THREE.CylinderGeometry(0.12, 0.15, 5, 12);
const poleL = new THREE.Mesh(poleGeo, poleMat);
poleL.position.set(-3.5, 2.5, 0);
poleL.castShadow = true;
billboardGroup.add(poleL);

const poleR = new THREE.Mesh(poleGeo, poleMat);
poleR.position.set(3.5, 2.5, 0);
poleR.castShadow = true;
billboardGroup.add(poleR);

// Cross brace
const braceGeo = new THREE.CylinderGeometry(0.06, 0.06, 7.2, 8);
const brace = new THREE.Mesh(braceGeo, poleMat);
brace.position.set(0, 3.5, 0);
brace.rotation.z = Math.PI / 2;
brace.castShadow = true;
billboardGroup.add(brace);

// ── Trees ────────────────────────────────────────────────
function createTree(x, z, scale = 1) {
  const group = new THREE.Group();

  const trunkGeo = new THREE.CylinderGeometry(0.15 * scale, 0.25 * scale, 2 * scale, 8);
  const trunkMat = new THREE.MeshStandardMaterial({ color: 0x5C4033, roughness: 0.9 });
  const trunk = new THREE.Mesh(trunkGeo, trunkMat);
  trunk.position.y = scale;
  trunk.castShadow = true;
  group.add(trunk);

  const leafMat = new THREE.MeshStandardMaterial({ color: 0x2D6B1E, roughness: 0.8 });
  for (let i = 0; i < 3; i++) {
    const r = (1.8 - i * 0.4) * scale;
    const h = (1.5 - i * 0.2) * scale;
    const leafGeo = new THREE.ConeGeometry(r, h, 8);
    const leaf = new THREE.Mesh(leafGeo, leafMat);
    leaf.position.y = (2 + i * 0.8) * scale;
    leaf.castShadow = true;
    group.add(leaf);
  }

  group.position.set(x, 0, z);
  return group;
}

const treePositions = [
  [-12, -8, 1.2], [-10, 5, 0.9], [-14, -2, 1.4],
  [12, -6, 1.1], [10, 8, 1.3], [14, 2, 0.8],
  [-8, -15, 1.0], [9, -12, 1.5], [-15, 10, 0.7],
  [16, 12, 1.2], [-11, 18, 1.0], [13, -18, 1.3],
];
treePositions.forEach(([x, z, s]) => scene.add(createTree(x, z, s)));

// ── Small rocks ──────────────────────────────────────────
const rockMat = new THREE.MeshStandardMaterial({ color: 0x777777, roughness: 0.9 });
for (let i = 0; i < 20; i++) {
  const s = 0.2 + Math.random() * 0.5;
  const rockGeo = new THREE.DodecahedronGeometry(s, 0);
  const rock = new THREE.Mesh(rockGeo, rockMat);
  rock.position.set(
    (Math.random() - 0.5) * 40,
    s * 0.4,
    (Math.random() - 0.5) * 40
  );
  rock.rotation.set(Math.random(), Math.random(), Math.random());
  rock.castShadow = true;
  rock.receiveShadow = true;
  scene.add(rock);
}

// ── Animation ────────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle billboard glow pulse
  sign.material.emissiveIntensity = 0.12 + Math.sin(t * 2) * 0.06;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ───────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
