  );
  const housing = new THREE.Mesh(housingGeo, bodyMaterial);
  housing.rotation.z = Math.PI / 2;
  housing.position.z = barrelLength / 2 + housingLength / 2;
  housing.castShadow = true;
  group.add(housing);

  // Metal ring around objective
  const objRingGeo = new THREE.TorusGeometry(housingRadius + 0.01, 0.025, 12, 48);
  const objRing = new THREE.Mesh(objRingGeo, metalMaterial);
  objRing.position.z = barrelLength / 2 + housingLength;
  objRing.castShadow = true;
  group.add(objRing);

  // Objective lens glass
  const objLensGeo = new THREE.CircleGeometry(housingRadius * 0.85, 48);
  const objLens = new THREE.Mesh(objLensGeo, lensGlassMaterial);
  objLens.position.z = barrelLength / 2 + housingLength + 0.01;
  group.add(objLens);

  // Lens coating reflection
  const coatingGeo = new THREE.CircleGeometry(housingRadius * 0.6, 48);
  const coating = new THREE.Mesh(coatingGeo, lensCoatingMaterial);
  coating.position.z = barrelLength / 2 + housingLength + 0.02;
  group.add(coating);

  // Lens interior depth
  const lensDepthGeo = new THREE.CircleGeometry(housingRadius * 0.88, 48);
  const lensDepth = new THREE.Mesh(lensDepthGeo, interiorMaterial);
  lensDepth.position.z = barrelLength / 2 + housingLength - 0.02;
  group.add(lensDepth);

  // Small prisms visible through the side (decorative)
  const prismGeo = new THREE.BoxGeometry(0.3, 0.3, 0.5);
  const prismMat = new THREE.MeshPhysicalMaterial({
    color: 0x4466aa,
    roughness: 0.1,
    metalness: 0.1,
    transmission: 0.5,
