const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.maxPolarAngle = Math.PI / 2.1;
controls.minDistance = 8;
controls.maxDistance = 100;
controls.target.set(0, 0, 0);

// ── Colors ──
const C = {
  bg:       0x060e1a,
  gridMajor: 0x1a3a5c,
  gridMinor: 0x0d2240,
  line:     0x4a9eff,
  lineBright: 0x80d0ff,
  lineDim:  0x1e4a7a,
  accent:   0x00e5ff,
  warm:     0xff6b35,
};

// ── Helpers ──
function makeLineMaterial(color, opacity = 1) {
  return new THREE.LineBasicMaterial({ color, transparent: true, opacity });
}

function makeEdgesGeometry(geo, color, opacity = 0.8) {
  const edges = new THREE.EdgesGeometry(geo, 15);
  const line = new THREE.LineSegments(edges, makeLineMaterial(color, opacity));
  return line;
}

// ── Blueprint Grid ──
function createGrid() {
  const group = new THREE.Group();
  const size = 80;
  const divisions = 80;
  const step = size / divisions;

  // Minor grid
  const minorMat = makeLineMaterial(C.gridMinor, 0.4);
  const majorMat = makeLineMaterial(C.gridMajor, 0.7);
  const axisMat = makeLineMaterial(C.lineDim, 0.5);

  const pointsMinor = [];
  const pointsMajor = [];
  for (let i = 0; i <= divisions; i++) {
    const v = -size / 2 + i * step;
    const isMajor = i % 10 === 0;
    const arr = isMajor ? pointsMajor : pointsMinor;
    arr.push(new THREE.Vector3(v, 0, -size / 2));
    arr.push(new THREE.Vector3(v, 0, size / 2));
    arr.push(new THREE.Vector3(-size / 2, 0, v));
    arr.push(new THREE.Vector3(size / 2, 0, v));
  }

  group.add(new THREE.LineSegments(new THREE.BufferGeometry().setFromPoints(pointsMinor), minorMat));
  group.add(new THREE.LineSegments(new THREE.BufferGeometry().setFromPoints(pointsMajor), majorMat));

  // Axes
  const ax = [
    [new THREE.Vector3(-size/2, 0, 0), new THREE.Vector3(size/2, 0, 0)],
    [new THREE.Vector3(0, 0, -size/2), new THREE.Vector3(0, 0, size/2)],
  ];
  const axPts = ax.flat();
  group.add(new THREE.LineSegments(new THREE.BufferGeometry().setFromPoints(axPts), axisMat));

  // Grid labels (as small planes with canvas textures)
  function makeLabel(text, x, z) {
    const canvas = document.createElement('canvas');
    canvas.width = 64; canvas.height = 32;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#1e4a7a';
    ctx.font = '18px Courier New';
    ctx.textAlign = 'center';
    ctx.fillText(text, 32, 22);
    const tex = new THREE.CanvasTexture(canvas);
    const mat = new THREE.MeshBasicMaterial({ map: tex, transparent: true, depthWrite: false });
    const mesh = new THREE.Mesh(new THREE.PlaneGeometry(2, 1), mat);
    mesh.rotation.x = -Math.PI / 2;
    mesh.position.set(x, 0.02, z);
    return mesh;
  }

  for (let i = -4; i <= 4; i++) {
    if (i === 0) continue;
    group.add(makeLabel(i * 10 + '', i * 10 - 0.8, -size / 2 - 1.5));
    group.add(makeLabel(i * 10 + '', -size / 2 - 1.5, i * 10 - 0.8));
  }

  group.position.y = -0.1;
  return group;
}
scene.add(createGrid());

