<body>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x110505, 0.02);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

// --- Bomb Group ---
const bomb = new THREE.Group();

// Body
const bodyGeo = new THREE.SphereGeometry(1.2, 32, 32);
bodyGeo.scale(1, 1.15, 1);
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a1a, roughness: 0.3, metalness: 0.8
});
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.castShadow = true;
bomb.add(body);

// Danger stripe
const stripeGeo = new THREE.TorusGeometry(1.22, 0.12, 8, 48);
const stripeMat = new THREE.MeshStandardMaterial({ color: 0xcc2200, roughness: 0.5, metalness: 0.3 });
const stripe = new THREE.Mesh(stripeGeo, stripeMat);
stripe.rotation.x = Math.PI / 2;
bomb.add(stripe);

// Fins
const finMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.4, metalness: 0.9 });
for (let i = 0; i < 4; i++) {
  const fin = new THREE.Mesh(new THREE.BoxGeometry(0.15, 1.0, 0.6), finMat);
  fin.position.set(0, -1.5, 0);
  fin.rotation.y = (Math.PI / 2) * i;
  fin.castShadow = true;
  bomb.add(fin);
}

// Nose cap
const noseGeo = new THREE.SphereGeometry(0.45, 16, 16, 0, Math.PI * 2, 0, Math.PI / 2);
const noseMat = new THREE.MeshStandardMaterial({ color: 0x888888, roughness: 0.2, metalness: 0.95 });
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.y = 1.2;
nose.rotation.x = Math.PI;
nose.castShadow = true;
bomb.add(nose);

// Fuse base
const fuseBase = new THREE.Mesh(
  new THREE.CylinderGeometry(0.15, 0.2, 0.3, 12),
  new THREE.MeshStandardMaterial({ color: 0x666666, metalness: 0.9, roughness: 0.3 })
);
fuseBase.position.y = 1.75;
bomb.add(fuseBase);

// Fuse stick
const fuseStick = new THREE.Mesh(
  new THREE.CylinderGeometry(0.04, 0.04, 0.8, 8),
  new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.9 })
);
fuseStick.position.y = 2.2;
bomb.add(fuseStick);

// Spark tip
const sparkGeo = new THREE.SphereGeometry(0.08, 8, 8);
const sparkMat = new THREE.MeshBasicMaterial({ color: 0xffaa00 });
const spark = new THREE.Mesh(sparkGeo, sparkMat);
spark.position.y = 2.62;
bomb.add(spark);

// Spark glow
const glowGeo = new THREE.SphereGeometry(0.2, 8, 8);
const glowMat = new THREE.MeshBasicMaterial({ color: 0xff6600, transparent: true, opacity: 0.4 });
const glow = new THREE.Mesh(glowGeo, glowMat);
glow.position.y = 2.62;
bomb.add(glow);

// Spark particles
const sparkCount = 40;
const sparkPositions = new Float32Array(sparkCount * 3);
const sparkVelocities = [];
const sparkLife = new Float32Array(sparkCount);
for (let i = 0; i < sparkCount; i++) {
  sparkPositions[i * 3] = 0;
  sparkPositions[i * 3 + 1] = 2.62;
  sparkPositions[i * 3 + 2] = 0;
  sparkVelocities.push(new THREE.Vector3(
    (Math.random() - 0.5) * 0.04,
    Math.random() * 0.06 + 0.02,
    (Math.random() - 0.5) * 0.04
  ));
  sparkLife[i] = Math.random();
}
const sparkParticlesGeo = new THREE.BufferGeometry();
sparkParticlesGeo.setAttribute('position', new THREE.BufferAttribute(sparkPositions, 3));
const sparkParticlesMat = new THREE.PointsMaterial({
  color: 0xffcc44, size: 0.06, transparent: true, opacity: 0.9
});
const sparkParticles = new THREE.Points(sparkParticlesGeo, sparkParticlesMat);
bomb.add(sparkParticles);

scene.add(bomb);

