scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xffeedd, 1.2);
mainLight.position.set(5, 5, 5);
mainLight.castShadow = true;
scene.add(mainLight);

const rimLight = new THREE.PointLight(0xff4400, 2, 10);
rimLight.position.set(-3, 2, -2);
scene.add(rimLight);

const sparkLight = new THREE.PointLight(0xff8800, 1.5, 4);
sparkLight.position.set(0, 2.6, 0);
bomb.add(sparkLight);

// Ground
const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -3;
ground.receiveShadow = true;
scene.add(ground);

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Slow rotation
  bomb.rotation.y = t * 0.3;

  // Spark flicker
  const flicker = 0.7 + Math.sin(t * 20) * 0.3;
  spark.scale.setScalar(flicker);
  glow.scale.setScalar(1 + Math.sin(t * 15) * 0.5);
  glowMat.opacity = 0.2 + Math.sin(t * 12) * 0.2;
  sparkLight.intensity = 1 + Math.sin(t * 18) * 0.8;

  // Update spark particles
  const positions = sparkParticlesGeo.attributes.position.array;
  for (let i = 0; i < sparkCount; i++) {
    sparkLife[i] -= 0.015;
    if (sparkLife[i] <= 0) {
      sparkLife[i] = 1;
      positions[i * 3] = 0;
      positions[i * 3 + 1] = 2.62;
      positions[i * 3 + 2] = 0;
      sparkVelocities[i].set(
        (Math.random() - 0.5) * 0.04,
        Math.random() * 0.06 + 0.02,
        (Math.random() - 0.5) * 0.04
      );
    }
    positions[i * 3] += sparkVelocities[i].x;
    positions[i * 3 + 1] += sparkVelocities[i].y;
    positions[i * 3 + 2] += sparkVelocities[i].z;
    sparkVelocities[i].y += 0.001; // slight upward drift
  }
  sparkParticlesGeo.attributes.position.needsUpdate = true;

  // Subtle camera bob
  camera.position.y = 1 + Math.sin(t * 0.5) * 0.2;
  camera.lookAt(0, 0, 0);

  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
