    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    document.body.appendChild(renderer.domElement);

    // ── Controls ───────────────────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;

    // ── Lighting ───────────────────────────────────
    const ambient = new THREE.AmbientLight(0x404060, 0.8);
    scene.add(ambient);

    const key = new THREE.DirectionalLight(0xfff4e0, 2.5);
    key.position.set(4, 6, 4);
    key.castShadow = true;
    scene.add(key);

    const fill = new THREE.DirectionalLight(0x8090ff, 0.6);
    fill.position.set(-3, 2, -2);
    scene.add(fill);

    const rim = new THREE.PointLight(0xff9040, 1.5, 12);
    rim.position.set(-2, 1, -3);
    scene.add(rim);

    // ── Bone Geometry (Lathe) ──────────────────────
    function createBoneProfile() {
      const pts = [];
      const n = 40;
      // Bulbous end
      for (let i = 0; i <= n; i++) {
        const t = i / n;
        const r = 0.35 + 0.12 * Math.sin(t * Math.PI * 1.2);
        pts.push(new THREE.Vector2(Math.max(0.001, r), -1.5 + t * 1.0));
      }
      // Shaft
      for (let i = 1; i <= n; i++) {
        const t = i / n;
        const r = 0.22 + 0.04 * Math.sin(t * Math.PI * 0.5);
        pts.push(new THREE.Vector2(r, -0.5 + t * 2.0));
      }
      // Other bulbous end
      for (let i = 0; i <= n; i++) {
        const t = i / n;
        const r = 0.35 + 0.12 * Math.sin(t * Math.PI * 1.2);
        pts.push(new THREE.Vector2(Math.max(0.001, r), 1.5 - t * 1.0));
      }
      return pts;
    }

    const boneGeo = new THREE.LatheGeometry(createBoneProfile(), 32);
    boneGeo.computeVertexNormals();

    // ── Bone Material ──────────────────────────────
    const boneMat = new THREE.MeshStandardMaterial({
      color: 0xe8dcc8,
      roughness: 0.55,
      metalness: 0.05,
    });

    const bone = new THREE.Mesh(boneGeo, boneMat);
    bone.castShadow = true;
    bone.receiveShadow = true;
    scene.add(bone);

    // ── Ground Plane ───────────────────────────────
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(30, 30),
      new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 1 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -2.5;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Animation ──────────────────────────────────
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      bone.rotation.y = t * 0.4;
      bone.rotation.x = Math.sin(t * 0.3) * 0.15;
      bone.position.y = Math.sin(t * 0.7) * 0.2;

      controls.update();
      renderer.render(scene, camera);
    }
    animate();

    // ── Resize ─────────────────────────────────────
    addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
