      return new THREE.Vector3(
        Math.cos(angle) * 1.4,
        1.82,
        Math.sin(angle) * 1.4
      );
    })
  ),
  128, 0.025, 16, true
);
const rimMesh = new THREE.Mesh(rimTubeGeo, outerMaterial);
rimMesh.castShadow = true;
bowlGroup.add(rimMesh);

scene.add(bowlGroup);

// --- Ground Plane ---
