// Procedural branch generation
function createBranch(origin, direction, length, radius, depth, maxDepth) {
  if (depth > maxDepth || radius < 0.015) return;

  const segments = 5;
  const geometry = new THREE.CylinderGeometry(
    radius * 0.7, radius, length, segments
  );
  geometry.translate(0, length / 2, 0);

  const mesh = new THREE.Mesh(geometry, barkMat);
  mesh.position.copy(origin);

  // Orient along direction
  const up = new THREE.Vector3(0, 1, 0);
  const quat = new THREE.Quaternion().setFromUnitVectors(up, direction.clone().normalize());
  mesh.quaternion.copy(quat);
  branchGroup.add(mesh);

  const tip = origin.clone().add(direction.clone().normalize().multiplyScalar(length));

  if (depth < maxDepth) {
    const numBranches = depth < 2 ? 3 : 2;
    const spread = 0.5 + Math.random() * 0.3;

    for (let i = 0; i < numBranches; i++) {
      const newDir = direction.clone().normalize();

      // Create perpendicular offsets
      const perp1 = new THREE.Vector3();
      const perp2 = new THREE.Vector3();
      newDir.clone().crossVectors(
        newDir, new THREE.Vector3(Math.random() - 0.5, Math.random() - 0.5, Math.random() - 0.5)
      ).normalize();
      perp1.crossVectors(newDir, perp1).normalize();
      perp2.crossVectors(newDir, perp1).normalize();

      const angle = spread * (0.6 + Math.random() * 0.4) * (i / (numBranches - 1 || 1));
      const tilt = (Math.random() - 0.5) * spread * 0.8;

      newDir.applyAxisAngle(perp1, angle);
      newDir.applyAxisAngle(perp2, tilt);

      // Slight upward bias
      newDir.y += 0.1;
      newDir.normalize();

      const newLength = length * (0.65 + Math.random() * 0.15);
      const newRadius = radius * (0.55 + Math.random() * 0.1);
      const branchOrigin = tip.clone().add(
        new THREE.Vector3(
          (Math.random() - 0.5) * 0.05,
          (Math.random() - 0.5) * 0.05,
          (Math.random() - 0.5) * 0.05
        )
      );

      createBranch(branchOrigin, newDir, newLength, newRadius, depth + 1, maxDepth);
    }

    // Add leaf clusters at tips
    if (depth >= maxDepth - 1) {
      const leafSize = 0.15 + Math.random() * 0.2;
      for (let j = 0; j < 3 + Math.floor(Math.random() * 4); j++) {
        const leafGeo = new THREE.SphereGeometry(leafSize * (0.5 + Math.random() * 0.5), 5, 4);
        const leaf = new THREE.Mesh(leafGeo, leafMat);
        leaf.position.copy(tip).add(
          new THREE.Vector3(
            (Math.random() - 0.5) * 0.8,
            (Math.random() - 0.5) * 0.8,
            (Math.random() - 0.5) * 0.8
          )
        );
        leaf.scale.set(1, 0.4 + Math.random() * 0.3, 1);
        branchGroup.add(leaf);
      }
    }
  }
}

// Seed the main trunk
const seed = 42;
createBranch(
  new THREE.Vector3(0, -1, 0),
  new THREE.Vector3(0.1, 1, 0.05),
  3.5, 0.22, 0, 5
);

