    const angle = (i / 12) * Math.PI * 2;
    const r = crownRadius * (0.85 + Math.random() * 0.2);
    clusters.push({
      pos: new THREE.Vector3(
        Math.cos(angle) * r,
        2.8 + Math.random() * 0.5,
        Math.sin(angle) * r
      ),
      scale: 0.18 + Math.random() * 0.1,
      tip: false
    });
  }

  // For each cluster, create multiple floret spheres
  const mainFlorets = [];
  const tipFlorets = [];

  for (const cluster of clusters) {
    const numSpheres = 4 + Math.floor(Math.random() * 4);
    for (let j = 0; j < numSpheres; j++) {
      const spread = cluster.scale * 0.6;
      const offset = new THREE.Vector3(
        (Math.random() - 0.5) * spread,
        (Math.random() - 0.5) * spread * 0.6,
        (Math.random() - 0.5) * spread
      );
      const pos = cluster.pos.clone().add(offset);
      const s = cluster.scale * (0.5 + Math.random() * 0.5);

      if (cluster.tip) {
        tipFlorets.push({ pos, scale: s });
      } else {
        mainFlorets.push({ pos, scale: s });
      }
    }
  }

  // Create instanced meshes
  if (mainFlorets.length > 0) {
    const instanced = new THREE.InstancedMesh(floretGeo, floretMat, mainFlorets.length);
    const dummy = new THREE.Object3D();
    mainFlorets.forEach((f, i) => {
      dummy.position.copy(f.pos);
      dummy.scale.setScalar(f.scale);
      dummy.rotation.set(Math.random() * 0.5, Math.random() * Math.PI, Math.random() * 0.5);
      dummy.updateMatrix();
      instanced.setMatrixAt(i, dummy.matrix);
    });
    instanced.castShadow = true;
    instanced.receiveShadow = true;
    scene.add(instanced);
  }

  if (tipFlorets.length > 0) {
    const instanced = new THREE.InstancedMesh(floretGeo, floretTipMat, tipFlorets.length);
    const dummy = new THREE.Object3D();
    tipFlorets.forEach((f, i) => {
      dummy.position.copy(f.pos);
      dummy.scale.setScalar(f.scale);
      dummy.rotation.set(Math.random() * 0.5, Math.random() * Math.PI, Math.random() * 0.5);
      dummy.updateMatrix();
      instanced.setMatrixAt(i, dummy.matrix);
    });
    instanced.castShadow = true;
    instanced.receiveShadow = true;
    scene.add(instanced);
  }
}
