function createCable(startX, endX, sag, zOffset) {
  const points = [];
  const segments = 60;
  const midX = (startX + endX) / 2;
  const span = endX - startX;

  for (let i = 0; i <= segments; i++) {
    const t = i / segments;
    const x = startX + span * t;
    // Parabolic sag
    const y = 10 + sag - sag * 4 * (t - 0.5) * (t - 0.5);
    points.push(new THREE.Vector3(x, y, zOffset));
  }

  const curve = new THREE.CatmullRomCurve3(points);
  const tubeGeo = new THREE.TubeGeometry(curve, 60, 0.12, 8, false);
  const cable = new THREE.Mesh(tubeGeo, cableMat);
  cable.castShadow = true;
  return cable;
}

