      cableY = 10 + 22 - 22 * 4 * (t - 0.5) * (t - 0.5);
    } else if (x > towerX) {
      const t = (x - towerX) / (deckLength / 2 + 15 - towerX);
      cableY = 10 + 22 - 22 * 4 * (t - 0.5) * (t - 0.5);
    } else {
      const t = (x + towerX) / (2 * towerX);
      cableY = 10 + 22 - 22 * 4 * (t - 0.5) * (t - 0.5);
