    const handleShape = new THREE.Shape();
    handleShape.absarc(0, 0, 0.12, 0, Math.PI * 2, false);

    const handlePath = new THREE.CatmullRomCurve3([
      new THREE.Vector3(-1.20, 2.05, 0),
      new THREE.Vector3(-1.35, 2.50, 0),
      new THREE.Vector3(-1.15, 3.30, 0),
      new THREE.Vector3(-0.50, 3.80, 0),
      new THREE.Vector3(0,    3.95, 0),
      new THREE.Vector3(0.50, 3.80, 0),
      new THREE.Vector3(1.15, 3.30, 0),
      new THREE.Vector3(1.35, 2.50, 0),
      new THREE.Vector3(1.20, 2.05, 0),
    ]);

    const handleMesh = new THREE.Mesh(
      new THREE.TubeGeometry(handlePath, 64, 0.06, 12, false),
      handleMat
    );
    handleMesh.castShadow = true;

    // ── Handle attachment rivets ──
    const rivetGeo = new THREE.CylinderGeometry(0.06, 0.06, 0.1, 12);
    const rivetPositions = [
      [-1.20, 2.05, 0.12], [-1.20, 2.05, -0.12],
      [ 1.20, 2.05, 0.12], [ 1.20, 2.05, -0.12],
    ];
    rivetPositions.forEach(pos => {
      const rivet = new THREE.Mesh(rivetGeo, darkMetalMat);
      rivet.position.set(...pos);
      rivet.rotation.x = Math.PI / 2;
      rivet.castShadow = true;
      scene.add(rivet);
    });

    // ── Assemble Bucket Group ──
    const bucket = new THREE.Group();
    bucket.add(bucketBody, bottomMesh, rimMesh, handleMesh);
    scene.add(bucket);

    // ── Ground Plane ──
    const ground = new THREE.Mesh(
      new THREE.CircleGeometry(15, 64),
      new THREE.MeshStandardMaterial({
        color: 0x2a2a3e,
        metalness: 0.1,
        roughness: 0.85,
      })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.01;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Water inside bucket (subtle) ──
    const waterGeo = new THREE.CircleGeometry(1.10, 32);
    const waterMat = new THREE.MeshStandardMaterial({
      color: 0x3388cc,
      transparent: true,
      opacity: 0.35,
      metalness: 0.1,
      roughness: 0.1,
    });
    const water = new THREE.Mesh(waterGeo, waterMat);
    water.rotation.x = -Math.PI / 2;
    water.position.y = 1.0;
    scene.add(water);

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });

    // ── Animate ──
    const clock = new THREE.Clock();
    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle water ripple
      water.material.opacity = 0.30 + Math.sin(t * 1.5) * 0.05;
      water.scale.setScalar(1 + Math.sin(t * 2) * 0.005);

      controls.update();
      renderer.render(scene, camera);
    }
    animate();
  </script>
</body>
</html>
```

## What's in the scene

| Element | Technique |
|---|---|
| **Bucket body** | `LatheGeometry` — 21 profile points create a realistic tapered shape (narrow bottom → wide top) |
| **Bottom** | `CircleGeometry` disc, darkened metal material |
| **Rim** | `TorusGeometry` ring at the top edge |
| **Handle** | `TubeGeometry` along a `CatmullRomCurve3` arch |
| **Rivets** | Small `CylinderGeometry` pieces where the handle meets the body |
| **Water** | Semi-transparent circle inside the bucket with a gentle animated ripple |
| **Ground** | Large disc receiving shadows |

### Lighting
- **Directional** key light with soft shadows
- **Blue rim** point light for edge highlight
- **Warm fill** point light for color contrast
- **Ambient** base fill

### Interactivity
- **OrbitControls** — drag to rotate, scroll to zoom, right-drag to pan
- Gentle water shimmer animation on each frame

