controls.maxDistance = 40;
controls.update();

// ─── Lighting ───
const ambientLight = new THREE.AmbientLight(0x6688AA, 0.5);
scene.add(ambientLight);

const sunLight = new THREE.DirectionalLight(0xFFEECC, 1.4);
sunLight.position.set(15, 20, 10);
