sunLight.shadow.mapSize.set(2048, 2048);
sunLight.shadow.camera.left = -15;
sunLight.shadow.camera.right = 15;
sunLight.shadow.camera.top = 15;
sunLight.shadow.camera.bottom = -15;
sunLight.shadow.camera.near = 1;
sunLight.shadow.camera.far = 50;
sunLight.shadow.bias = -0.001;
scene.add(sunLight);

const fillLight = new THREE.DirectionalLight(0x8899BB, 0.4);
fillLight.position.set(-10, 8, -5);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xFFDDAA, 0.3);
rimLight.position.set(-5, 3, -10);
scene.add(rimLight);

// ─── Materials ───
const darkBrown = new THREE.MeshStandardMaterial({
    color: 0x3D2B1F, roughness: 0.85, metalness: 0.05
});
const brown = new THREE.MeshStandardMaterial({
    color: 0x5C3D2E, roughness: 0.8, metalness: 0.05
});
const lightBrown = new THREE.MeshStandardMaterial({
    color: 0x7A5C47, roughness: 0.75, metalness: 0.05
});
const hornMat = new THREE.MeshStandardMaterial({
    color: 0x2A2A2A, roughness: 0.4, metalness: 0.15
});
const hoofMat = new THREE.MeshStandardMaterial({
    color: 0x1A1A1A, roughness: 0.6, metalness: 0.1
});
const noseMat = new THREE.MeshStandardMaterial({
    color: 0x2E1E12, roughness: 0.7, metalness: 0.05
});
const eyeMat = new THREE.MeshStandardMaterial({
    color: 0x111111, roughness: 0.3, metalness: 0.2
});
const eyeWhiteMat = new THREE.MeshStandardMaterial({
    color: 0xDDDDCC, roughness: 0.5, metalness: 0.0
});

// ─── Buffalo Group ───
const buffalo = new THREE.Group();

// ── Body (main torso) ──
const bodyGeo = new THREE.SphereGeometry(1, 24, 20);
bodyGeo.scale(1.6, 1.0, 1.1);
const body = new THREE.Mesh(bodyGeo, darkBrown);
body.position.set(0, 3.2, 0);
body.castShadow = true;
body.receiveShadow = true;
buffalo.add(body);

// Shoulder hump
const humpGeo = new THREE.SphereGeometry(1, 20, 16);
humpGeo.scale(1.3, 0.9, 1.0);
const hump = new THREE.Mesh(humpGeo, darkBrown);
hump.position.set(1.4, 4.0, 0);
hump.castShadow = true;
buffalo.add(hump);

// Upper back hump (more pronounced)
const upperHumpGeo = new THREE.SphereGeometry(0.7, 16, 12);
upperHumpGeo.scale(1.2, 0.7, 0.9);
const upperHump = new THREE.Mesh(upperHumpGeo, brown);
upperHump.position.set(1.0, 4.3, 0);
upperHump.castShadow = true;
buffalo.add(upperHump);

// Rump
const rumpGeo = new THREE.SphereGeometry(0.8, 16, 12);
rumpGeo.scale(1.0, 0.8, 0.9);
const rump = new THREE.Mesh(rumpGeo, brown);
rump.position.set(-1.6, 3.2, 0);
rump.castShadow = true;
buffalo.add(rump);

// ── Neck ──
const neckGeo = new THREE.SphereGeometry(0.7, 16, 12);
neckGeo.scale(1.1, 1.3, 0.9);
const neck = new THREE.Mesh(neckGeo, darkBrown);
neck.position.set(2.5, 3.6, 0);
neck.rotation.z = -0.5;
neck.castShadow = true;
buffalo.add(neck);

// ── Head ──
const headGroup = new THREE.Group();
headGroup.position.set(3.5, 3.8, 0);
headGroup.rotation.z = -0.3;

// Main head
const headGeo = new THREE.BoxGeometry(1.2, 1.0, 0.9, 2, 2, 2);
// Round the head a bit by using a sphere
const headMainGeo = new THREE.SphereGeometry(0.65, 16, 12);
headMainGeo.scale(1.0, 0.95, 0.85);
const headMain = new THREE.Mesh(headMainGeo, brown);
headMain.castShadow = true;
headGroup.add(headMain);

// Snout / muzzle
const snoutGeo = new THREE.SphereGeometry(0.45, 14, 10);
snoutGeo.scale(1.3, 0.85, 0.8);
const snout = new THREE.Mesh(snoutGeo, lightBrown);
snout.position.set(0.55, -0.15, 0);
snout.castShadow = true;
headGroup.add(snout);

// Nose pad
const noseGeo = new THREE.SphereGeometry(0.3, 12, 8);
noseGeo.scale(1.2, 0.6, 0.5);
const nose = new THREE.Mesh(noseGeo, noseMat);
nose.position.set(0.95, -0.1, 0);
headGroup.add(nose);

// Nostrils
const nostrilGeo = new THREE.SphereGeometry(0.06, 8, 6);
[-0.12, 0.12].forEach(z => {
    const nostril = new THREE.Mesh(nostrilGeo, noseMat);
    nostril.position.set(1.1, -0.15, z);
    headGroup.add(nostril);
});

// Eyes
[-0.35, 0.35].forEach(z => {
    const eyeWhiteGeo = new THREE.SphereGeometry(0.1, 10, 8);
    const eyeWhite = new THREE.Mesh(eyeWhiteGeo, eyeWhiteMat);
    eyeWhite.position.set(0.3, 0.2, z);
    headGroup.add(eyeWhite);

    const eyeGeo = new THREE.SphereGeometry(0.06, 10, 8);
    const eye = new THREE.Mesh(eyeGeo, eyeMat);
    eye.position.set(0.38, 0.2, z);
