    const ridge = new THREE.Mesh(ridgeGeo, brown);
    ridge.position.set(0.28, 0.25, z);
    ridge.rotation.x = -0.3;
    headGroup.add(ridge);
});

// Ears
[-0.5, 0.5].forEach(z => {
    const earGeo = new THREE.SphereGeometry(0.2, 10, 8);
    earGeo.scale(0.4, 0.6, 1.0);
    const ear = new THREE.Mesh(earGeo, brown);
    ear.position.set(-0.15, 0.45, z);
    ear.rotation.z = z > 0 ? 0.3 : -0.3;
    ear.rotation.x = 0.2;
    ear.castShadow = true;
    headGroup.add(ear);
});

// ── Horns ──
function createHorn(side) {
    const hornGroup = new THREE.Group();
    const points = [];
    const segments = 20;
    for (let i = 0; i <= segments; i++) {
        const t = i / segments;
        const x = -0.3 + t * 0.3;
        const y = 0.3 + t * 1.2 - Math.pow(t, 2) * 0.3;
        const z = side * (0.4 + t * 0.8 + Math.sin(t * Math.PI) * 0.2);
        points.push(new THREE.Vector3(x, y, z));
    }
    const curve = new THREE.CatmullRomCurve3(points);
    const tubeGeo = new THREE.TubeGeometry(curve, 20, 0.08, 8, false);
    const horn = new THREE.Mesh(tubeGeo, hornMat);
    horn.castShadow = true;
    hornGroup.add(horn);

    // Horn tip (slightly broader)
    const tipGeo = new THREE.SphereGeometry(0.1, 8, 6);
    const tip = new THREE.Mesh(tipGeo, hornMat);
    const lastPoint = points[points.length - 1];
    tip.position.set(lastPoint.x, lastPoint.y, lastPoint.z);
    hornGroup.add(tip);

    return hornGroup;
}

headGroup.add(createHorn(1));
headGroup.add(createHorn(-1));

buffalo.add(headGroup);

// ── Mane ──
const maneGroup = new THREE.Group();
for (let i = 0; i < 12; i++) {
