    );
    manePiece.castShadow = true;
    maneGroup.add(manePiece);
}
buffalo.add(maneGroup);

// ── Legs ──
function createLeg(x, z, isFront) {
    const legGroup = new THREE.Group();

    // Upper leg
    const upperLegGeo = new THREE.CylinderGeometry(0.22, 0.2, 1.8, 10);
    const upperLeg = new THREE.Mesh(upperLegGeo, darkBrown);
    upperLeg.position.y = -0.9;
    upperLeg.castShadow = true;
    legGroup.add(upperLeg);

    // Knee joint
    const kneeGeo = new THREE.SphereGeometry(0.22, 10, 8);
    const knee = new THREE.Mesh(kneeGeo, brown);
    knee.position.y = -1.8;
    knee.castShadow = true;
    legGroup.add(knee);

    // Lower leg
    const lowerLegGeo = new THREE.CylinderGeometry(0.18, 0.15, 1.4, 10);
    const lowerLeg = new THREE.Mesh(lowerLegGeo, brown);
    lowerLeg.position.y = -2.5;
    lowerLeg.castShadow = true;
    legGroup.add(lowerLeg);

    // Hoof
    const hoofGeo = new THREE.BoxGeometry(0.32, 0.15, 0.22, 1, 1, 1);
    const hoof = new THREE.Mesh(hoofGeo, hoofMat);
    hoof.position.y = -3.25;
    hoof.castShadow = true;
    legGroup.add(hoof);

    legGroup.position.set(x, 2.4, z);
    return legGroup;
