const swMat = new THREE.MeshStandardMaterial({ color: 0x999999, roughness: 0.8 });
[-7, 7].forEach(x => {
  const sw = new THREE.Mesh(swGeo, swMat);
  sw.position.set(x, 0.15, 0);
  sw.receiveShadow = true;
  scene.add(sw);
});

// --- Grass ---
const grassGeo = new THREE.PlaneGeometry(100, 100);
const grassMat = new THREE.MeshStandardMaterial({ color: 0x4a7c3f, roughness: 1 });
const grass = new THREE.Mesh(grassGeo, grassMat);
grass.rotation.x = -Math.PI / 2;
grass.position.y = -0.01;
scene.add(grass);

// --- Simple trees ---
function createTree(x, z) {
  const group = new THREE.Group();
  const trunkGeo = new THREE.CylinderGeometry(0.2, 0.3, 2, 8);
  const trunkMat = new THREE.MeshStandardMaterial({ color: 0x5D4037 });
  const trunk = new THREE.Mesh(trunkGeo, trunkMat);
  trunk.position.y = 1;
  trunk.castShadow = true;
  group.add(trunk);

  const leavesGeo = new THREE.SphereGeometry(1.2, 8, 8);
  const leavesMat = new THREE.MeshStandardMaterial({ color: 0x2E7D32 });
  const leaves = new THREE.Mesh(leavesGeo, leavesMat);
  leaves.position.y = 2.8;
  leaves.castShadow = true;
  group.add(leaves);

  group.position.set(x, 0, z);
  scene.add(group);
}

for (let i = -3; i <= 3; i++) {
  createTree(-9, i * 6);
  createTree(9, i * 6);
}

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle bus bob
  bus.position.y = 0.2 + Math.sin(t * 1.5) * 0.03;

  // Wheel rotation
  wheels.forEach(w => {
    w.children[0].rotation.x += 0.02;
    w.children[1].rotation.x += 0.02;
    for (let i = 2; i < w.children.length; i++) {
      w.children[i].rotation.x += 0.02;
    }
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
