  <div id="info">🌿 Bush — drag to orbit · scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    /* ── Scene, Camera, Renderer ─────────────────────────────── */
    const scene    = new THREE.Scene();
    scene.background = new THREE.Color(0x87ceeb);
    scene.fog = new THREE.FogExp2(0x87ceeb, 0.018);

    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
    camera.position.set(4, 3.5, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 1.2, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.maxPolarAngle = Math.PI / 2.05;
    controls.minDistance = 3;
    controls.maxDistance = 18;

    /* ── Lights ──────────────────────────────────────────────── */
    const ambient = new THREE.AmbientLight(0x406040, 0.8);
    scene.add(ambient);

    const sun = new THREE.DirectionalLight(0xfff4e0, 2.2);
    sun.position.set(5, 10, 4);
    sun.castShadow = true;
    sun.shadow.mapSize.set(1024, 1024);
    sun.shadow.camera.near = 1;
    sun.shadow.camera.far  = 30;
    sun.shadow.camera.left = sun.shadow.camera.bottom = -6;
    sun.shadow.camera.right = sun.shadow.camera.top = 6;
    scene.add(sun);

    const fill = new THREE.DirectionalLight(0x8090ff, 0.4);
    fill.position.set(-4, 3, -3);
    scene.add(fill);

    /* ── Ground ──────────────────────────────────────────────── */
    const groundGeo = new THREE.CircleGeometry(30, 64);
    const groundMat = new THREE.MeshStandardMaterial({
      color: 0x3a7d32, roughness: 1, metalness: 0
    });
    const ground = new THREE.Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // dirt patch under bush
    const dirtGeo = new THREE.CircleGeometry(1.6, 32);
    const dirtMat = new THREE.MeshStandardMaterial({ color: 0x5a3e28, roughness: 1 });
    const dirt = new THREE.Mesh(dirtGeo, dirtMat);
    dirt.rotation.x = -Math.PI / 2;
    dirt.position.y = 0.005;
    dirt.receiveShadow = true;
    scene.add(dirt);

    /* ── Bush Construction ───────────────────────────────────── */
    const bushGroup = new THREE.Group();
    scene.add(bushGroup);

    // Simple seeded RNG
    function mulberry32(a) {
      return () => {
        a |= 0; a = a + 0x6D2B79F5 | 0;
        let t = Math.imul(a ^ a >>> 15, 1 | a);
        t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
        return ((t ^ t >>> 14) >>> 0) / 4294967296;
      };
    }
    const rand = mulberry32(42);

    // Leaf cluster data: position + radius
    const clusters = [];

    // Main body — dense packing
    const bodyPositions = [];
    for (let i = 0; i < 120; i++) {
      const theta = rand() * Math.PI * 2;
      const phi   = Math.acos(2 * rand() - 1);
      const r     = 0.5 + rand() * 1.1;
      bodyPositions.push({
        x: r * Math.sin(phi) * Math.cos(theta),
        y: r * Math.sin(phi) * Math.sin(theta) + 1.0,
        z: r * Math.cos(phi),
        radius: 0.25 + rand() * 0.3
      });
    }
    clusters.push(...bodyPositions);

    // Top tuft
    for (let i = 0; i < 25; i++) {
      clusters.push({
        x: (rand() - 0.5) * 0.6,
        y: 1.6 + rand() * 0.6,
        z: (rand() - 0.5) * 0.6,
        radius: 0.2 + rand() * 0.25
      });
    }

    // Side bulges
    for (let side = 0; side < 4; side++) {
      const angle = (side / 4) * Math.PI * 2 + rand() * 0.5;
      for (let i = 0; i < 12; i++) {
        clusters.push({
          x: Math.cos(angle) * (1.0 + rand() * 0.4) + (rand() - 0.5) * 0.3,
          y: 0.6 + rand() * 0.9,
          z: Math.sin(angle) * (1.0 + rand() * 0.4) + (rand() - 0.5) * 0.3,
          radius: 0.25 + rand() * 0.3
        });
      }
    }

    // Create meshes with instancing for performance
    const leafGeo = new THREE.IcosahedronGeometry(1, 1);
    // Slightly deform vertices for organic look
    const posAttr = leafGeo.attributes.position;
    for (let i = 0; i < posAttr.count; i++) {
      const x = posAttr.getX(i), y = posAttr.getY(i), z = posAttr.getZ(i);
      const noise = 1 + (Math.sin(x * 5) * Math.cos(z * 3) * 0.08);
      posAttr.setXYZ(i, x * noise, y * noise, z * noise);
    }
    leafGeo.computeVertexNormals();

    const leafMat = new THREE.MeshStandardMaterial({
      roughness: 0.85,
      metalness: 0.0,
      flatShading: true
    });

    const leafMesh = new THREE.InstancedMesh(leafGeo, leafMat, clusters.length);
    leafMesh.castShadow = true;
    leafMesh.receiveShadow = true;

    const dummy = new THREE.Object3D();
    const color = new THREE.Color();

    clusters.forEach((c, i) => {
      dummy.position.set(c.x, c.y, c.z);
      dummy.scale.setScalar(c.radius);
      dummy.rotation.set(rand() * Math.PI, rand() * Math.PI, rand() * Math.PI);
      dummy.updateMatrix();
      leafMesh.setMatrixAt(i, dummy.matrix);

      // Green palette variation
      const hue = 0.25 + rand() * 0.12;        // green to yellow-green
      const sat = 0.5 + rand() * 0.4;
      const lit = 0.25 + rand() * 0.3;
      color.setHSL(hue, sat, lit);
      leafMesh.setColorAt(i, color);
    });

    leafMesh.instanceMatrix.needsUpdate = true;
    leafMesh.instanceColor.needsUpdate = true;
    bushGroup.add(leafMesh);

    /* ── Twigs / Branches ────────────────────────────────────── */
    const twigMat = new THREE.MeshStandardMaterial({
      color: 0x4a3520, roughness: 0.95, flatShading: true
    });

    function makeTwig(start, end, radius) {
      const dir = new THREE.Vector3().subVectors(end, start);
      const len = dir.length();
      const geo = new THREE.CylinderGeometry(radius * 0.6, radius, len, 5, 1);
      const mesh = new THREE.Mesh(geo, twigMat);
      mesh.position.copy(start).add(end).multiplyScalar(0.5);
      mesh.quaternion.setFromUnitVectors(new THREE.Vector3(0, 1, 0), dir.normalize());
      mesh.castShadow = true;
      bushGroup.add(mesh);
    }

    // Main stems
    for (let i = 0; i < 6; i++) {
      const angle = (i / 6) * Math.PI * 2;
      const base = new THREE.Vector3(Math.cos(angle) * 0.15, 0.2, Math.sin(angle) * 0.15);
      const tip  = new THREE.Vector3(
        Math.cos(angle) * (0.6 + rand() * 0.5),
        0.8 + rand() * 0.8,
        Math.sin(angle) * (0.6 + rand() * 0.5)
      );
      makeTwig(base, tip, 0.04 + rand() * 0.03);

      // Sub-branches
      if (rand() > 0.3) {
        const mid = new THREE.Vector3().lerpVectors(base, tip, 0.5 + rand() * 0.3);
        const subAngle = angle + (rand() - 0.5) * 1.2;
        const subTip = new THREE.Vector3(
          mid.x + Math.cos(subAngle) * (0.2 + rand() * 0.3),
          mid.y + 0.1 + rand() * 0.4,
          mid.z + Math.sin(subAngle) * (0.2 + rand() * 0.3)
        );
        makeTwig(mid, subTip, 0.02 + rand() * 0.015);
      }
    }

    /* ── Small Flowers ───────────────────────────────────────── */
    const flowerColors = [0xff6b8a, 0xffd700, 0xff4466, 0xffffff, 0xffaa44];
    const flowerGeo = new THREE.SphereGeometry(1, 6, 4);

    const flowerCount = 18;
    const flowerMesh = new THREE.InstancedMesh(flowerGeo, new THREE.MeshStandardMaterial({
      roughness: 0.6, flatShading: true
    }), flowerCount);

    for (let i = 0; i < flowerCount; i++) {
      const theta = rand() * Math.PI * 2;
      const phi   = Math.acos(2 * rand() - 1);
      const r     = 0.6 + rand() * 0.7;
      dummy.position.set(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta) + 1.0,
        r * Math.cos(phi)
      );
      const s = 0.04 + rand() * 0.05;
      dummy.scale.setScalar(s);
      dummy.updateMatrix();
      flowerMesh.setMatrixAt(i, dummy.matrix);
      color.setHex(flowerColors[Math.floor(rand() * flowerColors.length)]);
      flowerMesh.setColorAt(i, color);
    }
    flowerMesh.instanceMatrix.needsUpdate = true;
    flowerMesh.instanceColor.needsUpdate = true;
    bushGroup.add(flowerMesh);

    /* ── Grass Tufts Around Bush ─────────────────────────────── */
    const grassBladeGeo = new THREE.PlaneGeometry(0.06, 0.4);
    grassBladeGeo.translate(0, 0.2, 0);
    const grassMat = new THREE.MeshStandardMaterial({
      color: 0x2d6b24, roughness: 1, side: THREE.DoubleSide, flatShading: true
    });
    const grassCount = 200;
    const grassMesh = new THREE.InstancedMesh(grassBladeGeo, grassMat, grassCount);

    for (let i = 0; i < grassCount; i++) {
      const angle = rand() * Math.PI * 2;
      const dist  = 1.3 + rand() * 3;
      dummy.position.set(
        Math.cos(angle) * dist,
        0,
        Math.sin(angle) * dist
      );
      dummy.rotation.set(
        (rand() - 0.5) * 0.4,
        rand() * Math.PI,
        (rand() - 0.5) * 0.3
      );
      dummy.scale.set(0.8 + rand() * 0.6, 0.6 + rand() * 1.0, 1);
      dummy.updateMatrix();
      grassMesh.setMatrixAt(i, dummy.matrix);
    }
    grassMesh.instanceMatrix.needsUpdate = true;
    grassMesh.castShadow = true;
    scene.add(grassMesh);

    /* ── Animation ───────────────────────────────────────────── */
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Gentle wind sway on leaf clusters
      const matrices = leafMesh.instanceMatrix.array;
      for (let i = 0; i < clusters.length; i++) {
        const c = clusters[i];
        const swayX = Math.sin(t * 1.2 + c.x * 2 + c.z) * 0.02 * c.radius;
        const swayZ = Math.cos(t * 0.9 + c.y * 1.5 + c.x) * 0.015 * c.radius;

        dummy.position.set(c.x + swayX, c.y, c.z + swayZ);
        dummy.scale.setScalar(c.radius);
        dummy.rotation.set(
          (rand() * Math.PI),  // keep original-ish rotation
          (rand() * Math.PI),
          (rand() * Math.PI)
        );
        // We'll just translate — rotations from initial build are baked in
        dummy.rotation.set(0, 0, 0); // reset rotation for clean translation
        dummy.updateMatrix();
        leafMesh.setMatrixAt(i, dummy.matrix);
      }
      leafMesh.instanceMatrix.needsUpdate = true;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    /* ── Resize ──────────────────────────────────────────────── */
