// ── Catenary Curve ──
function catenaryCurve(a, x1, x2, segments) {
  const points = [];
  for (let i = 0; i <= segments; i++) {
    const t = i / segments;
    const x = x1 + (x2 - x1) * t;
    const y = a * Math.cosh(x / a) - a * Math.cosh(x1 / a);
    points.push(new THREE.Vector3(x, y, 0));
  }
  return new THREE.CatmullRomCurve3(points);
}

