const screenGeo = new THREE.PlaneGeometry(2.1, 0.7);
let screenText = '0';
let screenTex = createTextTexture(screenText, 512, 170, 64, '#00ff88', '#0a1a0a');
const screenMat = new THREE.MeshStandardMaterial({
  map: screenTex, emissiveMap: screenTex, emissive: new THREE.Color(0x00ff88),
  emissiveIntensity: 0.5, roughness: 0.5
});
const screen = new THREE.Mesh(screenGeo, screenMat);
screen.position.set(0, 0.08, -1.2);
screen.rotation.x = -0.15;
calc.add(screen);

// Screen border
const borderGeo = new THREE.BoxGeometry(2.2, 0.04, 0.85);
const borderMat = new THREE.MeshStandardMaterial({ color: 0x333344, roughness: 0.3, metalness: 0.5 });
const border = new THREE.Mesh(borderGeo, borderMat);
border.position.set(0, 0.07, -1.2);
calc.add(border);

// ── Button System ──
const buttons = [];
const buttonGroup = new THREE.Group();
calc.add(buttonGroup);

function makeLabelTexture(label, w, h, size, fg, bg) {
  const c = document.createElement('canvas');
  c.width = w; c.height = h;
  const ctx = c.getContext('2d');
  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, w, h);
  ctx.fillStyle = fg;
  ctx.font = `bold ${size}px monospace`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(label, w / 2, h / 2);
  return new THREE.CanvasTexture(c);
}

function createButton(label, x, y, z, color, labelColor, size = 1) {
  const btnGeo = new THREE.BoxGeometry(0.55 * size, 0.08, 0.55 * size);
  const tex = makeLabelTexture(label, 256, 256, 100, labelColor, color);
  const btnMat = new THREE.MeshStandardMaterial({
    map: tex, color: new THREE.Color(color),
    roughness: 0.4, metalness: 0.3,
    bumpMap: tex, bumpScale: 0.005
  });
  const btn = new THREE.Mesh(btnGeo, btnMat);
  btn.position.set(x, y, z);
  btn.castShadow = true;
  btn.receiveShadow = true;
  btn.userData = { label, baseY: y, color, labelColor, size, pressed: false };
  buttonGroup.add(btn);
  buttons.push(btn);
  return btn;
}

const BY = 0.12;

// Row layout: z goes from -0.5 to 1.1
// Numbers & ops
const layout = [
  ['C',  '±', '%', '÷'],
  ['7',  '8', '9', '×'],
  ['4',  '5', '6', '-'],
  ['1',  '2', '3', '+'],
  ['0',  '.', '=']
];

const opColor = '#ff8844';
const numColor = '#444458';
const eqColor = '#ff8844';
const numLabel = '#eeeeff';
const opLabel = '#ffffff';

layout.forEach((row, ri) => {
  const z = -0.45 + ri * 0.65;
  const rowSize = row.length === 4 ? 1 : 1;
  const startX = row.length === 3 ? -0.6 : -0.875;
  row.forEach((label, ci) => {
    const x = startX + ci * 0.65;
    let color = numColor, lColor = numLabel;
    if ('÷×-+%'.includes(label) || label === '±') { color = opColor; lColor = opLabel; }
    if (label === '=') { color = eqColor; lColor = opLabel; }
    if (label === 'C') { color = '#cc3333'; lColor = '#fff'; }
    const s = label === '0' ? 2 : 1;
    createButton(label, x, BY, z, color, lColor, s);
  });
});

// ── Calculator Logic ──
let expression = '';
let display = '0';
let newNumber = true;
let lastResult = null;

function updateScreen() {
  screenText = display;
  screenTex = createTextTexture(screenText, 512, 170, 64, '#00ff88', '#0a1a0a');
  screenMat.map = screenTex;
  screenMat.emissiveMap = screenTex;
  screenMat.needsUpdate = true;
}

function evaluate() {
  try {
    const expr = expression.replace(/×/g, '*').replace(/÷/g, '/');
    const result = Function('"use strict"; return (' + expr + ')')();
    display = String(Math.round(result * 1e10) / 1e10);
    if (display.length > 12) display = parseFloat(result).toExponential(6);
    expression = display;
    lastResult = result;
  } catch {
    display = 'Error';
    expression = '';
  }
  updateScreen();
}

function handlePress(label) {
  if (label === 'C') {
    expression = ''; display = '0'; newNumber = true; lastResult = null;
  } else if (label === '=') {
    if (expression) { evaluate(); newNumber = true; }
  } else if (label === '±') {
    if (expression && !newNumber) {
      expression = expression.startsWith('-') ? expression.slice(1) : '-' + expression;
      display = expression;
    }
  } else if (label === '%') {
    try {
      const v = parseFloat(expression || '0') / 100;
      display = String(v); expression = display;
    } catch {}
  } else if ('0123456789.'.includes(label)) {
    if (newNumber) { expression = label; newNumber = false; }
    else {
      if (label === '.' && expression.includes('.')) return;
      expression += label;
    }
    display = expression;
  } else {
    // operator
    if (expression && !newNumber) {
      expression += ' ' + label + ' ';
      newNumber = true;
    } else if (newNumber && lastResult !== null) {
      expression = display + ' ' + label + ' ';
      newNumber = true;
    }
    display = expression;
  }
  updateScreen();
}

// ── Raycasting ──
const raycaster = new THREE.Raycaster();
const mouse = new THREE.Vector2();
let hovered = null;

renderer.domElement.addEventListener('pointerdown', (e) => {
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);
  const hits = raycaster.intersectObjects(buttons);
  if (hits.length) {
    const btn = hits[0].object;
    handlePress(btn.userData.label);
    // Animate press
    btn.position.y = btn.userData.baseY - 0.03;
    btn.userData.pressed = true;
  }
});

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const dt = clock.getDelta();
  const t = clock.getElapsedTime();

  controls.update();

  // Button hover / press animation
  mouse.x = (event?.clientX ?? innerWidth / 2) / innerWidth * 2 - 1;
  mouse.y = -(event?.clientY ?? innerHeight / 2) / innerHeight * 2 + 1;
  raycaster.setFromCamera(mouse, camera);
  const hits = raycaster.intersectObjects(buttons);
  const newHovered = hits.length ? hits[0].object : null;

  if (newHovered !== hovered) {
    if (hovered && !hovered.userData.pressed) {
      hovered.material.emissive?.set(hovered.userData.color);
      hovered.material.emissiveIntensity = 0;
    }
    hovered = newHovered;
    if (hovered) {
      hovered.material.emissive?.set(0xffffff);
      hovered.material.emissiveIntensity = 0.15;
      renderer.domElement.style.cursor = 'pointer';
    } else {
      renderer.domElement.style.cursor = 'default';
    }
  }

  // Spring buttons back up
  buttons.forEach(b => {
    if (b.userData.pressed) {
      b.position.y += (b.userData.baseY - b.position.y) * 0.2;
      if (Math.abs(b.position.y - b.userData.baseY) < 0.001) {
        b.position.y = b.userData.baseY;
        b.userData.pressed = false;
      }
    }
  });

  // Subtle float
  calc.position.y = Math.sin(t * 0.8) * 0.03;
  calc.rotation.y = Math.sin(t * 0.3) * 0.02;

  renderer.render(scene, camera);
}

window.addEventListener('mousemove', e => { event = e; });
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

animate();
</script>
</body>
</html>
