// ── Canoe Hull ──
function createCanoeHull() {
  const segments = 40;       // longitudinal
  const ringSegs = 16;       // around cross-section

  const positions = [];
  const normals = [];
  const indices = [];

  const length = 10;
  const maxBeam = 1.8;
  const maxDepth = 0.65;

  for (let i = 0; i <= segments; i++) {
    const t = i / segments;
    const x = (t - 0.5) * length;

    // Hull profile functions
    const beam = maxBeam * Math.cos(t * Math.PI) * Math.cos(t * Math.PI);
    const depth = maxDepth * Math.cos(t * Math.PI);

    // Taper the bow and stern more sharply
    const bowStern = Math.pow(Math.cos((t - 0.5) * Math.PI), 0.7);
    const finalBeam = beam * bowStern;
    const finalDepth = depth * Math.pow(bowStern, 0.5);

    for (let j = 0; j <= ringSegs; j++) {
      const theta = (j / ringSegs) * Math.PI; // half ellipse (bottom only)

      const width = finalBeam * 0.5 * Math.cos(theta);
      const y = -finalDepth * 0.5 * Math.sin(theta);

      // Add slight V-shape to hull cross-section
      const vFactor = 0.3;
      const hullY = -finalDepth * 0.5 * (Math.pow(Math.sin(theta), 1.5) + vFactor * Math.sin(theta));

      // Gunwale flare at the top
      const flare = 0.12 * Math.cos(theta) * (1 - Math.pow(Math.sin(theta), 3));

      positions.push(x + flare, hullY, width);

      // Approximate normal
      const nx = 0;
      const ny = -Math.cos(theta) * 0.5;
      const nz = Math.sin(theta) * 0.5;
      const n = new THREE.Vector3(nx, ny, nz).normalize();
      normals.push(n.x, n.y, n.z);
    }
  }

  // Build indices (triangles between rings)
  for (let i = 0; i < segments; i++) {
    for (let j = 0; j < ringSegs; j++) {
      const a = i * (ringSegs + 1) + j;
      const b = a + ringSegs + 1;
      indices.push(a, b, a + 1);
      indices.push(a + 1, b, b + 1);
    }
  }

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3));
  geometry.setIndex(indices);
  geometry.computeVertexNormals();

  return geometry;
}

