function createGunwale(side) {
  const points = [];
  const segments = 40;
  const length = 10;
  const maxBeam = 1.8;

  for (let i = 0; i <= segments; i++) {
    const t = i / segments;
    const x = (t - 0.5) * length;
    const bowStern = Math.pow(Math.cos((t - 0.5) * Math.PI), 0.7);
    const beam = maxBeam * Math.cos(t * Math.PI) * Math.cos(t * Math.PI) * bowStern;
    const z = side * (beam * 0.5 + 0.12);
    const y = 0.05;
    points.push(new THREE.Vector3(x, y, z));
  }

  const curve = new THREE.CatmullRomCurve3(points);
  const tubeGeo = new THREE.TubeGeometry(curve, 40, 0.035, 8, false);
  return tubeGeo;
}

