rimLight.position.set(-2, 1, -3);
scene.add(rimLight);

// --- Carrot Body (LatheGeometry) ---
const points = [];
const segments = 30;
for (let i = 0; i <= segments; i++) {
  const t = i / segments;
  const y = t * 3 - 0.5;
  // Carrot profile: fat middle, tapered top & pointed bottom
  let r;
  if (t < 0.15) {
    // Top (near leaves): narrow
    r = 0.15 + t * 2.5;
  } else if (t < 0.55) {
    // Bulbous middle
    r = 0.52 + Math.sin((t - 0.15) / 0.4 * Math.PI) * 0.18;
  } else {
    // Tapered bottom
    const tt = (t - 0.55) / 0.45;
    r = 0.52 * (1 - tt * tt * 0.85);
  }
  points.push(new THREE.Vector2(Math.max(r, 0.01), y));
}

const carrotGeo = new THREE.LatheGeometry(points, 32);
carrotGeo.computeVertexNormals();

const carrotMat = new THREE.MeshStandardMaterial({
  color: 0xe8751a,
  roughness: 0.55,
  metalness: 0.05,
});

const carrot = new THREE.Mesh(carrotGeo, carrotMat);
carrot.castShadow = true;
carrot.receiveShadow = true;

