const ringMat = new THREE.MeshStandardMaterial({ color: 0xd46a12, roughness: 0.6 });

for (let i = 0; i < 6; i++) {
  const ring = new THREE.Mesh(ringGeo, ringMat);
  ring.position.y = -0.2 + i * 0.35;
  ring.rotation.x = Math.PI / 2;
  ring.scale.setScalar(0.95 - i * 0.04);
  carrot.add(ring);
}

// --- Leaves ---
