leafGroup.position.y = 2.6;

function createLeaf(angle, length, curve, tilt) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(length * 0.3, curve * 0.5, length, curve);
  shape.quadraticCurveTo(length * 0.3, -curve * 0.2, 0, 0);

  const geo = new THREE.ShapeGeometry(shape, 12);
  const mat = new THREE.MeshStandardMaterial({
    color: 0x3a8c2a,
    roughness: 0.7,
    metalness: 0.0,
    side: THREE.DoubleSide,
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.rotation.y = angle;
  mesh.rotation.x = tilt;
  mesh.castShadow = true;
  return mesh;
}

const leafData = [
  { a: 0,    l: 1.8, c: 0.4, t: -0.6 },
  { a: Math.PI * 0.4, l: 1.5, c: 0.3, t: -0.5 },
  { a: Math.PI * 0.8, l: 1.6, c: 0.35, t: -0.55 },
  { a: Math.PI * 1.2, l: 1.4, c: 0.25, t: -0.45 },
  { a: Math.PI * 1.6, l: 1.7, c: 0.3, t: -0.5 },
  { a: Math.PI * 0.2, l: 1.2, c: 0.2, t: -0.35 },
  { a: Math.PI * 1.0, l: 1.3, c: 0.2, t: -0.4 },
];

leafData.forEach(l => {
  leafGroup.add(createLeaf(l.a, l.l, l.c, l.t));
});

// Small leaf base
const baseGeo = new THREE.SphereGeometry(0.18, 16, 8);
const baseMat = new THREE.MeshStandardMaterial({ color: 0x4a9e32, roughness: 0.6 });
const base = new THREE.Mesh(baseGeo, baseMat);
leafGroup.add(base);

const carrotGroup = new THREE.Group();
carrotGroup.add(carrot);
carrotGroup.add(leafGroup);
scene.add(carrotGroup);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(4, 64);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x2a2a3e, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.5;
ground.receiveShadow = true;
scene.add(ground);

// --- Animation ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  carrotGroup.rotation.y = t * 0.4;
  carrotGroup.position.y = Math.sin(t * 0.8) * 0.15;

  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
