const fill = new THREE.DirectionalLight(0x8ec5fc, 0.6);
fill.position.set(-8, 4, -6);
scene.add(fill);

/* ── Ground ── */
const groundGeo = new THREE.PlaneGeometry(100, 100);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x3a7d44, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Road
const roadGeo = new THREE.PlaneGeometry(6, 60);
const roadMat = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.8 });
const road = new THREE.Mesh(roadGeo, roadMat);
road.rotation.x = -Math.PI / 2;
road.position.y = 0.005;
road.receiveShadow = true;
scene.add(road);

// Road lines
for (let z = -25; z < 25; z += 4) {
  const lineGeo = new THREE.PlaneGeometry(0.15, 2);
  const lineMat = new THREE.MeshStandardMaterial({ color: 0xffffff });
