cabin.castShadow = true;
car.add(cabin);

// Windshield (front glass)
const windshieldGeo = new THREE.BoxGeometry(1.75, 0.55, 0.08);
const windshield = new THREE.Mesh(windshieldGeo, glassMat);
windshield.position.set(0, 1.2, 0.88);
windshield.rotation.x = -0.35;
car.add(windshield);

// Rear window
const rearWindowGeo = new THREE.BoxGeometry(1.75, 0.5, 0.08);
const rearWindow = new THREE.Mesh(rearWindowGeo, glassMat);
rearWindow.position.set(0, 1.22, -1.28);
rearWindow.rotation.x = 0.3;
car.add(rearWindow);

