  hub.rotation.z = Math.PI / 2;
  group.add(hub);

  return group;
}

const wheelPositions = [
  { x: -1.1, y: 0.38, z: 1.45 },
  { x:  1.1, y: 0.38, z: 1.45 },
  { x: -1.1, y: 0.38, z: -1.45 },
  { x:  1.1, y: 0.38, z: -1.45 },
];

const wheels = [];
wheelPositions.forEach(pos => {
  const wheel = createWheel();
  wheel.position.set(pos.x, pos.y, pos.z);
  car.add(wheel);
  wheels.push(wheel);
});

// ── Door lines ──
for (const side of [-1, 1]) {
