  const leavesGeo = new THREE.SphereGeometry(0.9, 8, 8);
  const leavesMat = new THREE.MeshStandardMaterial({ color: 0x2d6b30, roughness: 0.8 });
  const leaves = new THREE.Mesh(leavesGeo, leavesMat);
  leaves.position.y = 2.0;
  leaves.castShadow = true;
  tree.add(leaves);

  tree.position.set(x, 0, z);
  scene.add(tree);
}

for (let z = -25; z < 25; z += 5) {
  createTree(-5.5, z + Math.random() * 2);
  createTree(5.5, z + Math.random() * 2);
}

/* ── Animation ── */
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle idle bob
  car.position.y = Math.sin(t * 1.5) * 0.015;

  // Subtle wheel spin (idle)
  wheels.forEach(w => {
    w.children[0].rotation.x = t * 0.3;
    w.children[1].rotation.x = t * 0.3;
    w.children[2].rotation.x = t * 0.3;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();

/* ── Resize ── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
