const scene = new THREE.Scene();
scene.background = new THREE.Color(0x020205);
scene.fog = new THREE.FogExp2(0x020208, 0.035);

// ─── Camera ────────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(70, window.innerWidth / window.innerHeight, 0.1, 200);
camera.position.set(0, 2, 0);

// ─── Noise ─────────────────────────────────────────────────
const perlin = new ImprovedNoise();
function fbm(x, y, z, octaves = 4) {
  let val = 0, amp = 0.5, freq = 1;
  for (let i = 0; i < octaves; i++) {
    val += amp * perlin.noise(x * freq, y * freq, z * freq);
    amp *= 0.5; freq *= 2.1;
  }
  return val;
}

// ─── Cave Path ─────────────────────────────────────────────
const pathPoints = [];
const pathLength = 120;
for (let i = 0; i <= 200; i++) {
  const t = i / 200;
  const z = -t * pathLength;
  const x = Math.sin(t * 3.7) * 4 + Math.sin(t * 7.3) * 1.5 + Math.cos(t * 1.3) * 2;
  const y = Math.cos(t * 2.9) * 2.5 + Math.sin(t * 5.1) * 1.2 + 1;
  pathPoints.push(new THREE.Vector3(x, y, z));
}
const caveCurve = new THREE.CatmullRomCurve3(pathPoints, false, 'catmullrom', 0.5);

// ─── Cave Tunnel (Tube) ────────────────────────────────────
const tubeRadius = 4.5;
const tubeSegments = 200;
const tubeRadialSegments = 32;
const tubeGeo = new THREE.TubeGeometry(caveCurve, tubeSegments, tubeRadius, tubeRadialSegments, false);

