const posAttr = tubeGeo.attributes.position;
const vertCount = posAttr.count;
const normals = [];

for (let i = 0; i < vertCount; i++) {
  const x = posAttr.getX(i);
  const y = posAttr.getY(i);
  const z = posAttr.getZ(i);

  const nx = x, ny = y, nz = z;
  const len = Math.sqrt(nx*nx + ny*ny + nz*nz) || 1;

  // Get direction from curve center
  const t = Math.max(0, Math.min(1, (pathLength + z) / pathLength));
  const center = caveCurve.getPointAt(t);

  const dx = x - center.x, dy = y - center.y, dz = z - center.z;
  const dLen = Math.sqrt(dx*dx + dy*dy + dz*dz) || 1;

  // Normalized direction from center
  const ndx = dx / dLen, ndy = dy / dLen, ndz = dz / dLen;

  // Noise displacement
  const scale = 0.8;
  const n1 = fbm(x * scale + 10, y * scale, z * scale, 4);
  const n2 = fbm(x * scale * 2.5 + 50, y * scale * 2.5 + 5, z * scale * 2.5, 3);
  const n3 = fbm(x * scale * 0.3, y * scale * 0.3 + 100, z * scale * 0.3, 3);

  const displacement = (n1 * 0.8 + n2 * 0.4 + n3 * 1.2) * 1.8;
  const pinch = 1.0 + n3 * 0.35; // Vary radius along tunnel

  const r = dLen + displacement;
  const newR = Math.max(0.8, r * pinch);

  posAttr.setXYZ(i, center.x + ndx * newR, center.y + ndy * newR, center.z + ndz * newR);

  normals.push(ndx, ndy, ndz);
}

