// ─── Floor & Ceiling Rocks ─────────────────────────────────
function createFloorCeiling() {
  const group = new THREE.Group();
  const rockGeo = new THREE.IcosahedronGeometry(1, 2);

  const rPos = rockGeo.attributes.position;
  for (let i = 0; i < rPos.count; i++) {
    const x = rPos.getX(i), y = rPos.getY(i), z = rPos.getZ(i);
    const n = fbm(x * 1.5, y * 1.5, z * 1.5, 3) * 0.4;
    const len = Math.sqrt(x*x + y*y + z*z);
    const scale = (len + n) / len;
    rPos.setXYZ(i, x * scale, y * scale, z * scale);
  }
  rockGeo.computeVertexNormals();

  const rockMat = new THREE.MeshStandardMaterial({
    color: 0x1e1a16, roughness: 0.9, metalness: 0.1, flatShading: true
  });

  for (let i = 0; i < 300; i++) {
    const t = Math.random();
    const center = caveCurve.getPointAt(t);
    const tangent = caveCurve.getTangentAt(t);
    const normal = new THREE.Vector3(-tangent.y, tangent.x, 0).normalize();
    const up = new THREE.Vector3(0, 1, 0);

    const side = Math.random() > 0.5 ? 1 : -1;
    const floorCeiling = Math.random() > 0.5;

    const offset = (Math.random() * 0.6 + 0.5) * tubeRadius * 0.85;
    const pos = center.clone()
      .add(normal.multiplyScalar(side * offset))
      .add(up.clone().multiplyScalar(floorCeiling ? (Math.random() - 0.3) : -(Math.random() * 1.5 + 0.5)));

    const scale = Math.random() * 1.5 + 0.3;
    const rock = new THREE.Mesh(rockGeo, rockMat);
    rock.position.copy(pos);
    rock.scale.setScalar(scale);
    rock.rotation.set(Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI);
    rock.castShadow = true;
    rock.receiveShadow = true;
    group.add(rock);
  }
  return group;
}
