<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { mergeGeometries } from 'three/addons/utils/BufferGeometryUtils.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(3, 3, 4);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);

// Lighting
scene.add(new THREE.AmbientLight(0xffeedd, 0.6));
const dir = new THREE.DirectionalLight(0xffffff, 1.8);
dir.position.set(5, 8, 4);
scene.add(dir);
const rim = new THREE.DirectionalLight(0xffaa44, 0.8);
rim.position.set(-4, 2, -3);
scene.add(rim);

// Cheese wedge shape
const shape = new THREE.Shape();
shape.moveTo(0, 0);
shape.lineTo(2.5, 0);
shape.lineTo(2.5, 0.3);
shape.lineTo(0.15, 0.3);
shape.lineTo(0.15, 1.8);
shape.quadraticCurveTo(0.15, 2.0, 0.35, 2.0);
shape.lineTo(1.5, 2.0);
shape.quadraticCurveTo(1.7, 2.0, 1.7, 1.8);
shape.lineTo(1.7, 0.3);
shape.lineTo(0, 0.3);
shape.closePath();

const extrudeSettings = { depth: 1.2, bevelEnabled: true, bevelThickness: 0.06, bevelSize: 0.06, bevelSegments: 4 };
const cheeseGeo = new THREE.ExtrudeGeometry(shape, extrudeSettings);

// Holes (Swiss cheese!)
const holePositions = [
  { x: 0.6, y: 1.2, z: 0.6, r: 0.18 },
  { x: 1.3, y: 1.5, z: 0.4, r: 0.14 },
  { x: 0.9, y: 0.7, z: 0.8, r: 0.16 },
  { x: 1.5, y: 1.0, z: 0.7, r: 0.12 },
  { x: 0.5, y: 1.6, z: 0.5, r: 0.13 },
  { x: 1.1, y: 0.9, z: 0.3, r: 0.15 },
  { x: 0.8, y: 1.4, z: 0.9, r: 0.11 },
  { x: 1.4, y: 1.7, z: 0.6, r: 0.10 },
];

const holeGeos = holePositions.map(h => {
  const g = new THREE.SphereGeometry(h.r, 16, 16);
  g.translate(h.x, h.y, h.z);
  return g;
});

// Subtract holes using a simple approach: render cheese with hole cutouts via CSG-like trick
// We'll use a custom approach: create the cheese and use small dark spheres embedded slightly inside
const cheeseMat = new THREE.MeshStandardMaterial({
  color: 0xf5c542,
  roughness: 0.75,
  metalness: 0.0,
  flatShading: false,
});

const cheese = new THREE.Mesh(cheeseGeo, cheeseMat);
cheese.rotation.y = Math.PI * 0.1;
scene.add(cheese);

// Embedded dark spheres for holes (slightly inside the surface)
const holeMat = new THREE.MeshStandardMaterial({ color: 0xb8922a, roughness: 0.9, metalness: 0 });
const holeGeo = mergeGeometries(holeGeos);
const holes = new THREE.Mesh(holeGeo, holeMat);
holes.position.copy(cheese.position);
holes.rotation.copy(cheese.rotation);
scene.add(holes);

// Rim highlights on holes
const rimMat = new THREE.MeshStandardMaterial({ color: 0xe8b830, roughness: 0.5, metalness: 0.1 });
const rimGeos = holePositions.map(h => {
  const g = new THREE.TorusGeometry(h.r, 0.02, 8, 24);
  g.translate(h.x, h.y, h.z + 0.01);
  return g;
});
const rims = new THREE.Mesh(mergeGeometries(rimGeos), rimMat);
rims.position.copy(cheese.position);
rims.rotation.copy(cheese.rotation);
scene.add(rims);

// Ground plane
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(6, 64),
  new THREE.MeshStandardMaterial({ color: 0x2a2a3e, roughness: 1 })
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.05;
scene.add(ground);

// Shadow
const shadow = new THREE.Mesh(
  new THREE.CircleGeometry(1.8, 32),
  new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.25 })
);
shadow.rotation.x = -Math.PI / 2;
shadow.position.y = -0.02;
scene.add(shadow);

// Animate
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();
  cheese.rotation.y = Math.PI * 0.1 + t * 0.3;
  holes.rotation.y = cheese.rotation.y;
  rims.rotation.y = cheese.rotation.y;
  cheese.position.y = Math.sin(t * 0.8) * 0.1;
  holes.position.y = cheese.position.y;
  rims.position.y = cheese.position.y;
  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

This single HTML file features:

- **Cheese wedge** — an extruded shape with a curved crust edge and beveled edges for realism
- **Swiss cheese holes** — dark embedded spheres with subtle golden rim rings to simulate depth
- **Warm lighting** — ambient + directional + rim light for a rich golden glow
- **Gentle animation** — slow rotation and a soft floating bob
- **OrbitControls** — click and drag to rotate, scroll to zoom
- **Dark moody background** with a ground plane and soft shadow

