```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Cherry</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
#info {
  position: absolute; bottom: 20px; left: 50%; transform: translateX(-50%);
  color: #ccc; font-family: 'Segoe UI', sans-serif; font-size: 14px;
  background: rgba(0,0,0,0.5); padding: 8px 18px; border-radius: 20px;
  pointer-events: none;
}
</style>
</head>
<body>
<div id="info">🍒 Drag to rotate · Scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.04);

// ── Camera ─────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);

// ── Renderer ───────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ── Controls ───────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0.5, 0);
controls.minDistance = 3;
controls.maxDistance = 15;

// ── Lighting ───────────────────────────────────────────
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const keyLight = new THREE.DirectionalLight(0xfff4e6, 3);
keyLight.position.set(5, 8, 5);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
keyLight.shadow.camera.near = 0.1;
keyLight.shadow.camera.far = 20;
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8888ff, 0.6);
fillLight.position.set(-4, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xff6688, 2, 15);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

const bottomLight = new THREE.PointLight(0x4444aa, 0.5, 10);
bottomLight.position.set(0, -3, 2);
scene.add(bottomLight);

// ── Cherry Body ────────────────────────────────────────
function createCherryBody() {
  // Slightly oblate sphere for realism
  const geometry = new THREE.SphereGeometry(1, 64, 64);

  // Deform vertices: squash slightly, add dimple at top
  const pos = geometry.attributes.position;
  const vec = new THREE.Vector3();
  for (let i = 0; i < pos.count; i++) {
    vec.fromBufferAttribute(pos, i);
    // Slight squash
    vec.y *= 0.92;
    // Dimple near the top (where stem attaches)
    const topFactor = Math.max(0, vec.y);
    const radialDist = Math.sqrt(vec.x * vec.x + vec.z * vec.z);
    if (topFactor > 0.6 && radialDist < 0.4) {
      const dimpleAmount = 0.08 * (1 - radialDist / 0.4) * ((topFactor - 0.6) / 0.4);
      vec.y -= dimpleAmount;
    }
    pos.setXYZ(i, vec.x, vec.y, vec.z);
  }
  geometry.computeVertexNormals();

  const material = new THREE.MeshPhysicalMaterial({
    color: 0xcc1133,
    roughness: 0.18,
    metalness: 0.0,
    clearcoat: 1.0,
    clearcoatRoughness: 0.08,
    reflectivity: 0.9,
    sheen: 0.3,
    sheenColor: new THREE.Color(0xff4466),
    sheenRoughness: 0.3,
  });

  const mesh = new THREE.Mesh(geometry, material);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  mesh.position.y = 0;
  return mesh;
}

// ── Stem ───────────────────────────────────────────────
function createStem() {
  // Curved stem using a quadratic bezier
  const curve = new THREE.QuadraticBezierCurve3(
    new THREE.Vector3(0, 0.88, 0),
    new THREE.Vector3(0.15, 1.7, 0.1),
    new THREE.Vector3(0.35, 2.3, -0.05)
  );

  const tubeGeo = new THREE.TubeGeometry(curve, 24, 0.025, 12, false);

  // Darken the bottom of the stem slightly by modifying vertices
  const stemMat = new THREE.MeshPhysicalMaterial({
    color: 0x4a6b2f,
    roughness: 0.6,
    metalness: 0.0,
    clearcoat: 0.2,
  });

  const mesh = new THREE.Mesh(tubeGeo, stemMat);
  mesh.castShadow = true;
  return mesh;
}

// ── Small Leaf ─────────────────────────────────────────
function createLeaf() {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.quadraticCurveTo(0.15, 0.2, 0.05, 0.5);
  shape.quadraticCurveTo(-0.05, 0.2, 0, 0);

  const extrudeSettings = { depth: 0.005, bevelEnabled: true, bevelThickness: 0.003, bevelSize: 0.003, bevelSegments: 3 };
  const geo = new THREE.ExtrudeGeometry(shape, extrudeSettings);

  const mat = new THREE.MeshPhysicalMaterial({
    color: 0x5a8a3a,
    roughness: 0.5,
    metalness: 0.0,
    side: THREE.DoubleSide,
    clearcoat: 0.3,
  });

  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(0.35, 2.3, -0.05);
  mesh.rotation.set(-0.3, 0.5, 0.8);
  mesh.scale.set(0.8, 0.8, 0.8);
  return mesh;
}

// ── Highlight / Specular Blob (fake reflection) ────────
function createHighlight() {
  const geo = new THREE.SphereGeometry(0.15, 32, 32);
  const mat = new THREE.MeshBasicMaterial({
    color: 0xffffff,
    transparent: true,
    opacity: 0.35,
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(0.45, 0.45, 0.75);
  mesh.scale.set(1, 0.6, 0.3);
  return mesh;
}

// ── Ground Plane ───────────────────────────────────────
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x222233,
  roughness: 0.8,
  metalness: 0.2,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -1.5;
ground.receiveShadow = true;
scene.add(ground);

// ── Assemble Cherry ────────────────────────────────────
const cherryGroup = new THREE.Group();

const cherryBody = createCherryBody();
const stem = createStem();
const leaf = createLeaf();
const highlight = createHighlight();

cherryGroup.add(cherryBody);
cherryGroup.add(stem);
cherryGroup.add(leaf);
cherryGroup.add(highlight);
cherryGroup.position.y = 0.5;
scene.add(cherryGroup);

// ── Subtle floating particles ──────────────────────────
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const particlePositions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  particlePositions[i * 3]     = (Math.random() - 0.5) * 10;
  particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 8;
  particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 10;
}
particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3));
const particleMat = new THREE.PointsMaterial({
  color: 0xff8899,
  size: 0.03,
  transparent: true,
  opacity: 0.5,
  sizeAttenuation: true,
});
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle bob
  cherryGroup.position.y = 0.5 + Math.sin(t * 0.8) * 0.08;
  cherryGroup.rotation.y = Math.sin(t * 0.3) * 0.15;

  // Slow particle drift
  const pPos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    let y = pPos.getY(i);
    y += 0.002;
    if (y > 4) y = -4;
    pPos.setY(i, y);
  }
  pPos.needsUpdate = true;
  particles.rotation.y = t * 0.05;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What this creates:

🍒 **A glossy 3D cherry** with:

- **Realistic cherry body** — slightly squashed sphere with a dimple where the stem attaches, using `MeshPhysicalMaterial` with clearcoat, sheen, and high reflectivity for that juicy, wet look
- **Curved green stem** — a `TubeGeometry` along a quadratic Bézier curve with a natural bend
- **Small leaf** — an extruded leaf shape near the stem tip
- **Fake specular highlight** — a subtle white blob to simulate a studio light reflection
- **Multi-light setup** — key, fill, rim, and bottom lights for dramatic, appetizing shading
- **Shadow-casting** onto a dark ground plane
- **Floating pink particles** drifting upward for atmosphere
- **Gentle animation** — the cherry bobs and sways slightly
- **OrbitControls** — drag to rotate, scroll to zoom

