body { overflow: hidden; background: #1a0a0a; }
canvas { display: block; }
#info {
position: absolute; bottom: 20px; width: 100%; text-align: center;
color: #ff6644; font-family: system-ui; font-size: 14px;
text-shadow: 0 0 10px rgba(255,80,40,.5); pointer-events: none;
}
</style>
</head>
<body>
<div id="info">🌶️ Three.js Chili Demo — Drag to orbit</div>
<script type="importmap">
{ "imports": { "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js", "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/" } }
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.fog = new THREE.FogExp2(0x1a0a0a, 0.04);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0.5, 0);

// --- Lights ---
const ambient = new THREE.AmbientLight(0x331111, 0.8);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xffeedd, 3);
key.position.set(5, 8, 5);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
scene.add(key);

const fill = new THREE.DirectionalLight(0xff6644, 1.5);
fill.position.set(-4, 3, -2);
scene.add(fill);

const rim = new THREE.PointLight(0xff2200, 2, 15);
rim.position.set(-3, 2, -4);
scene.add(rim);

// --- Chili Body Profile ---
const profile = [];
const pts = [
  [0.00, -1.80],
  [0.06, -1.60],
  [0.18, -1.30],
  [0.35, -0.95],
  [0.52, -0.55],
  [0.62, -0.10],
  [0.65,  0.20],
  [0.62,  0.50],
  [0.55,  0.80],
  [0.45,  1.05],
  [0.35,  1.25],
  [0.25,  1.40],
  [0.18,  1.50],
  [0.12,  1.58],
  [0.06,  1.64],
  [0.00,  1.68],
];
pts.forEach(([r, y]) => profile.push(new THREE.Vector2(r, y)));

const bodyGeo = new THREE.LatheGeometry(profile, 32);
bodyGeo.computeVertexNormals();

// Bend the chili
const pos = bodyGeo.attributes.position;
for (let i = 0; i < pos.count; i++) {
  const y = pos.getY(i);
  const bend = Math.pow(Math.max(0, (y + 1.5) / 3.2), 1.5) * 0.8;
  const x = pos.getX(i);
  const z = pos.getZ(i);
  const angle = bend / 3.5;
  pos.setX(i, x * Math.cos(angle) - z * Math.sin(angle));
  pos.setZ(i, x * Math.sin(angle) + z * Math.cos(angle));
}
bodyGeo.computeVertexNormals();

// --- Chili Material ---
const bodyMat = new THREE.MeshPhysicalMaterial({
  color: 0xcc1100,
  roughness: 0.35,
  metalness: 0.0,
  clearcoat: 0.6,
  clearcoatRoughness: 0.2,
  reflectivity: 0.5,
  sheen: 0.3,
  sheenColor: new THREE.Color(0xff4422),
});

const chili = new THREE.Mesh(bodyGeo, bodyMat);
chili.castShadow = true;
chili.receiveShadow = true;

// --- Stem ---
const stemGeo = new THREE.CylinderGeometry(0.035, 0.045, 0.7, 8);
const stemMat = new THREE.MeshPhysicalMaterial({
  color: 0x2d5a1e,
  roughness: 0.7,
  metalness: 0.0,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.position.set(0.15, 2.15, 0.05);
stem.rotation.z = 0.12;
stem.rotation.x = -0.08;
stem.castShadow = true;
chili.add(stem);

// --- Calyx (green cap) ---
const calyxGeo = new THREE.SphereGeometry(0.14, 16, 12, 0, Math.PI * 2, 0, Math.PI * 0.5);
const calyxMat = new THREE.MeshPhysicalMaterial({
  color: 0x2d6b1e,
  roughness: 0.6,
  side: THREE.DoubleSide,
});
const calyx = new THREE.Mesh(calyxGeo, calyxMat);
calyx.position.set(0.06, 1.72, 0.02);
calyx.rotation.x = Math.PI;
chili.add(calyx);

// --- Calyx points (little green spikes) ---
const spikeMat = calyxMat;
for (let i = 0; i < 6; i++) {
  const angle = (i / 6) * Math.PI * 2;
  const spikeGeo = new THREE.ConeGeometry(0.02, 0.18, 6);
  const spike = new THREE.Mesh(spikeGeo, spikeMat);
  spike.position.set(
    0.06 + Math.cos(angle) * 0.1,
    1.72 + 0.06,
    0.02 + Math.sin(angle) * 0.1
  );
  spike.rotation.x = Math.PI;
  spike.lookAt(new THREE.Vector3(0.06, 1.72, 0.02));
  spike.rotateX(Math.PI);
  chili.add(spike);
}

// --- Group ---
const group = new THREE.Group();
group.add(chili);
group.position.y = 0.5;
scene.add(group);

// --- Ground ---
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a0a0a,
  roughness: 0.9,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// --- Floating particles ---
const particleCount = 40;
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  pPos[i * 3]     = (Math.random() - 0.5) * 10;
  pPos[i * 3 + 1] = Math.random() * 6;
  pPos[i * 3 + 2] = (Math.random() - 0.5) * 10;
}
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
const pMat = new THREE.PointsMaterial({ color: 0xff4422, size: 0.03, transparent: true, opacity: 0.6 });
const particles = new THREE.Points(pGeo, pMat);
scene.add(particles);

// --- Animate ---
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  group.rotation.y = Math.sin(t * 0.3) * 0.4;
  group.position.y = 0.5 + Math.sin(t * 0.8) * 0.15;

  particles.rotation.y = t * 0.05;
  const pp = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    let y = pp.getY(i);
    y += 0.003;
    if (y > 6) y = 0;
    pp.setY(i, y);
  }
  pp.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// --- Resize ---
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What's in there:**

- **LatheGeometry** profile sculpted from 16 hand-placed radius/height points to form the classic chili silhouette — tapered tip, bulbous middle, narrow neck
- **Vertex bending** — a quadratic bend curve is applied so the chili has a natural S-curve rather than being perfectly straight
- **MeshPhysicalMaterial** with clearcoat, sheen, and reflectivity to mimic the waxy skin of a real chili
- **Stem + calyx** — a green cylinder stem and a hemispherical green cap with 6 little cone spikes (the sepals)
- **Three-point lighting** (key, fill, rim) with warm tones + ACES filmic tone mapping
- **Shadow mapping** onto a dark ground plane
- **Floating ember particles** rising slowly for atmosphere
- **Gentle idle animation** — the chili sways and bobs; particles drift upward
- **OrbitControls** — drag to rotate, scroll to zoom

