body { background: #111; overflow: hidden; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{ "imports": { "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js", "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/" } }
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x111111);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
document.body.appendChild(renderer.domElement);

new OrbitControls(camera, renderer.domElement);

scene.add(new THREE.AmbientLight(0x404050, 0.8));
const dir = new THREE.DirectionalLight(0xffffff, 1.5);
dir.position.set(5, 8, 5);
dir.castShadow = true;
scene.add(dir);
const fill = new THREE.DirectionalLight(0x8888ff, 0.3);
fill.position.set(-3, 2, -4);
scene.add(fill);

/* ── materials ── */
const bodyMat   = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.4, metalness: 0.1 });
const pinMat    = new THREE.MeshStandardMaterial({ color: 0xccaa44, roughness: 0.3, metalness: 0.8 });
const dotMat    = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.5 });
const pcbMat    = new THREE.MeshStandardMaterial({ color: 0x005533, roughness: 0.8 });

/* ── PCB board ── */
const pcb = new THREE.Mesh(new THREE.BoxGeometry(10, 0.1, 6), pcbMat);
pcb.position.y = -0.1;
pcb.receiveShadow = true;
scene.add(pcb);

/* ── chip body ── */
const W = 2.8, H = 0.35, D = 1.4;
const body = new THREE.Mesh(new THREE.BoxGeometry(W, H, D), bodyMat);
body.position.y = H / 2;
body.castShadow = true;
body.receiveShadow = true;
scene.add(body);

/* ── rounded top face (slightly bevelled look) ── */
const top = new THREE.Mesh(new THREE.BoxGeometry(W - 0.3, 0.02, D - 0.3), dotMat);
top.position.y = H + 0.01;
top.receiveShadow = true;
scene.add(top);

/* ── orientation dot ── */
const dot = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.06, 0.02, 16),
  new THREE.MeshStandardMaterial({ color: 0x555555, roughness: 0.6 }));
dot.rotation.x = Math.PI / 2;
dot.position.set(-W / 2 + 0.25, H + 0.025, -D / 2 + 0.25);
scene.add(dot);

/* ── pins ── */
const pinCount = 14;
const pinLen = 0.5;
const pinGeo = new THREE.BoxGeometry(0.1, 0.12, pinLen);

for (let i = 0; i < pinCount; i++) {
  const x = -W / 2 + 0.25 + (i / (pinCount - 1)) * (W - 0.5);

  // front side
  const pinF = new THREE.Mesh(pinGeo, pinMat);
  pinF.position.set(x, 0.06, D / 2 + pinLen / 2);
  pinF.castShadow = true;
  scene.add(pinF);

  // back side
  const pinB = new THREE.Mesh(pinGeo, pinMat);
  pinB.position.set(x, 0.06, -D / 2 - pinLen / 2);
  pinB.castShadow = true;
  scene.add(pinB);
}

/* ── pin 1 indicator (notch) ── */
const notch = new THREE.Mesh(
  new THREE.BoxGeometry(0.15, 0.015, 0.15),
  new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.7 })
);
notch.position.set(-W / 2 + 0.25, H + 0.02, -D / 2 + 0.25);
scene.add(notch);

/* ── animation ── */
function animate() {
  requestAnimationFrame(animate);
  renderer.render(scene, camera);
}
animate();

addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What you get:**

- **DIP-14 chip** — dark rectangular body with a subtle bevelled top face
- **28 gold pins** — 14 on each long edge, with metallic gold material
- **Orientation dot & notch** — top-left corner marking for pin 1 reference
- **Green PCB substrate** — the chip sits on a small board
- **Lighting** — directional + fill + ambient with shadows
- **Orbit controls** — click-drag to rotate, scroll to zoom

Open the file in any browser and drag to inspect the chip from any angle.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Three.js Chicken</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; background: #000; }
    canvas { display: block; }
    #info {
      position: absolute;
      bottom: 20px;
      width: 100%;
      text-align: center;
      color: #fff;
      font-family: 'Segoe UI', sans-serif;
      font-size: 14px;
      opacity: 0.7;
      pointer-events: none;
      text-shadow: 0 1px 3px rgba(0,0,0,0.5);
    }
  </style>
</head>
<body>
  <div id="info">🐔 Click &amp; drag to orbit · Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.163.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87CEEB);
    scene.fog = new THREE.Fog(0x87CEEB, 30, 60);

    // ── Camera ──
    const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
    camera.position.set(5, 4, 7);

    // ── Renderer ──
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.1;
    document.body.appendChild(renderer.domElement);

    // ── Controls ──
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 1.5, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.maxPolarAngle = Math.PI / 2.1;
    controls.minDistance = 4;
    controls.maxDistance = 20;

    // ── Lights ──
    const ambientLight = new THREE.AmbientLight(0xffeedd, 0.5);
    scene.add(ambientLight);

    const sunLight = new THREE.DirectionalLight(0xfff4e0, 1.8);
    sunLight.position.set(8, 12, 6);
    sunLight.castShadow = true;
    sunLight.shadow.mapSize.set(2048, 2048);
    sunLight.shadow.camera.near = 1;
    sunLight.shadow.camera.far = 30;
    sunLight.shadow.camera.left = -8;
    sunLight.shadow.camera.right = 8;
    sunLight.shadow.camera.top = 8;
    sunLight.shadow.camera.bottom = -8;
    sunLight.shadow.bias = -0.001;
    scene.add(sunLight);

    const fillLight = new THREE.DirectionalLight(0xaaccff, 0.4);
    fillLight.position.set(-5, 3, -4);
    scene.add(fillLight);

    const rimLight = new THREE.PointLight(0xffaa44, 0.6, 15);
    rimLight.position.set(-3, 5, -3);
    scene.add(rimLight);

    // ── Materials ──
    const bodyMat = new THREE.MeshStandardMaterial({
      color: 0xFFF8F0,
      roughness: 0.7,
      metalness: 0.0,
    });
    const wingMat = new THREE.MeshStandardMaterial({
      color: 0xF5E6D0,
      roughness: 0.8,
      metalness: 0.0,
    });
    const combMat = new THREE.MeshStandardMaterial({
      color: 0xE03030,
      roughness: 0.4,
      metalness: 0.1,
    });
    const beakMat = new THREE.MeshStandardMaterial({
      color: 0xF5A623,
      roughness: 0.5,
      metalness: 0.05,
    });
    const eyeMat = new THREE.MeshStandardMaterial({
      color: 0x111111,
      roughness: 0.2,
      metalness: 0.3,
    });
    const eyeWhiteMat = new THREE.MeshStandardMaterial({
      color: 0xFFFFFF,
      roughness: 0.3,
    });
    const legMat = new THREE.MeshStandardMaterial({
      color: 0xD4883A,
      roughness: 0.6,
    });
    const tailMat = new THREE.MeshStandardMaterial({
      color: 0x8B6914,
      roughness: 0.7,
    });
    const tailDarkMat = new THREE.MeshStandardMaterial({
      color: 0x5C4410,
      roughness: 0.7,
    });
    const wattleMat = new THREE.MeshStandardMaterial({
      color: 0xCC2020,
      roughness: 0.4,
    });

    // ── Chicken Group ──
    const chicken = new THREE.Group();

    // Body
    const bodyGeo = new THREE.SphereGeometry(1, 32, 32);
    const body = new THREE.Mesh(bodyGeo, bodyMat);
    body.scale.set(1, 0.9, 0.85);
    body.position.set(0, 1.6, 0);
    body.castShadow = true;
    body.receiveShadow = true;
    chicken.add(body);

    // Chest (slightly forward protrusion)
    const chestGeo = new THREE.SphereGeometry(0.7, 32, 32);
    const chest = new THREE.Mesh(chestGeo, bodyMat);
    chest.scale.set(0.9, 0.85, 0.7);
    chest.position.set(0, 1.3, 0.55);
    chest.castShadow = true;
    chicken.add(chest);

    // ── Head ──
    const headGroup = new THREE.Group();
    headGroup.position.set(0, 2.75, 0.55);

    const headGeo = new THREE.SphereGeometry(0.55, 32, 32);
    const head = new THREE.Mesh(headGeo, bodyMat);
    head.scale.set(1, 0.95, 0.9);
    head.castShadow = true;
    headGroup.add(head);

    // Eyes
    function createEye(side) {
      const eyeGroup = new THREE.Group();
      eyeGroup.position.set(side * 0.28, 0.12, 0.42);

      const whiteGeo = new THREE.SphereGeometry(0.13, 16, 16);
      const white = new THREE.Mesh(whiteGeo, eyeWhiteMat);
      eyeGroup.add(white);

      const pupilGeo = new THREE.SphereGeometry(0.07, 16, 16);
      const pupil = new THREE.Mesh(pupilGeo, eyeMat);
      pupil.position.z = 0.09;
      eyeGroup.add(pupil);

      // Tiny highlight
      const hlGeo = new THREE.SphereGeometry(0.025, 8, 8);
      const hlMat = new THREE.MeshBasicMaterial({ color: 0xffffff });
      const hl = new THREE.Mesh(hlGeo, hlMat);
      hl.position.set(0.03, 0.03, 0.14);
      eyeGroup.add(hl);

      return eyeGroup;
    }
    headGroup.add(createEye(-1));
    headGroup.add(createEye(1));

    // Beak
    const beakTopGeo = new THREE.ConeGeometry(0.1, 0.3, 8);
    const beakTop = new THREE.Mesh(beakTopGeo, beakMat);
    beakTop.rotation.x = Math.PI / 2;
    beakTop.position.set(0, 0.02, 0.6);
    beakTop.scale.set(0.8, 1, 1);
    beakTop.castShadow = true;
    headGroup.add(beakTop);

    const beakBotGeo = new THREE.ConeGeometry(0.07, 0.18, 8);
    const beakBot = new THREE.Mesh(beakBotGeo, beakMat);
    beakBot.rotation.x = -Math.PI / 2;
    beakBot.position.set(0, -0.08, 0.58);
    beakBot.scale.set(0.9, 1, 1);
    headGroup.add(beakBot);

    // Comb (warty top of head)
    function createCombLobe(x, y, z, sx, sy, sz) {
      const geo = new THREE.SphereGeometry(0.12, 12, 12);
      const lobe = new THREE.Mesh(geo, combMat);
      lobe.position.set(x, y, z);
      lobe.scale.set(sx, sy, sz);
      lobe.castShadow = true;
      return lobe;
    }
    headGroup.add(createCombLobe(0, 0.52, 0, 1.4, 1, 0.8));
    headGroup.add(createCombLobe(-0.15, 0.48, 0.05, 0.8, 0.9, 0.7));
    headGroup.add(createCombLobe(0.15, 0.48, 0.05, 0.8, 0.9, 0.7));
    headGroup.add(createCombLobe(0, 0.44, 0.12, 0.7, 0.8, 0.6));

    // Wattle (under beak)
    const wattleGeo = new THREE.SphereGeometry(0.12, 12, 12);
    const wattle = new THREE.Mesh(wattleGeo, wattleMat);
    wattle.position.set(0, -0.3, 0.4);
    wattle.scale.set(0.9, 1.2, 0.6);
    headGroup.add(wattle);

    chicken.add(headGroup);

    // ── Wings ──
    function createWing(side) {
      const wingGroup = new THREE.Group();
      wingGroup.position.set(side * 0.95, 1.7, 0);
      wingGroup.rotation.z = side * 0.15;
      wingGroup.rotation.x = -0.1;

      const wingGeo = new THREE.SphereGeometry(0.55, 24, 24);
      const wing = new THREE.Mesh(wingGeo, wingMat);
      wing.scale.set(0.35, 0.8, 0.6);
      wing.position.set(side * 0.15, -0.2, 0);
      wing.castShadow = true;
      wingGroup.add(wing);

      // Wing tip feathers
      const tipGeo = new THREE.SphereGeometry(0.2, 12, 12);
      const tip = new THREE.Mesh(tipGeo, wingMat);
      tip.scale.set(0.3, 1.2, 0.4);
      tip.position.set(side * 0.1, -0.65, 0);
      tip.castShadow = true;
      wingGroup.add(tip);

      return wingGroup;
    }
    const leftWing = createWing(-1);
    const rightWing = createWing(1);
    chicken.add(leftWing);
    chicken.add(rightWing);

    // ── Tail ──
    const tailGroup = new THREE.Group();
    tailGroup.position.set(0, 1.8, -0.7);

    function createTailFeather(angle, length, mat, yOffset = 0) {
      const featherGeo = new THREE.ConeGeometry(0.08, length, 8);
      const feather = new THREE.Mesh(featherGeo, mat);
      feather.position.set(Math.sin(angle) * length * 0.35, yOffset + length * 0.35, -length * 0.5);
      feather.rotation.x = -0.8;
      feather.rotation.z = angle;
      feather.castShadow = true;
      return feather;
    }

    tailGroup.add(createTailFeather(0, 1.2, tailMat, 0.1));
    tailGroup.add(createTailFeather(0.3, 1.0, tailDarkMat, 0.05));
    tailGroup.add(createTailFeather(-0.3, 1.0, tailDarkMat, 0.05));
    tailGroup.add(createTailFeather(0.55, 0.8, tailMat, -0.05));
    tailGroup.add(createTailFeather(-0.55, 0.8, tailMat, -0.05));
