renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ──
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.minDistance = 4;
controls.maxDistance = 16;
controls.maxPolarAngle = Math.PI * 0.85;

// ── Lighting ──
const ambientLight = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambientLight);

const mainLight = new THREE.DirectionalLight(0xfff4e6, 2.5);
mainLight.position.set(4, 8, 4);
mainLight.castShadow = true;
mainLight.shadow.mapSize.set(2048, 2048);
mainLight.shadow.camera.near = 1;
mainLight.shadow.camera.far = 20;
mainLight.shadow.camera.left = -6;
mainLight.shadow.camera.right = 6;
mainLight.shadow.camera.top = 6;
mainLight.shadow.camera.bottom = -6;
mainLight.shadow.bias = -0.001;
mainLight.shadow.radius = 4;
scene.add(mainLight);

const fillLight = new THREE.DirectionalLight(0xc8b8ff, 0.8);
fillLight.position.set(-5, 3, -3);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0xffccaa, 1.0);
rimLight.position.set(-3, 2, 5);
scene.add(rimLight);

const spotLight = new THREE.SpotLight(0xffe8cc, 3, 15, Math.PI / 6, 0.5);
spotLight.position.set(0, 6, 0);
spotLight.castShadow = true;
scene.add(spotLight);

// ── Chocolate Material ──
const chocolateMat = new THREE.MeshPhysicalMaterial({
  color: 0x3b1a08,
  roughness: 0.35,
  metalness: 0.0,
  clearcoat: 0.3,
  clearcoatRoughness: 0.2,
  reflectivity: 0.5,
  sheen: 0.3,
  sheenRoughness: 0.8,
  sheenColor: new THREE.Color(0x6b3a1f),
});

const chocolateMatLight = new THREE.MeshPhysicalMaterial({
  color: 0x5a2d12,
  roughness: 0.3,
  metalness: 0.0,
  clearcoat: 0.3,
  clearcoatRoughness: 0.2,
  sheen: 0.2,
  sheenColor: new THREE.Color(0x8b5a3a),
});

// ── Chocolate Bar ──
const barGroup = new THREE.Group();
const COLS = 4, ROWS = 3;
const W = 1.4, H = 0.25, D = 1.05;
const GAP = 0.025;
const pieceW = (W - GAP * (COLS - 1)) / COLS;
const pieceD = (D - GAP * (ROWS - 1)) / ROWS;

for (let r = 0; r < ROWS; r++) {
  for (let c = 0; c < COLS; c++) {
    const geo = new RoundedBoxGeometry(pieceW, H, pieceD, 4, 0.03);

    // Slight random variation for realism
    const mat = (r + c) % 2 === 0 ? chocolateMat : chocolateMatLight;
    const mesh = new THREE.Mesh(geo, mat);

    mesh.position.set(
      -W / 2 + pieceW / 2 + c * (pieceW + GAP),
      0,
      -D / 2 + pieceD / 2 + r * (pieceD + GAP)
    );

    // Tiny random tilt for organic feel
    mesh.rotation.y = (Math.random() - 0.5) * 0.01;
    mesh.rotation.x = (Math.random() - 0.5) * 0.005;

    mesh.castShadow = true;
    mesh.receiveShadow = true;
    barGroup.add(mesh);
  }
}

// Wrapper foil edges (gold)
const foilMat = new THREE.MeshPhysicalMaterial({
  color: 0xd4a843,
  roughness: 0.15,
  metalness: 0.9,
  clearcoat: 0.8,
  clearcoatRoughness: 0.1,
});

// Thin foil strips on the sides
const foilGeo1 = new THREE.BoxGeometry(W + 0.05, H + 0.02, 0.02);
const foil1 = new THREE.Mesh(foilGeo1, foilMat);
foil1.position.set(0, 0, D / 2 + 0.01);
foil1.castShadow = true;
barGroup.add(foil1);

const foil2 = foil1.clone();
foil2.position.z = -D / 2 - 0.01;
barGroup.add(foil2);

const foilGeo2 = new THREE.BoxGeometry(0.02, H + 0.02, D + 0.05);
const foil3 = new THREE.Mesh(foilGeo2, foilMat);
foil3.position.set(W / 2 + 0.01, 0, 0);
foil3.castShadow = true;
barGroup.add(foil3);

const foil4 = foil3.clone();
foil4.position.x = -W / 2 - 0.01;
barGroup.add(foil4);

barGroup.rotation.y = 0.3;
scene.add(barGroup);

// ── Ground Plane ──
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x222222,
  roughness: 0.85,
  metalness: 0.1,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -H / 2 - 0.01;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating particles (cocoa dust) ──
const particleCount = 60;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const sizes = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 10;
  positions[i * 3 + 1] = Math.random() * 6 - 1;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 10;
  sizes[i] = Math.random() * 3 + 1;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

const particleMat = new THREE.PointsMaterial({
  color: 0x8b6914,
  size: 0.04,
  transparent: true,
  opacity: 0.4,
  sizeAttenuation: true,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle float
  barGroup.position.y = Math.sin(t * 0.8) * 0.15;
  barGroup.rotation.y = 0.3 + Math.sin(t * 0.3) * 0.15;

  // Particles drift
  const pos = particles.geometry.attributes.position;
  for (let i = 0; i < particleCount; i++) {
    pos.array[i * 3 + 1] += Math.sin(t + i) * 0.001;
    pos.array[i * 3] += Math.cos(t * 0.5 + i * 0.3) * 0.0005;
  }
  pos.needsUpdate = true;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
