</script>
<script type="module">
import * as THREE from 'three';

// ——— Renderer ———
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ——— Scene & Camera ———
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87ceeb);
scene.fog = new THREE.FogExp2(0x87ceeb, 0.012);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 200);
camera.position.set(0, 2, 18);
camera.lookAt(0, 0, 0);

// ——— Lighting ———
scene.add(new THREE.AmbientLight(0xffffff, 0.6));

const sun = new THREE.DirectionalLight(0xfff4e0, 2.5);
sun.position.set(10, 15, 10);
scene.add(sun);

const fill = new THREE.DirectionalLight(0xc8d8ff, 0.8);
fill.position.set(-8, 3, -5);
scene.add(fill);

// ——— Cloud Factory ———
const puffGeo = new THREE.SphereGeometry(1, 16, 16);

function makePuff(scale) {
  const mat = new THREE.MeshStandardMaterial({
    color: 0xffffff,
    roughness: 1,
    metalness: 0,
    transparent: true,
    opacity: 0.92,
  });
  const mesh = new THREE.Mesh(puffGeo, mat);
  mesh.scale.setScalar(scale);
  return mesh;
}

function buildCloud() {
  const group = new THREE.Group();

  // Main body — a cluster of puffs
  const bodyPuffs = [
    // [x, y, z, scale]
    [0, 0, 0, 2.2],
    [-2.2, 0.2, 0.5, 1.8],
    [2.3, 0.1, -0.3, 1.9],
    [-0.8, 0.8, 1.2, 1.6],
    [1.0, 0.7, -0.8, 1.5],
    [-1.5, -0.3, -0.5, 1.4],
    [1.8, -0.2, 0.8, 1.3],
    [0, 1.2, 0, 1.3],
    [-3.0, 0, 0, 1.2],
    [3.0, 0.2, 0.2, 1.1],
    [-0.5, -0.8, 0.6, 1.1],
    [0.8, -0.7, -0.4, 1.0],
  ];

  for (const [x, y, z, s] of bodyPuffs) {
    const puff = makePuff(s);
    puff.position.set(x, y, z);
    // slight random tilt per puff
    puff.rotation.set(
      Math.random() * 0.3,
      Math.random() * 0.3,
      Math.random() * 0.3
    );
    group.add(puff);
  }

  return group;
}

const cloud = buildCloud();
scene.add(cloud);

// ——— Gentle Animation ———
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  cloud.position.y = Math.sin(t * 0.4) * 0.5;
  cloud.rotation.y = Math.sin(t * 0.15) * 0.08;
  cloud.rotation.z = Math.sin(t * 0.2) * 0.02;

  // Subtle individual puff breathing
  cloud.children.forEach((puff, i) => {
    const breathe = 1 + Math.sin(t * 0.6 + i * 0.7) * 0.04;
    puff.scale.setScalar(puff.userData.base ?? puff.scale.x);
    const base = puff.userData.base ?? puff.scale.x;
    puff.scale.setScalar(base * breathe);
    puff.userData.base = base;
  });

  renderer.render(scene, camera);
}

animate();

// ——— Resize ———
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
