const spine = makeBox(spineW, spineH, spineD, steelMat);
spine.position.set(-0.55, 0, 0);
spine.castShadow = true;
frameGroup.add(spine);

// Top arm
const armW = 1.6, armH = 0.35, armD = 0.35;
const topArm = makeBox(armW, armH, armD, steelMat);
topArm.position.set(-0.15, 1.25, 0);
topArm.castShadow = true;
frameGroup.add(topArm);

