const groundGeo = new THREE.PlaneGeometry(20, 20);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -2.2;
ground.receiveShadow = true;
scene.add(ground);

// ── Slider Control ─────────────────────────────────────
const slider = document.getElementById('closure');
const minY = -0.6, maxY = 0.9;

function updateJawPosition(t) {
  const newY = minY + t * (maxY - minY);
  movingJawGroup.position.y = newY - jawY;
  // Also raise/lower handle slightly with jaw for realism
  handleGroup.position.y = newY - jawY;
}
updateJawPosition(parseFloat(slider.value));
slider.addEventListener('input', e => updateJawPosition(parseFloat(e.target.value)));

