const dirLight = new THREE.DirectionalLight(0xffeedd, 3);
dirLight.position.set(5, 15, 10);
dirLight.castShadow = true;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x4488ff, 1.5);
rimLight.position.set(-8, 5, -5);
scene.add(rimLight);

// ── Cloth parameters ─────────────────────────────────────────
const COLS = 60, ROWS = 40;
const WIDTH = 14, HEIGHT = 10;
const SPACING_X = WIDTH / (COLS - 1);
const SPACING_Y = HEIGHT / (ROWS - 1);
const GRAVITY = -25;
const DAMPING = 0.985;
const ITERATIONS = 8;
const PIN_MASK = 5; // pin first 5 columns at top

// ── Particles (Verlet) ───────────────────────────────────────
class Particle {
  constructor(x, y, z, pinned = false) {
    this.pos = new THREE.Vector3(x, y, z);
    this.prev = this.pos.clone();
    this.pinned = pinned;
  }
}

const particles = [];
for (let row = 0; row < ROWS; row++) {
  for (let col = 0; col < COLS; col++) {
    const x = (col - (COLS - 1) / 2) * SPACING_X;
    const y = (ROWS - 1 - row) * SPACING_Y;
    const pinned = row === 0 && col % PIN_MASK === 0;
    particles.push(new Particle(x, y, 0, pinned));
  }
}

// ── Constraints ──────────────────────────────────────────────
const constraints = [];
function addConstraint(i, j) {
  const d = particles[i].pos.distanceTo(particles[j].pos);
  constraints.push({ i, j, restLength: d });
}

for (let row = 0; row < ROWS; row++) {
  for (let col = 0; col < COLS; col++) {
    const idx = row * COLS + col;
    if (col < COLS - 1) addConstraint(idx, idx + 1);           // horizontal
    if (row < ROWS - 1) addConstraint(idx, idx + COLS);        // vertical
    if (col < COLS - 1 && row < ROWS - 1) {
      addConstraint(idx, idx + COLS + 1);                       // diagonal
      addConstraint(idx + 1, idx + COLS);                       // diagonal
    }
  }
}

