const geometry = new THREE.BufferGeometry();
const positions = new Float32Array(particles.length * 3);
const normals = new Float32Array(particles.length * 3);
const colors = new Float32Array(particles.length * 3);

// Generate UVs
const uvs = new Float32Array(particles.length * 2);
for (let row = 0; row < ROWS; row++) {
  for (let col = 0; col < COLS; col++) {
    uvs[(row * COLS + col) * 2]     = col / (COLS - 1);
    uvs[(row * COLS + col) * 2 + 1] = row / (ROWS - 1);
  }
}
geometry.setAttribute('uv', new THREE.BufferAttribute(uvs, 2));

// Index
const indices = [];
for (let row = 0; row < ROWS - 1; row++) {
  for (let col = 0; col < COLS - 1; col++) {
    const a = row * COLS + col;
    const b = a + 1;
    const c = a + COLS;
    const d = c + 1;
    indices.push(a, b, c, b, d, c);
  }
}
geometry.setIndex(indices);
geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
geometry.setAttribute('normal', new THREE.BufferAttribute(normals, 3));
geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));

// Cloth material with a nice gradient
const clothMaterial = new THREE.MeshStandardMaterial({
  vertexColors: true,
  side: THREE.DoubleSide,
  roughness: 0.7,
  metalness: 0.05,
  flatShading: false,
});

const cloth = new THREE.Mesh(geometry, clothMaterial);
cloth.castShadow = true;
cloth.receiveShadow = true;
scene.add(cloth);

// ── Floor ────────────────────────────────────────────────────
const floor = new THREE.Mesh(
  new THREE.PlaneGeometry(60, 60),
  new THREE.MeshStandardMaterial({ color: 0x22223a, roughness: 0.9 })
);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -0.5;
floor.receiveShadow = true;
scene.add(floor);

// ── Physics step ─────────────────────────────────────────────
function simulate(dt) {
  dt = Math.min(dt, 0.033); // cap

  // Verlet integration
  for (const p of particles) {
    if (p.pinned) continue;
    const vel = new THREE.Vector3().subVectors(p.pos, p.prev).multiplyScalar(DAMPING);
    p.prev.copy(p.pos);
    p.pos.add(vel);
    p.pos.y += GRAVITY * dt * dt;
  }

  // Solve constraints
  for (let iter = 0; iter < ITERATIONS; iter++) {
    for (const { i, j, restLength } of constraints) {
      const a = particles[i], b = particles[j];
      const diff = new THREE.Vector3().subVectors(a.pos, b.pos);
      const dist = diff.length() || 0.0001;
      const correction = diff.multiplyScalar((dist - restLength) / dist / 2);

      if (!a.pinned) a.pos.add(correction);
      if (!b.pinned) b.pos.sub(correction);
    }

    // Floor collision
    for (const p of particles) {
      if (p.pos.y < -0.4) {
        p.pos.y = -0.4;
        const velX = p.pos.x - p.prev.x;
        const velZ = p.pos.z - p.prev.z;
        p.prev.x = p.pos.x - velX * 0.5;
        p.prev.z = p.pos.z - velZ * 0.5;
        p.prev.y = p.pos.y;
      }
    }
  }
}

// ── Mouse interaction ────────────────────────────────────────
const raycaster = new THREE.Raycaster();
const mouse = new THREE.Vector2();
const dragPlane = new THREE.Plane(new THREE.Vector3(0, 0, 1), 0);
let dragParticle = null;
let dragOffset = new THREE.Vector3();

renderer.domElement.addEventListener('pointerdown', (e) => {
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);

  // Find closest particle
  let minDist = Infinity;
  for (const p of particles) {
    const screenPos = p.pos.clone().project(camera);
    const dx = screenPos.x - mouse.x;
    const dy = screenPos.y - mouse.y;
    const d = Math.sqrt(dx * dx + dy * dy);
    if (d < minDist && d < 0.15) {
      minDist = d;
      dragParticle = p;
    }
  }
  if (dragParticle) controls.enabled = false;
});

renderer.domElement.addEventListener('pointermove', (e) => {
  if (!dragParticle) return;
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);
  const target = new THREE.Vector3();
  raycaster.ray.at(8, target);
  dragParticle.pos.copy(target);
  dragParticle.prev.copy(target);
});

renderer.domElement.addEventListener('pointerup', () => {
  dragParticle = null;
  controls.enabled = true;
});

// ── Wind ─────────────────────────────────────────────────────
function applyWind(time) {
  for (const p of particles) {
    if (p.pinned) continue;
    const wave = Math.sin(time * 1.5 + p.pos.x * 0.5 + p.pos.y * 0.3) * 0.3;
    const wave2 = Math.cos(time * 0.8 + p.pos.z * 0.7) * 0.15;
    p.pos.x += wave * 0.002;
    p.pos.z += wave2 * 0.002;
  }
}

// ── Update buffers ───────────────────────────────────────────
function updateBuffers() {
  const posAttr = geometry.getAttribute('position');
  const colAttr = geometry.getAttribute('color');

  for (let i = 0; i < particles.length; i++) {
    const p = particles[i];
    posAttr.setXYZ(i, p.pos.x, p.pos.y, p.pos.z);

    // Color gradient based on height
    const t = THREE.MathUtils.clamp((p.pos.y + 2) / 12, 0, 1);
    colAttr.setXYZ(i,
      0.15 + t * 0.5,
      0.1 + t * 0.3,
      0.3 + t * 0.5
    );
  }

  posAttr.needsUpdate = true;
  colAttr.needsUpdate = true;
  geometry.computeVertexNormals();
}

// ── Animation loop ───────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const dt = clock.getDelta();
  const time = clock.getElapsedTime();

  applyWind(time);
  simulate(dt);
  updateBuffers();

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ───────────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What this includes

| Feature | Details |
|---|---|
| **Physics engine** | Custom Verlet integration with spring constraints (structural + shear diagonals) |
| **Cloth grid** | 60×40 particles with 8 constraint-solving iterations per frame |
| **Pinned corners** | Every 5th vertex along the top row is fixed, creating a draped curtain look |
| **Wind** | Sinusoidal displacement adds gentle organic movement |
| **Floor collision** | Cloth bounces off a floor plane with energy loss |
| **Mouse interaction** | Click and drag any part of the cloth — it follows your cursor |
| **Orbit camera** | Right-click drag to orbit, scroll to zoom |
| **Vertex colors** | Height-based gradient (blue→purple) updated each frame |
| **Lighting** | Warm key light + cool rim light + ambient, with shadows |

Just save it as `index.html` and open in any modern browser — no build step needed.

