renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.target.set(0, 0.5, 0);

// ── Lights ──
const ambientLight = new THREE.AmbientLight(0x334433, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
scene.add(dirLight);

const rimLight = new THREE.DirectionalLight(0x44ff88, 0.8);
rimLight.position.set(-3, 2, -4);
scene.add(rimLight);

const pointLight = new THREE.PointLight(0x88ffaa, 1.5, 15);
pointLight.position.set(0, 3, 2);
scene.add(pointLight);

// ── Clover Shape (4-leaf rose curve: r = cos(2θ)) ──
function createCloverShape() {
  const shape = new THREE.Shape();
  const points = 512;
  const scale = 1.5;

  for (let i = 0; i <= points; i++) {
    const theta = (i / points) * Math.PI * 2;
    const r = Math.cos(2 * theta) * scale;
    const x = r * Math.cos(theta);
    const y = r * Math.sin(theta);

    if (i === 0) shape.moveTo(x, y);
    else shape.lineTo(x, y);
  }

  return shape;
}

// ── Create Clover Leaves ──
const cloverGroup = new THREE.Group();

const leafShape = createCloverShape();

const extrudeSettings = {
  depth: 0.12,
  bevelEnabled: true,
  bevelThickness: 0.04,
  bevelSize: 0.04,
  bevelSegments: 4,
  curveSegments: 64
};

const leafMaterial = new THREE.MeshStandardMaterial({
  color: 0x2d8a4e,
  roughness: 0.45,
  metalness: 0.1,
  side: THREE.DoubleSide,
});

const leaves = new THREE.Mesh(new THREE.ExtrudeGeometry(leafShape, extrudeSettings), leafMaterial);
leaves.rotation.x = -Math.PI / 2;
leaves.position.y = 2.0;
leaves.castShadow = true;
leaves.receiveShadow = true;
cloverGroup.add(leaves);

// ── Stem ──
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 2.0, 0),
  new THREE.Vector3(0, 1.2, 0.05),
  new THREE.Vector3(0, 0.6, -0.05),
  new THREE.Vector3(0, 0.0, 0.02),
]);

const stemGeo = new THREE.TubeGeometry(stemCurve, 20, 0.06, 12, false);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x3a7a3a,
  roughness: 0.7,
  metalness: 0.05,
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
cloverGroup.add(stem);

// ── Veins on each leaf ──
function addVein(parent, start, end, offset) {
  const dir = new THREE.Vector3().subVectors(end, start);
  const len = dir.length();
  const veinGeo = new THREE.CylinderGeometry(0.008, 0.012, len, 6);
  const veinMat = new THREE.MeshStandardMaterial({
    color: 0x1a6b35,
    roughness: 0.6,
    metalness: 0.0,
  });
  const vein = new THREE.Mesh(veinGeo, veinMat);

  const mid = new THREE.Vector3().addVectors(start, end).multiplyScalar(0.5);
  mid.x += offset.x;
  mid.y += offset.y;
  mid.z += offset.z;

  vein.position.copy(mid);
  vein.lookAt(end.clone().add(offset));
  vein.rotateX(Math.PI / 2);
  parent.add(vein);
}

// Add subtle veins
const veinPositions = [
  // Leaf 1 (top-right)
  { s: [0, 2.0, 0.12], e: [1.2, 2.8, 0.12], o: [0, 0, 0] },
  // Leaf 2 (bottom-right)
  { s: [0, 2.0, 0.12], e: [1.2, 1.2, 0.12], o: [0, 0, 0] },
  // Leaf 3 (bottom-left)
  { s: [0, 2.0, 0.12], e: [-1.2, 1.2, 0.12], o: [0, 0, 0] },
  // Leaf 4 (top-left)
  { s: [0, 2.0, 0.12], e: [-1.2, 2.8, 0.12], o: [0, 0, 0] },
];

veinPositions.forEach(v => {
  const start = new THREE.Vector3(...v.s);
  const end = new THREE.Vector3(...v.e);
  const offset = new THREE.Vector3(...v.o);
  addVein(cloverGroup, start, end, offset);
});

scene.add(cloverGroup);

// ── Ground ──
const groundGeo = new THREE.CircleGeometry(12, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x1a3a1a,
  roughness: 0.95,
  metalness: 0.0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -0.01;
ground.receiveShadow = true;
scene.add(ground);

// ── Floating Particles (dust/pollen) ──
const particleCount = 200;
const particleGeo = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
const sizes = new Float32Array(particleCount);

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 10;
  positions[i * 3 + 1] = Math.random() * 6;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 10;
  sizes[i] = Math.random() * 3 + 1;
}

particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

const particleMat = new THREE.PointsMaterial({
  color: 0xaaffaa,
  size: 0.04,
  transparent: true,
  opacity: 0.4,
  sizeAttenuation: true,
});

const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);

// ── Small grass tufts ──
for (let i = 0; i < 60; i++) {
  const angle = Math.random() * Math.PI * 2;
  const radius = 1.5 + Math.random() * 8;
  const x = Math.cos(angle) * radius;
  const z = Math.sin(angle) * radius;

  const grassH = 0.1 + Math.random() * 0.3;
  const grassGeo = new THREE.ConeGeometry(0.02, grassH, 4);
  const grassMat = new THREE.MeshStandardMaterial({
    color: new THREE.Color().setHSL(0.28 + Math.random() * 0.06, 0.6, 0.2 + Math.random() * 0.15),
    roughness: 0.9,
  });
  const grass = new THREE.Mesh(grassGeo, grassMat);
  grass.position.set(x, grassH / 2, z);
  grass.rotation.z = (Math.random() - 0.5) * 0.3;
  grass.castShadow = true;
  scene.add(grass);
}

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle sway
  cloverGroup.rotation.z = Math.sin(t * 0.5) * 0.05;
  cloverGroup.rotation.y = Math.sin(t * 0.3) * 0.1;
  cloverGroup.position.y = Math.sin(t * 0.8) * 0.05;

  // Leaf subtle breathing
  leaves.scale.setScalar(1 + Math.sin(t * 1.2) * 0.015);

  // Particles drift
  const pos = particles.geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    pos[i * 3 + 1] += Math.sin(t + i) * 0.0003;
    pos[i * 3] += Math.cos(t * 0.5 + i * 0.1) * 0.0002;
  }
  particles.geometry.attributes.position.needsUpdate = true;

  // Point light pulse
  pointLight.intensity = 1.5 + Math.sin(t * 2) * 0.3;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
