This single HTML file renders a **3D four-leaf clover** using Three.js with:

- **Rose curve shape** — the classic `r = cos(2θ)` polar equation extruded into a 3D leaf with beveled edges
- **Stem** — a curved tube connecting the clover to the ground
- **Veins** — subtle darker lines running through each leaf
- **Lighting** — directional sunlight, a green rim light, and a pulsing point light for atmosphere
- **Shadows** — soft PCF shadow mapping
- **Environment** — a dark ground plane, random grass tufts, and floating pollen/dust particles
- **Animation** — gentle swaying, breathing scale effect, drifting particles, and light pulsing
- **Orbit controls** — drag to rotate, scroll to zoom

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Coal</title>
<style>
* { margin: 0; padding: 0; }
body { overflow: hidden; background: #0a0a0a; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { RoomEnvironment } from 'three/addons/environments/RoomEnvironment.js';

// ── Scene ──────────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a0a);

const pmrem = new THREE.PMREMGenerator(renderer);
scene.environment = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;
pmrem.dispose();

const camera = new THREE.PerspectiveCamera(35, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 5);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.target.set(0, 0, 0);

// ── Simplex-like noise (compact) ──────────────────────
function hash(n) { return (Math.sin(n) * 43758.5453123) % 1; }
function noise3D(x, y, z) {
  const X = Math.floor(x) & 255, Y = Math.floor(y) & 255, Z = Math.floor(z) & 255;
  x -= Math.floor(x); y -= Math.floor(y); z -= Math.floor(z);
  const u = x * x * (3 - 2 * x), v = y * y * (3 - 2 * y), w = z * z * (3 - 2 * z);
  const a = hash(X) + Y * (hash(X + Y) + Z * hash(X + Y + Z));
  const b = hash(X + 1) + Y * (hash(X + 1 + Y) + Z * hash(X + 1 + Y + Z));
  const c = hash(X + Y) + Z * (hash(X + Y + 1) - hash(X + Y));
  const d = hash(X + Y + 1) + Z * (hash(X + Y + 1 + 1) - hash(X + Y + 1));
  return a + u * (b - a) + v * (c - a) + w * (d - a);
}
function fbm(x, y, z, octaves = 5) {
  let val = 0, amp = 0.5, freq = 1;
  for (let i = 0; i < octaves; i++) {
    val += amp * (noise3D(x * freq, y * freq, z * freq) * 0.5 + 0.5);
    amp *= 0.5; freq *= 2.1;
  }
  return val;
}

// ── Coal geometry ──────────────────────────────────────
const geo = new THREE.IcosahedronGeometry(1, 64);
const pos = geo.attributes.position;
const normals = [];

for (let i = 0; i < pos.count; i++) {
  const v = new THREE.Vector3(pos.getX(i), pos.getY(i), pos.getZ(i));
  const n = v.clone().normalize();

  // Multi-octave displacement for lumpy coal shape
  const n1 = fbm(n.x * 2 + 3.7, n.y * 2 + 1.3, n.z * 2 + 5.1, 5);
  const n2 = fbm(n.x * 4 + 0.5, n.y * 4 + 2.7, n.z * 4 + 4.2, 4);
  const n3 = fbm(n.x * 8 + 1.1, n.y * 8 + 0.3, n.z * 8 + 6.6, 3);

  const disp = 0.15 * n1 + 0.08 * n2 + 0.03 * n3;
  const scale = 0.85 + disp;

  // Stretch into irregular lump
  const stretch = 1 + 0.2 * Math.sin(n.y * 3.1 + 1.0);
  v.normalize().multiplyScalar(scale * stretch);

  pos.setXYZ(i, v.x, v.y, v.z);
  normals.push(n.clone());
}

geo.computeVertexNormals();
geo.setAttribute('normal', new THREE.BufferAttribute(new Float32Array(normals.flatMap(n => [n.x, n.y, n.z])), 3));

// ── Coal material ──────────────────────────────────────
const coalMat = new THREE.MeshPhysicalMaterial({
  color: new THREE.Color(0.06, 0.055, 0.058),
  roughness: 0.85,
  metalness: 0.05,
  clearcoat: 0.15,
  clearcoatRoughness: 0.6,
  sheen: 0.3,
  sheenRoughness: 0.8,
  sheenColor: new THREE.Color(0.08, 0.06, 0.1),
  envMapIntensity: 0.4,
});

const coal = new THREE.Mesh(geo, coalMat);
coal.rotation.set(0.2, 0.5, 0.1);
scene.add(coal);

// ── Crackle veins (subtle lighter fissures) ────────────
const veinMat = new THREE.MeshStandardMaterial({
  color: 0x1a1818,
  roughness: 0.9,
  metalness: 0.0,
  transparent: true,
  opacity: 0.3,
});

// ── Lighting accents ───────────────────────────────────
const rim = new THREE.DirectionalLight(0x4466aa, 0.6);
rim.position.set(-3, 2, -2);
scene.add(rim);

const warm = new THREE.DirectionalLight(0xaa7744, 0.3);
warm.position.set(3, -1, 2);
scene.add(warm);

// ── Ground shadow plane ────────────────────────────────
const shadowGeo = new THREE.CircleGeometry(1.8, 64);
const shadowMat = new THREE.MeshBasicMaterial({
  color: 0x000000,
  transparent: true,
  opacity: 0.5,
  depthWrite: false,
});
const shadow = new THREE.Mesh(shadowGeo, shadowMat);
shadow.rotation.x = -Math.PI / 2;
shadow.position.y = -1.35;
scene.add(shadow);

// ── Resize ─────────────────────────────────────────────
addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// ── Animate ────────────────────────────────────────────
const clock = new THREE.Clock();
function loop() {
  requestAnimationFrame(loop);
  const t = clock.getElapsedTime();
  coal.rotation.y = t * 0.15;
  controls.update();
  renderer.render(scene, camera);
}
loop();
</script>
</body>
</html>
