});
const chromeMat = new THREE.MeshStandardMaterial({
  color: 0xffffff, metalness: 1, roughness: 0.05
});
const glowMat = (color) => new THREE.MeshStandardMaterial({
  color, emissive: color, emissiveIntensity: 2, toneMapped: false
});

