  hLine.position.set(0, 0.01, i);
  gridGroup.add(hLine);
  const vLine = new THREE.Mesh(new THREE.BoxGeometry(0.03, 0.02, 24), gridLineMat);
  vLine.position.set(i, 0.01, 0);
  gridGroup.add(vLine);
}
scene.add(gridGroup);

// Walls
const wallGeo = new THREE.PlaneGeometry(40, 12);
