leftWall.rotation.y = Math.PI / 2;
scene.add(leftWall);
const rightWall = new THREE.Mesh(wallGeo, wallMat);
rightWall.position.set(20, 6, 0);
rightWall.rotation.y = -Math.PI / 2;
scene.add(rightWall);

// Ceiling
const ceiling = new THREE.Mesh(new THREE.PlaneGeometry(40, 40), wallMat);
ceiling.rotation.x = Math.PI / 2;
ceiling.position.y = 12;
scene.add(ceiling);

// ─── DJ BOOTH / STAGE ───
const stageGeo = new THREE.BoxGeometry(16, 1.5, 6);
const stageMat = new THREE.MeshStandardMaterial({ color: 0x1a1a2e, metalness: 0.5, roughness: 0.3 });
const stage = new THREE.Mesh(stageGeo, stageMat);
stage.position.set(0, 0.75, -16);
scene.add(stage);

// Stage LED panels
for (let i = 0; i < 8; i++) {
  const panel = new THREE.Mesh(
    new THREE.BoxGeometry(1.5, 0.8, 0.1),
    glowMat(new THREE.Color().setHSL(i / 8, 1, 0.5))
  );
  panel.position.set(-7 + i * 2, 2.5, -18.5);
  panel.userData = { hueOffset: i / 8, isLed: true };
  scene.add(panel);
}

// DJ Table
const djTable = new THREE.Mesh(
  new THREE.BoxGeometry(3, 1.2, 1.5),
