// ─── DISCO BALL ───
const discoGroup = new THREE.Group();
discoGroup.position.set(0, 10, 0);
scene.add(discoGroup);

// Mirror tiles
const tileGeo = new THREE.PlaneGeometry(0.12, 0.12);
const tileMat = new THREE.MeshStandardMaterial({
  color: 0xffffff, metalness: 1, roughness: 0, side: THREE.DoubleSide
});
const tileCount = 300;
for (let i = 0; i < tileCount; i++) {
  const phi = Math.acos(1 - 2 * (i + 0.5) / tileCount);
