  );
  housing.position.set(x, 11.5, z);
  scene.add(housing);

  spotlights.push({ light: spot, beam, angle, speed: 0.3 + Math.random() * 0.5, offset: Math.random() * Math.PI * 2 });
}

// ─── STROBE LIGHTS ───
const strobes = [];
for (let i = 0; i < 4; i++) {
  const s = new THREE.PointLight(0xffffff, 0, 20);
