<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ── Scene, Camera, Renderer ── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x87CEEB);
scene.fog = new THREE.FogExp2(0x87CEEB, 0.008);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 500);
camera.position.set(18, 10, 22);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 2.5, 0);
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 8;
controls.maxDistance = 60;

/* ── Lights ── */
const ambient = new THREE.AmbientLight(0xffffff, 0.5);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
sun.position.set(15, 25, 10);
sun.castShadow = true;
sun.shadow.mapSize.set(2048, 2048);
sun.shadow.camera.left = -30; sun.shadow.camera.right = 30;
sun.shadow.camera.top = 30; sun.shadow.camera.bottom = -30;
sun.shadow.camera.near = 1; sun.shadow.camera.far = 80;
sun.shadow.bias = -0.001;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8ec5fc, 0.4);
fill.position.set(-10, 8, -10);
scene.add(fill);

/* ── Helpers ── */
function mat(color, opts = {}) {
  return new THREE.MeshStandardMaterial({ color, roughness: opts.r ?? 0.5, metalness: opts.m ?? 0.1, ...opts });
}

/* ── Coach Body ── */
const coach = new THREE.Group();

// Main body
const bodyGeo = new THREE.BoxGeometry(3.4, 3.2, 12);
const bodyMat = mat(0xD42020, { r: 0.35, m: 0.05 });
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.position.y = 3.2;
body.castShadow = true; body.receiveShadow = true;
coach.add(body);

// White stripe
const stripeGeo = new THREE.BoxGeometry(3.42, 0.35, 12.02);
const stripeMat = mat(0xffffff, { r: 0.3 });
const stripe = new THREE.Mesh(stripeGeo, stripeMat);
stripe.position.y = 3.6;
coach.add(stripe);

// Lower body (darker red)
const lowerGeo = new THREE.BoxGeometry(3.42, 1.0, 12.02);
const lowerMat = mat(0x8B0000, { r: 0.4 });
const lower = new THREE.Mesh(lowerGeo, lowerMat);
lower.position.y = 1.9;
lower.castShadow = true;
coach.add(lower);

// Roof
const roofGeo = new THREE.BoxGeometry(3.2, 0.15, 11.5);
const roofMat = mat(0xcccccc, { r: 0.3, m: 0.2 });
const roof = new THREE.Mesh(roofGeo, roofMat);
roof.position.y = 4.88;
roof.castShadow = true;
coach.add(roof);

// Front windshield area (curved look via scaled cylinder)
const frontGeo = new THREE.BoxGeometry(3.0, 2.0, 0.3);
const frontMat = mat(0x1a1a2e, { r: 0.05, m: 0.8 });
const front = new THREE.Mesh(frontGeo, frontMat);
front.position.set(0, 3.6, 6.15);
coach.add(front);

// Front bumper
const bumperGeo = new THREE.BoxGeometry(3.5, 0.5, 0.4);
const bumperMat = mat(0x222222, { r: 0.6, m: 0.3 });
const bumper = new THREE.Mesh(bumperGeo, bumperMat);
bumper.position.set(0, 1.0, 6.2);
bumper.castShadow = true;
coach.add(bumper);

// Rear bumper
const rearBumper = new THREE.Mesh(bumperGeo, bumperMat);
rearBumper.position.set(0, 1.0, -6.2);
rearBumper.castShadow = true;
coach.add(rearBumper);

// Rear window
const rearWinGeo = new THREE.BoxGeometry(2.4, 1.2, 0.15);
const rearWinMat = mat(0x1a1a2e, { r: 0.05, m: 0.8 });
const rearWin = new THREE.Mesh(rearWinGeo, rearWinMat);
rearWin.position.set(0, 3.6, -6.05);
coach.add(rearWin);

/* ── Side Windows ── */
const winMat = mat(0x88ccff, { r: 0.05, m: 0.6, transparent: true, opacity: 0.7 });
for (let i = 0; i < 7; i++) {
  const wGeo = new THREE.BoxGeometry(0.08, 1.1, 1.2);
  // Left side
  const wL = new THREE.Mesh(wGeo, winMat);
  wL.position.set(-1.71, 3.5, 4.5 - i * 1.5);
  coach.add(wL);
  // Right side
  const wR = new THREE.Mesh(wGeo, winMat);
  wR.position.set(1.71, 3.5, 4.5 - i * 1.5);
  coach.add(wR);
}

/* ── Headlights ── */
const hlGeo = new THREE.CylinderGeometry(0.25, 0.25, 0.15, 16);
const hlMat = mat(0xffffcc, { r: 0.1, m: 0.3, emissive: 0xffffaa, emissiveIntensity: 0.5 });
[-1.1, 1.1].forEach(x => {
  const hl = new THREE.Mesh(hlGeo, hlMat);
  hl.rotation.x = Math.PI / 2;
  hl.position.set(x, 1.4, 6.35);
  coach.add(hl);
});

/* ── Tail lights ── */
const tlMat = mat(0xff0000, { r: 0.1, emissive: 0xff0000, emissiveIntensity: 0.3 });
[-1.1, 1.1].forEach(x => {
  const tl = new THREE.Mesh(hlGeo, tlMat);
  tl.rotation.x = Math.PI / 2;
  tl.position.set(x, 1.4, -6.35);
  coach.add(tl);
});

/* ── Wheels ── */
const wheelGeo = new THREE.CylinderGeometry(0.65, 0.65, 0.45, 24);
const wheelMat = mat(0x1a1a1a, { r: 0.8, m: 0.1 });
const hubGeo = new THREE.CylinderGeometry(0.25, 0.25, 0.47, 16);
const hubMat = mat(0xcccccc, { r: 0.2, m: 0.7 });

const wheelPositions = [
  { x: -1.75, z: 4.5 },
  { x: 1.75, z: 4.5 },
  { x: -1.75, z: -4.5 },
  { x: 1.75, z: -4.5 },
];

const wheels = [];
wheelPositions.forEach(({ x, z }) => {
  const group = new THREE.Group();
  const tire = new THREE.Mesh(wheelGeo, wheelMat);
  tire.rotation.z = Math.PI / 2;
  tire.castShadow = true;
  group.add(tire);

  const hub = new THREE.Mesh(hubGeo, hubMat);
  hub.rotation.z = Math.PI / 2;
  group.add(hub);

  // Rims (spokes)
  for (let s = 0; s < 5; s++) {
    const spokeGeo = new THREE.BoxGeometry(0.08, 0.45, 0.5);
    const spoke = new THREE.Mesh(spokeGeo, hubMat);
    spoke.rotation.z = Math.PI / 2;
    spoke.rotation.y = (s / 5) * Math.PI;
    group.add(spoke);
  }

  group.position.set(x, 0.65, z);
  wheels.push(group);
  coach.add(group);
});

/* ── Roof AC unit ── */
const acGeo = new THREE.BoxGeometry(2.0, 0.5, 1.8);
const acMat = mat(0x888888, { r: 0.4, m: 0.3 });
const ac = new THREE.Mesh(acGeo, acMat);
ac.position.set(0, 5.2, -2);
ac.castShadow = true;
coach.add(ac);

// AC fan circles
const fanGeo = new THREE.CircleGeometry(0.4, 24);
const fanMat = mat(0x444444, { r: 0.6 });
[-0.5, 0.5].forEach(x => {
  const fan = new THREE.Mesh(fanGeo, fanMat);
  fan.rotation.x = -Math.PI / 2;
  fan.position.set(x, 5.46, -2);
  coach.add(fan);
});

/* ── Door ── */
const doorGeo = new THREE.BoxGeometry(0.08, 2.6, 1.6);
const doorMat = mat(0x222222, { r: 0.2, m: 0.5 });
const door = new THREE.Mesh(doorGeo, doorMat);
door.position.set(1.72, 2.6, 3.2);
coach.add(door);

// Door glass
const doorGlassGeo = new THREE.BoxGeometry(0.1, 1.0, 1.0);
const doorGlass = new THREE.Mesh(doorGlassGeo, winMat);
doorGlass.position.set(1.73, 3.3, 3.2);
coach.add(doorGlass);

/* ── Mirror arms & mirrors ── */
const mirrorArmGeo = new THREE.BoxGeometry(0.06, 0.06, 0.8);
const mirrorMat = mat(0x333333, { r: 0.3, m: 0.5 });
const mirrorGlassGeo = new THREE.BoxGeometry(0.3, 0.5, 0.06);

[1.85, -1.85].forEach(x => {
  const arm = new THREE.Mesh(mirrorArmGeo, mirrorMat);
  arm.position.set(x, 4.2, 5.8);
  coach.add(arm);
  const mg = new THREE.Mesh(mirrorGlassGeo, mat(0x88ccff, { r: 0.05, m: 0.8 }));
  mg.position.set(x > 0 ? x + 0.35 : x - 0.35, 4.2, 5.8);
  coach.add(mg);
});

coach.position.y = 0;
scene.add(coach);

/* ── Ground / Road ── */
const groundGeo = new THREE.PlaneGeometry(200, 200);
const groundMat = mat(0x3a7d3a, { r: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Road
const roadGeo = new THREE.PlaneGeometry(8, 200);
const roadMat = mat(0x333333, { r: 0.85 });
const road = new THREE.Mesh(roadGeo, roadMat);
road.rotation.x = -Math.PI / 2;
road.position.y = 0.01;
road.receiveShadow = true;
scene.add(road);

// Road lines
for (let z = -95; z < 95; z += 6) {
  const lineGeo = new THREE.PlaneGeometry(0.15, 3);
  const lineMat = mat(0xffffff, { r: 0.6 });
  const line = new THREE.Mesh(lineGeo, lineMat);
  line.rotation.x = -Math.PI / 2;
  line.position.set(0, 0.02, z);
  scene.add(line);
}

// Sidewalk edges
[-4.3, 4.3].forEach(x => {
  const swGeo = new THREE.BoxGeometry(0.4, 0.15, 200);
  const swMat = mat(0xaaaaaa, { r: 0.7 });
  const sw = new THREE.Mesh(swGeo, swMat);
  sw.position.set(x, 0.075, 0);
  sw.receiveShadow = true;
  scene.add(sw);
});

