<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Cobra</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #000; }
canvas { display: block; }
</style>
</head>
<body>
<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene Setup ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a1a);
scene.fog = new THREE.FogExp2(0x0a0a1a, 0.035);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 7);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1.5, 0);
controls.enableDamping = true;

// ── Lighting ──
scene.add(new THREE.AmbientLight(0x334466, 0.8));

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 8, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 20;
dirLight.shadow.camera.left = -5;
dirLight.shadow.camera.right = 5;
dirLight.shadow.camera.top = 5;
dirLight.shadow.camera.bottom = -5;
scene.add(dirLight);

const rimLight = new THREE.PointLight(0x4488ff, 1.5, 15);
rimLight.position.set(-4, 3, -3);
scene.add(rimLight);

const fillLight = new THREE.PointLight(0xff6633, 0.6, 10);
fillLight.position.set(3, 1, 2);
scene.add(fillLight);

// ── Materials ──
const bodyMat = new THREE.MeshStandardMaterial({
  color: 0x1a5c2a,
  roughness: 0.45,
  metalness: 0.1,
});
const bellyMat = new THREE.MeshStandardMaterial({
  color: 0xd4c87a,
  roughness: 0.6,
  metalness: 0.0,
});
const hoodMat = new THREE.MeshStandardMaterial({
  color: 0x1a6b30,
  roughness: 0.4,
  metalness: 0.15,
  side: THREE.DoubleSide,
});
const hoodInnerMat = new THREE.MeshStandardMaterial({
  color: 0x2a8a40,
  roughness: 0.5,
  side: THREE.DoubleSide,
});
const eyeMat = new THREE.MeshStandardMaterial({
  color: 0xffcc00,
  emissive: 0xffaa00,
  emissiveIntensity: 0.8,
  roughness: 0.2,
  metalness: 0.3,
});
const pupilMat = new THREE.MeshStandardMaterial({
  color: 0x111111,
  roughness: 0.1,
  metalness: 0.5,
});
const tongueMat = new THREE.MeshStandardMaterial({
  color: 0xff2222,
  emissive: 0xff0000,
  emissiveIntensity: 0.3,
});

// ── Ground ──
const ground = new THREE.Mesh(
  new THREE.CircleGeometry(8, 64),
  new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 0.9 })
);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// ── Cobra Group ──
const cobra = new THREE.Group();
scene.add(cobra);

// ── Coiled Body ──
function createBodyCurve() {
  const pts = [];
  const coils = 2.5;
  const maxR = 2.2;
  const segs = 120;
  for (let i = 0; i <= segs; i++) {
    const t = i / segs;
    const angle = t * coils * Math.PI * 2;
    const r = maxR * (0.15 + 0.85 * t);
    const x = Math.cos(angle) * r;
    const z = Math.sin(angle) * r;
    const y = 0.05 + t * 0.15;
    pts.push(new THREE.Vector3(x, y, z));
  }
  return new THREE.CatmullRomCurve3(pts);
}

const bodyCurve = createBodyCurve();
const bodyGeo = new THREE.TubeGeometry(bodyCurve, 120, 0.18, 12, false);
const bodyMesh = new THREE.Mesh(bodyGeo, bodyMat);
bodyMesh.castShadow = true;
cobra.add(bodyMesh);

// Belly strip
const bellyCurve = createBodyCurve();
const bellyGeo = new THREE.TubeGeometry(bellyCurve, 120, 0.12, 12, false);
const bellyMesh = new THREE.Mesh(bellyGeo, bellyMat);
bellyMesh.rotation.z = Math.PI;
bellyMesh.position.y = -0.06;
cobra.add(bellyMesh);

// ── Rising Neck ──
const neckPts = [
  new THREE.Vector3(0, 0.3, -2.2),
  new THREE.Vector3(0, 0.8, -1.6),
  new THREE.Vector3(0, 1.4, -0.8),
  new THREE.Vector3(0, 2.0, -0.2),
  new THREE.Vector3(0, 2.4, 0.1),
];
const neckCurve = new THREE.CatmullRomCurve3(neckPts);
const neckGeo = new THREE.TubeGeometry(neckCurve, 32, 0.22, 12, false);
const neckMesh = new THREE.Mesh(neckGeo, bodyMat);
neckMesh.castShadow = true;
cobra.add(neckMesh);

// ── Hood (expanded canopy) ──
function createHoodGeometry() {
  const shape = new THREE.Shape();
  const outerR = 1.2;
  const innerR = 0.35;
  const segments = 48;

  // Outer edge (flared shape)
  for (let i = 0; i <= segments; i++) {
    const a = (i / segments) * Math.PI * 2;
    const r = outerR + Math.cos(a * 2) * 0.15;
    const x = Math.cos(a) * r;
    const y = Math.sin(a) * r * 0.6;
    i === 0 ? shape.moveTo(x, y) : shape.lineTo(x, y);
  }

  // Inner hole
  const holePath = new THREE.Path();
  for (let i = 0; i <= segments; i++) {
    const a = (i / segments) * Math.PI * 2;
    const x = Math.cos(a) * innerR;
    const y = Math.sin(a) * innerR * 0.6;
    i === 0 ? holePath.moveTo(x, y) : holePath.lineTo(x, y);
  }
  shape.holes.push(holePath);

  const extrudeSettings = {
    depth: 0.35,
    bevelEnabled: true,
    bevelThickness: 0.08,
    bevelSize: 0.08,
    bevelSegments: 4,
    curveSegments: segments,
  };

  return new THREE.ExtrudeGeometry(shape, extrudeSettings);
}

const hoodGroup = new THREE.Group();
hoodGroup.position.set(0, 2.35, -0.15);
hoodGroup.rotation.x = -0.3;

const hoodOuter = new THREE.Mesh(createHoodGeometry(), hoodMat);
hoodOuter.castShadow = true;
hoodGroup.add(hoodOuter);

const hoodInner = new THREE.Mesh(createHoodGeometry(), hoodInnerMat);
hoodInner.scale.set(0.92, 0.92, 0.5);
hoodGroup.add(hoodInner);

cobra.add(hoodGroup);

// ── Hood pattern (spectacle marking) ──
const spotGeo = new THREE.CircleGeometry(0.15, 16);
const spotMat = new THREE.MeshStandardMaterial({
  color: 0x0d3d18,
  roughness: 0.6,
  side: THREE.DoubleSide,
});

[-0.25, 0.25].forEach(xOff => {
  const spot = new THREE.Mesh(spotGeo, spotMat);
  spot.position.set(xOff, 2.55, 0.12);
  spot.rotation.x = -0.3;
  cobra.add(spot);
});

// ── Head ──
const headGeo = new THREE.SphereGeometry(0.28, 16, 12);
headGeo.scale(1, 0.7, 1.3);
const headMesh = new THREE.Mesh(headGeo, bodyMat);
headMesh.position.set(0, 2.55, 0.2);
headMesh.castShadow = true;
cobra.add(headMesh);

// Snout
const snoutGeo = new THREE.ConeGeometry(0.15, 0.35, 8);
snoutGeo.rotateX(Math.PI / 2);
const snoutMesh = new THREE.Mesh(snoutGeo, bodyMat);
snoutMesh.position.set(0, 2.52, 0.5);
cobra.add(snoutMesh);

// ── Eyes ──
[-0.18, 0.18].forEach(xOff => {
  const eyeGroup = new THREE.Group();

  const eyeWhite = new THREE.Mesh(
    new THREE.SphereGeometry(0.07, 12, 8),
    eyeMat
  );
  eyeGroup.add(eyeWhite);

  const pupil = new THREE.Mesh(
    new THREE.SphereGeometry(0.035, 8, 8),
    pupilMat
  );
  pupil.position.z = 0.05;
  eyeGroup.add(pupil);

  eyeGroup.position.set(xOff, 2.62, 0.35);
  eyeGroup.rotation.y = xOff > 0 ? -0.2 : 0.2;
  cobra.add(eyeGroup);
});

// ── Tongue ──
const tongueGroup = new THREE.Group();
tongueGroup.position.set(0, 2.48, 0.65);

const tongueBase = new THREE.Mesh(
  new THREE.CylinderGeometry(0.008, 0.012, 0.2, 6),
  tongueMat
);
tongueBase.rotation.x = Math.PI / 2;
tongueGroup.add(tongueBase);

// Fork
[-0.03, 0.03].forEach(xOff => {
  const fork = new THREE.Mesh(
    new THREE.CylinderGeometry(0.004, 0.008, 0.12, 4),
    tongueMat
  );
  fork.rotation.x = Math.PI / 2;
  fork.rotation.z = xOff > 0 ? -0.3 : 0.3;
  fork.position.set(xOff, 0, 0.14);
  tongueGroup.add(fork);
});

cobra.add(tongueGroup);

// ── Scale bumps along body ──
for (let i = 0; i < 80; i++) {
  const t = Math.random();
  const pt = bodyCurve.getPointAt(t);
  const bump = new THREE.Mesh(
    new THREE.SphereGeometry(0.03 + Math.random() * 0.02, 6, 4),
    bodyMat
  );
  bump.position.copy(pt);
  bump.position.y += 0.16;
  cobra.add(bump);
}

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Hood breathing
  const breathe = 1 + Math.sin(t * 1.5) * 0.04;
  hoodGroup.scale.set(breathe, breathe, breathe);

  // Tongue flick
  tongueGroup.visible = Math.sin(t * 2) > -0.3;
  if (tongueGroup.visible) {
    const tongueOut = Math.max(0, Math.sin(t * 2));
    tongueGroup.scale.set(1, 1, 0.5 + tongueOut * 0.8);
  }

  // Subtle body sway
  cobra.rotation.y = Math.sin(t * 0.4) * 0.08;

  // Eye glow pulse
  eyeMat.emissiveIntensity = 0.6 + Math.sin(t * 3) * 0.3;

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

## What this creates

A **3D cobra** built entirely from Three.js primitives, featuring:

| Part | Technique |
|---|---|
| **Coiled body** | `TubeGeometry` along a spiral `CatmullRomCurve3` — 2.5 coils widening outward |
| **Rising neck** | Second tube curving upward from the coil |
| **Expanded hood** | `ExtrudeGeometry` from a custom `Shape` with an inner hole, giving that iconic flared canopy |
| **Head & snout** | Scaled sphere + cone |
| **Eyes** | Glowing spheres with slit pupils, pulsing emissive |
| **Forked tongue** | Animated cylinder pair that flicks in/out |
| **Scale bumps** | Randomly placed small spheres along the body |
| **Spectacle markings** | Two dark spots on the hood front |

### Animations
- **Hood breathing** — subtle scale pulsation
- **Tongue flicking** — periodic extend/retract with visibility toggle
- **Body sway** — gentle rotation oscillation
- **Eye glow** — pulsing emissive intensity

### Interaction
- **OrbitControls** — click-drag to rotate, scroll to zoom, right-drag to pan

