<body>
<div id="info">🥥 Drag to orbit · Scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.163.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.163.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.06);

const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1.5, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0.3, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.update();

// ── Lighting ───────────────────────────────────────────
const ambient = new THREE.AmbientLight(0xffeedd, 0.4);
scene.add(ambient);

const sun = new THREE.DirectionalLight(0xfff4e0, 2.5);
sun.position.set(4, 8, 6);
sun.castShadow = true;
sun.shadow.mapSize.set(1024, 1024);
sun.shadow.camera.near = 1;
sun.shadow.camera.far = 20;
sun.shadow.camera.left = -4;
sun.shadow.camera.right = 4;
sun.shadow.camera.top = 4;
sun.shadow.camera.bottom = -4;
sun.shadow.bias = -0.002;
scene.add(sun);

const fill = new THREE.DirectionalLight(0x8899cc, 0.6);
fill.position.set(-5, 3, -4);
scene.add(fill);

const rim = new THREE.PointLight(0xffaa55, 1.2, 12);
rim.position.set(-3, 2, -3);
scene.add(rim);

// ── Ground ─────────────────────────────────────────────
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a1f14,
  roughness: 0.95,
  metalness: 0.0,
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

// Sand particles
const sandGeo = new THREE.PlaneGeometry(16, 16, 80, 80);
const sandPos = sandGeo.attributes.position;
for (let i = 0; i < sandPos.count; i++) {
  sandPos.setZ(i, Math.random() * 0.03);
}
sandGeo.computeVertexNormals();
const sandMat = new THREE.MeshStandardMaterial({
  color: 0x3d2b1f,
  roughness: 1,
  metalness: 0,
  transparent: true,
  opacity: 0.4,
});
const sand = new THREE.Mesh(sandGeo, sandMat);
sand.rotation.x = -Math.PI / 2;
sand.position.y = 0.005;
sand.receiveShadow = true;
scene.add(sand);

// ── Coconut Geometry (procedural) ──────────────────────
const coconutGeo = new THREE.SphereGeometry(1, 128, 128);

// Store original positions for animation
const origPositions = new Float32Array(coconutGeo.attributes.position.array);

// Noise function (simple layered sine)
function noise(x, y, z) {
  let v = 0;
  v += Math.sin(x * 3.1 + y * 1.7) * 0.5;
  v += Math.sin(y * 2.3 + z * 2.9) * 0.35;
  v += Math.sin(z * 3.7 + x * 1.3) * 0.3;
  v += Math.sin(x * 7.1 + y * 5.3 + z * 3.1) * 0.15;
  v += Math.cos(y * 4.7 - z * 3.3) * 0.2;
  v += Math.sin(x * 11.3 + z * 7.7) * 0.08;
  return v;
}

// Displace vertices to create fibrous, bumpy coconut surface
const posAttr = coconutGeo.attributes.position;
const normalAttr = coconutGeo.attributes.normal;
const colors = new Float32Array(posAttr.count * 3);

for (let i = 0; i < posAttr.count; i++) {
  const x = posAttr.getX(i);
  const y = posAttr.getY(i);
  const z = posAttr.getZ(i);

  // Make it slightly oblong (wider in the middle, slightly compressed top/bottom)
  const elongation = 1.0 + 0.08 * Math.sin(y * Math.PI * 0.5);
  const bulge = 1.0 + 0.05 * (1 - y * y);

  // Fibrous noise displacement
  const n = noise(x, y, z);
  const displacement = 1.0 + n * 0.06;

  // Create the three eyes on the "top" of the coconut (negative Y)
  const eyePositions = [
    new THREE.Vector3(0, -1.0, 0.45),
    new THREE.Vector3(-0.38, -1.0, -0.25),
    new THREE.Vector3(0.38, -1.0, -0.25),
  ];

  let eyeDisplacement = 0;
  for (const eye of eyePositions) {
    const dist = Math.sqrt(
      (x - eye.x) ** 2 + (y - eye.y) ** 2 + (z - eye.z) ** 2
    );
    if (dist < 0.3) {
      // Create a smooth depression
      const t = 1 - smoothstep(0.05, 0.28, dist);
      eyeDisplacement -= t * 0.12;
    }
  }

  // Slightly raised ring around eyes area
  const eyeRegionDist = Math.sqrt(x * x + (y + 1.0) ** 2 + z * z);
  const ringBoost = Math.max(0, 1 - smoothstep(0.3, 0.7, eyeRegionDist)) * 0.02;

  const finalScale = displacement * elongation * bulge + eyeDisplacement + ringBoost;

  const nx = normalAttr.getX(i);
  const ny = normalAttr.getY(i);
  const nz = normalAttr.getZ(i);

  posAttr.setXYZ(
    i,
    x * finalScale + nx * eyeDisplacement * 0.3,
    y * finalScale + ny * eyeDisplacement * 0.3,
    z * finalScale + nz * eyeDisplacement * 0.3
  );

  // Vertex colors for variation
  const baseR = 0.35 + n * 0.08;
  const baseG = 0.22 + n * 0.05;
  const baseB = 0.12 + n * 0.03;

  // Darken around eyes
  let darken = 0;
  for (const eye of eyePositions) {
    const dist = Math.sqrt((x - eye.x) ** 2 + (y - eye.y) ** 2 + (z - eye.z) ** 2);
    darken = Math.max(darken, 1 - smoothstep(0.05, 0.3, dist));
  }

  const eyeDark = darken * 0.3;

  colors[i * 3]     = Math.max(0, baseR - eyeDark);
  colors[i * 3 + 1] = Math.max(0, baseG - eyeDark * 0.7);
  colors[i * 3 + 2] = Math.max(0, baseB - eyeDark * 0.5);
}

coconutGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
coconutGeo.computeVertexNormals();

function smoothstep(edge0, edge1, x) {
  const t = Math.max(0, Math.min(1, (x - edge0) / (edge1 - edge0)));
  return t * t * (3 - 2 * t);
}

// ── Coconut Material ───────────────────────────────────
const coconutMat = new THREE.MeshStandardMaterial({
  vertexColors: true,
  roughness: 0.85,
  metalness: 0.0,
  bumpScale: 0.02,
});

// Create procedural bump map via canvas
const bumpCanvas = document.createElement('canvas');
bumpCanvas.width = 512;
bumpCanvas.height = 512;
const bCtx = bumpCanvas.getContext('2d');

// Generate fibrous noise texture
const imageData = bCtx.createImageData(512, 512);
for (let py = 0; py < 512; py++) {
  for (let px = 0; px < 512; px++) {
    const u = px / 512;
    const v = py / 512;
    const x = (u - 0.5) * 2;
    const y = (v - 0.5) * 2;
    const r = Math.sqrt(x * x + y * y);

    // Fibrous pattern - lines radiating from center
    const angle = Math.atan2(y, x);
    const freq = 40;
    const fiber = Math.sin(angle * freq + r * 30) * 0.5 + 0.5;
    const fiber2 = Math.sin(angle * freq * 1.5 + r * 20 + 1) * 0.3 + 0.5;
    const noise_val = (Math.sin(x * 50 + y * 37) * 0.5 + 0.5) * 0.3;

    const val = (fiber * 0.4 + fiber2 * 0.3 + noise_val * 0.3) * 255;
    const idx = (py * 512 + px) * 4;
    imageData.data[idx] = val;
    imageData.data[idx + 1] = val;
    imageData.data[idx + 2] = val;
    imageData.data[idx + 3] = 255;
  }
}
bCtx.putImageData(imageData, 0, 0);
const bumpTexture = new THREE.CanvasTexture(bumpCanvas);
coconutMat.bumpMap = bumpTexture;
coconutMat.bumpScale = 0.04;

// Create a normal map too for extra detail
const normalCanvas = document.createElement('canvas');
normalCanvas.width = 512;
normalCanvas.height = 512;
const nCtx = normalCanvas.getContext('2d');
const nImageData = nCtx.createImageData(512, 512);
for (let py = 0; py < 512; py++) {
  for (let px = 0; px < 512; px++) {
    const u = px / 512;
    const v = py / 512;
    const x = (u - 0.5) * 2;
    const y = (v - 0.5) * 2;
    const r = Math.sqrt(x * x + y * y);
    const angle = Math.atan2(y, x);

    // Get height from neighboring pixels for normal approximation
    const eps = 0.002;
    const h = (a, b) => {
      const ang = Math.atan2(b, a);
      const rr = Math.sqrt(a * a + b * b);
      return (Math.sin(ang * 40 + rr * 30) * 0.5 + 0.5) * 0.4
           + (Math.sin(ang * 60 + rr * 20 + 1) * 0.3 + 0.5) * 0.3
           + ((Math.sin(a * 50 + b * 37) * 0.5 + 0.5) * 0.3);
    };

    const dx = (h(x + eps, y) - h(x - eps)) / (2 * eps);
    const dy = (h(x, y + eps) - h(x, y - eps)) / (2 * eps);

    const idx = (py * 512 + px) * 4;
    nImageData.data[idx]     = (dx * 0.5 + 0.5) * 255;
    nImageData.data[idx + 1] = (dy * 0.5 + 0.5) * 255;
    nImageData.data[idx + 2] = 200;
    nImageData.data[idx + 3] = 255;
  }
}
nCtx.putImageData(nImageData, 0, 0);
const normalTexture = new THREE.CanvasTexture(normalCanvas);
coconutMat.normalMap = normalTexture;
coconutMat.normalScale = new THREE.Vector2(0.3, 0.3);

const coconut = new THREE.Mesh(coconutGeo, coconutMat);
coconut.castShadow = true;
coconut.receiveShadow = true;
coconut.position.y = 1.0;
coconut.rotation.x = 0.3;
scene.add(coconut);

// ── Coconut Eyes (inner dark circles) ──────────────────
const eyeGeo = new THREE.CircleGeometry(0.06, 32);
const eyeMat = new THREE.MeshStandardMaterial({
  color: 0x1a0f08,
  roughness: 0.6,
  metalness: 0.1,
