}
</style>
</head>
<body>
<div id="info">🪮 Three.js Comb — drag to orbit · scroll to zoom</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.025);

// ── Camera ─────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(40, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 3, 14);

// ── Renderer ───────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ── Controls ───────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.target.set(0, 0, 0);

// ── Lighting ───────────────────────────────────────────
const ambient = new THREE.AmbientLight(0x8090b0, 0.6);
scene.add(ambient);

const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(5, 8, 6);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
key.shadow.camera.near = 1;
key.shadow.camera.far = 30;
key.shadow.camera.left = -10;
key.shadow.camera.right = 10;
key.shadow.camera.top = 10;
key.shadow.camera.bottom = -10;
scene.add(key);

const fill = new THREE.DirectionalLight(0x6688cc, 0.8);
fill.position.set(-6, 2, -4);
scene.add(fill);

const rim = new THREE.PointLight(0xff8844, 1.5, 20);
rim.position.set(-3, 4, -5);
scene.add(rim);

// ── Comb Material (tortoiseshell / dark acrylic) ──────
const combMat = new THREE.MeshPhysicalMaterial({
  color: 0x2a1a0a,
  roughness: 0.25,
  metalness: 0.05,
  clearcoat: 0.6,
  clearcoatRoughness: 0.15,
  reflectivity: 0.5,
});

// ── Build Comb ─────────────────────────────────────────
const combGroup = new THREE.Group();

// Backbone (top bar)
const backGeo = new THREE.BoxGeometry(12, 0.35, 0.7, 1, 1, 1);
// Round the backbone edges slightly by beveling isn't available on BoxGeo,
// so we use a slightly rounded approach via a custom shape or just accept sharp edges.
// Instead let's build a rounded backbone with ExtrudeGeometry
const backShape = new THREE.Shape();
const bw = 12, bh = 0.35, br = 0.12;
backShape.moveTo(-bw/2 + br, -bh/2);
backShape.lineTo( bw/2 - br, -bh/2);
backShape.quadraticCurveTo( bw/2, -bh/2,  bw/2, -bh/2 + br);
backShape.lineTo( bw/2,  bh/2 - br);
backShape.quadraticCurveTo( bw/2,  bh/2,  bw/2 - br,  bh/2);
backShape.lineTo(-bw/2 + br,  bh/2);
backShape.quadraticCurveTo(-bw/2,  bh/2, -bw/2,  bh/2 - br);
backShape.lineTo(-bw/2, -bh/2 + br);
backShape.quadraticCurveTo(-bw/2, -bh/2, -bw/2 + br, -bh/2);

const extrudeSettings = { depth: 0.7, bevelEnabled: true, bevelThickness: 0.05, bevelSize: 0.05, bevelSegments: 3 };
const backboneGeo = new THREE.ExtrudeGeometry(backShape, extrudeSettings);
const backbone = new THREE.Mesh(backboneGeo, combMat);
backbone.rotation.x = -Math.PI / 2;
backbone.position.set(0, 0.175, 0);
backbone.castShadow = true;
backbone.receiveShadow = true;
combGroup.add(backbone);

// Teeth
const NUM_TEETH = 24;
const TOOTH_SPACING = 0.48;
const TOOTH_LENGTH = 2.8;
const TOOTH_WIDTH = 0.06;
const TOOTH_DEPTH = 0.55;

// Reusable tooth geometry (rounded top)
function createToothGeometry() {
  const shape = new THREE.Shape();
  const w = TOOTH_WIDTH, l = TOOTH_LENGTH, r = w * 0.6;
  shape.moveTo(-w/2, 0);
  shape.lineTo(-w/2, -l + r);
  shape.quadraticCurveTo(-w/2, -l, -w/2 + r, -l);
  shape.lineTo(w/2 - r, -l);
  shape.quadraticCurveTo(w/2, -l, w/2, -l + r);
  shape.lineTo(w/2, 0);
  shape.closePath();

  const geo = new THREE.ExtrudeGeometry(shape, {
    depth: TOOTH_DEPTH,
    bevelEnabled: true,
    bevelThickness: 0.02,
    bevelSize: 0.02,
    bevelSegments: 2,
  });
  geo.center();
  return geo;
}

const toothGeo = createToothGeometry();
const startX = -(NUM_TEETH - 1) * TOOTH_SPACING / 2;

for (let i = 0; i < NUM_TEETH; i++) {
  const tooth = new THREE.Mesh(toothGeo, combMat);
  tooth.position.set(startX + i * TOOTH_SPACING, -TOOTH_LENGTH / 2 + 0.1, 0);
  tooth.castShadow = true;
  tooth.receiveShadow = true;
  combGroup.add(tooth);
}

// Handle (bottom extension on one end)
const handleShape = new THREE.Shape();
const hw = 1.6, hh = 2.0, hr = 0.5;
handleShape.moveTo(-hw/2 + hr, -hh/2);
handleShape.lineTo( hw/2 - hr, -hh/2);
handleShape.quadraticCurveTo( hw/2, -hh/2,  hw/2, -hh/2 + hr);
handleShape.lineTo( hw/2,  hh/2 - hr);
handleShape.quadraticCurveTo( hw/2,  hh/2,  hw/2 - hr,  hh/2);
handleShape.lineTo(-hw/2 + hr,  hh/2);
handleShape.quadraticCurveTo(-hw/2,  hh/2, -hw/2,  hh/2 - hr);
handleShape.lineTo(-hw/2, -hh/2 + hr);
handleShape.quadraticCurveTo(-hw/2, -hh/2, -hw/2 + hr, -hh/2);

const handleGeo = new THREE.ExtrudeGeometry(handleShape, {
  depth: 0.75,
  bevelEnabled: true,
  bevelThickness: 0.06,
  bevelSize: 0.06,
  bevelSegments: 4,
});
const handle = new THREE.Mesh(handleGeo, combMat);
handle.rotation.x = -Math.PI / 2;
handle.position.set(-5.8, -1.0, 0);
handle.castShadow = true;
handle.receiveShadow = true;
combGroup.add(handle);

// ── Position comb ──────────────────────────────────────
combGroup.rotation.z = Math.PI;        // teeth point down after flip
combGroup.rotation.y = 0.15;
combGroup.position.y = 0.5;
scene.add(combGroup);

// ── Ground plane (shadow catcher) ──────────────────────
const groundGeo = new THREE.PlaneGeometry(40, 40);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x1a1a2e, roughness: 1 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -4.5;
ground.receiveShadow = true;
scene.add(ground);

// ── Subtle particle dust ───────────────────────────────
const particleCount = 120;
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  pPos[i*3]   = (Math.random() - 0.5) * 20;
  pPos[i*3+1] = (Math.random() - 0.5) * 12;
  pPos[i*3+2] = (Math.random() - 0.5) * 20;
}
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
const pMat = new THREE.PointsMaterial({ color: 0x667799, size: 0.03, transparent: true, opacity: 0.5 });
const particles = new THREE.Points(pGeo, pMat);
scene.add(particles);

// ── Animate ────────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Gentle floating rotation
  combGroup.rotation.y = 0.15 + Math.sin(t * 0.4) * 0.3;
  combGroup.position.y = 0.5 + Math.sin(t * 0.6) * 0.15;

  // Slow particle drift
  particles.rotation.y = t * 0.02;
  particles.rotation.x = Math.sin(t * 0.01) * 0.1;

  controls.update();
  renderer.render(scene, camera);
}
animate();

// ── Resize ─────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
```

**What this creates:**

- **Backbone** — a rounded rectangular bar with beveled edges (extruded shape)
- **24 teeth** — evenly-spaced, rounded-tip prongs extending downward from the backbone
- **Handle** — a rounded grip on the left end for realism
- **Material** — dark tortoiseshell acrylic look with clearcoat sheen via `MeshPhysicalMaterial`
- **Lighting** — 3-point setup (key, fill, rim) with soft shadows
- **Animation** — gentle floating/swaying motion + drifting dust particles
- **Interaction** — OrbitControls (drag to rotate, scroll to zoom)

