<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ─── Renderer ─── */
const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

/* ─── Scene & Camera ─── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x0a0a12);
scene.fog = new THREE.FogExp2(0x0a0a12, 0.025);

const camera = new THREE.PerspectiveCamera(40, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 6, 8);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 0, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.maxPolarAngle = Math.PI / 2.1;
controls.minDistance = 4;
controls.maxDistance = 20;
controls.update();

/* ─── Lighting ─── */
const ambientLight = new THREE.AmbientLight(0x30304a, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 2.5);
dirLight.position.set(5, 10, 5);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(2048, 2048);
dirLight.shadow.camera.near = 1;
dirLight.shadow.camera.far = 30;
dirLight.shadow.camera.left = -8;
dirLight.shadow.camera.right = 8;
dirLight.shadow.camera.top = 8;
dirLight.shadow.camera.bottom = -8;
dirLight.shadow.bias = -0.001;
scene.add(dirLight);

const fillLight = new THREE.DirectionalLight(0x8888cc, 0.6);
fillLight.position.set(-4, 3, -5);
scene.add(fillLight);

const rimLight = new THREE.PointLight(0xffaa44, 1.2, 15);
rimLight.position.set(-3, 4, -3);
scene.add(rimLight);

/* ─── Materials ─── */
const brassMat = new THREE.MeshStandardMaterial({
  color: 0xc4a35a, metalness: 0.85, roughness: 0.25
});
const darkBrassMat = new THREE.MeshStandardMaterial({
  color: 0x8a7238, metalness: 0.8, roughness: 0.35
});
const dialMat = new THREE.MeshStandardMaterial({
  color: 0x1a1a2e, metalness: 0.1, roughness: 0.6
});
const goldMat = new THREE.MeshStandardMaterial({
  color: 0xd4a843, metalness: 0.9, roughness: 0.15
});
const redMat = new THREE.MeshStandardMaterial({
  color: 0xcc2222, metalness: 0.3, roughness: 0.4, emissive: 0x330000
});
const whiteMat = new THREE.MeshStandardMaterial({
  color: 0xeeeeee, metalness: 0.2, roughness: 0.5
});
const glassMat = new THREE.MeshPhysicalMaterial({
  color: 0xffffff, metalness: 0, roughness: 0, transmission: 0.92,
  thickness: 0.3, ior: 1.5, transparent: true, opacity: 0.3,
  envMapIntensity: 1.0
});
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x0d0d18, metalness: 0.0, roughness: 0.9
});

/* ─── Compass Group ─── */
const compass = new THREE.Group();
scene.add(compass);

/* ─── Outer Ring ─── */
const outerRingGeo = new THREE.TorusGeometry(2.8, 0.18, 16, 64);
const outerRing = new THREE.Mesh(outerRingGeo, brassMat);
outerRing.rotation.x = -Math.PI / 2;
outerRing.position.y = 0.05;
outerRing.castShadow = true;
compass.add(outerRing);

/* ─── Outer Bezel (thick ring) ─── */
const bezelGeo = new THREE.TorusGeometry(2.65, 0.12, 12, 64);
const bezel = new THREE.Mesh(bezelGeo, darkBrassMat);
bezel.rotation.x = -Math.PI / 2;
bezel.position.y = 0.1;
bezel.castShadow = true;
compass.add(bezel);

/* ─── Dial Face ─── */
const dialGeo = new THREE.CylinderGeometry(2.5, 2.5, 0.08, 64);
const dial = new THREE.Mesh(dialGeo, dialMat);
dial.position.y = 0.04;
dial.receiveShadow = true;
compass.add(dial);

/* ─── Inner Ring Decorative ─── */
const innerRingGeo = new THREE.TorusGeometry(2.35, 0.04, 8, 64);
const innerRing = new THREE.Mesh(innerRingGeo, goldMat);
innerRing.rotation.x = -Math.PI / 2;
innerRing.position.y = 0.09;
compass.add(innerRing);

/* ─── Degree Tick Marks ─── */
for (let i = 0; i < 72; i++) {
  const angle = (i / 72) * Math.PI * 2;
  const isMajor = i % 18 === 0;     // N, S, E, W every 90°
  const isMid = i % 9 === 0;        // intercardinals every 45°
  const isMinor = i % 6 === 0;      // every 30°

  const tickLen = isMajor ? 0.2 : isMid ? 0.14 : isMinor ? 0.1 : 0.05;
  const tickWidth = isMajor ? 0.04 : 0.015;
  const r1 = 2.35;
  const r2 = r1 - tickLen;

  const shape = new THREE.Shape();
  const halfW = tickWidth / 2;
  shape.moveTo(-halfW, 0);
  shape.lineTo(halfW, 0);
  shape.lineTo(halfW * 0.5, -tickLen);
  shape.lineTo(-halfW * 0.5, -tickLen);
  shape.closePath();

  const tickGeo = new THREE.ExtrudeGeometry(shape, {
    depth: 0.02, bevelEnabled: false
  });
  const tickMat = isMajor ? goldMat : goldMat.clone();
  if (!isMajor) tickMat.color.set(0x888866);
  const tick = new THREE.Mesh(tickGeo, tickMat);
  tick.rotation.y = -angle;
  tick.position.set(
    Math.cos(angle) * r1,
    0.09,
    Math.sin(angle) * r1
  );
  tick.rotation.x = 0;
  compass.add(tick);
}

/* ─── Cardinal Direction Labels (as 3D text via canvas textures) ─── */
function createTextSprite(text, fontSize, color, scale) {
  const canvas = document.createElement('canvas');
  const size = 256;
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = 'transparent';
  ctx.fillRect(0, 0, size, size);
  ctx.font = `bold ${fontSize}px Georgia`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillStyle = color;
  ctx.shadowColor = 'rgba(0,0,0,0.5)';
  ctx.shadowBlur = 4;
  ctx.fillText(text, size / 2, size / 2);

  const texture = new THREE.CanvasTexture(canvas);
  texture.minFilter = THREE.LinearFilter;
  const mat = new THREE.SpriteMaterial({ map: texture, transparent: true, depthWrite: false });
  const sprite = new THREE.Sprite(mat);
  sprite.scale.set(scale, scale, 1);
  return sprite;
}

const labelRadius = 2.05;
const labels = [
  { text: 'N', angle: 0, color: '#dd3333', scale: 0.65 },
  { text: 'E', angle: Math.PI / 2, color: '#c0b89a', scale: 0.5 },
  { text: 'S', angle: Math.PI, color: '#c0b89a', scale: 0.5 },
  { text: 'W', angle: -Math.PI / 2, color: '#c0b89a', scale: 0.5 },
];
labels.forEach(l => {
  const sprite = createTextSprite(l.text, 140, l.color, l.scale);
  sprite.position.set(
    Math.cos(l.angle) * labelRadius,
    0.12,
    Math.sin(l.angle) * labelRadius
  );
  compass.add(sprite);
});

/* ─── Intercardinal Labels ─── */
const interLabels = ['NE', 'SE', 'SW', 'NW'];
const interAngles = [Math.PI/4, 3*Math.PI/4, 5*Math.PI/4, 7*Math.PI/4];
interLabels.forEach((text, i) => {
  const sprite = createTextSprite(text, 80, '#777766', 0.3);
  sprite.position.set(
    Math.cos(interAngles[i]) * 1.7,
    0.12,
    Math.sin(interAngles[i]) * 1.7
  );
  compass.add(sprite);
});

/* ─── Compass Rose (decorative star) ─── */
function createRosePoint(radius, width, depth) {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.lineTo(-width / 2, -radius);
  shape.lineTo(0, -radius * 1.15);
  shape.lineTo(width / 2, -radius);
  shape.closePath();
  return new THREE.ExtrudeGeometry(shape, { depth, bevelEnabled: true, bevelThickness: 0.01, bevelSize: 0.01, bevelSegments: 2 });
}

const roseGroup = new THREE.Group();
roseGroup.position.y = 0.1;

// 4 main points (N, S, E, W)
for (let i = 0; i < 4; i++) {
  const angle = (i * Math.PI) / 2;
  const geo = createRosePoint(1.6, 0.18, 0.02);
  const mat = i === 0 ? redMat : goldMat;
  const mesh = new THREE.Mesh(geo, mat);
  mesh.rotation.y = -angle;
  mesh.castShadow = true;
  roseGroup.add(mesh);
}

// 4 intercardinal points
for (let i = 0; i < 4; i++) {
  const angle = (i * Math.PI) / 2 + Math.PI / 4;
  const geo = createRosePoint(1.1, 0.12, 0.015);
  const mesh = new THREE.Mesh(geo, goldMat);
  mesh.rotation.y = -angle;
  roseGroup.add(mesh);
}

// Center circle
const centerGeo = new THREE.SphereGeometry(0.15, 24, 24);
const centerSphere = new THREE.Mesh(centerGeo, goldMat);
centerSphere.position.y = 0.02;
centerSphere.castShadow = true;
roseGroup.add(centerSphere);

compass.add(roseGroup);

/* ─── Magnetic Needle ─── */
const needleGroup = new THREE.Group();
needleGroup.position.y = 0.16;

// North half (red)
const northShape = new THREE.Shape();
northShape.moveTo(0, 0);
northShape.lineTo(-0.06, -1.5);
northShape.lineTo(0, -1.65);
northShape.lineTo(0.06, -1.5);
northShape.closePath();
const northGeo = new THREE.ExtrudeGeometry(northShape, {
  depth: 0.03, bevelEnabled: true, bevelThickness: 0.005, bevelSize: 0.005, bevelSegments: 2
});
const northNeedle = new THREE.Mesh(northGeo, redMat);
northNeedle.castShadow = true;
needleGroup.add(northNeedle);

// South half (white)
const southShape = new THREE.Shape();
southShape.moveTo(0, 0);
southShape.lineTo(-0.06, 1.5);
