        new THREE.Color(0xc4883c),
        new THREE.Color(0xd4954b),
        new THREE.Color(0xb5792f),
        new THREE.Color(0xc9924a),
        new THREE.Color(0xa8722a),
        new THREE.Color(0xd9a055),
        new THREE.Color(0xbc853e),
        new THREE.Color(0xc18238),
    ];

    for (let i = 0; i < pos.count; i++) {
        let x = pos.getX(i);
        let y = pos.getY(i);
        let z = pos.getZ(i);

        const dist = Math.sqrt(x * x + z * z);
        const angle = Math.atan2(z, x);
        const normalizedDist = dist / radius;

        // Irregular edge displacement - more organic shape
        let edgeNoise = 0;
        if (normalizedDist > 0.85) {
            const edgeFactor = (normalizedDist - 0.85) / 0.15;
            const n1 = Math.sin(angle * 5 + 1.2) * 0.08;
            const n2 = Math.sin(angle * 8 - 0.5) * 0.05;
            const n3 = Math.sin(angle * 3 + 2.1) * 0.06;
            const n4 = Math.sin(angle * 12 + 0.3) * 0.025;
            edgeNoise = (n1 + n2 + n3 + n4) * edgeFactor;
            x += (x / dist) * edgeNoise;
            z += (z / dist) * edgeNoise;
        }

        // Surface bumps and craters on top face
        let yDisplacement = 0;
        if (y > 0) {
            const b1 = Math.sin(x * 6 + z * 4) * 0.03;
            const b2 = Math.sin(x * 10 - z * 7 + 1) * 0.02;
            const b3 = Math.cos(x * 3 + z * 5 + 2) * 0.025;
            const b4 = Math.sin(x * 15 + z * 12) * 0.01;
            yDisplacement = b1 + b2 + b3 + b4;

            // Slight center depression
            const centerDepression = -0.02 * Math.exp(-normalizedDist * normalizedDist * 2);
            yDisplacement += centerDepression;
        }

        // Edge rounding - taper at sides
        const edgeAngle = Math.acos(Math.max(-1, Math.min(1, y / (thickness * 0.5))));
        const roundFactor = Math.sin(edgeAngle * Math.PI * 0.5);
        x *= (0.92 + 0.08 * roundFactor);
        z *= (0.92 + 0.08 * roundFactor);

        // Small thickness variation
        const thickNoise = Math.sin(angle * 4 + dist * 5) * 0.02;
        y += thickNoise;

