        const isTopFace = y > thickness * 0.2;
        const isBottomFace = y < -thickness * 0.2;
        const rand = (Math.sin(i * 127.1 + x * 311.7 + z * 74.7) * 43758.5453) % 1;
        const colorIdx = Math.abs(rand) % cookieColors.length;
        const baseColor = cookieColors[Math.floor(colorIdx)];

        let r, g, b;
        if (isTopFace) {
            // Lighter top with variation
            const lightVar = 0.9 + Math.abs(rand) * 0.2;
            r = baseColor.r * lightVar;
            g = baseColor.g * lightVar;
            b = baseColor.b * lightVar;
        } else if (isBottomFace) {
            // Darker bottom (baked more)
            r = baseColor.r * 0.65;
            g = baseColor.g * 0.55;
            b = baseColor.b * 0.45;
        } else {
            // Sides - medium
            const sideVar = 0.8 + Math.abs(rand) * 0.15;
            r = baseColor.r * sideVar;
            g = baseColor.g * sideVar;
            b = baseColor.b * sideVar;
        }

        colors[i * 3] = Math.min(1, r);
        colors[i * 3 + 1] = Math.min(1, g);
        colors[i * 3 + 2] = Math.min(1, b);
    }

    geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
    geo.computeVertexNormals();
    return geo;
}

