<script type="module">
import * as THREE from 'three';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x021b35);
scene.fog = new THREE.FogExp2(0x021b35, 0.035);

const camera = new THREE.PerspectiveCamera(55, innerWidth/innerHeight, 0.1, 100);
camera.position.set(0, 2, 12);
camera.lookAt(0, 3, 0);

const renderer = new THREE.WebGLRenderer({antialias:true});
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);

// Lights
scene.add(new THREE.AmbientLight(0x1a3a5c, 0.8));
const sun = new THREE.DirectionalLight(0x88ccff, 2.5);
sun.position.set(5, 15, 8);
scene.add(sun);
const rim = new THREE.DirectionalLight(0xff6644, 0.6);
rim.position.set(-5, 3, -5);
scene.add(rim);
const point = new THREE.PointLight(0xff4488, 1.5, 20);
point.position.set(0, 6, 3);
scene.add(point);

// Coral palette
const coralColors = [
  new THREE.Color(0xff4466),
  new THREE.Color(0xff6688),
  new THREE.Color(0xff3355),
  new THREE.Color(0xee5577),
  new THREE.Color(0xff7799),
  new THREE.Color(0xcc3355),
  new THREE.Color(0xff8866),
  new THREE.Color(0xdd4466),
];

// Build branching coral
function createCoral(x, y, z, height, colorIdx) {
  const group = new THREE.Group();
  group.position.set(x, y, z);

  const baseColor = coralColors[colorIdx % coralColors.length];
  const mat = new THREE.MeshStandardMaterial({
    color: baseColor,
    roughness: 0.75,
    metalness: 0.05,
    flatShading: true,
  });

  const branches = []; // {group, phase, speed}

  function branch(parent, origin, dir, radius, length, depth, maxDepth, angle, swayPhase) {
    if (depth > maxDepth || radius < 0.02) return;

    const end = origin.clone().add(dir.clone().multiplyScalar(length));

    // Cylinder segment
    const mid = origin.clone().add(end).multiplyScalar(0.5);
    const segLen = length;
    const geo = new THREE.CylinderGeometry(radius * 0.7, radius, segLen, 7, 1);
    const mesh = new THREE.Mesh(geo, mat.clone());
    mesh.position.copy(mid);
    mesh.quaternion.setFromUnitVectors(new THREE.Vector3(0,1,0), dir.clone().normalize());
    group.add(mesh);

    // Tip bulb
    const tipGeo = new THREE.IcosahedronGeometry(radius * 1.1, 1);
    const tip = new THREE.Mesh(tipGeo, mat);
    tip.position.copy(end);
    group.add(tip);

    // Store for animation
    const bGroup = new THREE.Group();
    bGroup.position.copy(end);
    group.add(bGroup);
    branches.push({
      group: bGroup,
      origin: end.clone(),
      phase: swayPhase + depth * 0.7 + Math.random() * 2,
      speed: 0.3 + Math.random() * 0.3,
      depth,
    });

    // Sub-branches
    const numChildren = depth < 2 ? 3 : 2;
    const childAngle = angle * (0.8 + Math.random() * 0.4);
    const shrink = 0.62 + Math.random() * 0.12;

    for (let i = 0; i < numChildren; i++) {
      const axis = new THREE.Vector3(
        (Math.random()-0.5), (Math.random()-0.5)*0.5, (Math.random()-0.5)
      ).normalize();
      const newDir = dir.clone().normalize();
      const rotated = newDir.clone().applyAxisAngle(axis, childAngle + (Math.random()-0.5)*0.3);

      const newLen = length * (0.7 + Math.random() * 0.25);
      const newRad = radius * shrink;

      branch(group, end, rotated, newRad, newLen, depth+1, maxDepth, childAngle * 0.8, swayPhase + i * 1.3);
    }
  }

  // Main trunk
  const trunkDir = new THREE.Vector3(0, 1, 0);
  branch(group, new THREE.Vector3(0,0,0), trunkDir, 0.25, height, 0, 5, 0.6, Math.random()*6);

  return { group, branches };
}

// Create multiple corals
const corals = [];
const coralConfigs = [
  {x:0, y:0, z:0, h:5.5, ci:0},
  {x:-3.5, y:0, z:-1, h:4.5, ci:2},
  {x:3, y:0, z:0.5, h:5, ci:4},
  {x:-1.5, y:0, z:3, h:4, ci:1},
  {x:2, y:0, z:3.5, h:4.8, ci:5},
  {x:-4, y:0, z:2, h:3.5, ci:3},
  {x:4.5, y:0, z:-2, h:4.2, ci:6},
];

coralConfigs.forEach(c => {
  const coral = createCoral(c.x, c.y, c.z, c.h, c.ci);
  scene.add(coral.group);
  corals.push(coral);
});

// Sea floor
const floorGeo = new THREE.CircleGeometry(30, 32);
const floorMat = new THREE.MeshStandardMaterial({color:0x1a2a1a, roughness:1});
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI/2;
floor.position.y = -0.5;
scene.add(floor);

// Sand particles on floor
const sandGeo = new THREE.BufferGeometry();
const sandCount = 2000;
const sandPos = new Float32Array(sandCount*3);
for(let i=0;i<sandCount;i++){
  sandPos[i*3] = (Math.random()-0.5)*50;
  sandPos[i*3+1] = -0.45 + Math.random()*0.1;
  sandPos[i*3+2] = (Math.random()-0.5)*50;
}
sandGeo.setAttribute('position', new THREE.BufferAttribute(sandPos,3));
const sandMat = new THREE.PointsMaterial({color:0x887755, size:0.08, transparent:true, opacity:0.5});
scene.add(new THREE.Points(sandGeo, sandMat));

// Floating particles (plankton)
const particleCount = 600;
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(particleCount*3);
const pVel = [];
for(let i=0;i<particleCount;i++){
  pPos[i*3] = (Math.random()-0.5)*30;
  pPos[i*3+1] = Math.random()*15;
  pPos[i*3+2] = (Math.random()-0.5)*30;
  pVel.push({x:(Math.random()-0.5)*0.003, y:0.005+Math.random()*0.01, z:(Math.random()-0.5)*0.003});
}
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos,3));
const pMat = new THREE.PointsMaterial({color:0x88ddff, size:0.06, transparent:true, opacity:0.4});
const particles = new THREE.Points(pGeo, pMat);
scene.add(particles);

// Bubbles
const bubbleCount = 30;
const bubbles = [];
for(let i=0;i<bubbleCount;i++){
  const bGeo = new THREE.SphereGeometry(0.03+Math.random()*0.06, 6, 6);
  const bMat = new THREE.MeshBasicMaterial({color:0xaaddff, transparent:true, opacity:0.3});
  const b = new THREE.Mesh(bGeo, bMat);
  b.position.set((Math.random()-0.5)*10, Math.random()*12, (Math.random()-0.5)*10);
  b.userData = {speed:0.01+Math.random()*0.02, wobble:Math.random()*Math.PI*2};
  scene.add(b);
  bubbles.push(b);
}

// Animation
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Sway corals
  corals.forEach(coral => {
    coral.branches.forEach(b => {
      const swayX = Math.sin(t * b.speed + b.phase) * 0.04 * (b.depth + 1);
      const swayZ = Math.cos(t * b.speed * 0.7 + b.phase + 1) * 0.03 * (b.depth + 1);
      b.group.rotation.z = swayX;
      b.group.rotation.x = swayZ;
    });
  });

  // Float particles
  const pp = particles.geometry.attributes.position.array;
  for(let i=0;i<particleCount;i++){
    pp[i*3] += pVel[i].x + Math.sin(t*0.5+i)*0.002;
    pp[i*3+1] += pVel[i].y;
    pp[i*3+2] += pVel[i].z + Math.cos(t*0.3+i)*0.002;
    if(pp[i*3+1]>15){pp[i*3+1]=0; pp[i*3]=(Math.random()-0.5)*30; pp[i*3+2]=(Math.random()-0.5)*30;}
  }
  particles.geometry.attributes.position.needsUpdate = true;

  // Bubbles
  bubbles.forEach(b => {
    b.position.y += b.userData.speed;
    b.position.x += Math.sin(t*2 + b.userData.wobble)*0.005;
    if(b.position.y>14){b.position.y=-1; b.position.x=(Math.random()-0.5)*10;}
  });

  // Gentle camera orbit
  camera.position.x = Math.sin(t*0.1)*2;
  camera.position.z = 12 + Math.cos(t*0.1)*1;
  camera.lookAt(0, 3, 0);

  renderer.render(scene, camera);
}
animate();

window.addEventListener('resize', ()=>{
  camera.aspect = innerWidth/innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
