This creates a **procedural 3D corn on the cob** with:

- **Cob** — tapered cylinder with a rounded tip
- **~224 kernels** — instanced hemispheres in staggered rows with color/size variation
- **6 husk leaves** — curved, double-sided shape geometries in varying greens
- **Top husk wrap** — partially covering the top
- **40 silk strands** — thin tubes along quadratic Bézier curves
- **Lighting** — directional, fill, rim, and ambient lights with shadows
- **Animation** — slow rotation + gentle floating + leaf sway
- **Ground plane** — dark surface with shadow reception

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Three.js Couch</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { overflow: hidden; background: #1a1a2e; }
canvas { display: block; }
</style>
</head>
<body>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ── Scene ──────────────────────────────────────────────
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 15, 30);

// ── Camera ─────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(6, 4, 8);

// ── Renderer ───────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Controls ───────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 1, 0);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.maxPolarAngle = Math.PI / 2.05;
controls.minDistance = 4;
controls.maxDistance = 20;
controls.update();

// ── Lighting ───────────────────────────────────────────
const ambient = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambient);

const hemi = new THREE.HemisphereLight(0xffeedd, 0x303040, 0.6);
scene.add(hemi);

const dir = new THREE.DirectionalLight(0xfff0dd, 2.5);
dir.position.set(5, 8, 4);
dir.castShadow = true;
dir.shadow.mapSize.set(2048, 2048);
dir.shadow.camera.near = 1;
dir.shadow.camera.far = 25;
dir.shadow.camera.left = -8;
dir.shadow.camera.right = 8;
dir.shadow.camera.top = 8;
dir.shadow.camera.bottom = -8;
dir.shadow.bias = -0.0005;
scene.add(dir);

const fill = new THREE.DirectionalLight(0x8888ff, 0.4);
fill.position.set(-4, 3, -3);
scene.add(fill);

const spot = new THREE.SpotLight(0xffaa66, 3, 15, Math.PI / 6, 0.5);
spot.position.set(0, 6, 0);
spot.castShadow = true;
scene.add(spot);

// ── Materials ──────────────────────────────────────────
const fabricMat = new THREE.MeshStandardMaterial({
  color: 0x8B4513,
  roughness: 0.85,
  metalness: 0.0,
});

const cushionMat = new THREE.MeshStandardMaterial({
  color: 0xA0522D,
  roughness: 0.75,
  metalness: 0.0,
});

const darkFabricMat = new THREE.MeshStandardMaterial({
  color: 0x6B3410,
  roughness: 0.8,
  metalness: 0.0,
});

const legMat = new THREE.MeshStandardMaterial({
  color: 0x2a1a0a,
  roughness: 0.4,
  metalness: 0.3,
});

const frameMat = new THREE.MeshStandardMaterial({
  color: 0x3a2210,
  roughness: 0.5,
  metalness: 0.1,
});

// ── Helper: rounded box via scaling ────────────────────
function makeBox(w, h, d, mat) {
  const geo = new THREE.BoxGeometry(w, h, d);
  const mesh = new THREE.Mesh(geo, mat);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  return mesh;
}

// ── Build Couch ────────────────────────────────────────
const couch = new THREE.Group();

// Base frame
const base = makeBox(4.2, 0.3, 1.8, frameMat);
base.position.set(0, 0.35, 0);
couch.add(base);

// Front apron
const apron = makeBox(4.0, 0.25, 0.08, darkFabricMat);
apron.position.set(0, 0.35, 0.85);
couch.add(apron);

// Back frame panel
const backPanel = makeBox(4.2, 1.2, 0.15, frameMat);
backPanel.position.set(0, 1.1, -0.82);
couch.add(backPanel);

// ── Seat cushions (3) ──────────────────────────────────
const seatW = 1.25, seatH = 0.22, seatD = 1.4;
const seatGap = 0.06;
for (let i = -1; i <= 1; i++) {
  const cushion = makeBox(seatW, seatH, seatD, cushionMat);
  cushion.position.set(i * (seatW + seatGap), 0.58, 0.05);
  couch.add(cushion);

  // Seat cushion top (slightly lighter, rounded feel)
  const top = makeBox(seatW - 0.05, 0.04, seatD - 0.05, fabricMat);
  top.position.set(i * (seatW + seatGap), 0.71, 0.05);
  couch.add(top);
}

// ── Back cushions (3) ──────────────────────────────────
const backW = 1.25, backH = 0.65, backD = 0.3;
for (let i = -1; i <= 1; i++) {
  const bc = makeBox(backW, backH, backD, cushionMat);
  bc.position.set(i * (backW + seatGap), 1.05, -0.45);
  couch.add(bc);

  // Pillow tufting detail (small indent look)
  const tuft = makeBox(0.08, 0.02, 0.08, darkFabricMat);
  tuft.position.set(i * (backW + seatGap), 1.38, -0.28);
  couch.add(tuft);
}

// ── Armrests ───────────────────────────────────────────
for (const side of [-1, 1]) {
  // Vertical part
  const armV = makeBox(0.2, 0.55, 1.6, fabricMat);
