// ── Cracker Material ──
function createCrackerMaterial() {
  const canvas = document.createElement('canvas');
  canvas.width = 512;
  canvas.height = 512;
  const ctx = canvas.getContext('2d');

  // Base color
  ctx.fillStyle = '#d4a04a';
  ctx.fillRect(0, 0, 512, 512);

  // Grain/noise texture
  for (let i = 0; i < 8000; i++) {
    const x = Math.random() * 512;
    const y = Math.random() * 512;
    const brightness = 160 + Math.random() * 60;
    const r = brightness + Math.random() * 30;
    const g = brightness - 20 + Math.random() * 20;
    const b = brightness - 80 + Math.random() * 30;
    ctx.fillStyle = `rgba(${r|0},${g|0},${b|0},${0.15 + Math.random() * 0.2})`;
    ctx.fillRect(x, y, 1 + Math.random() * 2, 1 + Math.random() * 2);
  }

  // Subtle darker spots
  for (let i = 0; i < 30; i++) {
    const x = Math.random() * 512;
    const y = Math.random() * 512;
    const radius = 2 + Math.random() * 8;
    const grad = ctx.createRadialGradient(x, y, 0, x, y, radius);
    grad.addColorStop(0, 'rgba(120, 70, 20, 0.3)');
    grad.addColorStop(1, 'rgba(120, 70, 20, 0)');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(x, y, radius, 0, Math.PI * 2);
    ctx.fill();
  }

  // Edge darkening
  const edgeGrad = ctx.createRadialGradient(256, 256, 180, 256, 256, 256);
  edgeGrad.addColorStop(0, 'rgba(0,0,0,0)');
  edgeGrad.addColorStop(0.7, 'rgba(0,0,0,0)');
  edgeGrad.addColorStop(1, 'rgba(60, 30, 5, 0.4)');
  ctx.fillStyle = edgeGrad;
  ctx.fillRect(0, 0, 512, 512);

  const texture = new THREE.CanvasTexture(canvas);
  texture.wrapS = texture.wrapT = THREE.RepeatWrapping;

  // Normal map via canvas
  const normCanvas = document.createElement('canvas');
  normCanvas.width = 512;
  normCanvas.height = 512;
  const nctx = normCanvas.getContext('2d');
  nctx.fillStyle = '#8080ff';
  nctx.fillRect(0, 0, 512, 512);
  for (let i = 0; i < 5000; i++) {
    const x = Math.random() * 512;
    const y = Math.random() * 512;
    const r = 128 + (Math.random() - 0.5) * 40;
    const g = 128 + (Math.random() - 0.5) * 40;
    nctx.fillStyle = `rgb(${r|0},${g|0},255)`;
    nctx.fillRect(x, y, 1 + Math.random(), 1 + Math.random());
  }
  const normalMap = new THREE.CanvasTexture(normCanvas);

  return new THREE.MeshStandardMaterial({
    map: texture,
    normalMap: normalMap,
    normalScale: new THREE.Vector2(0.3, 0.3),
    roughness: 0.85,
    metalness: 0.0,
    color: 0xd4a04a,
  });
}

// ── Build a single cracker ──
function buildCracker(radius = 1.5, thickness = 0.12, segments = 64) {
  const group = new THREE.Group();

  // Main body - cylinder with many segments for round shape
  const bodyGeo = new THREE.CylinderGeometry(radius, radius, thickness, segments);
  const bodyMat = createCrackerMaterial();
  const body = new THREE.Mesh(bodyGeo, bodyMat);
  body.castShadow = true;
  body.receiveShadow = true;
  group.add(body);

  // Decorative scalloped edge
  const scallopCount = 32;
  const scallopRadius = radius + 0.02;
  for (let i = 0; i < scallopCount; i++) {
    const angle = (i / scallopCount) * Math.PI * 2;
    const scallopGeo = new THREE.SphereGeometry(0.08, 12, 12);
    const scallop = new THREE.Mesh(scallopGeo, bodyMat.clone());
    scallop.position.set(
      Math.cos(angle) * scallopRadius,
      0,
      Math.sin(angle) * scallopRadius
    );
    scallop.scale.set(1, 0.4, 1);
    scallop.castShadow = true;
    group.add(scallop);
  }

  // Inner ring detail
  const ringGeo = new THREE.TorusGeometry(radius * 0.65, 0.015, 8, segments);
  const ringMat = new THREE.MeshStandardMaterial({
    color: 0xb8863a,
    roughness: 0.9,
    metalness: 0.0,
  });
  const ring = new THREE.Mesh(ringGeo, ringMat);
  ring.rotation.x = Math.PI / 2;
  ring.position.y = thickness / 2 + 0.001;
  group.add(ring);

  // Bottom ring too
  const ring2 = ring.clone();
  ring2.position.y = -thickness / 2 - 0.001;
  group.add(ring2);

  // Holes (the classic cracker holes)
  const holePositions = [];

  // Inner ring of holes
  for (let i = 0; i < 8; i++) {
    const angle = (i / 8) * Math.PI * 2;
    holePositions.push({
      x: Math.cos(angle) * radius * 0.35,
      z: Math.sin(angle) * radius * 0.35,
      r: 0.06
    });
  }

  // Outer ring of holes
  for (let i = 0; i < 12; i++) {
