function createCrayonPaperTexture(brandColor, crayonName) {
  const canvas = document.createElement('canvas');
  canvas.width = 512;
  canvas.height = 1024;
  const ctx = canvas.getContext('2d');

  // Paper base
  ctx.fillStyle = '#f5f0e8';
