    ctx.fillRect(Math.random()*512, Math.random()*1024, Math.random()*3, Math.random()*3);
  }

  // Top color band
  const bandHeight = 120;
  const gradient1 = ctx.createLinearGradient(0, 0, 0, bandHeight);
  gradient1.addColorStop(0, brandColor);
  gradient1.addColorStop(0.5, brandColor);
  gradient1.addColorStop(1, '#f5f0e8');
  ctx.fillStyle = gradient1;
  ctx.fillRect(0, 0, 512, bandHeight);

  // Bottom color band
  const gradient2 = ctx.createLinearGradient(0, 1024 - bandHeight, 0, 1024);
  gradient2.addColorStop(0, '#f5f0e8');
  gradient2.addColorStop(0.5, brandColor);
  gradient2.addColorStop(1, brandColor);
  ctx.fillStyle = gradient2;
  ctx.fillRect(0, 1024 - bandHeight, 512, bandHeight);

  // Middle label area
  ctx.fillStyle = '#f5f0e8';
  ctx.fillRect(0, bandHeight, 512, 1024 - bandHeight * 2);

  // Brand name at top
  ctx.fillStyle = brandColor;
  ctx.font = 'bold 48px Arial, sans-serif';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText('CRAYON', 256, 200);

  // Decorative line
  ctx.strokeStyle = brandColor;
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(120, 240);
  ctx.lineTo(392, 240);
  ctx.stroke();

  // Crayon color name
  ctx.fillStyle = '#333';
  ctx.font = 'bold 52px Arial, sans-serif';
  ctx.fillText(crayonName, 256, 320);

  // Color swatch
  ctx.fillStyle = brandColor;
  ctx.beginPath();
  ctx.roundRect(176, 400, 160, 120, 10);
  ctx.fill();
  ctx.strokeStyle = '#ccc';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.roundRect(176, 400, 160, 120, 10);
  ctx.stroke();

  // Small text
  ctx.fillStyle = '#999';
  ctx.font = '24px Arial, sans-serif';
  ctx.fillText('NON-TOXIC', 256, 600);

  ctx.fillStyle = '#bbb';
  ctx.font = '18px Arial, sans-serif';
  ctx.fillText('✓', 200, 660);
  ctx.fillText('WASHABLE', 256, 660);

