  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(511, 0);
  ctx.lineTo(511, 1024);
  ctx.stroke();

  const texture = new THREE.CanvasTexture(canvas);
  texture.wrapS = THREE.RepeatWrapping;
  texture.wrapT = THREE.ClampToEdgeWrapping;
