  const waxTopRadius = 0.23;
  const waxHeight = 3.2;
  const waxGeo = new THREE.CylinderGeometry(waxTopRadius, waxRadius, waxHeight, 32, 1, false);
  const waxMat = new THREE.MeshStandardMaterial({
    color: waxCol,
    roughness: 0.45,
    metalness: 0.0,
  });
  const waxMesh = new THREE.Mesh(waxGeo, waxMat);
  waxMesh.castShadow = true;
  waxMesh.receiveShadow = true;
  waxMesh.position.y = -0.2;
  group.add(waxMesh);

  // ── Exposed wax tip (top) ──
  const tipHeight = 0.6;
  const tipGeo = new THREE.CylinderGeometry(0.02, waxTopRadius, tipHeight, 32, 1, false);
  const tipMat = new THREE.MeshStandardMaterial({
    color: waxCol,
    roughness: 0.35,
    metalness: 0.0,
  });
  const tipMesh = new THREE.Mesh(tipGeo, tipMat);
  tipMesh.castShadow = true;
  tipMesh.position.y = waxHeight / 2 + tipHeight / 2 - 0.2;
  group.add(tipMesh);

  // ── Rounded tip cap ──
  const tipCapGeo = new THREE.SphereGeometry(0.02, 16, 8, 0, Math.PI * 2, 0, Math.PI / 2);
  const tipCapMesh = new THREE.Mesh(tipCapGeo, tipMat);
  tipCapMesh.position.y = waxHeight / 2 + tipHeight - 0.2;
  group.add(tipCapMesh);

  // ── Paper wrapper ──
  const paperTexture = createCrayonPaperTexture(paperColor, name);
  paperTexture.anisotropy = renderer.capabilities.getMaxAnisotropy();

  const paperGeo = new THREE.CylinderGeometry(waxTopRadius + 0.008, waxRadius + 0.008, waxHeight, 32, 1, true);
  const paperMat = new THREE.MeshStandardMaterial({
    map: paperTexture,
    roughness: 0.8,
    metalness: 0.0,
    side: THREE.DoubleSide,
  });
  const paperMesh = new THREE.Mesh(paperGeo, paperMat);
  paperMesh.castShadow = true;
  paperMesh.receiveShadow = true;
  paperMesh.position.y = -0.2;
  group.add(paperMesh);

  // ── Paper fold seam (thin dark line) ──
  const seamGeo = new THREE.CylinderGeometry(waxTopRadius + 0.01, waxRadius + 0.01, waxHeight, 4, 1, true);
  const seamMat = new THREE.MeshStandardMaterial({
    color: 0xccbbaa,
    roughness: 0.9,
    metalness: 0.0,
  });
  const seamMesh = new THREE.Mesh(seamGeo, seamMat);
  seamMesh.position.y = -0.2;
  seamMesh.rotation.y = 0.02;
  group.add(seamMesh);

  // ── Bottom tip (pointed end) ──
  const bottomTipHeight = 0.5;
  const bottomTipGeo = new THREE.ConeGeometry(waxRadius, bottomTipHeight, 32);
  const bottomTipMat = new THREE.MeshStandardMaterial({
    color: waxCol,
    roughness: 0.4,
    metalness: 0.0,
  });
  const bottomTipMesh = new THREE.Mesh(bottomTipGeo, bottomTipMat);
  bottomTipMesh.castShadow = true;
  bottomTipMesh.position.y = -waxHeight / 2 - bottomTipHeight / 2 - 0.2;
  group.add(bottomTipMesh);

  // ── Crayon end cap (where tip meets paper) ──
  const endCapGeo = new THREE.TorusGeometry(waxRadius, 0.012, 8, 32);
  const endCapMat = new THREE.MeshStandardMaterial({
    color: 0xd4c8b0,
    roughness: 0.8,
    metalness: 0.0,
  });
  const endCapMesh = new THREE.Mesh(endCapGeo, endCapMat);
  endCapMesh.position.y = -waxHeight / 2 - 0.2;
  endCapMesh.rotation.x = Math.PI / 2;
  group.add(endCapMesh);

  // Position and rotate the crayon
  group.position.copy(position);
  if (rotation) {
    group.rotation.set(rotation.x, rotation.y, rotation.z);
  }

  return group;
}

