  const angle = (i / NUM_SPIKES) * Math.PI * 2;
  const nextAngle = ((i + 1) / NUM_SPIKES) * Math.PI * 2;
  const midAngle = (angle + nextAngle) / 2;

  const archCurve = new THREE.QuadraticBezierCurve3(
    new THREE.Vector3(Math.cos(angle) * 1.2, 1.0, Math.sin(angle) * 1.2),
    new THREE.Vector3(Math.cos(midAngle) * 1.35, 1.5, Math.sin(midAngle) * 1.35),
    new THREE.Vector3(Math.cos(nextAngle) * 1.2, 1.0, Math.sin(nextAngle) * 1.2),
  );

  const archPoints = archCurve.getPoints(12);
  const archGeometry = new THREE.TubeGeometry(
    new THREE.CatmullRomCurve3(archPoints),
    12, 0.025, 8, false
  );
  const arch = new THREE.Mesh(archGeometry, goldMaterial);
  crownGroup.add(arch);
}

crownGroup.rotation.y = Math.PI;
scene.add(crownGroup);

// Floating particles
const particleCount = 200;
const particleGeometry = new THREE.BufferGeometry();
const positions = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = (Math.random() - 0.5) * 10;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
particleGeometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
const particleMaterial = new THREE.PointsMaterial({
  color: 0xffd700,
  size: 0.03,
  transparent: true,
  opacity: 0.6,
});
const particles = new THREE.Points(particleGeometry, particleMaterial);
scene.add(particles);

// Mouse interaction
let mouseX = 0, mouseY = 0;
document.addEventListener('mousemove', (e) => {
  mouseX = (e.clientX / innerWidth - 0.5) * 2;
  mouseY = (e.clientY / innerHeight - 0.5) * 2;
});

// Resize
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// Animate
function animate(time) {
  requestAnimationFrame(animate);
  const t = time * 0.001;

  crownGroup.rotation.y = Math.sin(t * 0.3) * 0.3 + mouseX * 0.5;
  crownGroup.position.y = Math.sin(t * 0.8) * 0.15;

  particles.rotation.y = t * 0.02;
  particles.rotation.x = Math.sin(t * 0.1) * 0.1;

  pointLight1.position.x = Math.sin(t) * 3;
  pointLight1.position.z = Math.cos(t) * 3;

  camera.position.x += (mouseX * 2 - camera.position.x) * 0.02;
  camera.position.y += (2 - mouseY * 1.5 - camera.position.y) * 0.02;
  camera.lookAt(0, 0.5, 0);

  renderer.render(scene, camera);
}
animate(0);
</script>
</body>
</html>
```

This creates a **3D golden crown** with:

- **Torus base** with decorative inner/outer bands
- **7 alternating tall/short cone spikes** around the rim
- **Colored gems** (ruby, sapphire, emerald) atop each spike
- **Small gems** embedded along the base band
- **Decorative arches** connecting the spikes
- **Gold particles** floating in the background
- **Rich lighting** — directional, point, and ambient with warm tones
- **Mouse interaction** — move your cursor to pan the camera and rotate the crown
- **Gentle floating animation** with slow rotation and bobbing

