function createCrystalGeometry() {
  const geo = new THREE.BufferGeometry();

  // Define crystal as a faceted bipyramid with extra vertices for complexity
  const top = 3.2, bottom = -1.8, mid = 0.3;
  const sides = 6;
  const rTop = 0.3, rMid = 1.4, rBot = 0.6;

  const vertices = [
    // Apex
    0, top, 0,
    // Bottom tip
    0, bottom, 0,
  ];

  const index = [];

  // Upper ring vertices
  const upperRing = [];
  for (let i = 0; i < sides; i++) {
    const a = (i / sides) * Math.PI * 2;
    const r = rMid * (0.7 + 0.3 * Math.sin(i * 2.1));
    const y = mid + (top - mid) * 0.55;
    const x = Math.cos(a) * r;
    const z = Math.sin(a) * r;
    vertices.push(x, y, z);
    upperRing.push(2 + i);
  }

  // Upper ring to apex
  for (let i = 0; i < sides; i++) {
    const next = (i + 1) % sides;
    index.push(0, upperRing[i], upperRing[next]);
  }

  // Middle ring
  const midRing = [];
  for (let i = 0; i < sides; i++) {
    const a = (i / sides) * Math.PI * 2 + Math.PI / sides;
    const r = rMid * (0.8 + 0.2 * Math.cos(i * 1.7));
    vertices.push(Math.cos(a) * r, mid, Math.sin(a) * r);
    midRing.push(2 + sides + i);
  }

  // Upper ring to middle ring
  for (let i = 0; i < sides; i++) {
    const next = (i + 1) % sides;
    const u = upperRing[i], m = midRing[i], mn = midRing[next];
    index.push(u, m, mn);
    index.push(u, mn, upperRing[next]);
  }

  // Lower ring
  const lowerRing = [];
  for (let i = 0; i < sides; i++) {
    const a = (i / sides) * Math.PI * 2;
    const r = rBot * (0.9 + 0.1 * Math.sin(i * 3.3));
    const y = mid + (bottom - mid) * 0.45;
    vertices.push(Math.cos(a) * r, y, Math.sin(a) * r);
    lowerRing.push(2 + sides + sides + i);
  }

  // Middle ring to lower ring
  for (let i = 0; i < sides; i++) {
    const prev = (i - 1 + sides) % sides;
    const m = midRing[i], l = lowerRing[i], lp = lowerRing[prev];
    index.push(m, l, lp);
    index.push(m, lp, midRing[prev]);
  }

  // Lower ring to bottom tip
  for (let i = 0; i < sides; i++) {
    const next = (i + 1) % sides;
    index.push(1, lowerRing[next], lowerRing[i]);
  }

  geo.setAttribute('position', new THREE.Float32BufferAttribute(vertices, 3));
  geo.setIndex(index);
  geo.computeVertexNormals();
  return geo;
}

