// ── Helper: Create a cactus arm along a curve ─────────────
function createCactusArm(points, radius, segments = 24) {
  const curve = new THREE.CatmullRomCurve3(points.map(p => new THREE.Vector3(...p)));
  const tubeGeo = new THREE.TubeGeometry(curve, 40, radius, segments, false);

  // Add ribs (ridges) along the tube by slightly displacing vertices
  const pos = tubeGeo.attributes.position;
  const ribCount = 8;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    const z = pos.getZ(i);
    const angle = Math.atan2(z, x);
    const ribFactor = Math.cos(angle * ribCount) * 0.06;
    const len = Math.sqrt(x * x + z * z);
    if (len > 0.001) {
      pos.setX(i, x + (x / len) * ribFactor);
      pos.setZ(i, z + (z / len) * ribFactor);
    }
  }
  pos.needsUpdate = true;
  tubeGeo.computeVertexNormals();

  const mesh = new THREE.Mesh(tubeGeo, cactusMat);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  return mesh;
}

