    // Static folds - multiple sine waves for realistic pleats
    float fold1 = sin(pos.x * 3.5) * uFoldAmplitude;
    float fold2 = sin(pos.x * 7.0 + 0.5) * uFoldAmplitude * 0.4;
    float fold3 = sin(pos.x * 14.0 + 1.0) * uFoldAmplitude * 0.15;
    float fold = fold1 + fold2 + fold3;

    // Gravity effect - folds are tighter near top, looser near bottom
    float gravityFactor = 1.0 - uv.y * 0.3;
    fold *= gravityFactor;

    // Gentle sway animation
    float sway = sin(uTime * 0.8 + pos.x * 0.8 - pos.y * 0.5) * uSwayAmplitude;
    sway += sin(uTime * 1.2 + pos.x * 1.5) * uSwayAmplitude * 0.3;
    sway *= (1.0 - uv.y) * 0.6 + 0.4; // more sway at bottom

