    color *= 0.85 + vUv.y * 0.25;

    // Soft fabric texture noise
    float noise = fract(sin(dot(vUv * 200.0, vec2(12.9898, 78.233))) * 43758.5453);
    color += (noise - 0.5) * 0.03;

    // Edge darkening (rim)
    float rim = 1.0 - abs(dot(vNormal, vec3(0.0, 0.0, 1.0)));
    color += vec3(0.9, 0.8, 0.6) * rim * 0.15;

    // Subtle sheen
    float sheen = pow(max(dot(vNormal, vec3(0.5, 0.5, 0.7)), 0.0), 8.0);
    color += vec3(1.0, 0.95, 0.85) * sheen * 0.12;

    gl_FragColor = vec4(color, 0.92);
  }
`;

