function createCurtainPanel(offsetX, color, swayPhase) {
  const width = 2.2;
  const height = 4.0;
  const segmentsX = 60;
  const segmentsY = 40;

  const geo = new THREE.PlaneGeometry(width, height, segmentsX, segmentsY);

  const uniforms = {
    uTime: { value: 0 },
    uFoldAmplitude: { value: 0.18 },
    uSwayAmplitude: { value: 0.12 },
    uColor: { value: new THREE.Color(color) },
  };

  const mat = new THREE.ShaderMaterial({
    vertexShader: curtainVertexShader,
    fragmentShader: curtainFragmentShader,
    uniforms,
    side: THREE.DoubleSide,
    transparent: true,
  });

  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(offsetX, 2.0, 0);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  mesh.userData = { uniforms, swayPhase };

  return mesh;
}

