// --- Cushion Creation ---
function createCushionGeometry(width, depth, height, segments) {
    const geo = new THREE.BoxGeometry(width, height, depth, segments, segments, segments);
    const pos = geo.attributes.position;
    const v = new THREE.Vector3();

    const w = width / 2;
    const h = height / 2;
    const d = depth / 2;
    const roundness = 0.35;

    for (let i = 0; i < pos.count; i++) {
        v.fromBufferAttribute(pos, i);

        // Distance from center normalized
        const nx = v.x / w;
        const ny = v.y / h;
        const nz = v.z / d;

        // Corner rounding - pull corners inward
        const cornerDist = Math.sqrt(nx * nx + ny * ny + nz * nz);
        const cornerFactor = Math.max(0, (cornerDist - 0.7) / 0.3);
        const pullIn = cornerFactor * roundness;

        // Push vertices toward center for rounded edges
        v.x -= v.x * pullIn * 0.5;
        v.y -= v.y * pullIn * 0.5;
        v.z -= v.z * pullIn * 0.5;

        // Bulge in the middle (pillow effect)
        const centerDist = Math.sqrt(nx * nx + nz * nz);
        const bulge = Math.exp(-centerDist * centerDist * 2) * 0.12;
        v.y += bulge;

        // Slight depression in center top (like sitting on it)
        const topFactor = Math.max(0, ny) * Math.exp(-centerDist * centerDist * 3);
        v.y -= topFactor * 0.06;

        // Soften the edges on top and bottom faces
        if (Math.abs(ny) > 0.6) {
            const edgeSoftness = Math.exp(-centerDist * centerDist * 1.5) * 0.04;
            v.x *= (1 - edgeSoftness * 0.3);
            v.z *= (1 - edgeSoftness * 0.3);
        }

        pos.setXYZ(i, v.x, v.y, v.z);
    }

    geo.computeVertexNormals();
    return geo;
}

// --- Fabric Material ---
function createFabricMaterial(color, roughness = 0.9, metalness = 0.0) {
    // Create a procedural fabric texture using canvas
    const canvas = document.createElement('canvas');
    canvas.width = 512;
    canvas.height = 512;
    const ctx = canvas.getContext('2d');

    // Base color
    ctx.fillStyle = color;
    ctx.fillRect(0, 0, 512, 512);

    // Add noise for fabric texture
    const imageData = ctx.getImageData(0, 0, 512, 512);
    const data = imageData.data;
    for (let i = 0; i < data.length; i += 4) {
        const noise = (Math.random() - 0.5) * 20;
        data[i] = Math.min(255, Math.max(0, data[i] + noise));
        data[i + 1] = Math.min(255, Math.max(0, data[i + 1] + noise));
        data[i + 2] = Math.min(255, Math.max(0, data[i + 2] + noise));
    }
    ctx.putImageData(imageData, 0, 0);

    // Add subtle weave pattern
    ctx.globalAlpha = 0.06;
    ctx.strokeStyle = '#000';
    for (let i = 0; i < 512; i += 4) {
        ctx.beginPath();
        ctx.moveTo(i, 0);
        ctx.lineTo(i, 512);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0, i);
        ctx.lineTo(512, i);
        ctx.stroke();
    }

    const texture = new THREE.CanvasTexture(canvas);
    texture.wrapS = THREE.RepeatWrapping;
    texture.wrapT = THREE.RepeatWrapping;
    texture.repeat.set(2, 2);

    // Normal map from canvas
    const normalCanvas = document.createElement('canvas');
    normalCanvas.width = 256;
    normalCanvas.height = 256;
    const nctx = normalCanvas.getContext('2d');
    nctx.fillStyle = '#8080ff';
    nctx.fillRect(0, 0, 256, 256);

    const nImageData = nctx.getImageData(0, 0, 256, 256);
    const ndata = nImageData.data;
    for (let i = 0; i < ndata.length; i += 4) {
        const nx = (Math.random() - 0.5) * 15;
        const ny = (Math.random() - 0.5) * 15;
        ndata[i] = Math.min(255, Math.max(0, 128 + nx));
        ndata[i + 1] = Math.min(255, Math.max(0, 128 + ny));
        ndata[i + 2] = 200;
    }
    nctx.putImageData(nImageData, 0, 0);

    const normalTexture = new THREE.CanvasTexture(normalCanvas);
    normalTexture.wrapS = THREE.RepeatWrapping;
    normalTexture.wrapT = THREE.RepeatWrapping;
    normalTexture.repeat.set(4, 4);

    return new THREE.MeshStandardMaterial({
        color: new THREE.Color(color),
        map: texture,
        normalMap: normalTexture,
        normalScale: new THREE.Vector2(0.3, 0.3),
        roughness: roughness,
        metalness: metalness,
    });
}

