// --- Stitching Lines ---
function addStitching(cushion, color, offset = 0.02) {
    const padding = 0.12;
    const w = cushion.geometry.parameters.width;
    const h = cushion.geometry.parameters.height;
    const d = cushion.geometry.parameters.depth;

    // Get the top face boundary
    const points = [];
    const corners = [
        [-w/2 + padding, h/2 + offset, -d/2 + padding],
        [w/2 - padding, h/2 + offset, -d/2 + padding],
        [w/2 - padding, h/2 + offset, d/2 - padding],
        [-w/2 + padding, h/2 + offset, d/2 - padding],
        [-w/2 + padding, h/2 + offset, -d/2 + padding],
    ];

    // Create rounded rectangle stitching path
    const stitchPoints = [];
    const steps = 60;

    for (let i = 0; i <= steps; i++) {
        const t = i / steps;
        let x, z;

        // Rounded rectangle path
        const perimeter = 2 * (w - 2 * padding) + 2 * (d - 2 * padding);
        const progress = t * perimeter;

        const hw = w / 2 - padding;
        const hd = d / 2 - padding;
        const r = 0.15; // corner radius

        if (progress < hw - r) {
            x = -hw + progress;
            z = -hd;
        } else if (progress < hw + r) {
            const angle = (progress - (hw - r)) / r * Math.PI / 2;
            x = hw - r + Math.sin(angle) * r;
            z = -hd + (1 - Math.cos(angle)) * r;
        } else if (progress < hw + r + (hd - r) * 2) {
            const p = progress - (hw + r) - (hd - r);
            x = hw;
            z = -hd + r + p;
        } else if (progress < perimeter - (hw - r) - (hd - r) * 2) {
            const p = progress - (hw + r + (hd - r) * 2);
            const angle = (p / r) * Math.PI / 2;
            x = hw - r - Math.sin(angle) * r;
            z = hd - r + (1 - Math.cos(angle)) * r;
        } else {
            const p = progress - (perimeter - (hw - r));
            x = hw - p;
            z = hd;
        }

        // Apply cushion's transformation
        const worldPos = new THREE.Vector3(x, h/2 + offset, z);
        worldPos.applyMatrix4(cushion.matrixWorld);
        stitchPoints.push(worldPos);
    }

    const curve = new THREE.CatmullRomCurve3(stitchPoints, true);
    const tubeGeo = new THREE.TubeGeometry(curve, 120, 0.008, 6, true);
    const stitchMat = new THREE.MeshStandardMaterial({
        color: color,
        roughness: 0.7,
        metalness: 0.1,
    });
    const stitchMesh = new THREE.Mesh(tubeGeo, stitchMat);
    scene.add(stitchMesh);
}

