controls.enableDamping = true;
controls.dampingFactor = 0.05;

// --- Diamond geometry (lathe from profile) ---
const points = [
  // Table (top flat)
  new THREE.Vector2(0.0, 1.0),
  new THREE.Vector2(0.5, 1.0),
  // Crown
  new THREE.Vector2(0.55, 0.85),
  new THREE.Vector2(0.6, 0.75),
