// ── Bowl ──
const bowlProfile = [];
const bowlSegments = 20;
for (let i = 0; i <= bowlSegments; i++) {
  const t = i / bowlSegments;
  let r, y;
  if (t < 0.05) {
    // foot
    r = 0.3 + t * 4;
    y = -0.05;
  } else if (t < 0.2) {
    // foot ring
    const ft = (t - 0.05) / 0.15;
    r = 0.5 + ft * 0.3;
    y = -0.05 + ft * 0.1;
  } else if (t < 0.85) {
    // bowl body
    const bt = (t - 0.2) / 0.65;
    r = 0.8 + Math.pow(bt, 0.6) * 1.2;
    y = 0.05 + bt * 1.4;
  } else {
    // rim
    const rt = (t - 0.85) / 0.15;
    r = 2.0 - rt * 0.1;
    y = 1.45 + rt * 0.15;
  }
  bowlProfile.push(new THREE.Vector2(r, y));
}

const bowlGeo = new THREE.LatheGeometry(bowlProfile, 64);
