  drop.position.set(Math.cos(angle) * radius, 1.02 + Math.random() * 0.02, Math.sin(angle) * radius);
  drop.scale.y = 0.5;
  scene.add(drop);
}

// ── Noodles ──
function createNoodle(startPos, controlPoints, endPos, color = 0xf5deb3) {
  const curve = new THREE.CatmullRomCurve3([startPos, ...controlPoints, endPos]);
  const tubeGeo = new THREE.TubeGeometry(curve, 40, 0.035, 8, false);
  const noodleMat = new THREE.MeshStandardMaterial({
    color, roughness: 0.7, metalness: 0.0
  });
  return new THREE.Mesh(tubeGeo, noodleMat);
}

const noodleGroup = new THREE.Group();
const noodleColors = [0xf5deb3, 0xf0d8a0, 0xe8d098, 0xf2dfb5];

for (let i = 0; i < 40; i++) {
  const angle = (i / 40) * Math.PI * 2 + Math.random() * 0.3;
  const r = 0.3 + Math.random() * 1.2;
  const x1 = Math.cos(angle) * r;
  const z1 = Math.sin(angle) * r;
  const x2 = Math.cos(angle + 0.5) * (r + 0.3);
  const z2 = Math.sin(angle + 0.5) * (r + 0.3);

  const cp1 = new THREE.Vector3(
    (x1 + x2) / 2 + (Math.random() - 0.5) * 0.5,
    0.7 + Math.random() * 0.4,
    (z1 + z2) / 2 + (Math.random() - 0.5) * 0.5
  );
  const cp2 = new THREE.Vector3(
    (x1 + x2) / 2 + (Math.random() - 0.5) * 0.3,
    0.5 + Math.random() * 0.3,
    (z1 + z2) / 2 + (Math.random() - 0.5) * 0.3
  );

  const noodle = createNoodle(
    new THREE.Vector3(x1, 0.3 + Math.random() * 0.3, z1),
    [cp1, cp2],
    new THREE.Vector3(x2, 0.3 + Math.random() * 0.3, z2),
    noodleColors[Math.floor(Math.random() * noodleColors.length)]
  );
  noodle.castShadow = true;
  noodleGroup.add(noodle);
}
scene.add(noodleGroup);

// ── Soft-boiled Egg (Ajitama) ──
