// ── Chashu (Pork Slices) ──
function createChashuSlice(x, z, rotation) {
  const shape = new THREE.Shape();
  shape.absellipse(0, 0, 0.35, 0.28, 0, Math.PI * 2, false, 0);

  const extrudeSettings = { depth: 0.06, bevelEnabled: true, bevelThickness: 0.02, bevelSize: 0.02, bevelSegments: 3 };
  const geo = new THREE.ExtrudeGeometry(shape, extrudeSettings);

  const mat = new THREE.MeshStandardMaterial({
    color: 0x8b4513, roughness: 0.6, metalness: 0.05
  });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(x, 1.0, z);
  mesh.rotation.x = -Math.PI / 2;
  mesh.rotation.z = rotation;
  mesh.castShadow = true;
  return mesh;
}

