// Wall dimensions
const wallW = 8, wallH = 3.5, wallD = 0.3;
const doorW = 1.4, doorH = 2.6;
const frameDepth = 0.35, frameOverhang = 0.08;

// Left wall section
const leftWallW = (wallW - doorW) / 2;
const leftWall = new THREE.Mesh(
