);
rightWall.position.set(doorW / 2 + leftWallW / 2, wallH / 2, 0);
rightWall.castShadow = true;
rightWall.receiveShadow = true;
wallGroup.add(rightWall);

// Top wall section (above door)
const topWallH = wallH - doorH;
