);
leftJamb.position.set(-doorW / 2 - frameOverhang, doorH / 2, 0);
leftJamb.castShadow = true;
frameGroup.add(leftJamb);

// Right jamb
const rightJamb = new THREE.Mesh(
  new THREE.BoxGeometry(frameOverhang * 2, doorH, frameDepth),
  frameMat
);
