const sill = new THREE.Mesh(
  new THREE.BoxGeometry(doorW + frameOverhang * 4, 0.06, frameDepth + 0.15),
  frameMat
);
sill.position.set(0, 0.03, 0.05);
sill.castShadow = true;
sill.receiveShadow = true;
frameGroup.add(sill);

// ── Door Panel ──
const doorPivot = new THREE.Group();
doorPivot.position.set(-doorW / 2, 0, 0);
scene.add(doorPivot);

const doorPanelW = doorW - 0.04;
const doorPanelH = doorH - 0.06;
const doorPanelD = 0.055;

