sideWall.position.set(-6, wallH / 2, 0);
sideWall.receiveShadow = true;
sideWall.castShadow = true;
scene.add(sideWall);

// ── Door opening animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);

  const t = clock.getElapsedTime();

  // Smooth door swing: open and close periodically
  const cycle = 6; // seconds per full cycle
  const phase = (t % cycle) / cycle;
  // Use a smooth easing
  let angle;
  if (phase < 0.3) {
    // Opening
    const p = phase / 0.3;
    angle = -Math.sin(p * Math.PI / 2) * 1.2; // open to ~69 degrees
  } else if (phase < 0.6) {
    // Stay open
    angle = -1.2;
  } else if (phase < 0.9) {
    // Closing
    const p = (phase - 0.6) / 0.3;
    angle = -Math.cos(p * Math.PI / 2) * 1.2;
  } else {
    // Stay closed
    angle = 0;
  }

  doorPivot.rotation.y = angle;

  // Subtle warm light flicker when door is open
  warmLight.intensity = 0.3 + Math.sin(t * 3) * 0.05 + (angle < -0.5 ? 0.3 : 0);

  controls.update();
  renderer.render(scene, camera);
}

animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
