// ── Interaction ──
const raycaster = new THREE.Raycaster();
const mouse = new THREE.Vector2();
let dragging = null;
let dragPlane = new THREE.Plane();
let dragOffset = new THREE.Vector3();
let intersection = new THREE.Vector3();
let drawerState = { drawer1: 0, drawer2: 0 };
const MAX_PULL = 0.7;

const handles = [
  { mesh: handle1, group: drawer1, key: 'drawer1' },
  { mesh: handle2, group: drawer2, key: 'drawer2' },
];

function onPointerDown(e) {
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);

  for (const h of handles) {
    const hits = raycaster.intersectObject(h.mesh, true);
    if (hits.length > 0) {
      dragging = h;
      controls.enabled = false;

      // Create drag plane facing camera at handle position
      const worldPos = new THREE.Vector3();
      h.mesh.getWorldPosition(worldPos);
      const camDir = camera.position.clone().sub(worldPos).normalize();
      dragPlane.setFromNormalAndCoplanarPoint(camDir, worldPos);

      raycaster.ray.intersectPlane(dragPlane, intersection);
      dragOffset.copy(worldPos).sub(intersection);
      break;
    }
  }
}

function onPointerMove(e) {
  if (!dragging) return;
  mouse.x = (e.clientX / innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / innerHeight) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);

  raycaster.ray.intersectPlane(dragPlane, intersection);
  if (!intersection) return;

  const target = intersection.add(dragOffset);
  const worldHandlePos = new THREE.Vector3();
  dragging.mesh.getWorldPosition(worldHandlePos);

  // Compute pull distance along Z (drawer direction)
  const localTarget = dragging.group.worldToLocal(target.clone());
  const pull = Math.max(0, Math.min(localTarget.z, MAX_PULL));
  drawerState[dragging.key] = pull;
}

function onPointerUp() {
  if (!dragging) return;

  // Snap: close if < 30%, open fully otherwise
  const key = dragging.key;
  if (drawerState[key] < MAX_PULL * 0.3) drawerState[key] = 0;
  else drawerState[key] = MAX_PULL;

  dragging = null;
  controls.enabled = true;
}

window.addEventListener('pointerdown', onPointerDown);
window.addEventListener('pointermove', onPointerMove);
window.addEventListener('pointerup', onPointerUp);

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

// ── Animate ──
function animate() {
  requestAnimationFrame(animate);

  // Smooth drawer positions
  const targets = { drawer1: drawer1.position.z, drawer2: drawer2.position.z };
  // We animate via position.z offset
  // Actually let's just set positions directly based on drawerState
  // The drawers slide along +Z

  // Smooth interpolation
  const lerpFactor = 0.12;
  [
    { group: drawer1, key: 'drawer1' },
    { group: drawer2, key: 'drawer2' }
  ].forEach(({ group, key }) => {
    const currentZ = group.position.z;
    const targetZ = drawerState[key];
    group.position.z = currentZ + (targetZ - currentZ) * lerpFactor;
  });

  controls.update();
  renderer.render(scene, camera);
}

animate();
</script>
