const necklineGeo = new THREE.TubeGeometry(necklineCurve, 30, 0.008, 8, false);
const neckline = new THREE.Mesh(necklineGeo, trimMat);
dressGroup.add(neckline);

// ── Hem Trim ──
const hemGeo = new THREE.TorusGeometry(0.92, 0.012, 8, 48);
const hemBand = new THREE.Mesh(hemGeo, trimMat);
hemBand.position.set(0, 1.97, 0);
hemBand.rotation.x = Math.PI / 2;
dressGroup.add(hemBand);

// ── Sparkle Particles on Dress ──
const sparkleCount = 120;
const sparkleGeo = new THREE.BufferGeometry();
const sparklePositions = new Float32Array(sparkleCount * 3);
const sparkleSizes = new Float32Array(sparkleCount);

for (let i = 0; i < sparkleCount; i++) {
  const t = Math.random();
  const angle = Math.random() * Math.PI * 2;
  const r = 0.22 + Math.pow(t, 1.3) * 0.9;
  const y = 1.95 + t * 1.8;
  const z = Math.cos(angle) * r * 0.3;
  const x = Math.sin(angle) * r;

  sparklePositions[i * 3] = x + (Math.random() - 0.5) * 0.05;
  sparklePositions[i * 3 + 1] = y;
  sparklePositions[i * 3 + 2] = z + (Math.random() - 0.5) * 0.05;
  sparkleSizes[i] = Math.random() * 3 + 1;
}

sparkleGeo.setAttribute('position', new THREE.BufferAttribute(sparklePositions, 3));
sparkleGeo.setAttribute('size', new THREE.BufferAttribute(sparkleSizes, 1));

const sparkleMat = new THREE.PointsMaterial({
  color: 0xffd700,
  size: 0.025,
  transparent: true,
  opacity: 0.7,
  blending: THREE.AdditiveBlending,
  depthWrite: false,
  sizeAttenuation: true,
});

const sparkles = new THREE.Points(sparkleGeo, sparkleMat);
dressGroup.add(sparkles);

