<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

/* ── Scene, Camera, Renderer ─────────────────────────────── */
const scene    = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 12, 25);

const camera   = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.target.set(0, 0.5, 0);

/* ── Lighting ─────────────────────────────────────────────── */
scene.add(new THREE.AmbientLight(0x404060, 1.5));

const dir = new THREE.DirectionalLight(0xffffff, 2.5);
dir.position.set(5, 8, 4);
dir.castShadow = true;
dir.shadow.mapSize.set(1024, 1024);
scene.add(dir);

const rim = new THREE.PointLight(0x4488ff, 1.5, 15);
rim.position.set(-4, 3, -3);
scene.add(rim);

const warm = new THREE.PointLight(0xff8844, 0.8, 12);
warm.position.set(3, 1, 3);
scene.add(warm);

/* ── Materials ────────────────────────────────────────────── */
const matBody    = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.35, metalness: 0.1 });
const matAccent  = new THREE.MeshStandardMaterial({ color: 0xcc3333, roughness: 0.4, metalness: 0.05 });
const matChrome  = new THREE.MeshStandardMaterial({ color: 0xcccccc, roughness: 0.15, metalness: 0.9 });
const matBit     = new THREE.MeshStandardMaterial({ color: 0x888899, roughness: 0.25, metalness: 0.85 });
const matGrip    = new THREE.MeshStandardMaterial({ color: 0x1a1a1a, roughness: 0.85, metalness: 0.0 });
const matTrigger = new THREE.MeshStandardMaterial({ color: 0x333333, roughness: 0.5, metalness: 0.2 });
const matBattery = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.6, metalness: 0.1 });
const matLabel   = new THREE.MeshStandardMaterial({ color: 0xcc3333, roughness: 0.3, metalness: 0.1, emissive: 0x330000, emissiveIntensity: 0.3 });

/* ── Drill Group ──────────────────────────────────────────── */
const drill = new THREE.Group();

/* ── Main body (motor housing) ────────────────────────────── */
const bodyGeo = new THREE.CylinderGeometry(0.32, 0.32, 1.6, 24);
const body = new THREE.Mesh(bodyGeo, matBody);
body.rotation.z = Math.PI / 2;
body.position.set(0.3, 1.15, 0);
body.castShadow = true;
drill.add(body);

/* ── Accent stripe on body ────────────────────────────────── */
const stripeGeo = new THREE.CylinderGeometry(0.33, 0.33, 0.12, 24, 1, true);
const stripe = new THREE.Mesh(stripeGeo, matAccent);
stripe.rotation.z = Math.PI / 2;
stripe.position.set(0.3, 1.15, 0);
drill.add(stripe);

/* ── Front cap (behind chuck) ─────────────────────────────── */
const capGeo = new THREE.CylinderGeometry(0.32, 0.28, 0.12, 24);
const cap = new THREE.Mesh(capGeo, matAccent);
cap.rotation.z = Math.PI / 2;
cap.position.set(1.16, 1.15, 0);
drill.add(cap);

/* ── Chuck housing ────────────────────────────────────────── */
const chuckGeo = new THREE.CylinderGeometry(0.22, 0.28, 0.45, 16);
const chuck = new THREE.Mesh(chuckGeo, matChrome);
chuck.rotation.z = Math.PI / 2;
chuck.position.set(1.52, 1.15, 0);
chuck.castShadow = true;
drill.add(chuck);

/* ── Chuck jaws (3 small cylinders around the axis) ───────── */
for (let i = 0; i < 3; i++) {
  const jawGeo = new THREE.BoxGeometry(0.38, 0.04, 0.04);
  const jaw = new THREE.Mesh(jawGeo, matChrome);
  const a = (i / 3) * Math.PI * 2;
  jaw.position.set(1.52, 1.15 + Math.cos(a) * 0.14, Math.sin(a) * 0.14);
  jaw.rotation.x = a;
  drill.add(jaw);
}

/* ── Chuck ring details ───────────────────────────────────── */
const ringGeo = new THREE.TorusGeometry(0.24, 0.025, 8, 24);
const ring = new THREE.Mesh(ringGeo, matAccent);
ring.position.set(1.74, 1.15, 0);
ring.rotation.y = Math.PI / 2;
drill.add(ring);

/* ── Drill bit group (spins) ──────────────────────────────── */
const bitGroup = new THREE.Group();
bitGroup.position.set(0, 0, 0);

const bitGeo = new THREE.CylinderGeometry(0.025, 0.025, 1.2, 8);
const bit = new THREE.Mesh(bitGeo, matBit);
bit.rotation.z = Math.PI / 2;
bit.position.set(2.35, 1.15, 0);
bit.castShadow = true;
bitGroup.add(bit);

/* Bit flutes (two twisted strips) */
for (let s = 0; s < 2; s++) {
  const fluteGeo = new THREE.BoxGeometry(1.0, 0.008, 0.035);
  const flute = new THREE.Mesh(fluteGeo, matBit);
  flute.position.set(2.35, 1.15 + (s === 0 ? 0.02 : -0.02), (s === 0 ? 1 : -1) * 0.015);
  flute.rotation.y = (s === 0 ? 1 : -1) * 0.15;
  bitGroup.add(flute);
}

/* Bit tip (cone) */
const tipGeo = new THREE.ConeGeometry(0.025, 0.12, 8);
const tip = new THREE.Mesh(tipGeo, matBit);
tip.rotation.z = -Math.PI / 2;
tip.position.set(3.01, 1.15, 0);
bitGroup.add(tip);

drill.add(bitGroup);

/* ── Handle (pistol grip) ─────────────────────────────────── */
const handleGeo = new THREE.BoxGeometry(0.3, 0.9, 0.28);
const handle = new THREE.Mesh(handleGeo, matGrip);
handle.position.set(-0.35, 0.6, 0);
handle.castShadow = true;
drill.add(handle);

/* Handle rubber grip texture lines */
for (let i = 0; i < 6; i++) {
  const lineGeo = new THREE.BoxGeometry(0.31, 0.015, 0.29);
  const line = new THREE.Mesh(lineGeo, matBody);
  line.position.set(-0.35, 0.2 + i * 0.12, 0);
  drill.add(line);
}

/* Handle angled cut */
const handleTopGeo = new THREE.CylinderGeometry(0.16, 0.16, 0.28, 4);
const handleTop = new THREE.Mesh(handleTopGeo, matGrip);
handleTop.rotation.z = Math.PI / 4;
handleTop.rotation.x = Math.PI / 2;
handleTop.position.set(-0.2, 1.05, 0);
drill.add(handleTop);

/* ── Trigger ──────────────────────────────────────────────── */
const triggerGeo = new THREE.BoxGeometry(0.06, 0.18, 0.06);
const trigger = new THREE.Mesh(triggerGeo, matTrigger);
trigger.position.set(-0.28, 0.82, 0.18);
trigger.rotation.x = 0.3;
drill.add(trigger);

/* Trigger guard */
const guardGeo = new THREE.TorusGeometry(0.1, 0.015, 8, 12, Math.PI);
const guard = new THREE.Mesh(guardGeo, matBody);
guard.position.set(-0.28, 0.88, 0.12);
guard.rotation.y = Math.PI / 2;
drill.add(guard);

/* ── Battery pack ─────────────────────────────────────────── */
const battGeo = new THREE.BoxGeometry(0.26, 0.35, 0.26);
const batt = new THREE.Mesh(battGeo, matBattery);
batt.position.set(-0.35, -0.02, 0);
batt.castShadow = true;
drill.add(batt);

/* Battery label */
const labelGeo = new THREE.BoxGeometry(0.27, 0.12, 0.01);
const label = new THREE.Mesh(labelGeo, matLabel);
label.position.set(-0.35, -0.02, 0.135);
drill.add(label);

/* Battery contact pins */
for (let i = -1; i <= 1; i += 2) {
  const pinGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.04, 8);
  const pin = new THREE.Mesh(pinGeo, matChrome);
  pin.position.set(-0.35 + i * 0.06, -0.2, 0);
  drill.add(pin);
}

/* Battery release button */
const btnGeo = new THREE.CylinderGeometry(0.03, 0.03, 0.03, 12);
const btn = new THREE.Mesh(btnGeo, matAccent);
btn.position.set(-0.35, 0.14, 0.14);
drill.add(btn);

/* ── Rear vent lines on body ──────────────────────────────── */
for (let i = 0; i < 5; i++) {
  const ventGeo = new THREE.BoxGeometry(0.02, 0.25, 0.01);
  const vent = new THREE.Mesh(ventGeo, matBody);
  vent.position.set(-0.1 + i * 0.06, 1.15, 0.33);
  drill.add(vent);
}

/* ── Side label / logo plate ──────────────────────────────── */
const plateGeo = new THREE.BoxGeometry(0.35, 0.15, 0.005);
const plate = new THREE.Mesh(plateGeo, matAccent);
plate.position.set(0.1, 1.15, 0.33);
drill.add(plate);

/* ── Position the whole drill ─────────────────────────────── */
drill.rotation.y = -0.3;
drill.rotation.x = 0.05;
scene.add(drill);

/* ── Ground plane ─────────────────────────────────────────── */
const groundGeo = new THREE.CircleGeometry(6, 48);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 0.9 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

/* ── Grid helper (subtle) ─────────────────────────────────── */
const grid = new THREE.GridHelper(12, 24, 0x222244, 0x1a1a33);
grid.position.y = 0.005;
scene.add(grid);

/* ── Animation ────────────────────────────────────────────── */
let time = 0;

function animate() {
  requestAnimationFrame(animate);
  time += 0.016;

  /* Spin the drill bit */
  bitGroup.rotation.x += 0.3;

  /* Subtle idle hover */
  drill.position.y = Math.sin(time * 1.2) * 0.03;

  controls.update();
  renderer.render(scene, camera);
}
animate();

/* ── Resize ───────────────────────────────────────────────── */
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
