function createLeg(x, z, scale = 1) {
  const legGroup = new THREE.Group();

  const upperGeo = new THREE.CylinderGeometry(0.42 * scale, 0.38 * scale, 1.6, 16);
  const upper = new THREE.Mesh(upperGeo, skinMat);
  upper.position.y = 1.8;
  upper.castShadow = true;
  legGroup.add(upper);

  const lowerGeo = new THREE.CylinderGeometry(0.38 * scale, 0.35 * scale, 1.2, 16);
  const lower = new THREE.Mesh(lowerGeo, skinMat);
  lower.position.y = 0.6;
  lower.castShadow = true;
