  const footGeo = new THREE.CylinderGeometry(0.45 * scale, 0.5 * scale, 0.25, 16);
  const foot = new THREE.Mesh(footGeo, darkSkinMat);
  foot.position.y = 0.12;
  foot.castShadow = true;
  foot.receiveShadow = true;
  legGroup.add(foot);

