renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
document.body.appendChild(renderer.domElement);

// ── Orbit Controls (manual implementation) ──
let isDragging = false, prevMouse = { x: 0, y: 0 };
let spherical = { theta: 0.7, phi: 1.1, radius: 18 };
let target = new THREE.Vector3(0, 1.5, 0);

function updateCamera() {
  spherical.phi = Math.max(0.2, Math.min(Math.PI - 0.2, spherical.phi));
  spherical.radius = Math.max(5, Math.min(40, spherical.radius));
  camera.position.set(
    target.x + spherical.radius * Math.sin(spherical.phi) * Math.cos(spherical.theta),
    target.y + spherical.radius * Math.cos(spherical.phi),
    target.z + spherical.radius * Math.sin(spherical.phi) * Math.sin(spherical.theta)
  );
  camera.lookAt(target);
}

renderer.domElement.addEventListener('mousedown', e => { isDragging = true; prevMouse = { x: e.clientX, y: e.clientY }; });
renderer.domElement.addEventListener('mousemove', e => {
