  spherical.theta -= (e.clientX - prevMouse.x) * 0.005;
  spherical.phi -= (e.clientY - prevMouse.y) * 0.005;
  prevMouse = { x: e.clientX, y: e.clientY };
  updateCamera();
});
renderer.domElement.addEventListener('mouseup', () => isDragging = false);
renderer.domElement.addEventListener('mouseleave', () => isDragging = false);
renderer.domElement.addEventListener('wheel', e => { spherical.radius += e.deltaY * 0.01; updateCamera(); });

// Touch support
renderer.domElement.addEventListener('touchstart', e => { if (e.touches.length === 1) { isDragging = true; prevMouse = { x: e.touches[0].clientX, y: e.touches[0].clientY }; } });
renderer.domElement.addEventListener('touchmove', e => {
  if (!isDragging || e.touches.length !== 1) return;
  spherical.theta -= (e.touches[0].clientX - prevMouse.x) * 0.005;
  spherical.phi -= (e.touches[0].clientY - prevMouse.y) * 0.005;
  prevMouse = { x: e.touches[0].clientX, y: e.touches[0].clientY };
