<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);

const camera = new THREE.PerspectiveCamera(45, innerWidth / innerHeight, 0.1, 100);
camera.position.set(0, 1, 6);
camera.lookAt(0, 0, 0);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(devicePixelRatio);
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

// ── Lights ──
const ambient = new THREE.AmbientLight(0xffffff, 0.4);
scene.add(ambient);

const dir = new THREE.DirectionalLight(0xfff4e6, 1.0);
dir.position.set(5, 8, 6);
dir.castShadow = true;
scene.add(dir);

const rim = new THREE.PointLight(0x4a90d9, 0.6, 20);
rim.position.set(-4, 2, -3);
scene.add(rim);

// ── Materials ──
const bodyMat   = new THREE.MeshStandardMaterial({ color: 0xf5f0e8, roughness: 0.8, metalness: 0.0 });
const flapMat   = new THREE.MeshStandardMaterial({ color: 0xe8dcc8, roughness: 0.8, metalness: 0.0 });
const backMat   = new THREE.MeshStandardMaterial({ color: 0xf0ebe3, roughness: 0.8, metalness: 0.0 });
const sealMat   = new THREE.MeshStandardMaterial({ color: 0xc0392b, roughness: 0.3, metalness: 0.2 });
const stampMat  = new THREE.MeshStandardMaterial({ color: 0x2980b9, roughness: 0.6 });
const heartMat  = new THREE.MeshStandardMaterial({ color: 0xe74c3c, roughness: 0.4, emissive: 0xe74c3c, emissiveIntensity: 0.15 });

// ── Envelope Group ──
const envelope = new THREE.Group();

// Body dimensions
const W = 3.0, H = 2.0, D = 0.08;

// ── Body (thin box) ──
const bodyGeo = new THREE.BoxGeometry(W, H, D);
const body = new THREE.Mesh(bodyGeo, bodyMat);
body.position.y = 0;
body.castShadow = true;
body.receiveShadow = true;
envelope.add(body);

// ── Back panel (slightly larger to show depth) ──
const backGeo = new THREE.BoxGeometry(W + 0.02, H + 0.02, D * 0.5);
const back = new THREE.Mesh(backGeo, backMat);
back.position.z = -D * 0.75;
envelope.add(back);

// ── Triangular flap ──
function createFlapGeometry() {
  const geo = new THREE.BufferGeometry();
  // Triangle: base along top edge, tip pointing down
  const hw = W / 2;
  const tipY = H / 2 - 0.9;
  const vertices = new Float32Array([
    // Front face
    -hw,  H / 2,  D * 0.5,
     hw,  H / 2,  D * 0.5,
     0,   tipY,   D * 0.5,
    // Back face
    -hw,  H / 2, -D * 0.5,
     hw,  H / 2, -D * 0.5,
     0,   tipY,  -D * 0.5,
  ]);

  const indices = [
    // Front
    0, 1, 2,
    // Back
    3, 5, 4,
    // Left side
    0, 3, 2, 2, 3, 5,
    // Right side
    1, 2, 4, 4, 2, 5,
    // Top edge (thin strip)
    0, 4, 1, 1, 4, 3,
  ];

  geo.setAttribute('position', new THREE.BufferAttribute(vertices, 3));
  geo.setIndex(indices);
  geo.computeVertexNormals();
  return geo;
}

const flapGeo = createFlapGeometry();
const flap = new THREE.Mesh(flapGeo, flapMat);
flap.castShadow = true;
envelope.add(flap);

// ── Wax seal ──
const sealGeo = new THREE.CylinderGeometry(0.18, 0.18, 0.06, 24);
const seal = new THREE.Mesh(sealGeo, sealMat);
seal.rotation.x = Math.PI / 2;
seal.position.set(0, H / 2 - 0.55, D * 0.5 + 0.03);
seal.castShadow = true;
envelope.add(seal);

// ── Stamp ──
const stampGeo = new THREE.BoxGeometry(0.45, 0.55, 0.01);
const stamp = new THREE.Mesh(stampGeo, stampMat);
stamp.position.set(W / 2 - 0.35, H / 2 - 0.35, D * 0.5 + 0.005);
envelope.add(stamp);

// ── Heart on front ──
const heartShape = new THREE.Shape();
const hx = 0, hy = 0, s = 0.12;
heartShape.moveTo(hx, hy + s * 4);
heartShape.bezierCurveTo(hx, hy + s * 4.6, hx - s * 3.2, hy + s * 5.4, hx - s * 3.2, hy + s * 3.4);
heartShape.bezierCurveTo(hx - s * 3.2, hy + s * 1.6, hx, hy, hx, hy);
heartShape.bezierCurveTo(hx, hy, hx + s * 3.2, hy + s * 1.6, hx + s * 3.2, hy + s * 3.4);
heartShape.bezierCurveTo(hx + s * 3.2, hy + s * 5.4, hx, hy + s * 4.6, hx, hy + s * 4);

const heartGeo = new THREE.ExtrudeGeometry(heartShape, { depth: 0.015, bevelEnabled: true, bevelThickness: 0.01, bevelSize: 0.01, bevelSegments: 3 });
const heart = new THREE.Mesh(heartGeo, heartMat);
heart.position.set(0, 0.1, D * 0.5 + 0.008);
heart.scale.set(1.3, 1.3, 1);
envelope.add(heart);

// ── Fold line (subtle crease) ──
const creaseGeo = new THREE.BoxGeometry(W - 0.02, 0.008, D * 1.1);
const creaseMat = new THREE.MeshStandardMaterial({ color: 0xd4c9b8, roughness: 0.9 });
const crease = new THREE.Mesh(creaseGeo, creaseMat);
crease.position.y = H / 2;
envelope.add(crease);

// ── Address lines ──
function makeLine(x, y, w) {
  const g = new THREE.BoxGeometry(w, 0.012, 0.005);
  const m = new THREE.MeshStandardMaterial({ color: 0xc9b99a, roughness: 0.9 });
  const mesh = new THREE.Mesh(g, m);
  mesh.position.set(x, y, D * 0.5 + 0.004);
  envelope.add(mesh);
}
makeLine(-0.3, -0.3, 1.2);
makeLine(-0.3, -0.5, 1.6);
makeLine(-0.3, -0.7, 1.0);

scene.add(envelope);

// ── Floor ──
const floorGeo = new THREE.PlaneGeometry(30, 30);
const floorMat = new THREE.MeshStandardMaterial({ color: 0x16213e, roughness: 0.95 });
const floor = new THREE.Mesh(floorGeo, floorMat);
floor.rotation.x = -Math.PI / 2;
floor.position.y = -2.2;
floor.receiveShadow = true;
scene.add(floor);

// ── Particles ──
const particleCount = 60;
const pGeo = new THREE.BufferGeometry();
const pPos = new Float32Array(particleCount * 3);
for (let i = 0; i < particleCount; i++) {
  pPos[i * 3]     = (Math.random() - 0.5) * 14;
  pPos[i * 3 + 1] = (Math.random() - 0.5) * 10;
  pPos[i * 3 + 2] = (Math.random() - 0.5) * 10;
}
pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
const pMat = new THREE.PointsMaterial({ color: 0x4a90d9, size: 0.04, transparent: true, opacity: 0.5 });
const particles = new THREE.Points(pGeo, pMat);
scene.add(particles);

// ── Animation ──
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  envelope.rotation.y = Math.sin(t * 0.4) * 0.5;
  envelope.rotation.x = Math.sin(t * 0.25) * 0.08;
  envelope.position.y = Math.sin(t * 0.6) * 0.15;

  particles.rotation.y = t * 0.02;
  particles.rotation.x = t * 0.01;

  renderer.render(scene, camera);
}
animate();

// ── Resize ──
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
</body>
</html>
