}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// --- Scene Setup ---
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.Fog(0x1a1a2e, 10, 25);

const camera = new THREE.PerspectiveCamera(50, innerWidth / innerHeight, 0.1, 100);
camera.position.set(4, 3, 5);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);
controls.target.set(0, 2.5, 0);
controls.update();

// --- Lighting ---
const ambientLight = new THREE.AmbientLight(0x404060, 0.8);
scene.add(ambientLight);

const dirLight = new THREE.DirectionalLight(0xffeedd, 1.5);
dirLight.position.set(5, 8, 4);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(1024, 1024);
scene.add(dirLight);

const pointLight = new THREE.PointLight(0x4488ff, 0.5, 15);
pointLight.position.set(-3, 4, -2);
scene.add(pointLight);

// --- Materials ---
const metalMat = new THREE.MeshStandardMaterial({ color: 0x888899, metalness: 0.8, roughness: 0.3 });
const darkMat = new THREE.MeshStandardMaterial({ color: 0x222233, metalness: 0.6, roughness: 0.4 });
const bladeMat = new THREE.MeshStandardMaterial({
  color: 0x3366aa, metalness: 0.4, roughness: 0.3, side: THREE.DoubleSide
});
const cageMat = new THREE.MeshStandardMaterial({ color: 0x666677, metalness: 0.7, roughness: 0.3 });
const baseMat = new THREE.MeshStandardMaterial({ color: 0x333344, metalness: 0.5, roughness: 0.5 });

// --- Floor ---
const floor = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  new THREE.MeshStandardMaterial({ color: 0x111122, roughness: 0.9 })
);
floor.rotation.x = -Math.PI / 2;
floor.receiveShadow = true;
scene.add(floor);

// --- Fan Group ---
const fan = new THREE.Group();
scene.add(fan);

// --- Base ---
const base = new THREE.Mesh(new THREE.CylinderGeometry(0.6, 0.7, 0.15, 32), baseMat);
base.position.y = 0.075;
base.castShadow = true;
fan.add(base);

const baseTop = new THREE.Mesh(new THREE.CylinderGeometry(0.5, 0.6, 0.08, 32), darkMat);
baseTop.position.y = 0.19;
fan.add(baseTop);

// --- Pole ---
const pole = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.08, 2.8, 16), metalMat);
pole.position.y = 1.58;
pole.castShadow = true;
fan.add(pole);

// --- Motor Housing ---
const motorHousing = new THREE.Mesh(
  new THREE.SphereGeometry(0.35, 32, 16, 0, Math.PI * 2, 0, Math.PI / 2),
  darkMat
);
motorHousing.position.y = 3.0;
motorHousing.castShadow = true;
fan.add(motorHousing);

const motorBack = new THREE.Mesh(
  new THREE.CylinderGeometry(0.3, 0.32, 0.15, 32),
  darkMat
);
motorBack.position.y = 3.0;
fan.add(motorBack);

// --- Blade Group (spinning) ---
const bladeGroup = new THREE.Group();
bladeGroup.position.y = 3.0;
fan.add(bladeGroup);

// --- Blades ---
const bladeShape = new THREE.Shape();
bladeShape.moveTo(0, 0);
bladeShape.bezierCurveTo(0.15, 0.3, 0.12, 0.7, 0.05, 1.0);
bladeShape.lineTo(-0.05, 1.0);
bladeShape.bezierCurveTo(-0.08, 0.7, -0.12, 0.3, -0.08, 0);
bladeShape.closePath();

const bladeGeo = new THREE.ExtrudeGeometry(bladeShape, {
  depth: 0.02, bevelEnabled: true, bevelThickness: 0.01, bevelSize: 0.01, bevelSegments: 3
});

const NUM_BLADES = 5;
for (let i = 0; i < NUM_BLADES; i++) {
  const blade = new THREE.Mesh(bladeGeo, bladeMat);
  blade.rotation.z = (Math.PI * 2 / NUM_BLADES) * i;
  blade.rotation.y = 0.3; // slight pitch
  blade.position.z = -0.01;
  blade.castShadow = true;
  bladeGroup.add(blade);
}

// --- Hub ---
const hub = new THREE.Mesh(new THREE.CylinderGeometry(0.1, 0.1, 0.08, 16), metalMat);
hub.rotation.x = Math.PI / 2;
bladeGroup.add(hub);

const hubCap = new THREE.Mesh(new THREE.SphereGeometry(0.08, 16, 16), metalMat);
hubCap.position.z = 0.04;
bladeGroup.add(hubCap);

// --- Cage (front & back) ---
function createCageRing(radius, segments) {
  const group = new THREE.Group();

  // Outer ring
  const outerRing = new THREE.Mesh(
    new THREE.TorusGeometry(radius, 0.02, 8, segments),
    cageMat
  );
  group.add(outerRing);

  // Inner ring
  const innerRing = new THREE.Mesh(
    new THREE.TorusGeometry(0.15, 0.015, 8, 16),
    cageMat
  );
  group.add(innerRing);

  // Radial wires
  for (let i = 0; i < segments; i++) {
    const angle = (Math.PI * 2 / segments) * i;
    const wire = new THREE.Mesh(
      new THREE.CylinderGeometry(0.008, 0.008, radius - 0.15, 6),
      cageMat
    );
    wire.position.set(
      Math.cos(angle) * (radius + 0.15) / 2,
      Math.sin(angle) * (radius + 0.15) / 2,
      0
    );
    wire.rotation.z = angle;
    group.add(wire);
  }

  // Cross wires (2 rings)
  for (let r = 0; r < 2; r++) {
    const ringR = 0.3 + r * 0.25;
    const crossRing = new THREE.Mesh(
      new THREE.TorusGeometry(ringR, 0.008, 6, segments),
      cageMat
    );
    group.add(crossRing);
  }

  return group;
}

const cageBack = createCageRing(1.05, 12);
cageBack.position.z = -0.06;
bladeGroup.add(cageBack);

const cageFront = createCageRing(1.05, 12);
cageFront.position.z = 0.06;
fan.add(cageFront);

// --- Tilt Joint ---
const tiltJoint = new THREE.Mesh(new THREE.SphereGeometry(0.12, 16, 16), darkMat);
tiltJoint.position.y = 3.0;
fan.add(tiltJoint);

// --- Speed Control Button (on base) ---
const btnGeo = new THREE.CylinderGeometry(0.06, 0.06, 0.04, 16);
const btnMat = new THREE.MeshStandardMaterial({ color: 0x22cc44, metalness: 0.3, roughness: 0.5, emissive: 0x114411 });
const powerBtn = new THREE.Mesh(btnGeo, btnMat);
powerBtn.rotation.x = Math.PI / 2;
powerBtn.position.set(0.35, 0.2, 0.35);
fan.add(powerBtn);

// --- Animation ---
let speed = 0.15;
let targetSpeed = 0.15;
let time = 0;

powerBtn.userData.isButton = true;

// Click to toggle speed
renderer.domElement.addEventListener('click', (e) => {
  const mouse = new THREE.Vector2(
    (e.clientX / innerWidth) * 2 - 1,
    -(e.clientY / innerHeight) * 2 + 1
  );
  const raycaster = new THREE.Raycaster();
  raycaster.setFromCamera(mouse, camera);
  const intersects = raycaster.intersectObject(powerBtn);
  if (intersects.length > 0) {
    if (targetSpeed > 0.01) {
      targetSpeed *= 0.7;
    } else {
      targetSpeed = 0.15;
    }
  }
});

function animate() {
  requestAnimationFrame(animate);
  time += 0.016;

  // Smooth speed transition
  speed += (targetSpeed - speed) * 0.05;
  bladeGroup.rotation.z += speed;

  // Subtle wobble at high speed
  if (speed > 0.05) {
    const wobble = Math.sin(time * 20) * (speed - 0.05) * 0.003;
    fan.rotation.z = wobble;
  }

  // Button glow pulse
  if (targetSpeed > 0.01) {
    btnMat.emissiveIntensity = 0.5 + Math.sin(time * 3) * 0.3;
  }

  controls.update();
  renderer.render(scene, camera);
}

animate();

// --- Resize ---
window.addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});
</script>
