  <div id="info">🖱 Drag to orbit &nbsp;|&nbsp; Scroll to zoom</div>

  <script type="importmap">
  {
    "imports": {
      "three": "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.js",
      "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/"
    }
  }
  </script>

  <script type="module">
    import * as THREE from 'three';
    import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

    // ── Scene, Camera, Renderer ──
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x87CEEB);
    scene.fog = new THREE.FogExp2(0x87CEEB, 0.012);

    const camera = new THREE.PerspectiveCamera(55, innerWidth / innerHeight, 0.1, 200);
    camera.position.set(10, 6, 14);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(innerWidth, innerHeight);
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    document.body.appendChild(renderer.domElement);

    // ── Controls ──
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.target.set(0, 1.2, 0);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.maxPolarAngle = Math.PI / 2.05;
    controls.minDistance = 5;
    controls.maxDistance = 40;

    // ── Lighting ──
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
    scene.add(ambientLight);

    const sun = new THREE.DirectionalLight(0xfff4e0, 1.8);
    sun.position.set(10, 15, 8);
    sun.castShadow = true;
    sun.shadow.mapSize.set(2048, 2048);
    sun.shadow.camera.near = 0.5;
    sun.shadow.camera.far = 50;
    sun.shadow.camera.left = -20;
    sun.shadow.camera.right = 20;
    sun.shadow.camera.top = 20;
    sun.shadow.camera.bottom = -20;
    sun.shadow.bias = -0.001;
    scene.add(sun);

    const hemi = new THREE.HemisphereLight(0x87CEEB, 0x3a7d3a, 0.4);
    scene.add(hemi);

    // ── Materials ──
    const postMat = new THREE.MeshStandardMaterial({ color: 0x8B6914, roughness: 0.85, metalness: 0.05 });
    const railMat = new THREE.MeshStandardMaterial({ color: 0xA0782C, roughness: 0.8, metalness: 0.05 });
    const picketMat = new THREE.MeshStandardMaterial({ color: 0x9B7B3A, roughness: 0.8, metalness: 0.05 });
    const groundMat = new THREE.MeshStandardMaterial({ color: 0x4a8c3f, roughness: 1.0 });
    const concreteMat = new THREE.MeshStandardMaterial({ color: 0x999999, roughness: 0.95 });

    // ── Ground ──
    const ground = new THREE.Mesh(
      new THREE.PlaneGeometry(80, 80),
      groundMat
    );
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);

    // ── Fence Builder ──
    const FENCE_LENGTH = 12;
    const POST_COUNT = 7;
    const POST_SPACING = FENCE_LENGTH / (POST_COUNT - 1);
    const POST_HEIGHT = 2.8;
    const POST_W = 0.18;
    const POST_D = 0.18;
    const RAIL_HEIGHTS = [0.6, 1.5];
    const RAIL_H = 0.1;
    const RAIL_D = 0.08;
    const PICKET_COUNT = 4;
    const PICKET_W = 0.06;
    const PICKET_D = 0.04;
    const PICKET_H = 1.2;

    const fenceGroup = new THREE.Group();
    scene.add(fenceGroup);

    function buildFence(startX, startZ, alongAxis) {
      const group = new THREE.Group();

      for (let i = 0; i < POST_COUNT; i++) {
        const t = i / (POST_COUNT - 1);
        const px = alongAxis === 'x' ? startX + t * FENCE_LENGTH : startX;
        const pz = alongAxis === 'z' ? startZ + t * FENCE_LENGTH : startZ;

        // Concrete base
        const base = new THREE.Mesh(
          new THREE.BoxGeometry(POST_W + 0.2, 0.15, POST_D + 0.2),
          concreteMat
        );
        base.position.set(px, 0.075, pz);
        base.castShadow = true;
        base.receiveShadow = true;
        group.add(base);

        // Post
        const post = new THREE.Mesh(
          new THREE.BoxGeometry(POST_W, POST_HEIGHT, POST_D),
          postMat
        );
        post.position.set(px, POST_HEIGHT / 2, pz);
        post.castShadow = true;
        post.receiveShadow = true;
        group.add(post);

        // Pickets (between rails)
        if (i < POST_COUNT - 1) {
          const nextX = alongAxis === 'x' ? px + POST_SPACING : px;
          const nextZ = alongAxis === 'z' ? pz + POST_SPACING : pz;
          const midX = (px + nextX) / 2;
          const midZ = (pz + nextZ) / 2;

          for (let p = 0; p < PICKET_COUNT; p++) {
            const offset = (p - (PICKET_COUNT - 1) / 2) * (POST_SPACING / PICKET_COUNT);
            const picketX = alongAxis === 'x' ? px + offset : px;
            const picketZ = alongAxis === 'z' ? pz + offset : pz;

            const picket = new THREE.Mesh(
              new THREE.BoxGeometry(PICKET_W, PICKET_H, PICKET_D),
              picketMat
            );
            picket.position.set(picketX, RAIL_HEIGHTS[0] + PICKET_H / 2, picketZ);
            picket.castShadow = true;
            picket.receiveShadow = true;
            group.add(picket);
          }
        }
      }

      // Rails
      for (const rh of RAIL_HEIGHTS) {
        const rail = new THREE.Mesh(
          new THREE.BoxGeometry(
            alongAxis === 'x' ? FENCE_LENGTH + POST_W : RAIL_D,
            RAIL_H,
            alongAxis === 'z' ? FENCE_LENGTH + POST_D : RAIL_D
          ),
          railMat
        );
        rail.position.set(
          alongAxis === 'x' ? startX + FENCE_LENGTH / 2 : startX,
          rh,
          alongAxis === 'z' ? startZ + FENCE_LENGTH / 2 : startZ
        );
        rail.castShadow = true;
        rail.receiveShadow = true;
        group.add(rail);
      }

      return group;
    }

    // Main fence along X axis
    fenceGroup.add(buildFence(-FENCE_LENGTH / 2, 0, 'x'));

    // Side fence along Z axis (perpendicular)
    fenceGroup.add(buildFence(FENCE_LENGTH / 2, -FENCE_LENGTH / 2, 'z'));

    // ── Decorative elements ──

    // Gate between two posts
    const gateGroup = new THREE.Group();
    const gatePost1 = new THREE.Mesh(
      new THREE.BoxGeometry(0.25, POST_HEIGHT, 0.25),
      postMat
    );
    gatePost1.position.set(FENCE_LENGTH / 2 - 0.6, POST_HEIGHT / 2, 0);
    gatePost1.castShadow = true;
    gateGroup.add(gatePost1);

    const gatePost2 = new THREE.Mesh(
      new THREE.BoxGeometry(0.25, POST_HEIGHT, 0.25),
      postMat
    );
    gatePost2.position.set(FENCE_LENGTH / 2 - 1.8, POST_HEIGHT / 2, 0);
    gatePost2.castShadow = true;
    gateGroup.add(gatePost2);

    // Gate rails
    for (const rh of RAIL_HEIGHTS) {
      const gateRail = new THREE.Mesh(
        new THREE.BoxGeometry(1.2, RAIL_H, 0.08),
        railMat
      );
      gateRail.position.set(FENCE_LENGTH / 2 - 1.2, rh, 0);
      gateRail.castShadow = true;
      gateGroup.add(gateRail);
    }

    // Gate pickets
    for (let p = 0; p < 3; p++) {
      const picket = new THREE.Mesh(
        new THREE.BoxGeometry(PICKET_W, PICKET_H, 0.04),
        picketMat
      );
      picket.position.set(FENCE_LENGTH / 2 - 1.2 + (p - 1) * 0.3, RAIL_HEIGHTS[0] + PICKET_H / 2, 0);
      picket.castShadow = true;
      gateGroup.add(picket);
    }

    // Gate latch
    const latch = new THREE.Mesh(
      new THREE.CylinderGeometry(0.02, 0.02, 0.2, 8),
      new THREE.MeshStandardMaterial({ color: 0x555555, metalness: 0.8, roughness: 0.3 })
    );
    latch.position.set(FENCE_LENGTH / 2 - 1.2, RAIL_HEIGHTS[0] + 0.3, 0.06);
    latch.rotation.z = Math.PI / 2;
    gateGroup.add(latch);

    fenceGroup.add(gateGroup);

    // ── Flowers / bushes ──
    const bushMat = new THREE.MeshStandardMaterial({ color: 0x2d6b2e, roughness: 0.95 });
    const flowerColors = [0xff6b8a, 0xffd700, 0xff4444, 0xffffff, 0xdd88ff];

    function addBush(x, z, scale = 1) {
      const bush = new THREE.Mesh(
        new THREE.SphereGeometry(0.4 * scale, 12, 8),
        bushMat
      );
      bush.position.set(x, 0.3 * scale, z);
      bush.castShadow = true;
      bush.receiveShadow = true;
      scene.add(bush);

      // Add flowers on top
      for (let f = 0; f < 3; f++) {
        const flower = new THREE.Mesh(
          new THREE.SphereGeometry(0.08, 8, 6),
          new THREE.MeshStandardMaterial({
            color: flowerColors[Math.floor(Math.random() * flowerColors.length)],
            roughness: 0.6
          })
        );
        const angle = (f / 3) * Math.PI * 2;
        flower.position.set(
          x + Math.cos(angle) * 0.2 * scale,
          0.55 * scale,
          z + Math.sin(angle) * 0.2 * scale
        );
        scene.add(flower);
      }
    }

    addBush(-6, -1.2, 1.2);
    addBush(-3, -1.0, 0.9);
    addBush(0, -1.3, 1.1);
    addBush(3, -1.0, 1.0);
    addBush(6, -1.2, 1.3);
    addBush(-1, -1.1, 0.8);
    addBush(5, -1.1, 0.9);

    // ── Clouds ──
    const cloudMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 1, transparent: true, opacity: 0.85 });

    function addCloud(x, y, z) {
      const cloud = new THREE.Group();
      const blobs = 3 + Math.floor(Math.random() * 3);
      for (let b = 0; b < blobs; b++) {
        const blob = new THREE.Mesh(
          new THREE.SphereGeometry(0.5 + Math.random() * 0.6, 10, 8),
          cloudMat
        );
        blob.position.set(b * 0.7 - blobs * 0.35, Math.random() * 0.2, Math.random() * 0.3);
        blob.scale.y = 0.5;
        cloud.add(blob);
      }
      cloud.position.set(x, y, z);
      scene.add(cloud);
      return cloud;
    }

    const clouds = [];
    clouds.push(addCloud(-15, 12, -20));
    clouds.push(addCloud(10, 14, -25));
    clouds.push(addCloud(20, 11, -18));
    clouds.push(addCloud(-8, 13, -22));
    clouds.push(addCloud(5, 15, -30));

    // ── Animation ──
    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const elapsed = clock.getElapsedTime();

      // Slow cloud drift
      clouds.forEach((cloud, i) => {
        cloud.position.x += 0.003 * (i % 2 === 0 ? 1 : -0.7);
        if (cloud.position.x > 30) cloud.position.x = -30;
        if (cloud.position.x < -30) cloud.position.x = 30;
      });

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
  </script>
</body>
