<body>
<div id="info">fig · ficus carica</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.164.1/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { RoomEnvironment } from 'three/addons/environments/RoomEnvironment.js';

/* ─── renderer ─── */
const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
document.body.appendChild(renderer.domElement);

/* ─── scene & camera ─── */
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1a2e);
scene.fog = new THREE.FogExp2(0x1a1a2e, 0.06);

const camera = new THREE.PerspectiveCamera(35, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 1.2, 5);

const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.target.set(0, 0.6, 0);
controls.minDistance = 2;
controls.maxDistance = 12;
controls.maxPolarAngle = Math.PI * 0.85;

/* ─── environment map ─── */
const pmrem = new THREE.PMREMGenerator(renderer);
pmrem.compileEquirectangularShader();
scene.environment = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;

/* ─── lights ─── */
const key = new THREE.DirectionalLight(0xffeedd, 2.5);
key.position.set(3, 6, 4);
key.castShadow = true;
key.shadow.mapSize.set(1024, 1024);
key.shadow.camera.near = 1; key.shadow.camera.far = 20;
key.shadow.camera.left = -4; key.shadow.camera.right = 4;
key.shadow.camera.top = 4;  key.shadow.camera.bottom = -4;
key.shadow.bias = -0.002;
scene.add(key);

const fill = new THREE.DirectionalLight(0x8899bb, 0.8);
fill.position.set(-4, 3, -2);
scene.add(fill);

const rim = new THREE.DirectionalLight(0xffc87a, 1.2);
rim.position.set(-2, 2, -5);
scene.add(rim);

const hemi = new THREE.HemisphereLight(0x99bbdd, 0x443322, 0.5);
scene.add(hemi);

/* ─── ground plane ─── */
const groundGeo = new THREE.CircleGeometry(8, 64);
const groundMat = new THREE.MeshStandardMaterial({
  color: 0x2a2a3e, roughness: 0.85, metalness: 0.0
});
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
ground.receiveShadow = true;
scene.add(ground);

/* ─── fig body via LatheGeometry ─── */
// Profile: trace the left half of a fig cross-section (radius vs height)
const profilePoints = [];
const N = 40;

// Bottom tip (narrow, near the ostiole)
for (let i = 0; i <= N; i++) {
  const t = i / N;
  let r, y;

  if (t < 0.04) {
    // very narrow bottom tip
    const s = t / 0.04;
    r = 0.01 + 0.12 * s;
    y = t * 2.2;
  } else if (t < 0.15) {
    // slight bulge at ostiole
    const s = (t - 0.04) / 0.11;
    r = 0.13 + 0.08 * Math.sin(s * Math.PI);
    y = 0.04 * 2.2 + s * 0.25;
  } else if (t < 0.55) {
    // main body – widest around t≈0.4
    const s = (t - 0.15) / 0.4;
    r = 0.21 + 0.38 * Math.sin(s * Math.PI);
    y = 0.29 + s * 0.7;
  } else if (t < 0.85) {
    // tapering toward top
    const s = (t - 0.55) / 0.3;
    r = 0.59 * (1 - s * 0.72);
    y = 0.99 + s * 0.55;
  } else {
    // top near stem – slight dimple
    const s = (t - 0.85) / 0.15;
    r = 0.166 * (1 - s * 0.65);
    y = 1.54 + s * 0.18;
  }

  profilePoints.push(new THREE.Vector2(r, y));
}

const figBodyGeo = new THREE.LatheGeometry(profilePoints, 48);
figBodyGeo.computeVertexNormals();

const figBodyMat = new THREE.MeshStandardMaterial({
  color: 0x6b2fa0,
  roughness: 0.55,
  metalness: 0.05,
  bumpScale: 0.005,
});

// Subtle bump map via canvas
const bumpCanvas = document.createElement('canvas');
bumpCanvas.width = 256; bumpCanvas.height = 256;
const bCtx = bumpCanvas.getContext('2d');
for (let x = 0; x < 256; x++) for (let y = 0; y < 256; y++) {
  const v = 128 + (Math.random() - 0.5) * 40;
  bCtx.fillStyle = `rgb(${v},${v},${v})`;
  bCtx.fillRect(x, y, 1, 1);
}
const bumpTex = new THREE.CanvasTexture(bumpCanvas);
bumpTex.wrapS = bumpTex.wrapT = THREE.RepeatWrapping;
figBodyMat.bumpMap = bumpTex;

const figBody = new THREE.Mesh(figBodyGeo, figBodyMat);
figBody.castShadow = true;
figBody.receiveShadow = true;
scene.add(figBody);

/* ─── ostiole (bottom opening) ─── */
const ostioleGeo = new THREE.TorusGeometry(0.055, 0.015, 12, 24);
const ostioleMat = new THREE.MeshStandardMaterial({
  color: 0x3d1a5c, roughness: 0.7, metalness: 0.0
});
const ostiole = new THREE.Mesh(ostioleGeo, ostioleMat);
ostiole.rotation.x = Math.PI / 2;
ostiole.position.y = 0.08;
scene.add(ostiole);

// Inner dark circle for the ostiole hole
const holeGeo = new THREE.CircleGeometry(0.045, 24);
const holeMat = new THREE.MeshStandardMaterial({ color: 0x1a0a2e, roughness: 1.0 });
const hole = new THREE.Mesh(holeGeo, holeMat);
hole.rotation.x = -Math.PI / 2;
hole.position.y = 0.078;
scene.add(hole);

/* ─── stem ─── */
const stemCurve = new THREE.CatmullRomCurve3([
  new THREE.Vector3(0, 1.72, 0),
  new THREE.Vector3(0.02, 1.85, 0.01),
  new THREE.Vector3(0.06, 1.98, 0.02),
  new THREE.Vector3(0.10, 2.10, 0.01),
]);
const stemGeo = new THREE.TubeGeometry(stemCurve, 12, 0.018, 8, false);
const stemMat = new THREE.MeshStandardMaterial({
  color: 0x5a3a2a, roughness: 0.8, metalness: 0.0
});
const stem = new THREE.Mesh(stemGeo, stemMat);
stem.castShadow = true;
scene.add(stem);

/* ─── leaf ─── */
function createLeaf() {
  const shape = new THREE.Shape();
  // Fig leaf lobes – approximate
  shape.moveTo(0, 0);
  shape.bezierCurveTo(0.08, 0.15, 0.12, 0.35, 0.06, 0.55);
  shape.bezierCurveTo(0.14, 0.50, 0.20, 0.55, 0.18, 0.65);
  shape.bezierCurveTo(0.22, 0.70, 0.18, 0.80, 0.12, 0.78);
  shape.bezierCurveTo(0.16, 0.85, 0.14, 0.95, 0.08, 0.92);
  shape.bezierCurveTo(0.10, 1.00, 0.05, 1.05, 0.0, 1.02);
  shape.bezierCurveTo(-0.05, 1.05, -0.10, 1.00, -0.08, 0.92);
  shape.bezierCurveTo(-0.14, 0.95, -0.16, 0.85, -0.12, 0.78);
  shape.bezierCurveTo(-0.18, 0.80, -0.22, 0.70, -0.18, 0.65);
  shape.bezierCurveTo(-0.20, 0.55, -0.14, 0.50, -0.06, 0.55);
  shape.bezierCurveTo(-0.12, 0.35, -0.08, 0.15, 0, 0);

  const geo = new THREE.ShapeGeometry(shape, 16);
  // Add slight curvature via vertex displacement
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    pos.setZ(i, -0.04 * y * (1 - y) + Math.sin(x * 12) * 0.008);
  }
  geo.computeVertexNormals();

  const mat = new THREE.MeshStandardMaterial({
    color: 0x3a7a3a,
    roughness: 0.65,
    metalness: 0.0,
    side: THREE.DoubleSide,
  });

  // Leaf veins
  const veinCanvas = document.createElement('canvas');
  veinCanvas.width = 256; veinCanvas.height = 256;
  const vCtx = veinCanvas.getContext('2d');
  vCtx.fillStyle = '#3a7a3a';
  vCtx.fillRect(0, 0, 256, 256);
  vCtx.strokeStyle = '#2a5a2a';
  vCtx.lineWidth = 2;
  // central vein
  vCtx.beginPath(); vCtx.moveTo(128, 250); vCtx.lineTo(128, 10); vCtx.stroke();
  // side veins
  for (let i = 0; i < 6; i++) {
    const yy = 50 + i * 35;
    vCtx.beginPath(); vCtx.moveTo(128, yy); vCtx.lineTo(80, yy - 20); vCtx.stroke();
    vCtx.beginPath(); vCtx.moveTo(128, yy); vCtx.lineTo(176, yy - 20); vCtx.stroke();
  }
  const veinTex = new THREE.CanvasTexture(veinCanvas);
  mat.alphaMap = veinTex;
  mat.transparent = false;

  return new THREE.Mesh(geo, mat);
}

const leaf = createLeaf();
leaf.scale.set(0.7, 0.7, 0.7);
leaf.position.set(0.12, 2.05, 0.02);
leaf.rotation.set(-0.3, 0.5, 0.4);
leaf.castShadow = true;
scene.add(leaf);

// Second smaller leaf
const leaf2 = createLeaf();
leaf2.scale.set(0.45, 0.45, 0.45);
leaf2.position.set(-0.05, 2.15, -0.02);
leaf2.rotation.set(0.4, -0.8, -0.3);
leaf2.castShadow = true;
