    const clock = new THREE.Clock();

    function animate() {
      requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      // Wave the flag
      const positions = flagGeo.attributes.position.array;
      for (let i = 0; i < positions.length; i += 3) {
        const ox = originalPositions[i];
        const oy = originalPositions[i + 1];

        // Normalized distance from pole (0 = pole, 1 = tip)
        const nx = ox / flagWidth;

        // Multiple sine waves for natural look
        const wave1 = Math.sin(nx * Math.PI * 3 - t * 3.0) * 0.18;
        const wave2 = Math.sin(nx * Math.PI * 5 - t * 4.5) * 0.08;
        const wave3 = Math.sin(nx * Math.PI * 2 - t * 2.0) * 0.12;

        // Amplitude increases away from pole
        const amplitude = nx * nx;

        // Vertical undulation
        const vertWave = Math.sin(nx * Math.PI * 2 - t * 2.5) * 0.06 * amplitude;

        positions[i]     = ox;
        positions[i + 1] = oy + vertWave;
        positions[i + 2] = (wave1 + wave2 + wave3) * amplitude;
      }
      flagGeo.attributes.position.needsUpdate = true;
      flagGeo.computeVertexNormals();

      // Slow star twinkle
      const starPos = starsGeo.attributes.position.array;
      for (let i = 0; i < starCount; i++) {
        starPos[i * 3 + 1] += Math.sin(t * 0.5 + i) * 0.001;
      }
      starsGeo.attributes.position.needsUpdate = true;

      controls.update();
      renderer.render(scene, camera);
    }

    animate();

    // ── Resize ──
    window.addEventListener('resize', () => {
      camera.aspect = innerWidth / innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(innerWidth, innerHeight);
    });
